-- Poems batch 381
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('845dd149-dee3-4ea0-9a64-c59138d2935a','甲午送甯子儀歸洛','呂本中','宋','宋诗','song-poetry','','[]','異時從公游，頗恨相得晚。',156,'全唐诗/poet.song.92000.json','["異時從公游，頗恨相得晚。", "同參長蘆禪，共聽資福板。", "公今三年病，我亦百事懶。", "春風廣陵城，笑語有未款。", "嵩陽有歸路，河水漸清暖。", "豈無一言贈，慰此千里遠。", "青松老合抱，意不在俗眼。", "豈如山上苗，共盡白日短。", "一身隨藥囊，萬事付茗盌。", "爐煙裊晴窗，自足了遲緩。", "奈何孔文舉，苦思坐客滿。", "更知蘇門公，遠效嵇中散。", "舟行儻見念，此語試三反。"]'),
('d1945ce8-7b0c-4c2d-a99e-03749b49c467','讀舊詩有感','呂本中','宋','宋诗','song-poetry','','[]','但聞微雨響梧桐，不悟高樓盡日風。',64,'全唐诗/poet.song.92000.json','["但聞微雨響梧桐，不悟高樓盡日風。", "團扇向人仍有意，短檠于汝漸無功。", "悮游兀者形骸外，恐墮淵源雲霧中。", "剩攪饑腸供好句，爲君常占一生窮。"]'),
('78884b6b-f1b2-44eb-b82c-bb1a90a1be6c','别後寄舍弟三十韻','呂本中','宋','宋诗','song-poetry','','[]','還家日已短，况此獨行情。',288,'全唐诗/poet.song.92000.json','["還家日已短，况此獨行情。", "客路三年别，秋帆十日程。", "小船擕手上，斜柳縱篙撐。", "岸失乖龍蟄，窗留素月縈。", "重回召伯埭，虛住廣陵城。", "破屋仍堅坐，殘鶯只强鳴。", "江猶渺漭去，草欲蔓延生。", "水縮蛙蟆鬬，場空霧雨横。", "土風沾瘧癘，民俗混蠻荆。", "豈識排門入，魚無倒屣迎。", "好詩思共讀，薄酒念同傾。", "枕席煩團扇，膏油乏短檠。", "可無道里念，或恐夢魂驚。", "惟昔交朋聚，相期文字盟。", "筆頭傳活法，胸次即圓成。", "孔劍猶霄鍊，隋珠有夜明。", "英華仰前輩，廓落到諸卿。", "敢計千金重，嘗叨一字榮。", "因觀劍器舞，復悟擔夫争。", "物固藏妙理，世誰能獨亨。", "乾坤在蒼莽，日月付峥嶸。", "凜凜曹劉上，容容沈謝并。", "直須用款款，未可笑平平。", "有弟能知我，他年肯過兄。"]'),
('fd69cb89-c13f-4212-94bb-23dbda659e1b','記夜','呂本中','宋','宋诗','song-poetry','','[]','殘暑薰炙人，安夢不得長。',180,'全唐诗/poet.song.92000.json','["殘暑薰炙人，安夢不得長。", "忽蒙千里風，慰此六尺牀。", "高梧舞清影，上懸明月光。", "初知枕簟穏，未厭塵土忙。", "中宵有臭蟲，其大如蛣蜣。", "排闥觸屏帳，怒欲凌空翔。", "熟視不得名，但見兩翼張。", "本草所不載，爾雅所未詳。", "夏蟲盛百族，此物尤猖狂。", "東窗不得睡，幸無疾病妨。", "惜哉有知物，點汚此微涼。", "人生要更事，美惡無不嘗。", "悉除糞壤念，頓悟服食方。", "去爲千丈松，凜然衝雪霜。", "慎勿學瓜瓠，置身籬落傍。"]'),
('dca93287-dc7c-4dd2-828c-27c34882efc9','夜坐','呂本中','宋','宋诗','song-poetry','','[]','廣陵城中聽夜雨，倒牀不眠問更鼓。',208,'全唐诗/poet.song.92000.json','["廣陵城中聽夜雨，倒牀不眠問更鼓。", "西風萬里卷長河，徧與淮山洗塵土。", "淮南米賤魚亦好，敢復摧頹歎羈旅。", "重簾複幕嬾相負，細字寒燈且如許。", "漫如爾雅注蟲魚，更就篇章考齊古。", "粗知俛首受寒餓，未暇着意尋豪舉。", "牀頭有酒不敢飲，况復閨門畫眉嫵。", "故人此去今幾時，亦有文字相撐拄。", "東明縣前濟陽路，每一夢至猶能數。", "少年不憚道里遠，平生未省别離苦。", "只今多病鬚已白，尚能呼渠醉而舞。", "田園未還君可恨，歲月漸晚吾何取。", "饑蟲遶壁不自聊，爾獨何情促機杼。"]'),
('95c66e5f-23d1-4e2f-a8c7-a2c50be48363','寄唐充之二十韻','呂本中','宋','宋诗','song-poetry','','[]','俗事自相促，吾生常作難。',240,'全唐诗/poet.song.92000.json','["俗事自相促，吾生常作難。", "長河已萬折，險路復千盤。", "坎壈深藏步，岑嶔穏轉鞍。", "誰知守樗散，略不悮泥蟠。", "末學多乖謬，微軀寔控摶。", "小兒成頂領，烈士吐心肝。", "許下少文舉，吴中無伯鸞。", "直須識根柢，始是極波瀾。", "念此欲誰語，想公還自寛。", "屢成長劍倚，得洗夜蟲酸。", "解后終年别，殷勤一笑歡。", "已除舌本强，仍斵鼻端漫。", "直節羣公念，高名四海間。", "相期更無事，所祝在加餐。", "晚日留殘雪，春雷續淺寒。", "欲行殊未必，堅坐只長歎。", "不厭道里遠，敢辭裘褐單。", "却尋三語掾，重對兩蒲團。", "剩欲洗胸次，先留倒筆端。", "何須灞陵岸，回首望長安。"]'),
('1387c0ff-26df-42c4-a4dd-83cbe6758e11','竹西亭','呂本中','宋','宋诗','song-poetry','','[]','十年走塵土，重上竹西亭。',48,'全唐诗/poet.song.92000.json','["十年走塵土，重上竹西亭。", "草木新容態，江山舊典刑。", "狂風掃毒暑，落月伴疏星。", "認取揚州路，荒城一抹青。"]'),
('11380a99-25c5-4c3a-9203-493c47cb686b','邵伯路中途遇前綱載茉莉花甚衆舟行甚急不得細觀也又有小盆榴等皆精妙奇靡之觀因成二絕  其一','呂本中','宋','宋诗','song-poetry','','[]','花似細薇香似蘭，已宜炎暑又宜寒。',32,'全唐诗/poet.song.92000.json','["花似細薇香似蘭，已宜炎暑又宜寒。", "心知合伴靈和柳，不許行人仔細看。"]'),
('a7af4d93-4550-49d8-9dc3-c88609e1591f','邵伯路中途遇前綱載茉莉花甚衆舟行甚急不得細觀也又有小盆榴等皆精妙奇靡之觀因成二絕  其二','呂本中','宋','宋诗','song-poetry','','[]','玉檜盆榴作隊来，異香相趁不相猜。',32,'全唐诗/poet.song.92000.json','["玉檜盆榴作隊来，異香相趁不相猜。", "從今閉向深宫裏，莫學江湖自在開。"]'),
('b865b61a-3313-41a7-aec2-7c52941a31d3','飲秦少方家','呂本中','宋','宋诗','song-poetry','','[]','秦郎家畔一甌茶，何處清涼不是家。',32,'全唐诗/poet.song.92000.json','["秦郎家畔一甌茶，何處清涼不是家。", "客子三杯玉泉酒，主人一曲浪淘沙。"]'),
('c4c1a8ef-a32a-4189-ae1c-2409c7c7d5c6','孫量臣約游乾明借秦少方韻見贈復次韻答之','呂本中','宋','宋诗','song-poetry','','[]','睦州香火趙州茶，走徧叢林不着家。',32,'全唐诗/poet.song.92000.json','["睦州香火趙州茶，走徧叢林不着家。", "今日爲公拈出也，兩橋人語是高沙。"]'),
('89127edf-9a75-4394-bf6e-3ba0884f6a89','春晚郊居','呂本中','宋','宋诗','song-poetry','','[]','柳外樓高綠半遮，傷心春色在天涯。',64,'全唐诗/poet.song.92000.json','["柳外樓高綠半遮，傷心春色在天涯。", "低迷簾幕家家雨，淡蕩園林處處花。", "簷影已飛新社燕，水痕初沒去年沙。", "地偏長者無車轍，掃地從教草徑斜。"]'),
('1dfea6ac-21b3-4b19-81ad-9eb20a0390e9','外姊趙夫人智量以良人沒祝髮感歎成詩','呂本中','宋','宋诗','song-poetry','','[]','故人前去冢纍纍，爲恨爲憂未肯歸。',64,'全唐诗/poet.song.92000.json','["故人前去冢纍纍，爲恨爲憂未肯歸。", "從有青山可藏骨，却無紅淚與沾衣。", "饒三笑汝參禪誤，晁四憐渠祝髪非。", "猶勝同儕二三子，枉隨秋草閉斜暉。"]'),
('7595aef6-93ab-4dbf-b871-c1327514c511','代贈','呂本中','宋','宋诗','song-poetry','','[]','十年流落漫西東，想見謝家林下風。',64,'全唐诗/poet.song.92000.json','["十年流落漫西東，想見謝家林下風。", "晉邑自思欒孺子，魯儒空望叔孫通。", "風花已分飄藩外，玉樹何情著土中。", "縱有春梢堪寓目，却無人面與争紅。"]'),
('2e3203f3-ae06-4d14-befc-df210a56122f','又代贈','呂本中','宋','宋诗','song-poetry','','[]','略無歸夢遶湖湘，漫逐微陰出建章。',64,'全唐诗/poet.song.92000.json','["略無歸夢遶湖湘，漫逐微陰出建章。", "月裏寒珠一生露，鏡中衰鬢十年霜。", "逢人莫唱相思調，閲世終無却老方。", "想得扁舟北還路，斷雲衰草更斜陽。"]'),
('39bc2f8c-1c7a-4a52-ae9b-c7ae54c5f420','臨川王坦夫故從谿堂先生謝無逸學北行過廣陵見余意甚勤其行也作詩送之','呂本中','宋','宋诗','song-poetry','','[]','王郎别我春已晚，索我題詩敢辭懶。',96,'全唐诗/poet.song.92000.json','["王郎别我春已晚，索我題詩敢辭懶。", "讀書萬卷君所聞，只要躬行不相反。", "聖人遺言凜可畏，小事未免書之簡。", "衣冠瞻視有法則，何獨文章要編剗。", "譬如逆風曳長艦，竭力正在千夫挽。", "君行念此須飽參，即是谿堂句中眼。"]'),
('076a6f29-5ba2-4568-bfc0-bf8787037adf','登淮南樓','呂本中','宋','宋诗','song-poetry','','[]','樓上西風日脚斜，樓前廣道更人家。',64,'全唐诗/poet.song.92000.json','["樓上西風日脚斜，樓前廣道更人家。", "高林稍稍變黄葉，細草重重冒白花。", "薄酒尚堪遶舌本，故人何事走天涯。", "蓬籠只繋南亭下，乞與寒江整釣車。"]'),
('5543f800-ad14-4459-b951-ea4d178dba11','題淮上亭子','呂本中','宋','宋诗','song-poetry','','[]','亭下長淮百尺深，亭前雙樹老侵尋。',64,'全唐诗/poet.song.92000.json','["亭下長淮百尺深，亭前雙樹老侵尋。", "暮雲秋雁且南北，斷壟荒園無古今。", "露草欲隨霜草盡，歸檣時度去檣陰。", "秋風未滿鱸魚興，更有江湖萬里心。"]'),
('b09f9949-971f-45ca-9229-cec4c3d241d4','夏夜大雨呈若谷叔并晁叔用江子之一上人','呂本中','宋','宋诗','song-poetry','','[]','中庭電光垂，四壁雨脚溜。',96,'全唐诗/poet.song.92000.json','["中庭電光垂，四壁雨脚溜。", "初如單車馳，忽若萬馬驟。", "並牆不相語，燈影照圭竇。", "飜思共按樂，日月不得又。", "叔能糠覈肥，姪且藜藿瘦。", "買田嵩潁間，欲往今已後。", "旦夕呼晁江，把酒且相就。", "更煩一上人，不語居坐右。"]'),
('ecec83af-bb5a-41df-ab04-447ee4a87871','贈一上人','呂本中','宋','宋诗','song-poetry','','[]','細褥紗幮卧軟綾，豈知秋色到襄陵。',64,'全唐诗/poet.song.92000.json','["細褥紗幮卧軟綾，豈知秋色到襄陵。", "饑烏乍定門門樹，寶塔新晴夜夜燈。", "晚菜聊充肉一臠，殘林才當飯三升。", "平生積嬾成驕惰，慚媿空房獨坐僧。"]'),
('00bc60b2-38cf-4605-a8e6-91a97ce40327','久雨路絕賓客稀少聞后土祠瓊花盛開亦未果一往也','呂本中','宋','宋诗','song-poetry','','[]','卧聞更鼓濕不鳴，曉窗但有摧簷聲。',160,'全唐诗/poet.song.92000.json','["卧聞更鼓濕不鳴，曉窗但有摧簷聲。", "雲横不放山入坐，風怒欲倒江衝城。", "東家酒熟花爛漫，折簡喚客留娉婷。", "街頭泥潦一尺許，意雖欲往無由行。", "儒生活計亦不惡，蒲團堅坐到日落。", "映窗香穗觸凝塵，過眼文書開病膜。", "明朝新晴有佳處，穏看小檻翻紅藥。", "無雙亭下一枝春，玉潔霜清未寥廓。", "閉門嬾出君莫笑，看汝多愁吾獨樂。", "故人無事倘能来，爲君試舉舒州杓。"]'),
('ca05e08a-23e7-4969-9ba1-7aa14b3894ec','同狼山印老早飯建隆遂登平山堂','呂本中','宋','宋诗','song-poetry','','[]','塵埃障西風，草木被朝日。',144,'全唐诗/poet.song.92000.json','["塵埃障西風，草木被朝日。", "籃輿郭北門，未厭來往疾。", "僮奴嬾不進，頗復費呵叱。", "道人先我行，宴坐已一室。", "殷勤勸客住，午飯當促膝。", "爐烟窗紙明，鳥語樹葉密。", "却上平山堂，晚景更蕭瑟。", "澄江渺天際，妙句不容乞。", "平生泉石念，固自有遺失。", "何能從兒曹，十事九不實。", "茲游豈不快，此老固坦率。", "尚從文殊師，一往問摩詰。"]'),
('e05084be-7029-4be4-b6ee-b61e09c6ffd2','舟行次靈璧二首  其一','呂本中','宋','宋诗','song-poetry','','[]','往来湖海一扁舟，汴水多情日自流。',32,'全唐诗/poet.song.92000.json','["往来湖海一扁舟，汴水多情日自流。", "已去淮山三百里，主人無念客無憂。"]'),
('7bfa35e5-30b8-477f-a3a5-77a9b01441ec','舟行次靈璧二首  其二','呂本中','宋','宋诗','song-poetry','','[]','小市荒橋貫濁河，故人雖在嬾誰何。',32,'全唐诗/poet.song.92000.json','["小市荒橋貫濁河，故人雖在嬾誰何。", "只因遠地經過少，更覺新年坐卧多。"]'),
('1186b3ae-c0fd-4f4e-ad7f-00461ace7cd5','己亥上元數同晁季一叔用清坐不出','呂本中','宋','宋诗','song-poetry','','[]','北風凜凜吹月高，萬木夜作窮猿號。',144,'全唐诗/poet.song.92000.json','["北風凜凜吹月高，萬木夜作窮猿號。", "卧聽車馬赴塵土，愛此一室明秋毫。", "小爐著火晚收焰，短檠照坐寒無膏。", "主人忘言客亦嬾，更煩赤脚送茗盌。", "子雲事業本清浄，維摩方丈常蕭散。", "出游苦畏今日閙，歸坐略盡平生款。", "自知衰病損剛腸，只要文書遮病眼。", "公能却掃趁閑暇，渠自低頭費牽挽。", "明朝乘興尚能來，咫尺吾廬不嫌遠。"]'),
('e84f39e3-81ba-4404-9f3f-d3745672bd1f','寄李商老','呂本中','宋','宋诗','song-poetry','','[]','黄塵車馬流，金火戰殘暑。',120,'全唐诗/poet.song.92000.json','["黄塵車馬流，金火戰殘暑。", "西風迎潮来，密雲復無雨。", "江淮旱已甚，映眼但塵土。", "田疇雜蕪穢，草樹翳洲渚。", "緬懷平生歡，捐棄各秦楚。", "千言偪胸次，到口不能吐。", "君非一臂舊，此意復可許。", "青蠅暗藩溷，有似嚇腐鼠。", "須君濟川手，略爲虹蜺舉。", "念之不能眠，清坐聽鳴櫓。"]'),
('8a04b7ff-df21-4717-9ea3-3f5b1345f74d','晚至城南','呂本中','宋','宋诗','song-poetry','','[]','来往城南路，今年又作冬。',48,'全唐诗/poet.song.92000.json','["来往城南路，今年又作冬。", "荒林掛落日，古寺疊疏鐘。", "職事日三出，交游時一逢。", "可憐河上水，唯少莫山重。"]'),
('daf2bded-0742-4a5c-9742-20ce4eb6eb58','汴上作','呂本中','宋','宋诗','song-poetry','','[]','不使西風便解維，且留殘暑震餘威。',64,'全唐诗/poet.song.92000.json','["不使西風便解維，且留殘暑震餘威。", "累累野水循河下，攝攝榆蟲撲面飛。", "五斗漫隨王績隱，一裘聊待晏嬰歸。", "平生事業新詩在，送與江南舊釣磯。"]'),
('fb225971-fbf2-4d94-8736-24982c619776','初抵曹南四首  其一','呂本中','宋','宋诗','song-poetry','','[]','未辨歸山計，今年學作官。',48,'全唐诗/poet.song.92000.json','["未辨歸山計，今年學作官。", "簿書妨好夢，塵土敗餘歡。", "但有妻孥累，初無肺腑寛。", "從来畜鮭菜，不上八珍盤。"]'),
('03e0ab0d-5dcc-4cde-9d81-7d17e653be33','初抵曹南四首  其二','呂本中','宋','宋诗','song-poetry','','[]','久罷攝生術，虚藏種樹書。',48,'全唐诗/poet.song.92000.json','["久罷攝生術，虚藏種樹書。", "病多詩輒廢，秋到客仍疏。", "約带何辭緩，穿靴不暇徐。", "猶勝策高足，辛苦曳長裾。"]'),
('c03e7828-ab04-4bfe-8a93-af7b171fac01','初抵曹南四首  其三','呂本中','宋','宋诗','song-poetry','','[]','併足經庭右，褰裳入座隅。',48,'全唐诗/poet.song.92000.json','["併足經庭右，褰裳入座隅。", "頻容著帽進，雅稱折腰趨。", "燥吻應難濕，殘杯莫强濡。", "平生駟跛蹩，今日更長途。"]'),
('8bfadd6d-0b95-4c3c-bd91-00d7f0820b39','初抵曹南四首  其四','呂本中','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','往時汪博士，勸我便歸休。',48,'全唐诗/poet.song.92000.json','["往時汪博士，勸我便歸休。", "細雨簷花夜，長江楓葉秋。", "欲行殊未必，高卧恐無由。", "感歎思亡友，端居可淚流。"]'),
('522e6fcd-6bc0-4ca7-b474-0a6d17ea2e61','言志','呂本中','宋','宋诗','song-poetry','','[]','馮驩客傳舍，彈鋏歌不已。',132,'全唐诗/poet.song.92000.json','["馮驩客傳舍，彈鋏歌不已。", "託身孟嘗君，惟有一劍耳。", "何事食無魚，何事出無輿。", "先生猶有劍，至我劍亦無。", "一來曹南郡，優游聊自娱。", "春風吹我衣，春草生庭除。", "小便胞略轉，晚髮手自梳。", "仰面送歸雁，低頭羨游魚。", "幸有薄薄酒，浸漬滿腹書。", "安得待天命，吾心亦何如。", "長鋏莫漫彈，何必憶吾廬。"]'),
('ea1cf345-d208-4ad3-b827-8dae52c4f3b5','學道','呂本中','宋','宋诗','song-poetry','','[]','學道如養氣，氣實病自除。',240,'全唐诗/poet.song.92000.json','["學道如養氣，氣實病自除。", "驗之寒暑中，可見實與虚。", "頹然覺志滿，乃是氣有餘。", "豈惟煖臍腹，便足榮肌膚。", "但能嚴關鍵，百歲終不枯。", "道苟明于心，如馬得堅車。", "養以歲月久，自然登坦途。", "江河失風浪，草莽成膏腴。", "熟視八荒中，何物能勝予。", "時來與消息，吾自有卷舒。", "死生亦大矣，汝急吾自徐。", "捷行不爲速，曲行不爲迂。", "一漚寓大海，此物定有無。", "誰能具此眼，况望捋其鬚。", "學有不精盡，遂至玉碔砆。", "昔人中道立，爲汝指一隅。", "千言不知要，徒自費吹嘘。", "所以季路勇，不如顔氏愚。", "請子罷百慮，一念回須臾。", "忽然遇事入，此語當不誣。"]'),
('bb610884-93fc-4155-855e-13a2b2884d54','和趙承之','呂本中','宋','宋诗','song-poetry','','[]','十日九日昏夢集，職事向人如束濕。',128,'全唐诗/poet.song.92000.json','["十日九日昏夢集，職事向人如束濕。", "看朱成碧有底忙，然萁煮豆相煎急。", "長官抵几入門去，小吏垂頭就行立。", "塵埃上下久可厭，學問峥嶸老難入。", "平生謬欲師古人，遇事始知吾不及。", "正須眼底去涇渭，便自胸中無棨戟。", "丈夫蓋棺事則已，破屋頽牆使誰葺。", "要隨歸雁刺天飛，莫待枯魚過河泣。"]'),
('73be765e-ec94-4a75-93bd-0cae4cf1fadf','曹州後囿夜行','呂本中','宋','宋诗','song-poetry','','[]','衣欲生稜夢不成，城頭高下打三更。',32,'全唐诗/poet.song.92000.json','["衣欲生稜夢不成，城頭高下打三更。", "月明如晝柳如畫，更向瑶池南岸行。"]'),
('e5ac899d-f6ec-4b91-a53a-ba6abf04b2a3','風吹蒲葦叢三首  其一','呂本中','宋','宋诗','song-poetry','','[]','風吹蒲葦叢，中有霜墮意。',24,'全唐诗/poet.song.92000.json','["風吹蒲葦叢，中有霜墮意。", "美人天一涯，行子初夜至。"]'),
('44c99184-29f5-43fa-8b6d-cbf11a3117e1','風吹蒲葦叢三首  其二','呂本中','宋','宋诗','song-poetry','','[]','風吹蒲葦叢，秋色日向晚。',24,'全唐诗/poet.song.92000.json','["風吹蒲葦叢，秋色日向晚。", "美人何時來，行子饑未飯。"]'),
('0be47545-e407-4697-94a2-c0fd5ceed7d7','風吹蒲葦叢三首  其三','呂本中','宋','宋诗','song-poetry','','[]','行子惜日月，美人輕别離。',24,'全唐诗/poet.song.92000.json','["行子惜日月，美人輕别離。", "風吹蒲葦叢，及時當早歸。"]'),
('75f2f27b-76d3-4e46-94cd-fd9ee74f6d90','曹南試院懷向子諲兄弟兼呈張擴','呂本中','宋','宋诗','song-poetry','','[]','大向金相玉爲表，小向堅車取長道。',64,'全唐诗/poet.song.92000.json','["大向金相玉爲表，小向堅車取長道。", "閉門不見今幾日，塵埃滿城何時好。", "病夫坐穏百不聞，讀書聒人到夜分。", "朝来雨過涼氣足，思與張侯同叩門。"]'),
('64e87495-6794-4c18-aac0-a90ab6c4307a','試院中作二首  其一','呂本中','宋','宋诗','song-poetry','','[]','客夢斷復續，角聲寒更長。',48,'全唐诗/poet.song.92000.json','["客夢斷復續，角聲寒更長。", "疏籬擁殘月，老木犯新霜。", "閗縶身何恨，馳驅汝自忙。", "稍知詩有味，復恐道相妨。"]'),
('fd4b3159-60cf-41d3-b33f-bddbe904d243','試院中作二首  其二','呂本中','宋','宋诗','song-poetry','','[]','諸生未下筆，客子且安眠。',48,'全唐诗/poet.song.92000.json','["諸生未下筆，客子且安眠。", "老覺文章退，官憂簿領纒。", "短檠仍有味，高枕自無緣。", "但願無他苦，今年如去年。"]'),
('1ee5dc97-f409-40c7-8c1a-196e5c6018e3','擬古','呂本中','宋','宋诗','song-poetry','','[]','西鄰有佳人，開户納明月。',132,'全唐诗/poet.song.92000.json','["西鄰有佳人，開户納明月。", "月照衣上纓，同心爲誰結。", "此結今幾時，未解心已折。", "隔林聞搗練，起坐更嗚噎。", "情人在萬里，我獨音問缺。", "不聞行路難，但見思歸切。", "年来契闊久，烈士或喪節。", "如何空牀居，初未見短闕。", "胡馬與越鳥，本自無離别。", "草搖新霜白，秋送池中竭。", "君心有斷絕，妾恨無盈歇。"]'),
('dffaee49-f646-474e-8290-d07500e71c9e','正月十五日試院中烹茶因閲溪碑','呂本中','宋','宋诗','song-poetry','','[]','小爐方鼎蛙蚓鳴，那知簾外東風驚。',256,'全唐诗/poet.song.92000.json','["小爐方鼎蛙蚓鳴，那知簾外東風驚。", "亂雲初破盤鳳影，缺月半墮春江明。", "已驅簿領出門去，更洗肝肺令愁醒。", "大碑古字久寂寞，高堂素壁空崢嶸。", "坐看光焰掃塵土，便覺冰霰臨窗屏。", "文章斷絕生氣在，妙句直欲無蘭亭。", "嶧山野火燒欲盡，瘞鶴半在江中陵。", "不知此書更奇古，反覆饜飫無譏評。", "山精地神肯愛護，至今歐虞來乞靈。", "要令石鼓舉吉日，不必細字臨黄庭。", "生平訪古少如意，對此自足忘經營。", "世間兒女爭媚好，紙上姓名誰重輕。", "邇來半月得堅坐，一室當行千里程。", "南樓燈火漫明滅，北里笙竽頻送迎。", "儒生事業了不惡，故人浮沈吾嬾聽。", "更闌更自取書讀，喚起奴僕尋短檠。"]'),
('8a0eae99-a922-46be-a20e-a313b782eca4','試院夜坐','呂本中','宋','宋诗','song-poetry','','[]','急雨翻燈夜不眠，小牀欹側似乘船。',64,'全唐诗/poet.song.92000.json','["急雨翻燈夜不眠，小牀欹側似乘船。", "平生萬事不如意，病後一身私自憐。", "海中神仙渺茫裏，方外酒徒憔悴邊。", "本自無心覓餘地，問公何苦愛逃禪。"]'),
('c90383d5-0939-4b53-96ac-4920e98c5efa','清都行','呂本中','宋','宋诗','song-poetry','','[]','我昔謁帝白玉墀，獨駕翠虬驂赤螭。',216,'全唐诗/poet.song.92000.json','["我昔謁帝白玉墀，獨駕翠虬驂赤螭。", "御風而行過日圍，遂登清都游太微。", "廣殿上建明月旗，綴以列宿懸雙蜺。", "帝顧而歎憐其癡，寸田不治來何遲。", "我拜稽首心自疑，世俗逼隘臣所知。", "黜慢之故還無期，後有美人雲霧衣。", "玉坐交映生光輝，不必翠被緣珠璣。", "祕文玉簡手自持，見我而笑揚蛾眉。", "問我此去来何時，握手贈吾藍田芝。", "汝生甚良學則宜，無自輕厭令神馳。", "一来人間今幾時，恍如夢覺不可追。", "骨肉腥穢顔忸怩，北風吹寒霜露微。", "想視倒景凌空飛，却從帝居尋玉妃，爲汝更賦無言詩。"]'),
('46630fe2-a4c5-41ae-bd71-b5ab852978d3','試院中呈工曹惠子澤教授張彦實','呂本中','宋','宋诗','song-poetry','','[]','十日虚房罷送迎，不知新雁已南征。',64,'全唐诗/poet.song.92000.json','["十日虚房罷送迎，不知新雁已南征。", "忍窮有味知詩進，處事無心覺累輕。", "殘葉入簾收薄暑，破窗留月漏微明。", "知公坐穏無他念，識我階前拄杖聲。"]'),
('8fa2e44b-2066-4189-92ae-cbafe19c2bbc','寄知止','呂本中','宋','宋诗','song-poetry','','[]','近有書来欲見尋，扁舟南下已春深。',64,'全唐诗/poet.song.92000.json','["近有書来欲見尋，扁舟南下已春深。", "濁河遠貫長淮水，峽岸遥瞻寶塔臨。", "楊子宦游常落拓，茂倫心事轉崎嶔。", "雲横雪擁藍關路，總是平生願學心。"]'),
('b611d342-1487-4914-adbd-66e0590cc27c','印纍纍','呂本中','宋','宋诗','song-poetry','','[]','印纍纍，綬若若，不如相逢一餉樂。',143,'全唐诗/poet.song.92000.json','["印纍纍，綬若若，不如相逢一餉樂。", "谷量牛馬斗量珠，不如閉門細讀平生書，居閑意氣或有餘。", "利害毫髮過，不能以手援其軀。", "風吹月明，落我庭樹。", "宿烏夜驚，徐徐飛去。", "晝夜有程，汝何不住。", "前畏彈射，後畏網羅。", "孰視鴻鵠，雲霄可摩。", "亦知人生，如意少不如意多。", "富貴欲長保，執斧不見柯。", "印纍纍如此，宿鳥飛去何。"]'),
('ad643abd-91b3-40ca-8173-9a33a127b138','曹南過五丈河隄入城訪顔岐夷仲清談久之乃歸','呂本中','宋','宋诗','song-poetry','','[]','春色不自惜，落花如許愁。',144,'全唐诗/poet.song.92000.json','["春色不自惜，落花如許愁。", "晴天一望遠，漕水十分流。", "每遶長隄去，頻因好句留。", "相隨覓季主，不必貸河侯。", "論極文章秘，居兼竹石幽。", "和風落香燼，晚日泛茶甌。", "壯節知無用，諸儒誤見收。", "江山亦在眼，歲月忽忘憂。", "南郭今喪我，長卿仍倦游。", "漫成長韻律，勝與小蠻謳。", "簿領憎頻過，塵埃嬾再謀。", "何須五湖口，風雨轉船頭。"]'),
('6dd2fff5-6645-479f-83e6-a3171f55f18d','雪夜','呂本中','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','曹州城南三日雪，半夜疾風吹石裂。',192,'全唐诗/poet.song.92000.json','["曹州城南三日雪，半夜疾風吹石裂。", "先生睡美喚不聞，不信衾裯冷如鐡。", "病妻索火少聲韻，稚子哦詩應歌節。", "殘書向人老可愛，舊劍空在磨先缺。", "未能去尋泉石伴，未用深藏狐兔穴。", "新正已過今幾日，歲事嬾復從人說。", "長江略無千里夢，故人動有十年别。", "相逢一笑又艱阻，所向端坐成癡絕。", "城中諸公不相棄，時有妙句扶衰拙。", "頗知晴意在明日，泥深不怕車輪折。", "便當脱帽過君家，共放南窗看新月。", "一杯凍酒君莫辭，預借炎天洗煩熱。"]'),
('49b9af29-f535-4938-845e-eeca5c0f078a','曹南官舍書事','呂本中','宋','宋诗','song-poetry','','[]','去歲頭已白，今年眼復昏。',48,'全唐诗/poet.song.92000.json','["去歲頭已白，今年眼復昏。", "不憂窮刺骨，仍有病傷魂。", "酒薄如官冷，年豐荷主恩。", "空庭閑草木，終未答乾坤。"]'),
('19ebb6be-ce11-47e2-a417-c23a24bce4db','早出','呂本中','宋','宋诗','song-poetry','','[]','早出公莫厭，此心吾已灰。',72,'全唐诗/poet.song.92000.json','["早出公莫厭，此心吾已灰。", "嚴風逸月落，曉氣浹霜回。", "疾病衝寒怯，衰遲畏事催。", "匆匆節漸去，袞袞事方來。", "破壁詩猶在，荒城菊半摧。", "還家一樽酒，思與故人開。"]'),
('56173492-1a13-44d6-a474-83b1cb2c1d54','寄江端太子之晁冲之叔用','呂本中','宋','宋诗','song-poetry','','[]','往歲孟秋月，我行東出關。',240,'全唐诗/poet.song.92000.json','["往歲孟秋月，我行東出關。", "人烟眇歸路，風雨轉河灣。", "别恨友游失，心成木石頑。", "有隨妻子嘆，無語鳥烏閑。", "曩事空回首，微官真强顔。", "舊諳塵土迸，頻辱簿書頒。", "日月勤憂患，庭闈實阻艱。", "自忘身窘束，時得淚潺湲。", "疾病衰猶活，漂流老未還。", "悮霑文字癖，虚覺鬢毛斑。", "苦語終難好，蕪辭漫不刪。", "絕知出意表，敢復見顔間。", "二子今懷璧，羣公時賜環。", "寄書常恨草，雕句得無慳。", "晚照雲千疊，新涼月半彎。", "相忘有道術，那得厭塵寰。", "聖治光三輔，皇威極百蠻。", "物能同應瑞，民自不藏姦。", "薄技寧堪奏，餘光或許攀。", "何須陽翟望，咫尺是箕山。"]'),
('02712bf3-1f9f-406c-9776-bfaf41ef9ca3','兩鶴行','呂本中','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','西風引湖光，上與月色亂。',108,'全唐诗/poet.song.92000.json','["西風引湖光，上與月色亂。", "化爲兩白鶴，飛来洞庭岸。", "洞庭無網羅，兩鶴願爲伴。", "鳴聲既清好，羽翼又璀璨。", "一鶴飛上天，久厭俗眼玩。", "一鶴不能飛，摧頹自悲歎。", "三年望絕壁，念汝腸已斷。", "昔既薄恩情，今還恨霄漢。", "未忍學鷦鷯，裁求一枝換。"]'),
('e22ed159-1609-4e23-b48e-c6af165634ef','陵城歌','呂本中','宋','宋诗','song-poetry','','[]','北風吹沙秋草黄，漢家故陵當路傍。',147,'全唐诗/poet.song.92000.json','["北風吹沙秋草黄，漢家故陵當路傍。", "殘墓斷壠趁風雨，狹徑小樹行牛羊。", "當時王子朝未央，飛燕姊弟承龍光。", "大策已定回朝陽，不知外家諸舅忙。", "後來變化尤猖狂，佞賢賊莽分行藏。", "豈知漢運中更長，濟陽舍中方赤光。", "終亦變化隨飛揚，何獨此地令人傷。", "人生覩此當自顧，位高金多終此路。", "君不見五陵佳氣且如此，更復何情說丁傅。"]'),
('169e7004-83ed-40fb-82ca-f32c056edab7','早至天寧寺即趙州受業院也','呂本中','宋','宋诗','song-poetry','','[]','殘月曉未落，疏星點寒林。',144,'全唐诗/poet.song.92000.json','["殘月曉未落，疏星點寒林。", "嚴車城南路，先聞鐘磬音。", "道人迎我入，共步重廊深。", "瀹琖施净供，冰味雜海沈。", "蒲團近宿火，不受塵埃侵。", "欲求半日息，簿領勤相尋。", "東堂老禪師，枯木尚龍吟。", "一轉庭前柏，諸方疑至今。", "我生晚聞道，所向足崎嶔。", "謬傳無字印，嘗恐力不任。", "淮海罷行役，吾人多滯淫。", "于焉一枕夢，可見平生心。"]'),
('f9c9c700-a3d0-49c1-804a-6ec2845f5efd','曹南寄親舊','呂本中','宋','宋诗','song-poetry','','[]','净名居士黙無語，翰林子卿虚見尋。',64,'全唐诗/poet.song.92000.json','["净名居士黙無語，翰林子卿虚見尋。", "半世泥塗催老大，中年詩律費光陰。", "江湖每有同歸志，酒炙初無獨飽心。", "三尺枯桐取煨燼，斷弦遺譜有知音。"]'),
('c506627d-26a3-4a05-8777-d40b8fd756b5','大雪不出寄陽翟寧陵','呂本中','宋','宋诗','song-poetry','','[]','簿書終歲忙，風雪一日静。',192,'全唐诗/poet.song.92000.json','["簿書終歲忙，風雪一日静。", "閉門近殘火，稍覺諸事勝。", "平生汗漫游，已負麋鹿性。", "微官不能歸，但見日月競。", "老人去已遠，我行復未定。", "訓言實在耳，無因問温清。", "歸心止陽翟，悲夢識新鄭。", "大女癡無比，有語多未聽。", "小女索乳啼，不與窮屋稱。", "想喚添丁來，與汝相和應。", "低頭坐兒曹，氣血安得盛。", "非無車馬心，未忍求捷徑。", "顧自阻饑寒，疇能免譏評。", "諸郎何時逢，相作玉樹映。", "文章有活法，得與前古並。", "默念智與成，猶能愈吾病。"]'),
('a349e2b7-45c6-4d88-b697-983eed1d5583','與寧陵叔弟别後有懷兼寄趙才仲二首  其一','呂本中','宋','宋诗','song-poetry','','[]','一别又經月，欲来渾未期。',48,'全唐诗/poet.song.92000.json','["一别又經月，欲来渾未期。", "寧知萬卷讀，難療十年饑。", "長物新添女，生涯舊有詩。", "更傷新况味，不報老親知。"]'),
('56bd7bff-7549-4be4-80fa-c3abf7afd79e','與寧陵叔弟别後有懷兼寄趙才仲二首  其二','呂本中','宋','宋诗','song-poetry','','[]','表弟今何在，中郎亦漫游。',48,'全唐诗/poet.song.92000.json','["表弟今何在，中郎亦漫游。", "平生足艱阻，今日倍遲留。", "誤辱瓊瑶報，兼蒙札翰投。", "南窗五更月，常照别離愁。"]'),
('139eeb14-c590-4978-8e3c-cf50b762dc22','大雪不出','呂本中','宋','宋诗','song-poetry','','[]','晶晶日欲出，翻翻風自横。',48,'全唐诗/poet.song.92000.json','["晶晶日欲出，翻翻風自横。", "近階三尺雪，附火一杯羮。", "老樹春難别，深簷烏或鳴。", "新春第三日，堅坐若爲情。"]'),
('db4debeb-c7ea-4d41-a253-e3e7ab903ae4','自曹南至陽翟追懷江上舊游呈叔弟','呂本中','宋','宋诗','song-poetry','','[]','醉别白沙江上亭，晚蟬高樹各秋聲。',64,'全唐诗/poet.song.92000.json','["醉别白沙江上亭，晚蟬高樹各秋聲。", "風乘小艇鳬鷖進，雨歷疏簷環珮鳴。", "家事不隨王事了，新愁常接舊愁生。", "只今疲病嫌鞍馬，十日同居眼暫明。"]'),
('1abcd487-dab6-4c0f-99fe-9d2b64b520a2','自陽翟至寧陵與虛已叔諸弟别還曹未久知止復來偶成二十八字','呂本中','宋','宋诗','song-poetry','','[]','綠徧牆頭楊柳枝，小亭春盡阻歸期。',32,'全唐诗/poet.song.92000.json','["綠徧牆頭楊柳枝，小亭春盡阻歸期。", "頭昏目暗無情緒，不比少年離别時。"]'),
('104bdfcb-83b9-4c5e-9f61-7a033e8105a2','試院中作','呂本中','宋','宋诗','song-poetry','','[]','職事侵人畏作官，略偷身去不能還。',64,'全唐诗/poet.song.92000.json','["職事侵人畏作官，略偷身去不能還。", "樹移午影重簾静，門閉春風十日閑。", "尚有文書遮病目，却無塵土犯衰顔。", "故人何處蓬籠底，看盡江南江北山。"]'),
('bdc844bb-f833-4ca4-a376-43b0b3114915','去冬試院中嘗作詩云衣敝蝨可捨髮垢櫛不下披衣坐牆角尚有微火跨平生足拘窘今日幸閑暇新文加點竄欲歇不能罷雖微塵事妨頗畏俗子罵出門見諸老此語君可畫今年復入試院職事多窘迫者簿書滿前如赴蹈湯火也再次前韻','呂本中','宋','宋诗','song-poetry','','[]','誰令君作官，袞袞簿書下。',72,'全唐诗/poet.song.92000.json','["誰令君作官，袞袞簿書下。", "誰令君不學，陷穽乃欲跨。", "緬懷北窗翁，斯人蓋多暇。", "田疇望家遠，日月已秋罷。", "尚蒙諸公憐，未至官長罵。", "何時歸来圖，更作一段畫。"]'),
('9e452fd8-1924-446a-9031-eb7ee6d777c6','雨後數與李仲輔兄弟往来且約十七日同過士特因成長韻','呂本中','宋','宋诗','song-poetry','','[]','鄰鷄再三鳴，不改風雨晦。',144,'全唐诗/poet.song.92000.json','["鄰鷄再三鳴，不改風雨晦。", "束裝向前塗，恐與泥潦會。", "故人時一来，共此一室內。", "微言久已絕，苦語或未遂。", "子孫甚奇古，却立有餘地。", "舊從伯氏游，則已聞令季。", "斯文倘未遠，吾今盡憔悴。", "相期無何鄉，獲保清凈退。", "收身稠人中，着眼世事外。", "山空倚巖石，雪立老杉檜。", "往來相遇難，更自少如意。", "旦日過城南，把酒公一醉。"]'),
('77263418-7efe-42da-836c-39c0de16cca1','首夏二首  其一','呂本中','宋','宋诗','song-poetry','','[]','生平寡嗜欲，頗願得少閑。',132,'全唐诗/poet.song.92000.json','["生平寡嗜欲，頗願得少閑。", "盡讀未見書，徧尋雲外山。", "往来二十年，昔者盟未寒。", "妻子見驅廹，低頭言作官。", "朝翻朱墨案，暮對藜藿盤。", "豈無一畝宫，令汝得少安。", "向来棲息地，苔竹奉餘歡。", "何時二三子，共駕牛車還。", "汝實江海人，悮令塵土干。", "舊游在彷彿，欲往當不難。", "但去眼界窄，自然心地寛。"]'),
('036d13fc-c6b6-4ae6-83f2-23280b8822fc','首夏二首  其二','呂本中','宋','宋诗','song-poetry','','[]','空庭下疏箔，樂此樹蔭美。',132,'全唐诗/poet.song.92000.json','["空庭下疏箔，樂此樹蔭美。", "鳥聲相續来，百種皆可喜。", "日長少文字，俗事不到耳。", "開窗略須夜，月露欣瀰瀰。", "頗念閑居樂，感歎投筆起。", "吾家老清源，愛我入骨髓。", "還家治場圃，喚我共料理。", "會同江海去，更欲附船尾。", "平生跨款段，不敢廢鞭箠。", "誰云馬中龍，一日有萬里。", "卜鄰吾所知，江晁老兄弟。"]'),
('b1fdae37-c8d6-4ccc-9d8e-d723d3aee924','問晁伯宇疾二首  其一','呂本中','宋','宋诗','song-poetry','','[]','晁子臥京城，歲月晚不用。',144,'全唐诗/poet.song.92000.json','["晁子臥京城，歲月晚不用。", "偷身出塵土，閉戶忍疾痛。", "客來不與語，有口吾懶動。", "今年又請老，氣力當少縱。", "生平厭筆墨，棄去不復弄。", "頗念白頭親，甘旨須子奉。", "呻吟不衽席，妙語時一諷。", "誰令稻粱謀，未答泉石夢。", "鄙夫託未契，義實憂患共。", "天定或勝人，寡固不敵衆。", "請公但縮手，保此清凈供。", "因書報安否，兼與問群從。"]'),
('701e6b28-8d29-4e1c-a60b-225cc3883253','問晁伯宇疾二首  其二','呂本中','宋','宋诗','song-poetry','','[]','取驥伏鹽車，更欲縶其足。',144,'全唐诗/poet.song.92000.json','["取驥伏鹽車，更欲縶其足。", "於物未有害，罰汝則已酷。", "晁子江海士，老去自窘束。", "平生萬卷書，豈止十年讀。", "隨身幾箱篋，一一手自錄。", "初無解衣贈，未免操戈逐。", "仲也抱瑚璉，幼亦好奇服。", "西堂老弘微，與子同軌躅。", "過門有江謝，共語喧破屋。", "棄官吾已懶，覆種子未孰。", "逢人強應接，遇事多詬辱。", "何時把鋤頭，得止季路宿。"]'),
('21cf5b36-6f3e-465c-861c-56909b922a78','商村河決','呂本中','宋','宋诗','song-poetry','','[]','今年河口決商村，遠望飛濤匹馬奔。',64,'全唐诗/poet.song.92000.json','["今年河口決商村，遠望飛濤匹馬奔。", "曲港定無蛟鱷橫，下田甘受雨泥渾。", "衣裳蟣虱藏針縫，頭面塵沙露爪痕。", "猶恐因循葬魚腹，故人無地與招魂。"]'),
('9b369f2f-5148-4893-b890-381608e20224','新霜行','呂本中','宋','宋诗','song-poetry','','[]','新霜下幽蘭，昔在顧眄間。',168,'全唐诗/poet.song.92000.json','["新霜下幽蘭，昔在顧眄間。", "時過理當爾，敢復致一言。", "物生無榮賤，悉是君所見。", "相值有相違，誰能滿吾願。", "田園棄荒蕪，官居走郵傳。", "誤尋文字盟，秣馬當百戰。", "一飯或未飽，逢人足嫌怨。", "窮於投林猿，窘若巢幕燕。", "忍學少年子，羽翼偷絢練。", "百萬買纒頭，千金奉娱宴。", "願爲匣中玉，不作秋後扇。", "丈夫重許與，正爾未爲倦。", "絕糧有不死，酒肉虛健羡。", "古人馬伏波，吾猶識君面。"]'),
('c4a6b5a6-b983-47a1-bf95-497e9a1a635b','將去曹南連得江晁書因歎存沒諸友遂成長韻','呂本中','宋','宋诗','song-poetry','','[]','西風脱殘暑，我病不自聊。',240,'全唐诗/poet.song.92000.json','["西風脱殘暑，我病不自聊。", "吏舍少還往，亦復長蓬蒿。", "欣然脱帽去，念此非一朝。", "陽翟未遽往，寧陵虚見招。", "初無食息地，未免柴水勞。", "故人數遺書，尚有江與晁。", "窮途感節義，俗耳受風騷。", "向來相知人，昔盛今寂寥。", "落日送汪謝，荒小留老饒。", "關侯最傑立，亦以膏自燒。", "後生有向子，更盡兒女嬌。", "出門天奪之，不令上雲霄。", "坐看朋友淚，未減春秋褒。", "怪我但羸疾，悮蒙風雨搖。", "日月費奔走，文章勤琢雕。", "會須領妻子，更欲投吾曹。", "耆舊喚歸隱，諸公憐久要。", "出同赴鷄黍，歸但守簞瓢。", "相將訪雲山，所至雜漁樵。", "還當古渡口，卧聽西江潮。"]'),
('d645bb9c-2720-458d-9936-7116c66311c6','精衛詩','呂本中','宋','宋诗','song-poetry','','[]','西山有鳥，其狀如烏。',240,'全唐诗/poet.song.92000.json','["西山有鳥，其狀如烏。", "名曰精衛，其名自呼。", "精衛堙海，不堙不止。", "問誰之報，云帝之子。", "帝子女娃，往游不還。", "精衛求之，不敢有安。", "海流不改，汝堙不遷。", "嗟哉精衛，志則可憐。", "我昔讀書，惟聖之求。", "竭力從之，以春及秋。", "老人宴居，審吾之學。", "惟時友朋，日就雕琢。", "聖言甚微，吾意則近。", "近以識微，退或有進。", "三年于曹，惟罪之恐。", "人雖甚厭，子亦不勇。", "舒舒其雲，沄沄其水。", "子不與歸，而曰有以。", "豕羊在牢，芻秣之戀。", "烹庖及之，抑又誰怨。", "予學日遠，子道日疏。", "有愧精衛，其誰與居。", "精衛之飛，不必戾天。", "子之不如，寧有智焉。"]'),
('0a8027e3-295d-4f15-9ea6-d7681dbea0a7','寧陵弟相送至南京因成四韻寄季一子之叔用','呂本中','宋','宋诗','song-poetry','','[]','白髮無端巧上頭，鏡中顔狀不能羞。',64,'全唐诗/poet.song.92000.json','["白髮無端巧上頭，鏡中顔狀不能羞。", "要尋揚子一廛地，未用劉公百尺樓。", "野竹連陰護蒼蘚，暮雲生雨續黄流。", "秋風有信鱸魚在，更約江晁共小舟。"]'),
('0f0c6595-0420-4b11-bde6-24edfd27d8b5','十一月一日步河堤上','呂本中','宋','宋诗','song-poetry','','[]','簿書糾纒人，欲出不自許。',120,'全唐诗/poet.song.92000.json','["簿書糾纒人，欲出不自許。", "老叟環我前，更作附耳語。", "脱身上河隄，頗似晝伏鼠。", "河堤平如掌，下有千歲土。", "夕陽斂殘照，草木過寒雨。", "游魚著鈎餌，舟子快新煮。", "煮魚得放飯，尚歎行役苦。", "江湖平生心，歲月可逆數。", "故人書斷絕，吾事有去取。", "歸来討清尊，妙句還一吐。"]'),
('7d982e17-64fe-4c32-91a7-abdd80d741ec','留侯','呂本中','宋','宋诗','song-poetry','','[]','留侯下邳時，豪氣或未除。',180,'全唐诗/poet.song.92000.json','["留侯下邳時，豪氣或未除。", "晚節欲輕舉，效在黄石書。", "其書本無言，一嘆三嗚呼。", "彼公實天人，識此鵷鳳雛。", "良田有蕪穢，令子痛自鉏。", "萬事不得已，一身常晏如。", "袖手默無語，四方瞻步趨。", "不知隆準公，果能知子無。", "小兒荀彧輩，下及崔浩徒。", "謂能明子心，此語亦已誣。", "不能處其知，正足殺其軀。", "所恨生已晚，聖門無坦途。", "學不盡其才，未免風俗驅。", "詩書在煨燼，子何不回車。", "試問禮之本，更觀心地初。"]'),
('aeaf86db-41a0-4279-a0ea-7a672f5b0a5d','送韓撝秉則赴棣倅','呂本中','宋','宋诗','song-poetry','','[]','公如玉壺冰，見即離煩熱。',168,'全唐诗/poet.song.92000.json','["公如玉壺冰，見即離煩熱。", "况當清秋懸，更自貯霜月。", "中邊本無垢，何處覓焚爇。", "盛以百鍊銅，此亦不得折。", "初蒙一日款，遽有千里别。", "扁舟轉青齊，歲事當雨雪。", "遠行不贏糧，已悟服食訣。", "古来饕餮徒，頗謂一世傑。", "唾壺彼何知，便爲如意缺。", "觀其所用心，俱不異鼠竊。", "首陽獨往人，渠自飽薇蕨。", "舉頭公一笑，百慮無以絕。", "江源初濫觴，末乃流不竭。", "傷哉韝上鷹，一飽便飛掣。"]'),
('ffcc61ff-3142-480d-8ac6-aac9db0b60ad','讀秦碑','呂本中','宋','宋诗','song-poetry','','[]','秦人跨九州，欲以傳萬世。',276,'全唐诗/poet.song.92000.json','["秦人跨九州，欲以傳萬世。", "立石名山傍，往往章得意。", "至今見遺刻，字體甚雄異。", "壯哉蒼蘚文，未改回屈勢。", "風雨所侵蝕，中有千丈氣。", "嚴如虬龍蟠，深若鐵石利。", "餘威到山鬼，謹守敢失墜。", "漢魏能書人，亦豈可睥睨。", "未能識藩籬，何止趁姿媚。", "初無一日雅，但有三舍避。", "文章又奇古，遷雄蓋苗裔。", "觀其所稱述，肯爲尊者諱。", "巧言未大失，末乃爲俗累。", "嗚呼結繩前，此又誰與記。", "君臣共無爲，垂拱天下治。", "春秋紀日月，大易垂彖繋。", "嬴氏厭休息，動以衡石計。", "斯翁變古文，程邈分篆隸。", "自此更滋蔓，日以趨簡易。", "馳驅千百年，漫有紙筆費。", "誰能罷煩文，盡掃諸天外。", "此書雖見存，或以少爲貴。", "持此槁木枝，我亦無甚愧。"]'),
('ba63eb44-2177-4662-b876-67f48709011c','次韻答曹州同官兼簡范寥信中','呂本中','宋','宋诗','song-poetry','','[]','好詩有味終難捨，俗事無功莫羨渠。',64,'全唐诗/poet.song.92000.json','["好詩有味終難捨，俗事無功莫羨渠。", "破歷屢翻深甕酒，短檠時檢舊窗書。", "何年鷄黍先投社，是處田園可結廬。", "更請二公搜好句，一身疴癢要爬梳。"]'),
('f5b9dcc8-49c8-4661-aaf6-51ee100b9ff5','龔彦承觀軒','呂本中','宋','宋诗','song-poetry','','[]','愛山不能歸，常恐山怪責。',132,'全唐诗/poet.song.92000.json','["愛山不能歸，常恐山怪責。", "終歲在行役，感動頭已白。", "高秋强僮僕，路過龔掾宅。", "蒙君開南軒，除我眼界窄。", "白波遶青嶂，彷彿見顔色。", "江上飛來峰，却立對君側。", "蕭蕭蒲葦叢，不受塵土隔。", "知君有奇趣，笑我常偪仄。", "人生無窮已，得一乃願百。", "牀頭貯美酒，窗下著好客。", "請公但黙然，歲晚當有獲。"]'),
('28e81bd0-8fd2-43ae-89a8-6a767fd31bf1','畫馬圖','呂本中','宋','宋诗','song-poetry','','[]','平沙遠草春未生，萬木夜起争悲鳴。',176,'全唐诗/poet.song.92000.json','["平沙遠草春未生，萬木夜起争悲鳴。", "秋雲欲墜都護壘，急雪暗下屯田營。", "胡人却走畏深入，漢家飛將已雲集。", "此時一馬直萬錢，隴右河湟更供給。", "邊塵净盡今百年，萬馬潦倒西風前。", "天生駿骨例艱阻，是處雕鞍蒙受憐。", "君家九幅開新帳，欻見腰褭華堂上。", "長鞭不用覊絡遠，霧縠雲羅倚惆悵。", "高旌嫋嫋霜露微，苜蓿得雨連山肥。", "同時戰士今不歸，曹霸弟子能神奇。", "毫端妙處君得之，駑駘往来空爾爲。"]'),
('8f6667b2-9b40-42b4-bfd5-c77e8e406f93','堤上','呂本中','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','落花吹盡不堪憂，只見河堤水漫流。',64,'全唐诗/poet.song.92000.json','["落花吹盡不堪憂，只見河堤水漫流。", "晚日强穿城北市，春風猶駐驛南樓。", "妻孥轉覺爲身累，歲月終難望汝留。", "萬里長江一樽酒，故人何處倚扁舟。"]'),
('ee1c83e8-705b-40fd-89d7-6330705af585','將赴海陵出京治泎覓舟候送客不至遂行','呂本中','宋','宋诗','song-poetry','','[]','子行殊未来，我馬已再秣。',96,'全唐诗/poet.song.92000.json','["子行殊未来，我馬已再秣。", "略投故人飯，苦厭從者聒。", "長河見舟楫，尚恐塵事奪。", "風翻蟬急噪，雨潄岸欲脫。", "南山已在眼，想望淮水闊。", "别離古所重，况在交友末。", "翩然欲行際，所寄一短褐。", "路長書来稀，何以慰饑渇。"]'),
('d8ccb08e-aa8b-40b6-b355-10ee8968ada3','京師新鄭與諸晁兄弟往還前後數詩  其一','呂本中','宋','宋诗','song-poetry','','[]','夜語不嫌久，凜然天欲秋。',48,'全唐诗/poet.song.92000.json','["夜語不嫌久，凜然天欲秋。", "客燈吹屢滅，細雨落還休。", "未許金張並，虛爲鄠杜游。", "江河少歸夢，知爲故人留。"]'),
('d572b897-2450-486d-a306-ffdc3b5b0927','京師新鄭與諸晁兄弟往還前後數詩  其二','呂本中','宋','宋诗','song-poetry','','[]','我髮日已短，公愁安得長。',48,'全唐诗/poet.song.92000.json','["我髮日已短，公愁安得長。", "牆根春薺老，瓶水臘梅香。", "侍立無天女，相隨有漫郎。", "平生湖海興，今夜宿連牀。"]'),
('d33d07a9-6c9e-4e45-b977-cf42e79f9a94','京師新鄭與諸晁兄弟往還前後數詩  其三','呂本中','宋','宋诗','song-poetry','','[]','髮短各已白，眼昏誰復明。',48,'全唐诗/poet.song.92000.json','["髮短各已白，眼昏誰復明。", "殘春斷花柳，晚日閉柴荆。", "潦倒書常廢，驅馳夢或驚。", "尚於團聚樂，雖老未忘情。"]'),
('f00b6b5a-b755-49ac-9eb0-e6ed36cd4cf5','京師新鄭與諸晁兄弟往還前後數詩  其四','呂本中','宋','宋诗','song-poetry','','[]','今弟窮顔蠋，書生老仲舒。',48,'全唐诗/poet.song.92000.json','["今弟窮顔蠋，書生老仲舒。", "相招得共處，何往更安居。", "歲月塵埃外，桑麻雨露餘。", "送行無别物，圮上一編書。"]'),
('e0261644-7916-4dca-9493-0491f423c101','京師新鄭與諸晁兄弟往還前後數詩  其五','呂本中','宋','宋诗','song-poetry','','[]','苦語相留極，虚牀會宿頻。',48,'全唐诗/poet.song.92000.json','["苦語相留極，虚牀會宿頻。", "山東今出相，海內不無人。", "婦女能尊客，兒童不厭貧。", "長途有如遇，今日倍情親。"]'),
('20144f38-57ea-4c28-b0f6-faf44af89014','本中將爲海陵之行念當復與子之作别意殊憒憒偶得兩詩上呈并告送與壯輿叔用也  其一','呂本中','宋','宋诗','song-poetry','','[]','斯人如玉雪，可愛不可忘。',108,'全唐诗/poet.song.92000.json','["斯人如玉雪，可愛不可忘。", "助以濯滄海，亦復閟餘光。", "今茲困塵土，更伴衆翼翔。", "時来喚我語，共此一榻涼。", "風雨来頰舌，冰霜清肺腸。", "我老漸窘束，公才方頡頏。", "春秋有體製，子蓋能文章。", "要當纂微言，不以近故妨。", "粲然東園花，不登葵藿場。"]'),
('18542fc1-875f-4ef4-b6e1-463140891d57','本中將爲海陵之行念當復與子之作别意殊憒憒偶得兩詩上呈并告送與壯輿叔用也  其二','呂本中','宋','宋诗','song-poetry','','[]','老僕倦日長，羸馬困道遠。',108,'全唐诗/poet.song.92000.json','["老僕倦日長，羸馬困道遠。", "東行數日間，尚欲一再款。", "我能喻子意，子亦識我嬾。", "追懷十年游，僅得一笑莞。", "時能煮湯餅，更復下茗盌。", "晁郎本京邑，劉子蓋楚産。", "江山兩秀異，與子日在眼。", "南風動歸興，感慨毛髮短。", "相尋倘有日，歲月亦未晚。"]'),
('3b7ec62a-33b3-4de1-b0ac-1e703c8dced2','雁','呂本中','宋','宋诗','song-poetry','','[]','雁從何方来，云自燕趙北。',108,'全唐诗/poet.song.92000.json','["雁從何方来，云自燕趙北。", "今當何所往，暖日近暘谷。", "寒雲墮江漢，未見所棲宿。", "朝憂稻粱少，暮畏羅網逐。", "惜哉還往頻，愈覺歲月促。", "悔不近藩籬，隨羣伴鷄鶩。", "羽幹何必好，志願亦易足。", "物生有高下，終恐厭摧伏。", "公看滄海頭，萬里飛鴻鵠。"]'),
('4a986c8d-aed3-4e5f-b95f-aaac4f48e50e','赴海陵行次寶應','呂本中','宋','宋诗','song-poetry','','[]','半升濁酒試蓴羮，賤買魚蝦已厭烹。',64,'全唐诗/poet.song.92000.json','["半升濁酒試蓴羮，賤買魚蝦已厭烹。", "淺水依蒲有船過，淡烟籠月更人行。", "交游潦倒腸先斷，疾病侵陵涕自横。", "北望中原一千里，故人誰復喚歸耕。"]'),
('7c7d32be-6deb-480c-b171-40f80f2f59b2','海陵雜興八首  其一','呂本中','宋','宋诗','song-poetry','','[]','四海今誰託，飄然未有歸。',48,'全唐诗/poet.song.92000.json','["四海今誰託，飄然未有歸。", "先生作詩瘦，稚子食言肥。", "未忍螢枯死，甘隨鷁退飛。", "故人取堅坐，不爲賦無衣。"]'),
('8e774752-f654-4a87-967e-2e0237c8e33a','海陵雜興八首  其二','呂本中','宋','宋诗','song-poetry','','[]','相見各已老，壯懷如昔然。',48,'全唐诗/poet.song.92000.json','["相見各已老，壯懷如昔然。", "蛟龍夜改穴，風雨暗移船。", "把酒猶堪醉，逢人嬾問禪。", "還家有餘地，留我買山錢。"]'),
('bc6f7b22-f93e-44a6-b117-f05426a41779','海陵雜興八首  其三','呂本中','宋','宋诗','song-poetry','','[]','諸老今無恙，秋来數寄聲。',48,'全唐诗/poet.song.92000.json','["諸老今無恙，秋来數寄聲。", "尚能無事飲，猶勝不平鳴。", "行李虚長鋏，生涯共短檠。", "江湖日在眼，恐負白鷗盟。"]'),
('f1616a7b-fa73-445e-954f-94aa1c4916f1','海陵雜興八首  其四','呂本中','宋','宋诗','song-poetry','','[]','荒城足風雨，今日更新冬。',48,'全唐诗/poet.song.92000.json','["荒城足風雨，今日更新冬。", "草木山嵐暗，人家水影重。", "漫看文字過，時有簿書逢。", "目極横塘路，西樓聞暮鐘。"]'),
('f77c6a1d-dd21-4af9-9a54-dc43e1d32ea1','海陵雜興八首  其五','呂本中','宋','宋诗','song-poetry','','[]','曾子不復見，斯人絕可憐。',48,'全唐诗/poet.song.92000.json','["曾子不復見，斯人絕可憐。", "夢回千嶂裏，氣奪萬夫前。", "異日文章社，平生香火緣。", "高樓更南望，霜露倚江天。"]'),
('18493e6b-5a38-48c5-a9ec-cbb1939e40ba','海陵雜興八首  其六','呂本中','宋','宋诗','song-poetry','','[]','萬事不如意，自然添白鬚。',48,'全唐诗/poet.song.92000.json','["萬事不如意，自然添白鬚。", "極知少餘韻，何敢厭窮途。", "土俗尊魚婢，生涯欠木奴。", "東行見李白，誰爲致區區。"]'),
('2cf525c7-36c1-4a2b-b089-f7250ebbad92','海陵雜興八首  其七','呂本中','宋','宋诗','song-poetry','','[]','空山鶴夜鳴，海風令人驚。',48,'全唐诗/poet.song.92000.json','["空山鶴夜鳴，海風令人驚。", "對月且愁思，看書終眼明。", "斗酒不爲薄，客帆那計程。", "猶憐他夜雨，曾作打窗聲。"]'),
('64080bd8-aa33-4e53-8312-70fb14d12cc1','海陵雜興八首  其八','呂本中','宋','宋诗','song-poetry','','[]','輕帆載曉月，和夢到揚州。',48,'全唐诗/poet.song.92000.json','["輕帆載曉月，和夢到揚州。", "木落山光寺，江横北固樓。", "漫抛王倕隱，虛有十年游。", "尚勝劉師命，才因越女留。"]'),
('ec04bc12-a201-437a-9c2e-16d3bf7d844a','往来送迎城南道中二絕  其一','呂本中','宋','宋诗','song-poetry','','[]','破裘重補却勝寒，暗減頭圍覺帽寛。',32,'全唐诗/poet.song.92000.json','["破裘重補却勝寒，暗減頭圍覺帽寛。", "數頃桑麻遶城路，每隨妓吏去迎官。"]'),
('96972a60-e75f-4706-a13f-b07fd7881e39','往来送迎城南道中二絕  其二','呂本中','宋','宋诗','song-poetry','','[]','海氣如煙跨市樓，北風連夜舞梧楸。',32,'全唐诗/poet.song.92000.json','["海氣如煙跨市樓，北風連夜舞梧楸。", "平生事業難牽强，坐聽寒燈守聒囚。"]'),
('5cd4901c-7a73-4d84-afc5-9be3cc132620','往来送迎城南道中二絕  其三','呂本中','宋','宋诗','song-poetry','','[]','家叔舍弟與黎介然會于符離因用兩絕奉寄。',19,'全唐诗/poet.song.92000.json','["家叔舍弟與黎介然會于符離因用兩絕奉寄。"]'),
('ca864f99-445b-4ceb-8345-fabefe82ab55','往来送迎城南道中二絕  其四','呂本中','宋','宋诗','song-poetry','','[]','漫約同歸久未償，只今留滯各他鄉。',32,'全唐诗/poet.song.92000.json','["漫約同歸久未償，只今留滯各他鄉。", "春風有信勤歸雁，夜雨何時復對牀。"]'),
('f0eed49c-c258-4784-b2ed-2f5a55bc6334','往来送迎城南道中二絕  其五','呂本中','宋','宋诗','song-poetry','','[]','老覺爲官百不宜，故人雖在鬢如絲。',32,'全唐诗/poet.song.92000.json','["老覺爲官百不宜，故人雖在鬢如絲。", "遥知再踏同游地，更想汪饒曳杖時。"]'),
('96cee119-0e3e-42d4-b191-96709ac1b5f3','病中夜聞雪作時堯明有廣陵之行未歸思爲數語奉寄久之未就他日堯明歸擕詩相過飄然有御風凌雲之氣因以前詩答之','呂本中','宋','宋诗','song-poetry','','[]','公方他山行，我此一室病。',156,'全唐诗/poet.song.92000.json','["公方他山行，我此一室病。", "擁爐聽夜雪，若與風勢競。", "蕭條中疑休，狼藉久未定。", "平明望屋瓦，入我眼界净。", "所恨子猷遠，無復肯乘興。", "想當巖壑間，玉立與輝映。", "時来有傑句，遂入風雅正。", "寒威固深避，草木自温凊。", "公家鶴氅翁，韻與羲皇並。", "流風及遠孫，筆力如此勁。", "雕繢或過眼，惟我乃弗稱。", "新春上河堤，梅柳當歷聘。", "過從不厭數，荒疇取微徑。"]'),
('bee84d98-9897-4a92-ac68-f8320fdca04e','次韻堯明貢院詩','呂本中','宋','宋诗','song-poetry','','[]','忍窮不能歸，强飯亦良計。',228,'全唐诗/poet.song.92000.json','["忍窮不能歸，强飯亦良計。", "東風頻報春，草木可次第。", "厭爲龍頭縮，寧作龜尾曳。", "從來翰墨場，即有聞見滯。", "譬如已耕田，更欲深種藝。", "或蒙鹵莽報，未肯即賣棄。", "不聞太倉粟，亦校毫髮細。", "王卿固倦游，穢濁有蟬蜕。", "聲名動時人，我實託末契。", "泥塗倒屐齒，塵埃涴衣裌。", "要爲無用用，乃作不事事。", "下馬舊戰場，午日在庭戺。", "向来槁木枝，忽有紅綠綴。", "來非偶然住，去亦無所詣。", "聚蚊著甌中，得聽此鶴唳。", "窗前有餘馥，勝韻入松桂。", "扁舟下淮南，閭里思少憩。", "熟觀昔所歷，請與居士戲。", "江湖要同歸，不假木蘭枻。"]'),
('b8f8cc4a-59a4-4aac-a9e3-282cda1165ad','海陵夜作','呂本中','宋','宋诗','song-poetry','','[]','夜長夜長天復霜，海陵城中今夜長。',160,'全唐诗/poet.song.92000.json','["夜長夜長天復霜，海陵城中今夜長。", "夜長夜長冬向晚，寒階無人看月滿。", "路長家遠来信稀，水闊山深歸夢短。", "堂上書生頭已白，朔方健兒十年客。", "想渠當此夜長時，撫劍雖長酒杯窄。", "明妃愛惜漢宫衣，烏孫公主終不歸。", "戚姬去視鴻鵠舉，更爲君王作楚舞。", "當此夜長誰送迎，此月還如今夜明。", "夜長夜短公莫厭，寒即重裘熱須簟。", "夜長夜短公莫憂，多憂多厭公白頭。"]'),
('274732b4-56b7-477b-9894-1abd29a5a8a4','秋夜行','呂本中','宋','宋诗','song-poetry','','[]','八月九月啼寒螿，十月北風天雨霜。',88,'全唐诗/poet.song.92000.json','["八月九月啼寒螿，十月北風天雨霜。", "客游無聊思故鄉，鄉書不来空斷腸。", "鴻飛何爲滿夕陽，舉頭攬取明月光。", "置我堂上方天牀，滿酌玉杯碧淋浪。", "喚取姮娥来共嘗，人間歡樂壽命長，不須辛苦老桂傍。"]'),
('f010c8b7-f64d-4678-ab8f-b9e1a14ebeb6','臘梅','呂本中','宋','宋诗','song-poetry','','[]','學得漢宫粧，偷傳半額黄。',24,'全唐诗/poet.song.92000.json','["學得漢宫粧，偷傳半額黄。", "不將供俗鼻，愈覺更清香。"]'),
('06aa39e2-dbce-4db8-9df6-38b03e0fe646','牧牛兒','呂本中','宋','宋诗','song-poetry','','[]','牧牛兒，放牛莫放澗水西，澗水流急牛苦饑。',68,'全唐诗/poet.song.92000.json','["牧牛兒，放牛莫放澗水西，澗水流急牛苦饑。", "放牛只放青草畔，牛卧得草兒亦嬾。", "兒嬾隨牛莫著鞭，幾年力作無荒田。", "雨調風順租税了，兒但放牛相對眠。"]'),
('4a40b827-b8fb-4b6c-aae7-5b7314a02353','洞庭','呂本中','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','嘗聞洞庭湖，秋至清皎潔。',60,'全唐诗/poet.song.92000.json','["嘗聞洞庭湖，秋至清皎潔。", "往来八百里，長風駕明月。", "中有仙人居，容顔若冰雪。", "我願從之游，問渠傳寶訣。", "脱冠着霞佩，長與塵世别。"]'),
('65dcfa8e-fc97-4ff6-8855-72fdab40c734','細雨','呂本中','宋','宋诗','song-poetry','','[]','細雨不成雪，北風来解紛。',48,'全唐诗/poet.song.92000.json','["細雨不成雪，北風来解紛。", "冥冥小江樹，漠漠暮空雲。", "誰惜江東弟，令修地下文。", "西齊千萬里，遺恨不堪聞。"]'),
('1bc3866d-6bd4-4e1d-894f-2b5c3f54a471','王陽','呂本中','宋','宋诗','song-poetry','','[]','王陽作黄金，才了車馬費。',72,'全唐诗/poet.song.92000.json','["王陽作黄金，才了車馬費。", "苦身邀聲名，未免遺俗累。", "何如陶淵明，蕭散塵世外。", "公田二頃餘，覓酒償一醉。", "高風久寂寞，斯文若旈綴。", "白眼看世人，此意渠不會。"]'),
('0767c81a-9754-45ef-9392-794d0b3e3a17','題趙丞瑞薏苡圖','呂本中','宋','宋诗','song-poetry','','[]','甘泉殿中芝九莖，不與百草同條生。',131,'全唐诗/poet.song.92000.json','["甘泉殿中芝九莖，不與百草同條生。", "當時祥瑞已稠疊，薏苡亦未來争衡。", "漢星不容矍鑠翁，此物不與明珠同。", "爾来萬物更變化，薏苡寧甘死荒野。", "故遣根苗霜雪白，炯若微月来清夜。", "趙郎好事古亦無，俯拾傍觀盡圖畫。", "畫師不辭粉繪費，遇時亦得千金價。", "君不見古来異瑞與奇祥，何曾不致南宫下。"]'),
('8cb6e64d-84bb-481f-b7f4-0f17b67ebd4a','即事','呂本中','宋','宋诗','song-poetry','','[]','清陰庭中槐，綠潤牆外草。',96,'全唐诗/poet.song.92000.json','["清陰庭中槐，綠潤牆外草。", "職事苦見妨，令人惡懷抱。", "朋從多飄徙，今我獨枮槁。", "高牀書數帙，時節豈不好。", "不能遂爾去，但覺歸思浩。", "人情便久習，世態嫌衰老。", "閉門了殘詩，昔者跡已掃。", "何時北窗風，清尊爲君倒。"]'),
('9623c22c-df2a-45d9-8be5-ee963e3ebbc4','寄晁以道','呂本中','宋','宋诗','song-poetry','','[]','朝辭陘山清，暮宿頼水綠。',180,'全唐诗/poet.song.92000.json','["朝辭陘山清，暮宿頼水綠。", "往来百里間，得此意已足。", "吾人少如願，夫子更絕俗。", "閉門觀易象，未用傷局促。", "使我三日留，共此一室獨。", "皎如嶺頭月，凜若霜後竹。", "欲爲斯文壽，以作學者福。", "洛陽佳少年，撫事多慟哭。", "此其於聖學，何異狗尾續。", "寧知草玄翁，萬事不掛目。", "深湛而雅澹，亦不在反覆。", "吾祖早聞道，晚與夫子熟。", "相期千載外，未得一世伏。", "渫山竄鼯鼬，晚日度鴻鵠。", "誰能從公游，歲月如轉燭。"]'),
('3f466bb0-e6c7-4a51-b29b-ddf2a7bc3562','橋上口占二首  其一','呂本中','宋','宋诗','song-poetry','','[]','城北城南柳絮飛，街東街西鵓鴣啼。',32,'全唐诗/poet.song.92000.json','["城北城南柳絮飛，街東街西鵓鴣啼。", "海陵三月與春别，一夜雨成三尺泥。"]'),
('60f79150-031b-4e45-a390-002501fc4c93','橋上口占二首  其二','呂本中','宋','宋诗','song-poetry','','[]','風雨屬連春事休，十日九日轉城頭。',32,'全唐诗/poet.song.92000.json','["風雨屬連春事休，十日九日轉城頭。", "雖無俗物敗人意，可使澄江消客愁。"]'),
('2db8e759-edbb-4ff1-b62f-edd2b26bddb8','次韻遜叔直門見寄兼請堯明同和','呂本中','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','紛紛塵土計秋豪，忽送長江八月濤。',64,'全唐诗/poet.song.92000.json','["紛紛塵土計秋豪，忽送長江八月濤。", "陶令且爲州祭酒，鄧公才可掾功曹。", "但看秋到猶絺綌，即是花時合緼袍。", "待得公歸吾已老，滿田荼蓼與誰薅。"]'),
('faf80598-423d-4251-a428-09b863faeddd','再和兼寄奉符大有叔','呂本中','宋','宋诗','song-poetry','','[]','血氣侵凌不復豪，往来欹倒似乘濤。',64,'全唐诗/poet.song.92000.json','["血氣侵凌不復豪，往来欹倒似乘濤。", "寧知嬾過嵇中散，亦有詩如謝法曹。", "舊稿只堪供醬瓿，故人相贈有綈袍。", "兖州賓主同風味，惡句煩公更一薅。"]'),
('b7a9139c-e093-42b3-91c1-c06d5d1efed3','雨後至城外','呂本中','宋','宋诗','song-poetry','','[]','日日思歸未就歸，只今行露已沾衣。',64,'全唐诗/poet.song.92000.json','["日日思歸未就歸，只今行露已沾衣。", "江村過雨蓬麻亂，野水連天鸛鶴飛。", "塵務却嫌經意少，故人新更得書稀。", "鹿門縱隱猶多事，苦向人前說是非。"]'),
('2535c62b-561b-49a9-bd6f-91f89671663a','龐公','呂本中','宋','宋诗','song-poetry','','[]','卧龍雛鳳不曾閑，舉世皆危子獨安。',32,'全唐诗/poet.song.92000.json','["卧龍雛鳳不曾閑，舉世皆危子獨安。", "應念橋公無特操，晚將情話向曹瞞。"]'),
('040b83a8-89f7-4078-8825-0f5d019defcf','衛青','呂本中','宋','宋诗','song-poetry','','[]','將軍相繼出天山，漢主吞胡意未闌。',32,'全唐诗/poet.song.92000.json','["將軍相繼出天山，漢主吞胡意未闌。", "本自無心接賓客，故人猶有一任安。"]'),
('c38b318b-52bc-456b-a3e2-d715896827dd','雜詩三首  其一','呂本中','宋','宋诗','song-poetry','','[]','烹葵去王畿，剥棗在海角。',84,'全唐诗/poet.song.92000.json','["烹葵去王畿，剥棗在海角。", "歲序忽已周，月亦頻告朔。", "向来手中扇，今此已倦捉。", "尚嫌簿領繁，不厭朋友數。", "塵埃向奔走，文字費雕琢。", "途人有前知，子乃獨未覺。", "出門見大路，夫子焉不學。"]'),
('7e4e239f-8ff5-4cb0-aefc-409ce5448129','雜詩三首  其二','呂本中','宋','宋诗','song-poetry','','[]','結髮在簡編，俗事方刺促。',84,'全唐诗/poet.song.92000.json','["結髮在簡編，俗事方刺促。", "往来三十年，未見可棲宿。", "微官不能去，尚恐遭逼逐。", "歸棲則在念，所望一枝足。", "頻蒙故人悮，豈有鄰可卜。", "出門雖無車，徑自騎黄鵠。", "重尋置錐地，青燈一盂粥。"]'),
('75e0ccb9-a521-45d2-a873-615b464c0bb8','雜詩三首  其三','呂本中','宋','宋诗','song-poetry','','[]','饑蚊青而化，怒目虬兩鬚。',84,'全唐诗/poet.song.92000.json','["饑蚊青而化，怒目虬兩鬚。", "黄昏與我遇，且復少踟蹰。", "肌膚恣啖齧，熟視不可敺。", "中宵盛徒黨，意氣若有餘。", "傷哉陷穽虎，有時被囚拘。", "求食至搖尾，曾此蚊不如。", "雲龍困螻蟻，此語不可誣。"]'),
('818d9cf7-2d4d-47a9-a607-78b053adb30e','秋日三首  其一','呂本中','宋','宋诗','song-poetry','','[]','諸卿談笑賞先登，我欲從之病不能。',32,'全唐诗/poet.song.92000.json','["諸卿談笑賞先登，我欲從之病不能。", "門閉日長公事少，祇疑身是住庵僧。"]'),
('9fff7f9e-fae5-41e9-a8e9-742cfb53e70c','秋日三首  其二','呂本中','宋','宋诗','song-poetry','','[]','塵滿文書燈暗檠，荒城相望數殘更。',32,'全唐诗/poet.song.92000.json','["塵滿文書燈暗檠，荒城相望數殘更。", "莫言愁罷無佳處，睡正熟時聞雨聲。"]'),
('9f9ad455-7d7b-48d0-8622-44e820931091','秋日三首  其三','呂本中','宋','宋诗','song-poetry','','[]','往来奔走看渠忙，疾病低回却未妨。',32,'全唐诗/poet.song.92000.json','["往来奔走看渠忙，疾病低回却未妨。", "喚客不須嫌酒惡，隔牆時喜送橙香。"]'),
('7e5abb8d-26ff-4601-a563-481c9094351a','橙二首  其一','呂本中','宋','宋诗','song-poetry','','[]','西風吹雁欲斜行，小檻寒花却未香。',32,'全唐诗/poet.song.92000.json','["西風吹雁欲斜行，小檻寒花却未香。", "將謂諸公頻載酒，枉留橙菊十分黄。"]'),
('a1d5409e-a83e-41bd-b281-934b0d8b2090','橙二首  其二','呂本中','宋','宋诗','song-poetry','','[]','不辭玉露著新行，漫作人間徹骨香。',32,'全唐诗/poet.song.92000.json','["不辭玉露著新行，漫作人間徹骨香。", "知道輸棋償舊約，故留殘菊一時黄。"]'),
('56c72878-2395-4763-b32c-b2d31d4d9388','寄京師親舊','呂本中','宋','宋诗','song-poetry','','[]','屋頭橙實如李梅，庭下葵花深覆盃。',128,'全唐诗/poet.song.92000.json','["屋頭橙實如李梅，庭下葵花深覆盃。", "豆田失雨不稱意，野菊出苗虚見猜。", "故人相望一尊酒，問我此住何時回。", "江山空自汚敲扑，筆硯洗復生塵埃。", "交情自惜少同調，人事只今多好乖。", "欲隨明月覓公處，限以白浪搖長淮。", "舟楫誤逢蛟鱷横，歲月苦遭霜露催。", "側身西望莫回首，堂上書生心已灰。"]'),
('33812ee6-a006-466f-a66c-40a9d0459aa7','和成士瑴鹿女泉詩','呂本中','宋','宋诗','song-poetry','','[]','成子東游十日程，駝裘顛倒帽欹傾。',64,'全唐诗/poet.song.92000.json','["成子東游十日程，駝裘顛倒帽欹傾。", "新詩頓數神仙事，病耳忽聞京洛聲。", "去住閑經幾塵刹，往来相望一牛鳴。", "再尋六月山前路，分我寒泉數勺清。"]'),
('cb3ed9e4-7e85-4fc8-b7f5-df041a8450aa','春申君','呂本中','宋','宋诗','song-poetry','','[]','少年談笑解秦兵，便欲連從却未成。',32,'全唐诗/poet.song.92000.json','["少年談笑解秦兵，便欲連從却未成。", "莫謂江東可長保，暮年無意引朱英。"]'),
('8c041c05-aa19-464f-b442-bb784c86528e','秋日三首  其一','呂本中','宋','宋诗','song-poetry','','[]','罷馬厭鞭策，征鴻思稻粱。',48,'全唐诗/poet.song.92000.json','["罷馬厭鞭策，征鴻思稻粱。", "終年在泥土，永路困風霜。", "慎勿鞍韉愛，直須矰繳防。", "吾衰亦已甚，念爾不能忘。"]'),
('23a07209-6c51-4ca3-839a-f28b62c9211f','秋日三首  其二','呂本中','宋','宋诗','song-poetry','','[]','交游大半死，吾亦老相侵。',48,'全唐诗/poet.song.92000.json','["交游大半死，吾亦老相侵。", "古木十圍大，寒泉百尺深。", "恨猶能切骨，愁或至傷心。", "寄語南飛雁，君無笑苦吟。"]'),
('519c887d-5fab-48c2-9bb1-2d0a695545fe','秋日三首  其三','呂本中','宋','宋诗','song-poetry','','[]','獄掾酸寒極，官曹冗長催。',48,'全唐诗/poet.song.92000.json','["獄掾酸寒極，官曹冗長催。", "真同鶴久住，不學雁輕回。", "婦女能相笑，兒童忍見猜。", "猶憐舊耆老，時有一書來。"]'),
('7d1e61df-c074-4914-b2df-a0fc5183547a','和成士瑴海安道中見寄','呂本中','宋','宋诗','song-poetry','','[]','成侯老更嬾，處世一虛舟。',48,'全唐诗/poet.song.92000.json','["成侯老更嬾，處世一虛舟。", "暫脱塵埃夢，還尋江海秋。", "從来仙聖宅，不數鳳麟洲。", "有意相隨否，因公更一游。"]'),
('97067dee-b5ee-4fd7-8426-1e64213813d7','送虞澹季然之官京師','呂本中','宋','宋诗','song-poetry','','[]','車如鷄棲馬如狗，勸君莫美循牆走。',160,'全唐诗/poet.song.92000.json','["車如鷄棲馬如狗，勸君莫美循牆走。", "車如流水馬如龍，不如還家行御風。", "以尻爲輪神爲馬，世人計出車馬下。", "出門險阻道里遠，只今誰是能行者。", "海陵事劇俸則薄，得公相從亦不惡。", "小吏相欺官長怒，我自作煩公笑樂。", "庾公故是豐年玉，道貌更自見不足。", "斷崖獨立老松柏，青天何處飛鴻鵠。", "汴堤六月塵自障，請公登高更南望。", "馬煩車怠早歸来，且從夫子濠梁上。"]'),
('2b759fc1-e279-4b91-9a4a-3c644bb106f1','海陵病中  其一','呂本中','宋','宋诗','song-poetry','','[]','病知前路資糧少，老覺平生事業非。',32,'全唐诗/poet.song.92000.json','["病知前路資糧少，老覺平生事業非。", "無數青山隔滄海，與誰同往却同歸。"]'),
('c8c046fd-da97-4135-bdbe-0af8757acf45','海陵病中  其二','呂本中','宋','宋诗','song-poetry','','[]','先生高卧了殘冬，我亦年来不諱窮。',32,'全唐诗/poet.song.92000.json','["先生高卧了殘冬，我亦年来不諱窮。", "夜半打窗人不會，滿天風雨角聲中。"]'),
('644cb295-ad77-4ab7-a5df-052c43c1a853','海陵病中  其三','呂本中','宋','宋诗','song-poetry','','[]','客游歷歷都如夢，身事悠悠略似僧。',32,'全唐诗/poet.song.92000.json','["客游歷歷都如夢，身事悠悠略似僧。", "只麽隨緣作官去，不知從古更誰曾。"]'),
('dd88ca2e-1561-4e88-a965-8474f40a43e5','海陵病中  其四','呂本中','宋','宋诗','song-poetry','','[]','往来車馬閙泥塗，一室蕭然百事無。',32,'全唐诗/poet.song.92000.json','["往来車馬閙泥塗，一室蕭然百事無。", "語黙二途俱不涉，不勞辛苦對文殊。"]'),
('36d5d91b-cc32-4ebb-97f9-d040cdf7faef','海陵病中  其五','呂本中','宋','宋诗','song-poetry','','[]','久諳罷卧嬾呼醫，剩讀文書不療饑。',32,'全唐诗/poet.song.92000.json','["久諳罷卧嬾呼醫，剩讀文書不療饑。", "數有故人来問疾，更煩耆舊與傳詩。"]'),
('f8df63d7-af0f-4a76-b454-435c3cb07e79','次韻季叔友賀堯明登第叔友丹陽人也本中得其人之詳於王堯明恨未之識也堯明擢第叔友作詩賀之堯明令繼作既喜叔友能不妄許可又嘉堯明進退取捨皆中乎道也三首  其一','呂本中','宋','宋诗','song-poetry','','[]','柴桑無復陶元亮，谷口虛傳鄭子真。',32,'全唐诗/poet.song.92000.json','["柴桑無復陶元亮，谷口虛傳鄭子真。", "二子風流知有在，且留餘味及吾人。"]'),
('5481365f-9d5f-4a9f-b7ce-c5be25346fa2','次韻季叔友賀堯明登第叔友丹陽人也本中得其人之詳於王堯明恨未之識也堯明擢第叔友作詩賀之堯明令繼作既喜叔友能不妄許可又嘉堯明進退取捨皆中乎道也三首  其二','呂本中','宋','宋诗','song-poetry','','[]','澄江雖近不容親，亦是人間可喜人。',32,'全唐诗/poet.song.92000.json','["澄江雖近不容親，亦是人間可喜人。", "枯木巖前有岐路，一杯濁酒自成春。"]'),
('38f896fb-b87c-48fb-89ed-cf91d9596cc3','次韻季叔友賀堯明登第叔友丹陽人也本中得其人之詳於王堯明恨未之識也堯明擢第叔友作詩賀之堯明令繼作既喜叔友能不妄許可又嘉堯明進退取捨皆中乎道也三首  其三','呂本中','宋','宋诗','song-poetry','','[]','二子深居筆吐虹，從来節氣萬夫雄。',32,'全唐诗/poet.song.92000.json','["二子深居筆吐虹，從来節氣萬夫雄。", "欲知聖主求賢意，不爲相如詞賦工。"]'),
('8f05dfb5-f9a5-49b6-a963-fce93c782ceb','次韻堯明見和因及李蕭遠五詩  其一','呂本中','宋','宋诗','song-poetry','','[]','小閣才堪置一牀，病軀雖在鬢滄浪。',32,'全唐诗/poet.song.92000.json','["小閣才堪置一牀，病軀雖在鬢滄浪。", "隨身行李無長劍，猶勝堆錢與窟郎。"]'),
('5d382e32-cb93-4296-b389-05c10d10e624','次韻堯明見和因及李蕭遠五詩  其二','呂本中','宋','宋诗','song-poetry','','[]','交游潦倒漫虚名，悮結他生文字盟。',32,'全唐诗/poet.song.92000.json','["交游潦倒漫虚名，悮結他生文字盟。", "踏盡塵埃公莫厭，不應因酒愛江清。"]'),
('f3dd3b39-ed8a-4bae-a067-24550da84904','次韻堯明見和因及李蕭遠五詩  其三','呂本中','宋','宋诗','song-poetry','','[]','故人飄散各窮途，諸老交情却未疏。',32,'全唐诗/poet.song.92000.json','["故人飄散各窮途，諸老交情却未疏。", "賴有清詩在書案，時時翻讀伴更初。"]'),
('09834105-02cb-4a0c-a7cf-e4f2ef3e90f0','次韻堯明見和因及李蕭遠五詩  其四','呂本中','宋','宋诗','song-poetry','','[]','萬里星河指顧間，此中何自著江山。',32,'全唐诗/poet.song.92000.json','["萬里星河指顧間，此中何自著江山。", "精金百鍊終無用，才與佳人照指鐶。"]'),
('542e3d3b-5a0e-4fdc-aad2-83ccd187463a','次韻堯明見和因及李蕭遠五詩  其五','呂本中','宋','宋诗','song-poetry','','[]','阮公游宦喜東平，賀監從来憶四明。',32,'全唐诗/poet.song.92000.json','["阮公游宦喜東平，賀監從来憶四明。", "但得從容飽粗糲，不須辛苦辨肴鯖。"]'),
('158a2272-a838-469d-a314-5a9fb63f3450','西歸舟中懷通泰諸君','呂本中','宋','宋诗','song-poetry','','[]','一雙一隻路傍堠，乍有乍無天際星。',64,'全唐诗/poet.song.92000.json','["一雙一隻路傍堠，乍有乍無天際星。", "亂葉入船侵破衲，疾風吹水擁枯萍。", "山林何謝難方駕，詩語曹劉可乞靈。", "酒碗茶甌俱不厭，爲公醉倒爲公醒。"]'),
('2e81f592-061b-44ca-9860-457b3c9b2641','寄馬巨濟察院時監泰州酒得宫祠歸南京','呂本中','宋','宋诗','song-poetry','','[]','新春款南園，積雨寒不歇。',108,'全唐诗/poet.song.92000.json','["新春款南園，積雨寒不歇。", "起望海陵城，幸未還往缺。", "聞公得安還，未放車軌折。", "毫端倒江海，胸次湛明月。", "東風片帆来，乃復爲此别。", "田園到荒蕪，歲事有曲折。", "不見南山松，高卧擁霜雪。", "鬢髯凜可畏，此豈念容悦。", "願公考其然，一向鼻頭說。"]'),
('abdec948-3ac4-45ed-9cb1-3f24492529f4','寄趙十弟','呂本中','宋','宋诗','song-poetry','','[]','十年流落各西東，再見初非舊阿蒙。',64,'全唐诗/poet.song.92000.json','["十年流落各西東，再見初非舊阿蒙。", "晉邑自思欒孺子，魯儒空望叔孫通。", "宦情潦倒三荒徑，世味衰頹一秃翁。", "石室度籌吾豈敢，且看鮮健勝龐公。"]'),
('949be669-4c49-4e6e-8213-fb3f3644159a','叔度季明學問甚勤而求於余甚重其將必有所成也因作兩詩寄之  其一','呂本中','宋','宋诗','song-poetry','','[]','兩章後来秀，頭角固嶄然。',48,'全唐诗/poet.song.92000.json','["兩章後来秀，頭角固嶄然。", "但語强弩末，不争駑馬先。", "寓言有十九，曲禮至三千。", "所要在守節，末言能與權。"]'),
('f7af52f1-90ae-4c35-b4e4-8d8fed1307f2','叔度季明學問甚勤而求於余甚重其將必有所成也因作兩詩寄之  其二','呂本中','宋','宋诗','song-poetry','','[]','念我少年日，結交皆老蒼。',48,'全唐诗/poet.song.92000.json','["念我少年日，結交皆老蒼。", "曹南見顔石，甬上拜饒汪。", "敢幸江海浸，得霑藜藿腸。", "諸郎但勉力，餘事及文章。"]'),
('182e8971-86bb-4520-9493-10fc56ce57ba','與季宏子植同過信中飲薜荔亭下夜分乃散别後奉懷遂成長韻','呂本中','宋','宋诗','song-poetry','','[]','殘花無言卧風雨，小亭寂寞延初暑。',144,'全唐诗/poet.song.92000.json','["殘花無言卧風雨，小亭寂寞延初暑。", "范侯置酒呼我来，共坐階前洗塵土。", "坐間問有李與韓，文字峥嶸各奇古。", "起卧逡巡失杯杓，笑語瀾翻雜歌舞。", "滿城車馬閧侵淫，誰解牆陰着樽俎。", "薜荔扶疏出枝葉，老氣横空君一吐。", "人生此會不可常，昔者各在天一方。", "簿書相急如探湯，好風吹我来君旁。", "鶯啼燕乳各自忙，明日酒醒空斷腸。"]'),
('fd7484e4-cc13-4f3f-ac13-45b54a4bb84f','秋日呈顔夷仲','呂本中','宋','宋诗','song-poetry','','[]','老去身已衰，事過意愈嬾。',144,'全唐诗/poet.song.92000.json','["老去身已衰，事過意愈嬾。", "斯人未寂寞，吾此歸亦晚。", "疏籬带落葉，秋色忽已滿。", "南窗可炙背，喚婦同茗盌。", "舊讀無新功，亦復費編纂。", "凝塵亂朱墨，妙句折編簡。", "往者荷蓧翁，實具世外眼。", "不能與之游，只有興盡返。", "曹南二三老，夙昔荷推挽。", "平生萬卷書，未盡一日款。", "微詞絕端兆，自怪識者罕。", "願聞片言佳，庶用收褊短。"]'),
('362b8131-9fd1-4a2a-aa35-9c62422ea336','謝任伯夫人挽詩','呂本中','宋','宋诗','song-poetry','','[]','幽蘭在深山，無人終自芳。',132,'全唐诗/poet.song.92000.json','["幽蘭在深山，無人終自芳。", "豈伊桃李顔，取媚少年腸。", "高氏有潛德，奕世被輝光。", "自其父祖来，低首不肯昂。", "夫人生既賢，豈止秀閨房。", "出身事夫子，和鳴更鏘鏘。", "笙鏞列兩序，圭幣羅中堂。", "云何去日遠，遂棄凌風翔。", "伋也奉慈訓，將見久必昌。", "瞻彼汝南路，松柏泣新霜。", "凄然馬鬛封，千歲終不亡。"]'),
('b65cad9e-7db9-4eec-98f0-276fc0c15d7a','贈筆工安伋','呂本中','宋','宋诗','song-poetry','','[]','昔人三年學屠龍，技成不試身已窮。',128,'全唐诗/poet.song.92000.json','["昔人三年學屠龍，技成不試身已窮。", "安生不願洴澼封，嗜好乃與屠龍同。", "使世淬礪磨其鋒，側出逆曳求新功。", "伋也中立無適從，随所欲用吾能供。", "歙溪孕石南山松，四方萬里時一逢。", "病夫乍閑百念空，敗毫破管塵埃蒙。", "明窗浄几聊從容，眼無列宿羅心胸。", "使汝得見文章公，展卷略書吾已慵。"]'),
('f88a71b4-ffad-42a7-8326-5f9ade73344b','寄共誠賈秀才','呂本中','宋','宋诗','song-poetry','','[]','萬里歸来四壁空，舊游渾在黙然中。',32,'全唐诗/poet.song.92000.json','["萬里歸来四壁空，舊游渾在黙然中。", "明年我欲江南去，何處留詩可寄公。"]'),
('ef5b55e0-7d41-4816-87a9-95cfb10a76c2','題大名官舍','呂本中','宋','宋诗','song-poetry','','[]','宿昔尚殘暑，晚風吹欲無。',24,'全唐诗/poet.song.92000.json','["宿昔尚殘暑，晚風吹欲無。", "不知留此住，更白幾莖鬚。"]'),
('1c3ef6c0-be84-4614-a1f9-c46df5ffe4d0','秋日即事四首  其一','呂本中','宋','宋诗','song-poetry','','[]','瓦爐香燼欲凝塵，小檻黄花更一新。',32,'全唐诗/poet.song.92000.json','["瓦爐香燼欲凝塵，小檻黄花更一新。", "絡緯戒寒鳩喚雨，世間那有自由人。"]'),
('8f925e95-ea8d-433c-88f5-15fe3a39fc19','秋日即事四首  其二','呂本中','宋','宋诗','song-poetry','','[]','鬢髪蒼然雪欲垂，問君何苦讀書爲。',32,'全唐诗/poet.song.92000.json','["鬢髪蒼然雪欲垂，問君何苦讀書爲。", "旁人不會回頭意，猶記田光盛壯時。"]'),
('2809b734-7027-46a1-8f42-a18a65a322d5','秋日即事四首  其三','呂本中','宋','宋诗','song-poetry','','[]','簿書塵土亂蒙茸，無復江船萬里風。',32,'全唐诗/poet.song.92000.json','["簿書塵土亂蒙茸，無復江船萬里風。", "臥聽秋聲滿簷溜，不知牆下有梧桐。"]'),
('abbbe333-a399-4aad-abab-fcef492b8a37','秋日即事四首  其四','呂本中','宋','宋诗','song-poetry','','[]','何處此時此刻欲捕蟬，主人初未覺鳴弦。',34,'全唐诗/poet.song.92000.json','["何處此時此刻欲捕蟬，主人初未覺鳴弦。", "稍知東里能堪事，一任神龍鬬洧淵。"]'),
('b908751b-6194-4b83-b67a-a7dbc8f2ed97','閏月九日','呂本中','宋','宋诗','song-poetry','','[]','疏林渺渺下新霜，留得黄花小檻香。',32,'全唐诗/poet.song.92000.json','["疏林渺渺下新霜，留得黄花小檻香。", "莫道窮秋少風味，一時頓有兩重陽。"]'),
('4b6efb17-5ddc-44d2-bb6d-1692fa0ad5d5','惡木','呂本中','宋','宋诗','song-poetry','','[]','惡木不忍伐，留我窻戶前。',168,'全唐诗/poet.song.92000.json','["惡木不忍伐，留我窻戶前。", "人皆笑我拙，我獨爲汝賢。", "共生天地間，誰不願長年。", "如何枝葉內，便縱斤斧穿。", "人或甚於斯，同被恩愛纏。", "燕昭與漢武，所享固已偏。", "樂極未肯休，更欲求神仙。", "孰能以此心，擴爲無盡泉。", "大哉周文王，尚結枯胔緣。", "傷生有禁止，亦具月令篇。", "好木雖云好，不須公愛憐。", "惡木雖云惡，莫自生讎冤。", "歲晏霜雪穩，夏深雷雨顛。", "扶疏有震落，與公常晏然。"]'),
('bfe14422-6649-4bf3-a7af-1aa35fa3e232','江上二首  其一','呂本中','宋','宋诗','song-poetry','','[]','南山稍疏闊，病眼不能明。',48,'全唐诗/poet.song.92000.json','["南山稍疏闊，病眼不能明。", "月挾清霜下，風隨細浪行。", "未蒙青鳥信，虛負白鷗盟。", "不見臺城路，年年春草生。"]'),
('6f907624-7771-4bf9-bd2c-70b5bd9c4515','江上二首  其二','呂本中','宋','宋诗','song-poetry','','[]','甚欲從此去，作煩渠未休。',48,'全唐诗/poet.song.92000.json','["甚欲從此去，作煩渠未休。", "風期竹萬箇，活業橘千頭。", "漢水覓二老，青門尋故侯。", "情知作寒士，不解殺袁劉。"]'),
('97b6c18f-a5d7-403c-a3b1-55d89d3456f7','寄外弟蔡明善','呂本中','宋','宋诗','song-poetry','','[]','相見還須未白頭，只今君是富春秋。',64,'全唐诗/poet.song.92000.json','["相見還須未白頭，只今君是富春秋。", "鶯花與夢飛騰去，甲子如川日夜流。", "白酒可澆千卷讀，青山欲喚十年愁。", "無因早辦歸耕計，更就深公買沃洲。"]'),
('bf867a01-a12e-46bf-9e3b-7ceb5a6d3db6','秋夜','呂本中','宋','宋诗','song-poetry','','[]','鳴鳩喚雨入西樓，草樹蟲聲旋作秋。',64,'全唐诗/poet.song.92000.json','["鳴鳩喚雨入西樓，草樹蟲聲旋作秋。", "明月自如常夜好，晚山仍發去年愁。", "久拋詩酒尋思去，勝與兒童作隊遊。", "辜負禪心多少事，石城看渡木蘭舟。"]'),
('4192a440-0002-427e-8718-3206c4f00688','蛇','呂本中','宋','宋诗','song-poetry','','[]','山雲樓起風旋磨，百毒乘陰出相賀。',96,'全唐诗/poet.song.92000.json','["山雲樓起風旋磨，百毒乘陰出相賀。", "中庭夜夜蛇作堆，草堂病夫愁欲破。", "時須兵子設符呪，更遣貍奴旁坐臥。", "雖非當道白帝子，恐是多年老書佐。", "蛟龍變化未可量，草莽連崗足逋播。", "農夫催租正苦辛，莫向零陵作奇貨。"]'),
('5e64c977-0ca2-49f3-8f24-9469b030b4dc','謝新酒螃蟹','呂本中','宋','宋诗','song-poetry','','[]','提壺滿送小槽春，尖團未霜亦可人。',32,'全唐诗/poet.song.92000.json','["提壺滿送小槽春，尖團未霜亦可人。", "略借畢郎左右手，爲公一洗庾公塵。"]'),
('92409357-90fd-4dd4-bf4e-443303914fd0','寄諸子','呂本中','宋','宋诗','song-poetry','','[]','南國旱愈甚，西郊雨復休。',48,'全唐诗/poet.song.92000.json','["南國旱愈甚，西郊雨復休。", "蠅蛆作殘暑，蛙黽鬬清秋。", "草暗黄沙盡，風吹白日愁。", "祇應有相憶，時倚仲宣樓。"]'),
('3b8bbd14-905e-4e09-a20e-47ef4e12a516','湘水','呂本中','宋','宋诗','song-poetry','','[]','湘水一番竹，下有千畝陰。',24,'全唐诗/poet.song.92000.json','["湘水一番竹，下有千畝陰。", "寧知竹上淚，是妾一生心。"]'),
('b8190d5a-51f4-4fd8-b54d-1647066f01f9','頃與知止相別於曹州西門外蓋今十四年矣聞嘗自澶淵過此感嘆','呂本中','宋','宋诗','song-poetry','','[]','昔別是茲土，今游還偶然。',48,'全唐诗/poet.song.92000.json','["昔別是茲土，今游還偶然。", "似聞嘗少憩，猶自未真傳。", "所過有陳跡，相逢多少年。", "長涂守病馬，何敢更爭先。"]'),
('59754b4b-009d-4f74-8569-ce400b45ca0e','雙廟','呂本中','宋','宋诗','song-poetry','','[]','唐四葉孫德下衰，久厭坐穩思奔馳。',216,'全唐诗/poet.song.92000.json','["唐四葉孫德下衰，久厭坐穩思奔馳。", "外由驕胡內艷妻，楊李氣燄相奪移。", "太宗之業甚整齊，爾曹忽來撞㨋之。", "旁人爲之掩涕悲，處之甚安渠不疑。", "賊風忽來吹白陂，翠輿走避彎弓追。", "倒立卻視千熊羆，猛將不解河北圍。", "睢陽失守東南危，城中月餘析骨炊。", "兩公奮髯死不回，鼎鑊在前惟恐遲。", "蜀中消息未可期，此輩未易折箠笞。", "念公不量勢力微，本自不辱國士知。", "大廈又非一木支，何必感慨如此爲。", "往時開元全盛時，公胡不念鱸魚歸，亦不往吊湘江纍。", "死後聲名何足奇，商山老人吾所歸。"]'),
('b098af10-c02e-4d5e-b89b-8a7227fff41e','歸自成園','呂本中','宋','宋诗','song-poetry','','[]','新春今幾時，忽有簷外朵。',120,'全唐诗/poet.song.92000.json','["新春今幾時，忽有簷外朵。", "病眼久不明，念此歲月頗。", "橋南數畝園，風雨與關鎖。", "主人厭敲門，荆棘生道左。", "還家續殘章，妙句仍帖妥。", "雖無鑪錘工，亦有盤礴臝。", "歸帆渺江湖，宿疾眩風火。", "扶犁伴老農，此語當自我。", "君看鄉閭鬬，則有閉戶可。", "慎無學春蠶，作繭自纏裹。"]'),
('2d652d31-fe68-45fc-b264-108b36654558','與諸舍弟游董村','呂本中','宋','宋诗','song-poetry','','[]','來往無十里，頗能妨晝眠。',48,'全唐诗/poet.song.92000.json','["來往無十里，頗能妨晝眠。", "疏籬董村水，遠樹洛城煙。", "酒薄詩牽強，身閑病接連。", "荒田點殘雪，知在甬山前。"]'),
('17dcd76b-ccb0-4ee0-b230-3439c87699ea','見信民舊書有感','呂本中','宋','宋诗','song-poetry','','[]','蝸涏狼籍閣殘書，仿佛黄公舊酒壚。',32,'全唐诗/poet.song.92000.json','["蝸涏狼籍閣殘書，仿佛黄公舊酒壚。", "試問東山謝安石，不知能似此人無。"]'),
('06be0d2e-24d0-49cd-80bc-d92d83470456','同叔用宿子之家','呂本中','宋','宋诗','song-poetry','','[]','老足交親薄，江晁爾獨賢。',48,'全唐诗/poet.song.92000.json','["老足交親薄，江晁爾獨賢。", "文章未遽絕，歲月成堪憐。", "薄酒寧非道，寒灰卻會禪。", "猶須五湖口，風雨夜同船。"]'),
('4d3f0381-7287-44d2-9b84-192b8bf93618','游西池歸','呂本中','宋','宋诗','song-poetry','','[]','偶爲池上游，入郭天尚早。',60,'全唐诗/poet.song.92000.json','["偶爲池上游，入郭天尚早。", "香塵入晚霧，柳色映馳道。", "我馬亦未疲，歸路貪月好。", "還舍了無事，百念紛未掃。", "近店酒可沽，重當爲君討。"]'),
('da6f70cd-f1a0-463a-9796-74d17f1e3c2b','出順天門歸陽翟二首  其一','呂本中','宋','宋诗','song-poetry','','[]','遲明出都城，夾路多柳色。',96,'全唐诗/poet.song.92000.json','["遲明出都城，夾路多柳色。", "行人半歌哭，莽不見阡陌。", "西池已春晚，我復道里迫。", "枯田甚渴雨，久作龜兆拆。", "屢遭人馬饑，更悟坡壠隔。", "微官戀升斗，恐負朋友責。", "初無秦楚遇，亦有陳蔡厄。", "沉憂能傷人，今汝頭已白。"]'),
('226bdd46-a3ab-4f3e-a5d5-eb900c331eb9','出順天門歸陽翟二首  其二','呂本中','宋','宋诗','song-poetry','','[]','淵明在柴桑，意亦憚遠役。',96,'全唐诗/poet.song.92000.json','["淵明在柴桑，意亦憚遠役。", "豈無好事人，助子了耕植。", "還家賦歸來，破自悔平昔。", "向時經由地，風雨晦行跡。", "欣然倚南窗，謂此可容膝。", "孰知劉檀輩，生有五鼎食。", "流風未遽遠，此士真有力。", "傷哉謝太傅，辛苦至折屐。"]'),
('a37d36f2-d1b5-4099-8168-b7dcc9267430','新鄭路中','呂本中','宋','宋诗','song-poetry','','[]','柳絮飛時與君別，南樓把酒看新月。',110,'全唐诗/poet.song.92000.json','["柳絮飛時與君別，南樓把酒看新月。", "月似當年離別時，柳絮隨君何處飛。", "落花寂寂長安路，陌上十人九人去。", "準擬歸鴻寄得書，回頭已失秦州樹。", "丈夫薄情多可念，爾獨何心守貧賤。", "勸君以金屈卮，贈君以長短歌。", "城南城北春草多，明月如此奈愁何。"]'),
('06694f6b-7f06-4ed3-a052-1a39d4fe172f','離新鄭','呂本中','宋','宋诗','song-poetry','','[]','荒村更柳色，節物近清明。',48,'全唐诗/poet.song.92000.json','["荒村更柳色，節物近清明。", "去國三年恨，還家一日程。", "故人投曉別，驘馬傍山行。", "何事逢寒食，春來苦要餳。"]'),
('76c8f415-6f0b-4ca2-96b2-71dd61371f08','宿潁昌范氏水閣','呂本中','宋','宋诗','song-poetry','','[]','溪流淺無聲，月色初到竹。',132,'全唐诗/poet.song.92000.json','["溪流淺無聲，月色初到竹。", "主人中夜歸，客子睡已熟。", "向來湖海興，歲事方窘束。", "云何蟋蟀歌，更自傷局促。", "相尋覓舊約，見子故未足。", "翛然解衣臥，高枕被數幅。", "賢哉五年別，有此一室獨。", "我鬚日已白，子髪良未禿。", "尚懷平生歡，歌呼聲徹屋。", "何須豕腹脹，更伴狗尾續。", "明朝尋故人，戲語公一讀。"]'),
('1981751f-feb0-4f72-b114-ea0a3e404c90','聞南寇已平歡快之甚作詩五十韻','呂本中','宋','宋诗','song-poetry','','[]','日月開南極，山河拱上都。',288,'全唐诗/poet.song.92000.json','["日月開南極，山河拱上都。", "聖朝頻決勝，賊黨莫狂圖。", "驛道傳烽燧，官軍下舳艫。", "弄兵心已壯，渫血氣猶粗。", "臘月杭州破，驩聲歙縣屠。", "跡雖連勁越，勢欲動全吳。", "劍戟排空上，芻糧夾路輸。", "予方在衰杖，意不保頭顱。", "豈謂除關傳，都非驗漢符。", "坐看前乘沒，誰救左輪朱。", "守將仍安枕，鄉豪肯棄軀。", "百川歸巨浸，一命仰洪鑪。", "撫事思同輩，低頭失壯夫。", "風雷蟄龍臥，名字列仙臞。", "遇寇來淮口，迎家傍海隅。", "未隨霜雪死，甘伴甲裳趨。", "每有妻孥問，寧知道里虞。", "荒城補泥土，旱水著菰蒲。", "交友多流寓，人煙乍有無。", "相逢可慟哭，掩淚只長吁。", "羽檄跡鋒數，江船取路迂。", "艱難脫紛擾，潤澤到焦枯。", "屢辱分金送，兼容折簡呼。", "同群見鸑鷟，猛獸伏於菟。"]'),
('9ed1ed2a-eaf5-48ed-b491-c98f7fe6a9e8','還韓城三首  其一','呂本中','宋','宋诗','song-poetry','','[]','乍喜全家脫，虛疑匹馬奔。',48,'全唐诗/poet.song.92000.json','["乍喜全家脫，虛疑匹馬奔。", "乾坤德甚大，盜賊爾猶存。", "稻壠秋仍旱，溪流晚自渾。", "素冠兼白髪，愁絕更誰論。"]'),
('fd8a4f36-9ef5-4fb0-979f-d546308647e2','還韓城三首  其二','呂本中','宋','宋诗','song-poetry','','[]','老有幽禪着，窮知俗事疏。',48,'全唐诗/poet.song.92000.json','["老有幽禪着，窮知俗事疏。", "漸諳深屋病，無復故人書。", "日月馳驅後，江山疾病餘。", "新涼有佳句，端爲述離居。"]'),
('ecb854d7-1ba6-4433-95df-51dc8fbdefcb','還韓城三首  其三','呂本中','宋','宋诗','song-poetry','','[]','讀易初無說，言詩既有功。',48,'全唐诗/poet.song.92000.json','["讀易初無說，言詩既有功。", "客游千里異，心事一尊同。", "藥裹難休老，經函可御窮。", "江淮足知遇，耆舊憶徐公。"]'),
('98133ca4-fd40-426f-9312-186dd43b32cf','秋日至孟明莊','呂本中','宋','宋诗','song-poetry','','[]','野色幽花靜有餘，好山雖近不同途。',65,'全唐诗/poet.song.92000.json','["野色幽花靜有餘，好山雖近不同途。", "荒村被雨泥三日，草具留僧飯一盂。", "斷壠入秋頻放水，老農垂手怕催租。", "平生粗識田園興，更復何幅度可曳裾。"]'),
('2ce85212-02d8-4595-8861-b2ec78b507e0','韓城紀事五首  其一','呂本中','宋','宋诗','song-poetry','','[]','老恥爲儒不學禪，還家常欠買山錢。',32,'全唐诗/poet.song.92000.json','["老恥爲儒不學禪，還家常欠買山錢。", "成州太守憐衰病，時有書來說太玄。"]'),
('1bff5cde-d7e3-40e6-a3cf-4762eac30cee','韓城紀事五首  其二','呂本中','宋','宋诗','song-poetry','','[]','糠豆猶慳不到盤，小兒寒至尚衣單。',32,'全唐诗/poet.song.92000.json','["糠豆猶慳不到盤，小兒寒至尚衣單。", "雖無事業傳惇史，或有聲名託稗官。"]'),
('affb276f-8e39-4642-b7a6-053db56aed72','韓城紀事五首  其三','呂本中','宋','宋诗','song-poetry','','[]','穩看飛蟲着網黏，爐香欲盡不須添。',32,'全唐诗/poet.song.92000.json','["穩看飛蟲着網黏，爐香欲盡不須添。", "未嫌禿頂如壺赤，何處香醪似蜜甜。"]'),
('aae69057-e0f9-4b44-ba3b-f24982709f60','韓城紀事五首  其四','呂本中','宋','宋诗','song-poetry','','[]','病來每有爲僧興，老去初無涉世心。',32,'全唐诗/poet.song.92000.json','["病來每有爲僧興，老去初無涉世心。", "它日三江五湖口，斷雲寒水有知音。"]'),
('752d57ab-f956-4eca-a510-7030d0e1b10f','韓城紀事五首  其五','呂本中','宋','宋诗','song-poetry','','[]','老不謀身望子公，少年豪氣想元龍。',32,'全唐诗/poet.song.92000.json','["老不謀身望子公，少年豪氣想元龍。", "倚松菴下香嚴路，今日書來第一封。"]'),
('c794703d-39d0-435c-8213-3b6473e498b1','陽翟冬夜','呂本中','宋','宋诗','song-poetry','','[]','便往吾何敢，長閑力未能。',48,'全唐诗/poet.song.92000.json','["便往吾何敢，長閑力未能。", "寒爐夜篝火，急雪暗翻燈。", "喚客初無酒，敲門尚有僧。", "不嫌空四壁，相對倚枯藤。"]'),
('b489ce7d-323b-480d-b978-09747b36979a','孟明田舍','呂本中','宋','宋诗','song-poetry','','[]','未嫌衰病出無驢，尚喜冬來食有魚。',64,'全唐诗/poet.song.92000.json','["未嫌衰病出無驢，尚喜冬來食有魚。", "往事高低半枕夢，故人南北數行書。", "茅茨獨倚風霜下，粳稻微收雁鶩餘。", "欲識淵明只公是，爾來吾亦愛吾廬。"]'),
('9fbf2c51-3198-403e-84e3-d4e1fa065ddc','雪後','呂本中','宋','宋诗','song-poetry','','[]','謾遣兒童掃雪開，卻穿籬落看春回。',64,'全唐诗/poet.song.92000.json','["謾遣兒童掃雪開，卻穿籬落看春回。", "溪山冷淡泥三尺，故舊飄零酒一杯。", "近買芒鞋供踏雨，更收藜杖與尋梅。", "玉川老去生涯在，時有鄰僧送米來。"]'),
('c42ad596-0803-4810-a1b5-cd1316a1fff7','宿田舍','呂本中','宋','宋诗','song-poetry','','[]','饑腸不貯酒，凍粟自生膚。',48,'全唐诗/poet.song.92000.json','["饑腸不貯酒，凍粟自生膚。", "旅枕三年夢，荒村一事無。", "不愁風折木，時有火添爐。", "尚想崔夫子，冬來體更臞。"]'),
('ce3c8306-fa28-4963-a281-bd760b07261d','除日','呂本中','宋','宋诗','song-poetry','','[]','我食已併日，子來能隔年。',48,'全唐诗/poet.song.92000.json','["我食已併日，子來能隔年。", "溪山出城路，風雪探梅天。", "納息初聞妙，繙經舊有緣。", "相陪得清坐，不敢嘆無氈。"]'),
('bdba27fb-3cb7-4a72-9aa0-7b13778ae693','將遊嵩少題石淙','呂本中','宋','宋诗','song-poetry','','[]','南山吐雲柳絮飛，北山之外煙草微。',144,'全唐诗/poet.song.92000.json','["南山吐雲柳絮飛，北山之外煙草微。", "南山北山日在眼，問公此去何時歸。", "石淙山水更奇絕，水怒決石山崩摧。", "長空無聲曉色靜，忽聽萬壑懸驚雷。", "珊瑚缺折玉破碎，月落倒卷從天回。", "中流險絕不須道，笑侮灧澦憐離堆。", "平生好事心突兀，時於圖畫見仿佛。", "褰衣度水公莫畏，何須苦避蛟龍窟。", "明朝更作嵩少遊，五更絕頂看日出。"]'),
('b1e911a3-949b-4a0a-8724-a943c73a1b24','登太室絕頂','呂本中','宋','宋诗','song-poetry','','[]','生平仰嵩丘，今日上絕頂。',168,'全唐诗/poet.song.92000.json','["生平仰嵩丘，今日上絕頂。", "蒼天不能高，星斗閟光景。", "風雲乍起伏，雷雨半蘇醒。", "下看飛鳥背，錯亂松柏影。", "神龍不深遁，偃蹇臥半嶺。", "舊聞飛石鬬，不受懸瀑梗。", "大河東北流，渺渺黄數頃。", "五更看日出，平地湧金餅。", "誰能啜其華，夜氣初未冷。", "諸峰環而立，一一皆秀整。", "中居此丈夫，衆象不得騁。", "巍然萬物表，獨閱百代永。", "同來有奇士，可得一笑領。", "不用貯微言，區區吊箕潁。"]'),
('73bb28e8-764f-4bae-89b3-bf06bbd9d81d','與崔德符田元邈別後奉寄','呂本中','宋','宋诗','song-poetry','','[]','處僻猶多事，陪公得暫閑。',48,'全唐诗/poet.song.92000.json','["處僻猶多事，陪公得暫閑。", "直緣怕酒去，不爲憶家還。", "苦語知無策，微官直強顔。", "高城更南望，林斷有青山。"]'),
('12f7108d-fb6e-4d6f-a5a8-2f43c98684ab','出遊','呂本中','宋','宋诗','song-poetry','','[]','日日春濃病不知，偶游僧寺送春歸。',64,'全唐诗/poet.song.92000.json','["日日春濃病不知，偶游僧寺送春歸。", "長年誤跨將軍馬，漸老空悲游子衣。", "山路有泥知雨過，村場無酒驗人稀。", "今秋定作江東計，趁得鱸魚八月肥。"]'),
('b081ccbd-13a7-42d3-961f-3419a85357d4','董村歸路馬上口占','呂本中','宋','宋诗','song-poetry','','[]','水聲高下竹回環，薄酒無功不耐寒。',32,'全唐诗/poet.song.92000.json','["水聲高下竹回環，薄酒無功不耐寒。", "白塔忽從林外出，青山常在馬頭看。"]'),
('78fa73e1-d1cf-4e39-8033-32027e7c176e','嘲拄杖','呂本中','宋','宋诗','song-poetry','','[]','王郎贈我桄榔杖，三歲庵中伴我閑。',32,'全唐诗/poet.song.92000.json','["王郎贈我桄榔杖，三歲庵中伴我閑。", "只爲嬾行常靠壁，不能隨我過嵩山。"]'),
('f7598742-19b2-404b-8d32-29159f295e7a','朮煎','呂本中','宋','宋诗','song-poetry','','[]','斷苗取靈根，斸石不到土。',120,'全唐诗/poet.song.92000.json','["斷苗取靈根，斸石不到土。", "道人掃落葉，閉戶手自煮。", "晴煙溜窗几，初夜過風雨。", "老盆酌天醴，春罋發膏乳。", "檐囊到城市，餽我一勺許。", "中年血氣敗，今我飲此醑。", "色如膠飴重，味有荷心苦。", "京城舊交游，臡醢亂鼎俎。", "誰能供此飲，遠視鴻鵠舉。", "一洗肝肺塵，但嚥公勿吐。"]'),
('6ed8526f-baf3-4075-bbf9-7b6e24b930d3','有客','呂本中','宋','宋诗','song-poetry','','[]','燥硯渴水不濡筆，濁酒欠錢長臥瓶。',64,'全唐诗/poet.song.92000.json','["燥硯渴水不濡筆，濁酒欠錢長臥瓶。", "此中定自有佳處，紙帳蒲團增眼明。", "故人江南江北岸，千書不如一見面。", "人生歡會不可常，畫梁已送西飛燕。"]'),
('80f2901d-b49e-4011-9997-5e0c799a2a2f','李文若季敵訪余高安留連累日臨行贈之','呂本中','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','十年奔走風塵中，學殖不進身愈窮。',208,'全唐诗/poet.song.92000.json','["十年奔走風塵中，學殖不進身愈窮。", "夢斷江南不得往，坐嘆歲月如驚鴻。", "君家政當匡廬路，時有僧行附書去。", "每念君家草堂好，便欲移家就君住。", "當時氣象已參差，今日情懷況遲暮。", "斯文未喪欲誰託，交游十人九不樂。", "百川東下障狂瀾，伯兄嶷然如斷山。", "蒼蒼在上久無意，空使妙句留人間。", "兩季只今名籍籍，北方人士所未識。", "未歇中原胡馬塵，且喜沙頭風浪息。", "高安相遇一長吟，盛夏苦雨成淫霖。", "顧我無能甘畎畝，如君豈合在山林。", "豫章老矣棟梁在，莫厭它時斤斧尋。"]'),
('5829d019-2afe-4046-ba24-4074058139cd','木芙蓉','呂本中','宋','宋诗','song-poetry','','[]','小池南畔木芙蓉，雨後霜前著意紅。',32,'全唐诗/poet.song.92000.json','["小池南畔木芙蓉，雨後霜前著意紅。", "猶勝無言舊桃李，一生開落任東風。"]'),
('86bd9f72-715b-4638-b7d2-2e232fc2c753','食筍','呂本中','宋','宋诗','song-poetry','','[]','窮鄉未寂寥，五月富筍茁。',120,'全唐诗/poet.song.92000.json','["窮鄉未寂寥，五月富筍茁。", "近山新得雨，此物晚亦發。", "初看數寸出，意有千尺抜。", "長條不成鞭，乃以美見伐。", "錦綳罷駢頭，玉指已不襪。", "坐令藜藿口，如受滫瀡滑。", "連年江海病，未免魚蟹罰。", "甘津到齒頰，恐此或未察。", "居閑快一飽，我已久斷殺。", "更莫厭比隣，時時聽羮戛。"]'),
('2fd11bef-f310-4932-800a-d077df55d85c','白鬚','呂本中','宋','宋诗','song-poetry','','[]','不作韓城住，虛爲河朔行。',24,'全唐诗/poet.song.92000.json','["不作韓城住，虛爲河朔行。", "白鬚鑷更出，知爲阿誰生。"]'),
('596ffbe2-8af4-4c50-8747-ad9d87eeee65','宿劉固寺佛殿下即劉伶墳也','呂本中','宋','宋诗','song-poetry','','[]','劉伶墳上土，佛殿古崔嵬。',48,'全唐诗/poet.song.92000.json','["劉伶墳上土，佛殿古崔嵬。", "坐久野僧出，天寒饑雁來。", "千年醉裏魄，一臿死前灰。", "未盡先生意，空留數字回。"]'),
('ea2ca86d-76b1-4fac-b84c-6ecb7d2fa96c','懷衛道中寄京師諸友三首  其一','呂本中','宋','宋诗','song-poetry','','[]','客舍冷如漿，客夢甘如飴。',72,'全唐诗/poet.song.92000.json','["客舍冷如漿，客夢甘如飴。", "初無遠行念，况有徂年悲。", "平生好交游，大半走路岐。", "不如亭前月，所到長相隨。", "何時脱身去，共採西山芝。", "有兒當似公，尚能傳我詩。"]'),
('33a25472-6dfa-41bb-8da3-779057dab5cc','懷衛道中寄京師諸友三首  其二','呂本中','宋','宋诗','song-poetry','','[]','直莫如兩王，清莫如兩方。',60,'全唐诗/poet.song.92000.json','["直莫如兩王，清莫如兩方。", "孫謝豈不美，久滯尚書郎。", "黎子老歸國，只今鬚髩蒼。", "邵子住山雲，欲出未肯忙。", "高子出林壑，坐看天際翔。"]'),
('2bbc92e7-4c9d-43c7-a146-eebdccc9df50','懷衛道中寄京師諸友三首  其三','呂本中','宋','宋诗','song-poetry','','[]','人誰不小康，李趙常窘束。',48,'全唐诗/poet.song.92000.json','["人誰不小康，李趙常窘束。", "窮閻爨温火，老未飽饘粥。", "它長未遽數，此事已絕俗。", "爲人死不厭，自奉一米足。"]'),
('4f2b4375-e6a6-46a7-a9ec-78df3392cf62','河堤','呂本中','宋','宋诗','song-poetry','','[]','平田接長河，眼界起突兀。',60,'全唐诗/poet.song.92000.json','["平田接長河，眼界起突兀。", "今日兹堤行，麥壠青已出。", "客行不知晚，但感此節物。", "新霜被西山，久厭塵土没。", "坐懷故人面，於此見仿佛。"]'),
('4922424b-fb07-4fa8-bef0-44332cafdc36','寄濬州張掞','呂本中','宋','宋诗','song-poetry','','[]','張卿留客酒如澠，我欲從之病不能。',32,'全唐诗/poet.song.92000.json','["張卿留客酒如澠，我欲從之病不能。", "憶過公家更東望，斷崖高樹雪層層。"]'),
('57ec5d39-7e8c-4af9-93b5-6c44a1a4efb0','田家樂','呂本中','宋','宋诗','song-poetry','','[]','東家西家蠶上簇，南村北村麥白熟。',64,'全唐诗/poet.song.92000.json','["東家西家蠶上簇，南村北村麥白熟。", "小兒腰鎌日早歸，大兒去就田間宿。", "斗酒相邀不爲薄，鄰翁相對且斟酌。", "聖主當陽億萬年，年年歲歲田家樂。"]'),
('89a7b24d-a270-472e-937f-a6deeb7ea9da','梅','呂本中','宋','宋诗','song-poetry','','[]','獨自不爭春，都無一點塵。',24,'全唐诗/poet.song.92000.json','["獨自不爭春，都無一點塵。", "忍將冰雪面，所至媚游人。"]'),
('6133c0a5-dd88-48c6-9827-70a690e2d8df','寄崔德符','呂本中','宋','宋诗','song-poetry','','[]','江城昔還往，耆舊各能文。',48,'全唐诗/poet.song.92000.json','["江城昔還往，耆舊各能文。", "暫别猶相憶，雖忙亦見存。", "好詩能愈疾，濁酒不勝渾。", "它日經行地，相尋夜叩門。"]'),
('6c0fa0c8-c643-4411-82d3-1321b6ef1561','還家','呂本中','宋','宋诗','song-poetry','','[]','解鞍歇馬倦西游，過眼文書且罷休。',64,'全唐诗/poet.song.92000.json','["解鞍歇馬倦西游，過眼文書且罷休。", "薄酒向人殊有味，長年於世已無求。", "常情未語溝中木，俗眼能驚海上鷗。", "何處雲山不堪隱，更誰辛苦訪菟裘。"]'),
('c77ffcb6-e778-46b7-a128-a64906ea3a4f','即事','呂本中','宋','宋诗','song-poetry','','[]','晚菘早韭老不厭，夜鯉晨鳬多見疏。',64,'全唐诗/poet.song.92000.json','["晚菘早韭老不厭，夜鯉晨鳬多見疏。", "地僻難尋野僧飯，路長時枉故人車。", "青山出没塵埃裏，白髮栽培疾病餘。", "更有腐儒窮事業，夜窗殘燭一編書。"]'),
('1a1b057b-1c33-4fd3-bf91-42d140f1ba76','讀易','呂本中','宋','宋诗','song-poetry','','[]','春温瘡疥繁，衣敝蟣蝨細。',156,'全唐诗/poet.song.92000.json','["春温瘡疥繁，衣敝蟣蝨細。", "頹然坐南軒，讀易初有味。", "初看象數殊，忽此爻彖異。", "紛紛者衆說，行各半途滯。", "大言累千百，雜說記一二。", "坐令天人分，復以小大計。", "或強出枝葉，或自起旒贅。", "孰能言語表，能使意獨至。", "空中本無華，眼病因有翳。", "沈思忽有得，是則入精義。", "吾生晚聞道，歲月今少憩。", "遺經日在眼，似足了一世。", "臨流濯垢衣，尚勿惜餘棄。"]'),
('fc5b7778-3979-49e8-891b-459a330f42e4','復往大名三首  其一','呂本中','宋','宋诗','song-poetry','','[]','復往真無策，兹行亦漫游。',48,'全唐诗/poet.song.92000.json','["復往真無策，兹行亦漫游。", "塵埃走劇暑，風雨占新秋。", "便欲還家去，其誰爲汝謀。", "尚憐蘇季子，虛敝黒貂裘。"]'),
('ee1842e4-4265-4cb9-9517-fbed554976da','復往大名三首  其二','呂本中','宋','宋诗','song-poetry','','[]','我老不自得，每爲饑所驅。',48,'全唐诗/poet.song.92000.json','["我老不自得，每爲饑所驅。", "漫抛青箬笠，空負白髭鬚。", "見賊猶堪鬬，逢人莫問途。", "寰區足秀句，山澤有臞儒。"]'),
('33e77994-7f9c-4be1-8421-d03003feab1e','復往大名三首  其三','呂本中','宋','宋诗','song-poetry','','[]','地濕頻經水，田荒亦未收。',48,'全唐诗/poet.song.92000.json','["地濕頻經水，田荒亦未收。", "斷雲催雨過，漲水没橋流。", "半世想高卧，十年悲遠游。", "藜羮不用挾，尚足誑饑喉。"]'),
('b55d08b8-50cf-4abd-b9f9-ff00dff23834','聞德道中','呂本中','宋','宋诗','song-poetry','','[]','五更發荒村，小憩草市北。',96,'全唐诗/poet.song.92000.json','["五更發荒村，小憩草市北。", "披衣度積水，月落天正黒。", "豆苗半委地，野父厭匍匐。", "我馬則已饑，泥土汚羈勒。", "翻思在家時，一飯亦假貣。", "小兒不解事，笑語頗自得。", "一官走道路，此責久未塞。", "速行勿遲留，有手須擊賊。"]'),
('9034cac9-ca4e-451d-95dc-b63c3e91d87f','陽翟道中','呂本中','宋','宋诗','song-poetry','','[]','不爲傷離别，其如漸老何。',24,'全唐诗/poet.song.92000.json','["不爲傷離别，其如漸老何。", "秖應從此去，轉覺白鬚多。"]'),
('5210e250-5a04-4368-adb9-3726018dd3ae','長葛道中遇周原仲','呂本中','宋','宋诗','song-poetry','','[]','羸馬衝寒驕不駛，積雪殘冰雜泥滓。',128,'全唐诗/poet.song.92000.json','["羸馬衝寒驕不駛，積雪殘冰雜泥滓。", "長葛縣中日落時，舉頭忽見周夫子。", "下馬相看兩驚怪，各喜南歸此身在。", "僧房夜語久不眠，更摩枵腹償詩債。", "子行四方尚謀食，我亦年來倦行役。", "櫪下驊騮世得知，海底珊瑚人未識。", "長安公卿富貴客，誰能日在子思側。", "洛陽年少未宜輕，看子重陳治安策。"]'),
('1e93b175-53f7-49f1-b023-a9935614e7e1','簡叔易益謙兄弟','呂本中','宋','宋诗','song-poetry','','[]','秋來歸興復何如，李范聲名更羨渠。',32,'全唐诗/poet.song.92000.json','["秋來歸興復何如，李范聲名更羨渠。", "它日買田吾有策，兩家兄弟要鄰居。"]'),
('5c22756b-59aa-4023-947f-5910b6da1af1','贈益謙兄弟','呂本中','宋','宋诗','song-poetry','','[]','范郎走微官，清固不絕俗。',156,'全唐诗/poet.song.92000.json','["范郎走微官，清固不絕俗。", "家常四壁立，腹有萬卷讀。", "邇來所爲文，深若泉萬斛。", "紆餘風過水，宛轉蟲注木。", "諸弟况可人，不但好眉目。", "丹穴固出鳳，藍田自宜玉。", "行扛九鼎重，頓使一世伏。", "聖朝急用士，如子尚窮獨。", "乃知德在躬，不必富潤屋。", "我病拙文詞，筆鈍如髮禿。", "時逢子兄弟，未語心已足。", "長空絕纖埃，何處著鳬鶩。", "朝來秋氣清，佇看飛鴻鵠。"]'),
('3de851cb-7eb9-4196-b684-60d438e5d880','題蘆雁扇','呂本中','宋','宋诗','song-poetry','','[]','雁下秋已晚，江天風雨微。',24,'全唐诗/poet.song.92000.json','["雁下秋已晚，江天風雨微。", "寧爲聚沙立，不作傍雲飛。"]'),
('04319981-2215-4c5f-80f7-87424be330fa','遊西宫有感','呂本中','宋','宋诗','song-poetry','','[]','種種不如意，悠悠無復聽。',72,'全唐诗/poet.song.92000.json','["種種不如意，悠悠無復聽。", "漫尋村路好，似得片時醒。", "水隱城坳白，山來樹杪青。", "晚田收襏襫，殘日度笭箵。", "興入山陰道，詩如歷下亭。", "荒原子胥廟，千載想儀刑。"]'),
('e4d05b39-a4f7-4678-8e34-61432c0f05af','送一書記果公作天寧化士','呂本中','宋','宋诗','song-poetry','','[]','田家得米輸官倉，一粒不得囊中藏。',64,'全唐诗/poet.song.92000.json','["田家得米輸官倉，一粒不得囊中藏。", "天寧化士去如雨，此亦未易能低昂。", "因官乞取民始病，况復妄邀檀越敬。", "縱令不得半錢歸，堂中聖僧應自知。"]'),
('5ae3c612-7680-4662-8568-2d560e1ed6ff','京城圍閉之初天氣晴和軍士乘城不以爲難也因成四韻','呂本中','宋','宋诗','song-poetry','','[]','賊馬侵城急，官軍報捷頻。',48,'全唐诗/poet.song.92000.json','["賊馬侵城急，官軍報捷頻。", "民心皆欲鬬，天意已如春。", "魏闕方佳氣，王畿且戰塵。", "不妨來往路，經月絕行人。"]'),
('582121bd-9447-4b0f-aa19-3ce62dad2543','守城士','呂本中','宋','宋诗','song-poetry','','[]','北風且莫雪，一雪三日寒。',108,'全唐诗/poet.song.92000.json','["北風且莫雪，一雪三日寒。", "不念守城士，歲晚衣裳單。", "衣單未爲苦，隔壕聞戰鼓。", "殺賊須長槍，防城要強弩。", "炮來大如席，城頭且撐柱。", "豈不知愛身，傾心報明主。", "報主此其時，一死吾亦宜。", "未敢望爵賞，且今無事歸。", "寄語守城士，此言君所知。"]'),
('ee507055-1fe9-4de4-8cd9-95f6510b1e5c','聞軍士求戰甚力作詩勉之','呂本中','宋','宋诗','song-poetry','','[]','今春賊來時，軍士怖而走。',84,'全唐诗/poet.song.92000.json','["今春賊來時，軍士怖而走。", "今冬賊來時，決拾揎兩肘。", "憤然思出鬬，不但要死守。", "仰懷吾君仁，愈覺戎虜醜。", "欲以占天心，於焉卜長久。", "暫勞何足道，富貴要力取。", "行看斬賊頭，金印大如斗。"]'),
('9a14147c-87aa-4865-93ae-0e3c2762bfb6','丁未二月上旬四首  其一','呂本中','宋','宋诗','song-poetry','','[]','丞相憂宗及，編氓恐禍延。',48,'全唐诗/poet.song.92000.json','["丞相憂宗及，編氓恐禍延。", "乾坤正反覆，河洛擾戈鋋。", "報主悲無術，傷時秪自憐。", "遙知漢社稷，别有中興年。"]'),
('62ad0f51-e7e1-482d-984e-a0fc121c95d4','丁未二月上旬四首  其二','呂本中','宋','宋诗','song-poetry','','[]','厄運雖云極，羣公莫自疑。',48,'全唐诗/poet.song.92000.json','["厄運雖云極，羣公莫自疑。", "民心空有望，天道本無知。", "野帳留黄屋，青城插皂旗。", "燕雲舊耆老，寧識漢官儀。"]'),
('2ea3f2de-26be-4a58-8880-9131d447d701','丁未二月上旬四首  其三','呂本中','宋','宋诗','song-poetry','','[]','羽檄從天下，于今久未回。',48,'全唐诗/poet.song.92000.json','["羽檄從天下，于今久未回。", "如何半年內，不見一人來。", "周室仍遭變，宣王且遇災。", "猶存九廟在，咫尺得祈哀。"]'),
('63116dbf-9b1d-4237-8212-3914453b0342','丁未二月上旬四首  其四','呂本中','宋','宋诗','song-poetry','','[]','主辱臣當死，時危命亦輕。',48,'全唐诗/poet.song.92000.json','["主辱臣當死，時危命亦輕。", "謀吞豫讓炭，肯結仲由纓。", "灑血瞻行殿，傷心望虜營。", "尚留儀衛否，早晚復神京。"]'),
('050bb3e5-5a59-47f8-ae68-3af165f3feeb','兵亂寓小巷中作','呂本中','宋','宋诗','song-poetry','','[]','城北殺人聲徹天，城南放火夜燒船。',64,'全唐诗/poet.song.92000.json','["城北殺人聲徹天，城南放火夜燒船。", "江河夢斷不得往，問君此住何因緣。", "竄身窮巷米如玉，翁尋濕薪媪爨粥。", "明日開門雪到簷，隔墻更聽鄰家哭。"]'),
('f0ece7f9-72a5-4273-9828-053a67b7a2c4','圍城中故人多避寇在鄰巷者雪晴往訪問之坐語既久意亦暫適也','呂本中','宋','宋诗','song-poetry','','[]','雪泥春既融，曉日初破霧。',120,'全唐诗/poet.song.92000.json','["雪泥春既融，曉日初破霧。", "出門尋故人，來往不數步。", "共談江南勝，閉眼想去路。", "松風被茅屋，稻壠立白鷺。", "行看賊圍解，春水即可渡。", "先當上鍾山，次第入廬阜。", "生平泉石念，久受塵土汚。", "况今九死餘，轉覺處事悞。", "豫懷巖壑裏，所至陪杖屨。", "可行君莫辭，行李我已具。"]'),
('70b3d791-eb45-45e8-a024-91bba4476011','城中紀事','呂本中','宋','宋诗','song-poetry','','[]','生平足艱窘，可歎不可言。',216,'全唐诗/poet.song.92000.json','["生平足艱窘，可歎不可言。", "兩遭重城閉，再因羣盜奔。", "今兹所值遇，我豈不與聞。", "脱身保兒女，恐辜明主恩。", "傍徨不忍去，敢計生理存。", "昨者城破日，賊燒東郭門。", "中夜半天赤，所憂驚至尊。", "是日雪正作，疾風飄大雲。", "十室九經盜，巨家多見焚。", "至今馳道中，但行塞馬羣。", "翠華久不返，魏闕横烟氛。", "都人向天泣，欲語聲復吞。", "我病未即死，爾來春既分。", "剥床供晨炊，兩眼烟已昏。", "豈無好少年，可與共殊勲。", "志士或不恥，有身期報君。", "塞水須塞源，伐木須伐根。", "子莫笑短拙，荆蠻生伍員。"]'),
('7f6681bf-79ee-45e8-8c75-f51d5deaa2dd','讀易','呂本中','宋','宋诗','song-poetry','','[]','江北江南公不歸，人言公懶笑公痴。',32,'全唐诗/poet.song.92000.json','["江北江南公不歸，人言公懶笑公痴。", "閉門端坐讀周易，直過新春圍閉時。"]'),
('e62e2b37-9de1-48a2-951d-9c4c7fa9531d','無題','呂本中','宋','宋诗','song-poetry','','[]','胡虜安知鼎重輕，禍胎元是漢公卿。',32,'全唐诗/poet.song.92000.json','["胡虜安知鼎重輕，禍胎元是漢公卿。", "襄陽耆舊唯龐老，受禪碑中無姓名。"]'),
('a3a04473-7403-4962-a7ef-c1189a22bf9a','懷京師','呂本中','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','北風作霜秋已寒，長江浪生船去難。',96,'全唐诗/poet.song.92000.json','["北風作霜秋已寒，長江浪生船去難。", "客愁不斷若江水，朝思莫思在長安。", "長安城外高十丈，此地豈容胡馬傍。", "親見去年城破時，至今銕馬黄河上。", "小臣位下才則拙，有謀未獻空惆悵。", "漢家宗廟有神靈，但語胡兒莫狂蕩。"]'),
('10917cef-f520-4e9b-bf35-f9bb5dffff0c','讀司馬公集解大玄','呂本中','宋','宋诗','song-poetry','','[]','京城半年圍，道路三月病。',204,'全唐诗/poet.song.92000.json','["京城半年圍，道路三月病。", "輕舟過江來，所向復未定。", "客房夜涼冷，氣體亦粗勝。", "月穿窗罅白，風入桐葉勁。", "挑燈讀太玄，愛此頃刻靜。", "物數極三甲，此理本天命。", "首贊則分行，故未及世應。", "古曆漢則亡，易實更三聖。", "哀哉楊子雲，上與數子競。", "雖云耗心力，固自有捷徑。", "後來司馬公，獨斂衆說盛。", "錙銖判訛謬，一宗蒙是正。", "讀玄則知易，此實公所證。", "如何少年子，便欲獻譏評。", "我老未知學，讀此知不稱。", "掩卷坐搔首，一洗肝肺淨。", "明朝尋故人，此語殊未竟。"]'),
('7e48f580-8b54-49eb-b08f-5b25aacede65','黄池西阻風','呂本中','宋','宋诗','song-poetry','','[]','烏雲銜日日不出，驟雨飄風吼三日。',160,'全唐诗/poet.song.92000.json','["烏雲銜日日不出，驟雨飄風吼三日。", "扁舟寸步不得行，坐歎輕鷗如箭疾。", "我行去家秋復冬，故園回思春夢中。", "客愁茫茫若江水，生計渺渺隨征鴻。", "三年京城共憔悴，一杯此地難從容。", "長溪卷浪雪花碎，遠山横空眉黛濃。", "故人别我上江去，亦有書來喚同住。", "破屋數間君有餘，太倉五升吾已具。", "嚴霜未放鷹隼擊，盤渦恐致蛟龍怒。", "片帆欲挂任篙師，君但徐行莫深懼。"]'),
('523161df-2729-498d-afe7-603a207bdecb','景德北窗','呂本中','宋','宋诗','song-poetry','','[]','雲横樹陰濃，雨漲溪水白。',132,'全唐诗/poet.song.92000.json','["雲横樹陰濃，雨漲溪水白。", "故人喚我出，已度蒸暑厄。", "北窗非不佳，尚苦眼界窄。", "小樓隱床後，自與塵霧隔。", "更憐昭亭山，相向有佳色。", "君能具鷄黍，略不厭須索。", "我能知子窮，子亦能愛客。", "人生要如是，一舉乃諷百。", "我病思遠引，未塞交友責。", "便當約諸公，歸耕作長策。", "囊無一錢贏，歲晚會有獲。"]'),
('aaff003d-98b1-40a2-8292-57c17b2f900f','昭亭廣教寺','呂本中','宋','宋诗','song-poetry','','[]','故人喚我去，久雨值新晴。',48,'全唐诗/poet.song.92000.json','["故人喚我去，久雨值新晴。", "草暗鼯鼠出，山深鶗鴂鳴。", "齋廚半盂粥，草具一杯羮。", "尚肯頻來否，門前春筍生。"]'),
('6ff33e32-1f4a-47e1-bbbd-5846bf8caca3','昨日之熱一首贈趙彦強','呂本中','宋','宋诗','song-poetry','','[]','昨日之熱未爲熱，涼風頗隨團扇發。',192,'全唐诗/poet.song.92000.json','["昨日之熱未爲熱，涼風頗隨團扇發。", "今日之熱不可言，西山火炎塵障天。", "高樓堅坐若燔炙，常恐秋到無夤緣。", "與君相從今幾日，欲度一日如長年。", "憶昔京城值秋雨，人家邂逅得細語。", "不愁歸舍少薪米，且喜尊前好賓主。", "去年君自雲中歸，隔巷尋君相勞苦。", "是時強虜在城下，耳猶厭聽賊營鼓。", "豈知喪亂到江南，同向宣城過殘暑。", "晚來一雨天遂涼，便思約君來對床。", "床前適有新酒熟，君醉可舞吾能狂。", "醉中談天亦未妨，回船吳中君勿忙。"]'),
('2c19f263-421c-428c-8b96-47dd93a6add2','又贈','呂本中','宋','宋诗','song-poetry','','[]','日日住叠嶂，君能同此游。',48,'全唐诗/poet.song.92000.json','["日日住叠嶂，君能同此游。", "黑雲才映日，白雨忽穿樓。", "盜賊何時定，溪山且自幽。", "炎蒸不須厭，俄頃是新秋。"]'),
('01dfcd2e-7cc7-4378-9bcd-31ec6a417200','題涇縣水西','呂本中','宋','宋诗','song-poetry','','[]','江東住已厭，又却過江西。',48,'全唐诗/poet.song.92000.json','["江東住已厭，又却過江西。", "急雨投涇縣，窮秋渡賞溪。", "稻田猶少水，山路已多泥。", "珍重高僧意，求詩索自題。"]'),
('6c0a2409-de4a-4505-86da-359986a9bdca','宿秋霜閣後方丈','呂本中','宋','宋诗','song-poetry','','[]','秋霜閣後山屈蟠，行人衝泥脚未乾。',32,'全唐诗/poet.song.92000.json','["秋霜閣後山屈蟠，行人衝泥脚未乾。", "正是水西佳絕處，不辭風雨夜深寒。"]'),
('2d2a1ce9-8242-4c70-9d75-595ffcdabcb7','水西與李彦恢相從余將取旌德趨徽州彦恢先歸旌德相候彭元任亦自太平縣來相送遇於三溪驛遂同過旌德道中呈二子三首  其一','呂本中','宋','宋诗','song-poetry','','[]','水西投宿返秋霜，起聽晨鐘厭束裝。',32,'全唐诗/poet.song.92000.json','["水西投宿返秋霜，起聽晨鐘厭束裝。", "尚惜故人輕作别，亂山深處過重陽。"]'),
('31d3a701-eccc-4d21-982f-bd1d76a123db','水西與李彦恢相從余將取旌德趨徽州彦恢先歸旌德相候彭元任亦自太平縣來相送遇於三溪驛遂同過旌德道中呈二子三首  其二','呂本中','宋','宋诗','song-poetry','','[]','村場路僻多無酒，野菊寒深亦未花。',32,'全唐诗/poet.song.92000.json','["村場路僻多無酒，野菊寒深亦未花。", "底事中原歸不得，又扶衰病過天涯。"]'),
('d53c491d-a452-4f1b-9f6c-8f728c46fb58','水西與李彦恢相從余將取旌德趨徽州彦恢先歸旌德相候彭元任亦自太平縣來相送遇於三溪驛遂同過旌德道中呈二子三首  其三','呂本中','宋','宋诗','song-poetry','','[]','白頭嬾入少年場，二老追隨却味長。',32,'全唐诗/poet.song.92000.json','["白頭嬾入少年場，二老追隨却味長。", "預喜尊前聽清話，夜窗相對一爐香。"]'),
('70e62740-04f0-48ad-9f7c-f82b5ee935d2','休寧縣與汪致道諸公别後晚宿黟縣界魚亭驛二首  其一','呂本中','宋','宋诗','song-poetry','','[]','竹密如雲不見天，好山無數簇溪田。',32,'全唐诗/poet.song.92000.json','["竹密如雲不見天，好山無數簇溪田。", "秪應黟縣溪山勝，盡在魚亭驛舍前。"]'),
('d69cbb6c-3d04-4482-90e3-ce9b9832301a','休寧縣與汪致道諸公别後晚宿黟縣界魚亭驛二首  其二','呂本中','宋','宋诗','song-poetry','','[]','故人相繼别休寧，山路籃輿睡復醒。',32,'全唐诗/poet.song.92000.json','["故人相繼别休寧，山路籃輿睡復醒。", "所恨溪山正佳處，不能同我到魚亭。"]'),
('238adcd0-88b6-4067-be25-278d7ae89fe9','寄宣城故舊','呂本中','宋','宋诗','song-poetry','','[]','宣城經歲無它事，尚喜交游不棄遺。',64,'全唐诗/poet.song.92000.json','["宣城經歲無它事，尚喜交游不棄遺。", "疊嶂樓頭納涼處，宛陵堂下探梅時。", "君今尚要一囊粟，我去亦無三徑資。", "歸卧雲山更深處，因書頻報故人知。"]'),
('8b44dd81-a01f-45a5-b039-c06b69756957','祁門道中四首  其一','呂本中','宋','宋诗','song-poetry','','[]','去程歸雁兩悠悠，行到荒山儘上頭。',32,'全唐诗/poet.song.92000.json','["去程歸雁兩悠悠，行到荒山儘上頭。", "試問中原何處是，只言東些是宣州。"]'),
('b8d9612f-515c-4fcd-8d3d-757bb89bc783','祁門道中四首  其二','呂本中','宋','宋诗','song-poetry','','[]','風落千山雨夜鳴，時因歸夢識宣城。',32,'全唐诗/poet.song.92000.json','["風落千山雨夜鳴，時因歸夢識宣城。", "欲知溪路行多少，已過徽州第五程。"]'),
('8246cebc-7281-41a3-bb34-57249d2e07b2','祁門道中四首  其三','呂本中','宋','宋诗','song-poetry','','[]','宣城人物未全衰，四士風流世不知。',32,'全唐诗/poet.song.92000.json','["宣城人物未全衰，四士風流世不知。", "别後略無佳語寄，道中才有數篇詩。"]'),
('29ef9552-a0fc-4f61-84c8-4407142973a2','祁門道中四首  其四','呂本中','宋','宋诗','song-poetry','','[]','詹郎逸氣今誰似，李令清言久不聞。',32,'全唐诗/poet.song.92000.json','["詹郎逸氣今誰似，李令清言久不聞。", "獨立共傳摩詰後，隱居還見伯仁孫。"]'),
('ee81878c-6beb-47f3-9b9b-94ec17bf6d2e','桂林别珂首座二首  其一','呂本中','宋','宋诗','song-poetry','','[]','故人相望馬牛風，世事波濤滉漾中。',32,'全唐诗/poet.song.92000.json','["故人相望馬牛風，世事波濤滉漾中。", "灕水東邊兩年住，往還才有一珂公。"]'),
('af3f1f80-df9f-4266-a082-844b02fbf835','桂林别珂首座二首  其二','呂本中','宋','宋诗','song-poetry','','[]','北歸我已辦行纒，久約相從却未然。',32,'全唐诗/poet.song.92000.json','["北歸我已辦行纒，久約相從却未然。", "何處雲山堪著子，亂松回首嶺南天。"]'),
('b50e2600-707f-4a04-8444-79058cce080d','答趙祖文陳夢授','呂本中','宋','宋诗','song-poetry','','[]','嶺海畏深入，江湖成遠游。',48,'全唐诗/poet.song.92000.json','["嶺海畏深入，江湖成遠游。", "猶懷不活怖，少爲故人留。", "苦乏瓊琚報，虚蒙札翰投。", "因來問消息，不必計沈浮。"]'),
('d7872ad2-3f8b-45e9-a230-d4bbf8eb0a98','寄趙十一弟','呂本中','宋','宋诗','song-poetry','','[]','親朋雖近懶追尋，湖嶺歸來病至今。',32,'全唐诗/poet.song.92000.json','["親朋雖近懶追尋，湖嶺歸來病至今。", "寄語洪州趙從事，忍令無酒過冬深。"]'),
('538f8b0a-c745-4740-b9cb-96080b574ccd','浮梁道中見小松數寸者極多然皆與蓬蒿雜出不能即長也余傷之作詩寄范四弟','呂本中','宋','宋诗','song-poetry','','[]','青松數寸根，意出千丈外。',96,'全唐诗/poet.song.92000.json','["青松數寸根，意出千丈外。", "如何蓬蒿底，此志久未遂。", "朝爲牛羊踐，莫受塵土翳。", "雖云歲寒姿，當此亦憔悴。", "今年雖小出，尚與凡草類。", "會須扶其根，與作棟梁計。", "大厦千萬間，匠石所睥眤。", "世或未盡知，慎勿傷汝志。"]'),
('2e048f77-f4e6-4310-9686-0328bb70dac7','自祁門至進賢路中懷舊二絕  其一','呂本中','宋','宋诗','song-poetry','','[]','雨歇路逾滑，山空鳥不飛。',24,'全唐诗/poet.song.92000.json','["雨歇路逾滑，山空鳥不飛。", "却思無事日，騎馬踏泥歸。"]'),
('c6cbd7ae-3e7f-424b-9c89-6b60a0cadd28','自祁門至進賢路中懷舊二絕  其二','呂本中','宋','宋诗','song-poetry','','[]','汴水夾榆柳，今留胡馬蹤。',24,'全唐诗/poet.song.92000.json','["汴水夾榆柳，今留胡馬蹤。", "如何進賢路，只是見青松。"]'),
('cb6dd83a-fe70-4941-bd0a-83d7b8de9390','離洪州渡西江至翠微寺紫清宫','呂本中','宋','宋诗','song-poetry','','[]','平明渡西江，西山正崔嵬。',168,'全唐诗/poet.song.92000.json','["平明渡西江，西山正崔嵬。", "中流欲浪作，細雨隨風回。", "促櫂赴前浦，頗爲風雨催。", "寒沙引細路，人家山半隈。", "密雨蔭脩竹，久旱無莓苔。", "晚入翠微寺，諸峰環抱來。", "其西洪崖居，百代所仰懷。", "何年蛟龍怒，更擊深山開。", "懸瀑瀉洪井，噴噫藏風雷。", "客行少休息，暫此得徘徊。", "城中二三老，咫尺不得陪。", "豈無陵風翰，邀致山中臺。", "澗水清且寒，可以當餘杯。", "獨來不敢久，恐爲神物猜。"]'),
('91a026ef-b856-4094-8618-1cb08ca80dfd','宿翠微寺','呂本中','宋','宋诗','song-poetry','','[]','西山今夜雨，不爲故人留。',48,'全唐诗/poet.song.92000.json','["西山今夜雨，不爲故人留。", "泥滑淹行李，風聲欲送秋。", "中原且多事，吾黨敢無憂。", "明日經由地，江南更幾州。"]'),
('d7d1f685-ffbe-4c99-9efd-c38ab9432b3b','發翠微寺','呂本中','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','古殿突兀風有聲，粥魚欲打雞三鳴。',128,'全唐诗/poet.song.92000.json','["古殿突兀風有聲，粥魚欲打雞三鳴。", "披衣起坐問行李，僕夫屢報天陰晴。", "昨日路長頻雨阻，今日東風得無苦。", "杉松連山寒欲動，橘柚隔籬香半吐。", "却憶京城無事時，人家打酒夜深歸。", "醉裏不知妻子罵，醒後肯顧兒啼饑。", "如今流落長江上，所至盜賊猶旌旗。", "已憐吳縣風俗僻，况復中原消息稀。"]'),
('220dda8e-200f-42ec-ad10-f60bc24ef025','送宋仲安往虔州','呂本中','宋','宋诗','song-poetry','','[]','已流之水不可以復回，已往之日不可以復來。',150,'全唐诗/poet.song.92000.json','["已流之水不可以復回，已往之日不可以復來。", "唯有野外籬邊之黄菊，年年歲歲見花開。", "君如此菊不我厭，處處相逢同酒杯。", "三年喪亂那可說，君頭已白我齒缺。", "高才抑塞久未用，坐守松檜凌霜雪。", "君今又作章貢游，我猶少忍住筠州。", "破屋不憂遭鬼瞰，端坐或恐貽神羞。", "求田問舍古所歎，敢有遠去惟身謀。", "爲約嶺南三數子，明年乘興欲東流。"]'),
('b23b8c61-cd33-4b5e-b1b3-dcd19f4c57cb','與仲安别後奉寄','呂本中','宋','宋诗','song-poetry','','[]','出門送君時，一步再徘徊。',204,'全唐诗/poet.song.92000.json','["出門送君時，一步再徘徊。", "雖云非遠别，念與始謀乖。", "欲求連牆居，故作千里來。", "君今不我待，欲跨洪溝回。", "我獨滯一方，後會良未諧。", "冬初風浪息，蛟龍深蟄雷。", "其如中原盜，所至尚揚埃。", "子行莫夷猶，恐致狼虎猜。", "胡人更遠適，畏死投烟霾。", "皇天久助順，似不及吾儕。", "獨以智力免，寧有此理哉。", "因書寄苦語，亦以謝不才。", "新春好天色，指望妖氛開。", "即當候歸艎，取酒尋尊罍。", "欣然得一笑，便足禳千災。", "豫章百里遠，可以慰客懷。", "須君起我病，同上徐孺臺。"]'),
('e77a808d-9838-4f9b-8975-fecba077f6ee','題筠州僧房','呂本中','宋','宋诗','song-poetry','','[]','客來無語坐禪房，共賞西窗一榻涼。',64,'全唐诗/poet.song.92000.json','["客來無語坐禪房，共賞西窗一榻涼。", "山路雨餘新筍出，江城春色雜花香。", "烟廚已逐鐘聲遠，樹色初隨塔影長。", "敢道閑居便安稳，今年更欲下湖湘。"]'),
('90f59fc2-45f8-4697-a667-070a654e1d93','離筠州','呂本中','宋','宋诗','song-poetry','','[]','舊日閑居日，無悰已倦游。',48,'全唐诗/poet.song.92000.json','["舊日閑居日，無悰已倦游。", "如今避地走，不復爲山留。", "淮甸初經夏，江西復度秋。", "今朝小亭望，東北是筠州。"]'),
('38d1a045-3366-41f7-b8de-c26cc64323d0','題圜悟與惇兄法語','呂本中','宋','宋诗','song-poetry','','[]','杲公昔踏胡馬塵，城中草木凍不春。',64,'全唐诗/poet.song.92000.json','["杲公昔踏胡馬塵，城中草木凍不春。", "甲士却立不敢問，其誰從之惇上人。", "袖手歸來兩無語，如今且向江南住。", "雲居老人費精神，送向高安灘頭去。"]'),
('9b18676a-6ca8-4824-909c-9b1694cfd84e','建城道中','呂本中','宋','宋诗','song-poetry','','[]','建城南路入袁州，怪石縱横水亂流。',64,'全唐诗/poet.song.92000.json','["建城南路入袁州，怪石縱横水亂流。", "盡日衣冠在圖畫，百年心跡付林丘。", "中原未作重歸計，胡馬能令此地憂。", "浪跡江湖亦吾分，運籌帷幄有留侯。"]'),
('ec0d1b7f-f308-44ff-b378-5822e1354f2a','行至醴陵寄故人','呂本中','宋','宋诗','song-poetry','','[]','淺溪沙磧寒，月白樹影疏。',108,'全唐诗/poet.song.92000.json','["淺溪沙磧寒，月白樹影疏。", "我行天一角，所至尚躊躇。", "偶逢勝絕地，不異嵩潁居。", "臨流遂忘歸，黙坐數游魚。", "寧知胡馬閙，江縣已丘墟。", "故人亦未來，一旬三寄書。", "不必問淺深，但當膏子車。", "新霜隨北風，慘慘度重湖。", "相尋近五嶺，慎勿厭長途。"]'),
('d3185e89-2c46-4a95-9b68-b8af035ae34e','將至南嶽先寄演公禪師善公華嚴','呂本中','宋','宋诗','song-poetry','','["\u8861\u5c71"]','胡馬揚塵烽燧作，我行乃在天一角。',160,'全唐诗/poet.song.92000.json','["胡馬揚塵烽燧作，我行乃在天一角。", "江西趼足過湖南，本赴郴陽故人約。", "中途羣盜又蜂起，所至往往爲囊橐。", "遲回改路心自笑，隱忍畏事人所薄。", "不因此去渡湘水，更欲何時到南嶽。", "山中况有二老人，萬里同來且安樂。", "遙瞻見我應大笑，白鬚黒面都如昨。", "平生故舊幾人在，不早從公老丘壑。", "自經喪亂可過從，每一思之懷抱惡。", "請公更說因地初，一解人間因慧縛。"]'),
('c8cbe347-91f1-4a69-93c8-5e7691fd33ea','避寇南行','呂本中','宋','宋诗','song-poetry','','[]','何處田園不是家，儘扶衰病過天涯。',64,'全唐诗/poet.song.92000.json','["何處田園不是家，儘扶衰病過天涯。", "山村酒熟人人醉，客路春濃處處花。", "敢道嶺南無賊馬，側聞江左尚風沙。", "囊空甑倒君休笑，亦有新詩伴齒牙。"]'),
('c367d03c-1d7c-4bb0-89b6-8dca4ee473b6','貞女峽','呂本中','宋','宋诗','song-poetry','','[]','欲上貞女峽，江險未敢行。',96,'全唐诗/poet.song.92000.json','["欲上貞女峽，江險未敢行。", "豈是畏江險，愧此貞女名。", "時經喪亂後，世不聞堅貞。", "烈士久喪節，丈夫多敗盟。", "寧聞閨房秀，感義不偷生。", "窮荒禮法在，尚此留佳聲。", "時事有通塞，江流無濁清。", "欲行勿憚險，爲君先濯纓。"]'),
('0fbe9c80-72ca-4487-bbc4-9eed9f43b2f2','山水圖','呂本中','宋','宋诗','song-poetry','','[]','君家茅屋低蓬蒿，客來頗厭蛙蚓號。',144,'全唐诗/poet.song.92000.json','["君家茅屋低蓬蒿，客來頗厭蛙蚓號。", "何得有此山突兀，氣壓太華陵嵩高。", "坐看遠澗受懸瀑，似聽跬步鳴秋濤。", "槎牙老樹半枯死，上倚絕壁緣飛猱。", "我行日畏盜賊逼，敢厭瘴癘多腥臊。", "偶逢坐稳懶歸去，豁達眼界無纖毫。", "嶺南山水固多異，恨無中州清淑氣。", "對君圖障心怳然，便如太華嵩高前。", "君但對此能高眠，當有好句令君傳。"]'),
('a011c861-fae4-44d4-bb12-6b0d175edf69','連州陽山歸路三絕  其一','呂本中','宋','宋诗','song-poetry','','[]','蒼黄避地出連州，邃谷深巖懶轉頭。',32,'全唐诗/poet.song.92000.json','["蒼黄避地出連州，邃谷深巖懶轉頭。", "歸路始知山水好，少留村驛當閑游。"]'),
('9592e205-c751-41e9-aed2-add8fb82f337','連州陽山歸路三絕  其二','呂本中','宋','宋诗','song-poetry','','["\u7f81\u65c5", "\u6292\u60c5", "\u53e4\u8bd7\u4e09\u767e\u9996", "\u5b8b\u8bd7"]','稍離烟瘴近湘潭，疾病衰頽已不堪。',32,'全唐诗/poet.song.92000.json','["稍離烟瘴近湘潭，疾病衰頽已不堪。", "兒女不知來避地，强言風物勝江南。"]'),
('c4c0cc9a-1a77-4138-b3fe-411bef6c83ec','連州陽山歸路三絕  其三','呂本中','宋','宋诗','song-poetry','','[]','嶺外從來不識春，青梅年後已嘗新。',32,'全唐诗/poet.song.92000.json','["嶺外從來不識春，青梅年後已嘗新。", "深山忽有殘花在，知與清明待北人。"]'),
('3cf8ce0f-c9bd-4b31-9c7c-0becb94da5cd','陽山道中遇大風雨暴寒有感','呂本中','宋','宋诗','song-poetry','','[]','嶺南二月春已盡，百花委棄隨風吹。',256,'全唐诗/poet.song.92000.json','["嶺南二月春已盡，百花委棄隨風吹。", "山前山後綠陰滿，已過中原初夏時。", "不知何氣忽乖沴，風雨夜作雷乘之。", "鞭笞宇宙敝日月，萬象倒錯藏光輝。", "巖傾澗絕水府現，捕搏虎豹擒蛟螭。", "百圍老樹不須說，忍凍欲壓摧其枝。", "崢嶸屋瓦走飛雹，如戰初合麾旌旗。", "我行避地更值此，閉目但聽兒啼饑。", "僕夫噤死者數輩，牛馬懼不存毛皮。", "長途三日斷還往，况有鳥雀凌雲飛。", "只今胡塵暗江路，盜賊往往乘餘威。", "良民雖在困須索，四海萬里皆瘡痍。", "天公忍不一顧此，反更震動窮荒爲。", "此方亦是神所主，我欲告訴心先疑。", "明朝風定寒亦解，收召魂魄尋歸期。", "澗毛自可薦筐筥，試出苦語令神知。"]'),
('c6b1077b-7a33-4ace-ae88-3cb454a8bcb3','答朱成伯見贈四首  其一','呂本中','宋','宋诗','song-poetry','','[]','三年轉東南，足跡不得息。',132,'全唐诗/poet.song.92000.json','["三年轉東南，足跡不得息。", "新霜未壓瘴，已畏賊馬迫。", "蒼黄度嶺去，山路楓葉赤。", "慨然念平生，謬自有欣戚。", "交游半鬼錄，在者費相憶。", "朱卿早聞道，一如見舊識。", "新詩入要妙，如射已破的。", "我行囊貯空，所至但四壁。", "豈如投異縣，忽枉和氏璧。", "斯文得未喪，豈不係人力。", "出門仰高山，此道如矢直。"]'),
('5fe7c1bb-3419-4df9-a6cd-0e99f615b79c','答朱成伯見贈四首  其二','呂本中','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','我適蒼梧野，君來洞庭岸。',60,'全唐诗/poet.song.92000.json','["我適蒼梧野，君來洞庭岸。", "相逢迫盜賊，一笑未得款。", "欣然望眉宇，於我意自滿。", "天寒道路長，歲晚日晷短。", "僧房肯再來，晴窗自妍暖。"]'),
('540a55c5-c4e8-4af1-a57d-b7b39d97a271','答朱成伯見贈四首  其三','呂本中','宋','宋诗','song-poetry','','[]','入林恐不遠，入山恐不深。',48,'全唐诗/poet.song.92000.json','["入林恐不遠，入山恐不深。", "城市有深遠，不必在山林。", "隋珠不自寶，豈在須淵沈。", "斷弦得遺譜，千載有知音。"]'),
('357b8e46-7b0d-4985-b003-058d9d44ec90','答朱成伯見贈四首  其四','呂本中','宋','宋诗','song-poetry','','[]','昔在中朝時，每從賢俊游。',96,'全唐诗/poet.song.92000.json','["昔在中朝時，每從賢俊游。", "酒酣握手歡，預懷今日憂。", "兩經嶺嶠春，三度江湖秋。", "朱卿抱奇節，好語忽見收。", "我無濟世策，君有活國謀。", "相尋不相笑，夜光猶暗投。", "道喪師友絕，寧有民不偷。", "風波極浩渺，欲濟能無舟。"]'),
('ec25b858-d225-468c-92a2-094aa10b8c5f','連州行衙水閣望溪西諸山','呂本中','宋','宋诗','song-poetry','','["\u8861\u5c71"]','嶠南氣常昏，終日如霧隔。',216,'全唐诗/poet.song.92000.json','["嶠南氣常昏，終日如霧隔。", "我來已經時，初不辨山色。", "紛紛翳犯眼，黙黙悸動魄。", "今晨忽晴快，如語見肝膈。", "羣峰插天青，野水恣意白。", "深窺木杪靜，細數鳥道窄。", "天心豈無意，直欲慰北客。", "才經盜賊擾，更脫瘴癘厄。", "湖湘雖未定，勢已初夏迫。", "頗聞鐵騎遠，不復更追索。", "我歸當何時，俗事累千百。", "便擬衡山前，今年飽新麥。", "憂慮則未已，四海方逼仄。", "羣公獻納際，或肯任此責。", "先當肅區夏，次用及蠻貃。", "豈容肆蹂躙，歲必有大獲。", "天雖未悔禍，世豈無良策。", "生人苟未盡，狐兔當有宅。"]'),
('b2bfc226-9f4e-4e8e-bb87-e4b173d58f95','贈歐陽處士','呂本中','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','愛君年少便知足，今君雖老更無欲。',224,'全唐诗/poet.song.92000.json','["愛君年少便知足，今君雖老更無欲。", "閉門不出動經時，保此無窮清淨福。", "黄衣弟子雜僧徒，共守荒郊數椽屋。", "門前山水各有態，君但疏籬對脩竹。", "直如季路恥有聞，清似之推不言祿。", "坐看世事雲變化，一任兒曹手反覆。", "上皇龍飛三十春，臨軒亦嘗思異人。", "詔書屢下廣搜索，當時幾人能識真。", "君時聲名動天子，高臥不起空逡巡。", "謾收符籙養丹火，一旦四海生風塵。", "我來見君斛嶺下，識君無營真靜者。", "殷勤愛我莫遽行，尚肯相從結茅舍。", "時當喪亂足淹留，豺狼恣横空山夜。", "它年有意過匡廬，更許淵明入蓮社。"]'),
('9c44e833-658f-476d-bd66-137157194795','嶺外懷宣城舊游','呂本中','宋','宋诗','song-poetry','','[]','中原未敢說歸期，却憶宣城近别離。',64,'全唐诗/poet.song.92000.json','["中原未敢說歸期，却憶宣城近别離。", "疊嶂雨來如畫裏，敬亭秋入勝花時。", "每憎卑濕尤多病，苦愛風光屢有詩。", "今日衰頹那可說，髩鬚經瘴總成絲。"]'),
('dd74200d-f4bb-40bd-9572-638bc28f0ead','余避地踰嶺寄書宜章孫氏賊去則盡失之感歎有作','呂本中','宋','宋诗','song-poetry','','[]','賊馬縱横未說歸，草間梁上借餘威。',64,'全唐诗/poet.song.92000.json','["賊馬縱横未說歸，草間梁上借餘威。", "布帆此去應無恙，銀盌從來亦解飛。", "世事只堪開口笑，主人空有食言肥。", "自慚學道工夫少，坐覺文書到眼稀。"]'),
('f3ba4e78-7d97-4658-aca3-d78adabb3e2b','過嶺將至江華先寄朱成伯二首  其一','呂本中','宋','宋诗','song-poetry','','[]','自怪匆匆來往忙，又攜兒女過湖湘。',32,'全唐诗/poet.song.92000.json','["自怪匆匆來往忙，又攜兒女過湖湘。", "敢言此地能安稳，且道新年離瘴鄉。"]'),
('fe198a15-6655-406c-802c-cff37bf2ea9b','過嶺將至江華先寄朱成伯二首  其二','呂本中','宋','宋诗','song-poetry','','[]','嶺下微陰已自寒，早行山路覺衣單。',32,'全唐诗/poet.song.92000.json','["嶺下微陰已自寒，早行山路覺衣單。", "故人見我應驚笑，疾病衰顔怯據鞍。"]'),
('7537ba65-8e26-4ec2-836a-8ceec2620cdb','端午日北還至斛嶺寄連州諸公','呂本中','宋','宋诗','song-poetry','','[]','嶺上逢端午，隨家更北征。',48,'全唐诗/poet.song.92000.json','["嶺上逢端午，隨家更北征。", "隔村聞賊鬬，通夕畏蛇行。", "厭病初辭瘴，衝泥却勝晴。", "猶憐昌歜酒，不與故人傾。"]'),
('619fd11b-c93a-4143-981d-38fcd8e0a588','山居素飯','呂本中','宋','宋诗','song-poetry','','[]','豆苗可瀹瓠可羮，僧廚午飯蒸香粳。',64,'全唐诗/poet.song.92000.json','["豆苗可瀹瓠可羮，僧廚午飯蒸香粳。", "道人得此清淨供，下箸已勝肥羊烹。", "平生爲腹不爲目，偶逢一飽心自足。", "晚菘早韭舊所知，五鼎百牢未爲福。"]'),
('e06c4d8f-df88-4a7e-b500-e8f9fab8105c','寺居夜起','呂本中','宋','宋诗','song-poetry','','[]','山深夜無人，竹密風露集。',84,'全唐诗/poet.song.92000.json','["山深夜無人，竹密風露集。", "長空新過雨，尚覺星斗濕。", "避地走天涯，如何免拘縶。", "朝憂粟囊盡，莫恐賊報急。", "荒城兵火後，所至復未葺。", "古寺半頹垣，梟嘯鬼亦泣。", "感事念平生，徘徊近階立。"]'),
('a8893508-7088-481c-836f-37219aaf2cb1','寺居即事三首  其一','呂本中','宋','宋诗','song-poetry','','[]','瘴癘過庚伏，庶幾其少瘳。',48,'全唐诗/poet.song.92000.json','["瘴癘過庚伏，庶幾其少瘳。", "甘心忍殘暑，指日是清秋。", "汴水他年别，郴江此日留。", "如何理歸夢，只見嶺南州。"]'),
('3f880bd8-ec77-4134-8734-3c8aa3cdb4a6','寺居即事三首  其二','呂本中','宋','宋诗','song-poetry','','[]','因循過嶺表，忽復到湖南。',48,'全唐诗/poet.song.92000.json','["因循過嶺表，忽復到湖南。", "氣力渾非舊，情懷老不堪。", "無錢供痛飲，因病廢清談。", "尚有尋書僻，窮搜未免貪。"]'),
('a6b35a61-46de-4a4c-b073-b8203327edf2','寺居即事三首  其三','呂本中','宋','宋诗','song-poetry','','[]','中原是何處，敢道幾時回。',48,'全唐诗/poet.song.92000.json','["中原是何處，敢道幾時回。", "一夏無書讀，經時畏賊來。", "老松猶偃蹇，病鶴久摧頹。", "莫怪論兵少，吾今心已灰。"]'),
('3cac91a0-ed2d-462b-bd02-624be9e3b0b7','贈夏庭别兄弟','呂本中','宋','宋诗','song-poetry','','[]','披沙揀金勤乃見，讀書何止須百遍。',64,'全唐诗/poet.song.92000.json','["披沙揀金勤乃見，讀書何止須百遍。", "如君心期已不凡，况有長兵可鏖戰。", "一寒濕薪薰病目，君但讀書聲徹屋。", "僧房夜永燈火足，更肯襆被來同宿。"]'),
('947dac1e-6af9-4fa0-9618-c82642594c2e','墨梅','呂本中','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','嶺南十月春漸回，妍暖先到前村梅。',224,'全唐诗/poet.song.92000.json','["嶺南十月春漸回，妍暖先到前村梅。", "問君何處得此妙，一枝冷艷隨霜開。", "長江凜凜欲奔岸，乃見好事移牆隈。", "初疑滲漉入瘴霧，更欲寂寞埋烟煤。", "微風不動暗香遠，淡月入户空徘徊。", "坐看粉黛化腐惡，豈但桃李成輿臺。", "我行萬里厭窮獨，疾病未已心先灰。", "對此不覺三歎息，恐是轉側同南來。", "異鄉久處少意緒，破壁相對無根荄。", "古來寒士每如此，一世埋没隨蒿萊。", "遁光藏德老不燿，肯與世俗相追陪。", "輪囷離奇多見用，犧尊青黄未爲災。", "含毫吮墨去顔色，况自不必須穿栽。", "歲窮路遠莫惆悵，此去保無蜂蝶猜。"]'),
('7c2e1c84-8536-4006-ba40-aa60adf854ff','賀州聞席大光陳去非諸公將至作詩迎之','呂本中','宋','宋诗','song-poetry','','[]','五年避地走窮荒，嶺海江湖半是鄉。',64,'全唐诗/poet.song.92000.json','["五年避地走窮荒，嶺海江湖半是鄉。", "歡喜聞君俱趣召，衰頽如我合深藏。", "曉寒已靜千山瘴，宿霧先吞萬瓦霜。", "日日江頭望行李，幾回驅馬度浮梁。"]'),
('a9727a1b-75eb-4cb4-b581-973a472fcf8c','送周靈運入閩浙','呂本中','宋','宋诗','song-poetry','','[]','青松著塵市，不辭塵土侵。',144,'全唐诗/poet.song.92000.json','["青松著塵市，不辭塵土侵。", "忍恥伴桃李，不言歸故林。", "交游在貧賤，始見平生心。", "周侯客異縣，屢蒙金玉音。", "殷勤不我厭，自昔以至今。", "使其少富貴，未必能相尋。", "豈謂子誠然，此風今則深。", "子欲轉嶺海，歲暮足愁陰。", "路經盜賊窟，往往未就擒。", "加鞭策駑馬，欲行無滯淫。", "故人散天涯，所在亦崎嶔。", "相尋倘見及，道我病難任。"]'),
('f8088d07-4d64-4192-af30-cb278fdd4c3c','次韻錢遜叔見寄','呂本中','宋','宋诗','song-poetry','','[]','異時文物漢庭臣，公是中朝第一人。',64,'全唐诗/poet.song.92000.json','["異時文物漢庭臣，公是中朝第一人。", "忍使閑行犯山瘴，不令疾去掃胡塵。", "情懷縱老元非病，時運方隆只暫屯。", "顧我衰頹已無用，尚煩新語訪沈淪。"]'),
('c8899a8d-cc5b-4dd4-a6e2-ff8b86f94594','贈宗真上人','呂本中','宋','宋诗','song-poetry','','[]','到處相逢是偶然，淛江湖嶺屢經年。',32,'全唐诗/poet.song.92000.json','["到處相逢是偶然，淛江湖嶺屢經年。", "贈君頌子君休笑，我已新來不問禪。"]'),
('3d54bc83-1f99-4918-bba8-13bb7f10f268','全州與解子中向伯恭相會','呂本中','宋','宋诗','song-poetry','','[]','五年流落判西東，尚喜交游一再逢。',64,'全唐诗/poet.song.92000.json','["五年流落判西東，尚喜交游一再逢。", "但得低頭拜東野，不妨下卧見元龍。", "中原極目山千叠，往事傷心酒一鍾。", "如我支離久無用，敢因窮約廢過從。"]'),
('f2f0e132-e448-41b1-8956-062215f957ff','初至桂州二首  其一','呂本中','宋','宋诗','song-poetry','','[]','連年走遐方，所至若郵傳。',72,'全唐诗/poet.song.92000.json','["連年走遐方，所至若郵傳。", "未論道艱阻，先問米貴賤。", "賊勢來未已，行役我已倦。", "解鞍憩空館，敢歎此異縣。", "清泉上短綆，一洗塵垢面。", "瘴癘非不深，美醖良可戀。"]'),
('64f2786b-7452-471b-8bd6-8062c0f6ed89','初至桂州二首  其二','呂本中','宋','宋诗','song-poetry','','[]','胡沙久衝突，賊馬亦馳騖。',72,'全唐诗/poet.song.92000.json','["胡沙久衝突，賊馬亦馳騖。", "我行不得息，終歲在道路。", "敢言更多事，尚恐與時忤。", "低頭訪殊俗，何處可放步。", "江流下滄海，日慘蛟鱷怒。", "出門尋故人，風雨已斷渡。"]'),
('44be594d-b8e5-4f3f-ab59-2ad2ebbe110f','桂林解后拜見仲古龍圖吉父學士别後得兩詩書懷奉寄  其一','呂本中','宋','宋诗','song-poetry','','[]','所至艱危裏，如何更别離。',48,'全唐诗/poet.song.92000.json','["所至艱危裏，如何更别離。", "只看山似戟，自合鬢如絲。", "湯熨徒增疾，文章不療饑。", "端居温餘論，苦語自成詩。"]'),
('3ff4a017-5d9e-47ab-ae8a-456d8c02849a','桂林解后拜見仲古龍圖吉父學士别後得兩詩書懷奉寄  其二','呂本中','宋','宋诗','song-poetry','','[]','折老久高卧，曾鄉仍倦游。',48,'全唐诗/poet.song.92000.json','["折老久高卧，曾鄉仍倦游。", "同爲萬里走，肯避數年留。", "賊幟江湖晚，嵐烟嶺嶠秋。", "相逢得安稳，乘興莫東流。"]'),
('5649fdb1-8b57-4540-9f67-fb414a5fbfd2','次韻吉父見寄新句','呂本中','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','詞源久矣多岐路，句法相傳共一家。',64,'全唐诗/poet.song.92000.json','["詞源久矣多岐路，句法相傳共一家。", "良賈深藏宜有待，大圭可寶在無瑕。", "長江渺渺看秋注，孤騖悠悠伴落霞。", "盛欲寄書商榷此，嶺南不見雁行斜。"]'),
('55907a68-bba2-41c9-bfdc-5c3c6e8dd41d','桂州水西','呂本中','宋','宋诗','song-poetry','','[]','隆隆而雷風乘之，斷霓落日江東西。',80,'全唐诗/poet.song.92000.json','["隆隆而雷風乘之，斷霓落日江東西。", "江頭古寺頗岑寂，僧簷正與南山齊。", "我來端坐已寒暑，終日看山黙無語。", "盜賊連村那敢問，藜莧充腸未爲苦。", "早禾已旱心所知，正待前山一犁雨。"]'),
('c3b72007-d6ab-4fee-9a7d-41c7972e4fda','斷橋','呂本中','宋','宋诗','song-poetry','','[]','橋斷客途少，春深花已休。',48,'全唐诗/poet.song.92000.json','["橋斷客途少，春深花已休。", "閉門尤省事，於世轉無求。", "來往只諸老，相期非壯游。", "欲知身所住，同寓訾家洲。"]'),
('5df41b7d-d63c-4143-9d1a-fa2552d23f95','贈嶺東陳秀才','呂本中','宋','宋诗','song-poetry','','[]','風吹賀江浪如雪，浮梁左右行人絕。',176,'全唐诗/poet.song.92000.json','["風吹賀江浪如雪，浮梁左右行人絕。", "病夫坐稳懶出行，破屋只愁吹瓦裂。", "東縣陳卿忽叩門，笑語歡然相暖熱。", "怪我長貧走道路，所至不安寧有說。", "鄰州賊報又警急，欲泛扁舟窮百粤。", "如君長才亦未用，獨守區區負奇莭。", "未能俯首效兒輩，肯便出門探虎穴。", "馬羣時致千里足，烈士寧無一時傑。", "我復何人敢言事，一世摧頽甘短拙。", "幸君無事時一過，喜聽高談健其決。", "瘴癘參差畏久留，歲月崢嶸惜輕别。"]'),
('2574e084-246e-486a-a6ef-0fe2cd7e4b6a','衡州逢解子中别後奉寄','呂本中','宋','宋诗','song-poetry','','["\u8861\u5c71"]','我來筠水陽，君亦發章貢。',168,'全唐诗/poet.song.92000.json','["我來筠水陽，君亦發章貢。", "相逢瀟湘門，及此兵未動。", "卧聞羽書馳，起已行者衆。", "匆匆不及款，尚辱苦語送。", "慨然念平生，相從已如夢。", "交游半生死，所至多罅縫。", "我衰學不入，君亦老未用。", "熟知一世中，有此九鼎重。", "子賤則君子，閔子言必中。", "師門未遽絕，斯文實天奉。", "别離又幾日，坐想發孤諷。", "衡州逼南嶽，湘水寒不凍。", "頗傳江西擾，盜賊已放縱。", "往從田蘇游，此樂不得共。"]'),
('7ae2dab4-07a1-4b38-8569-52dd8997272a','范縣丞惠雙鷄','呂本中','宋','宋诗','song-poetry','','[]','羸病不能除肉味，每逢齋缽愧餘生。',32,'全唐诗/poet.song.92000.json','["羸病不能除肉味，每逢齋缽愧餘生。", "雙鷄未可爲公饍，留與山僧報五更。"]'),
('2e053013-b540-47b1-9891-d5eca3b1cdfb','王撫幹失去毛裘','呂本中','宋','宋诗','song-poetry','','[]','王郎隨身一駝裘，偷兒遽作壑失舟。',64,'全唐诗/poet.song.92000.json','["王郎隨身一駝裘，偷兒遽作壑失舟。", "春初未免霜露迫，歲晚可無遷徙憂。", "客房夜坐薪當燭，不怕近江風裂屋。", "馬平編户更艱難，君行莫忘民號寒。"]'),
('ff8e4e3d-0286-41d5-9f7f-06fb910bc98c','四十二弟將還賓州相過夜話','呂本中','宋','宋诗','song-poetry','','[]','兵戈久未歇，所至轉搶攘。',48,'全唐诗/poet.song.92000.json','["兵戈久未歇，所至轉搶攘。", "萬里逢吾弟，三年走瘴鄉。", "春風入古寺，夜雨暗浮梁。", "尚肯留連否，僧廬可對床。"]'),
('ab3c997a-11c9-45ca-bdea-f9cf11fb7c9d','呈折仲古四首  其一','呂本中','宋','宋诗','song-poetry','','[]','市酒酸甜久絕沽，濕薪薰眼坐僧廬。',32,'全唐诗/poet.song.92000.json','["市酒酸甜久絕沽，濕薪薰眼坐僧廬。", "尚憐諸老無機事，不待愁人折簡呼。"]'),
('cfb73a96-fbda-4070-a4df-3b79dde6e7e2','呈折仲古四首  其二','呂本中','宋','宋诗','song-poetry','','[]','龍閣老翁流落久，如今辛苦去朝天。',32,'全唐诗/poet.song.92000.json','["龍閣老翁流落久，如今辛苦去朝天。", "向來嶺海經行地，分付蠻溪著釣舟。"]'),
('3e29b3c7-162a-4cb6-8d34-3341bc127aca','呈折仲古四首  其三','呂本中','宋','宋诗','song-poetry','','[]','已無厚祿故人書，尚有相尋長者車。',32,'全唐诗/poet.song.92000.json','["已無厚祿故人書，尚有相尋長者車。", "所至紛然兵火裏，不知從此更何如。"]'),
('2cee46dd-d780-484b-a8ea-818b4691c914','呈折仲古四首  其四','呂本中','宋','宋诗','song-poetry','','[]','疾病侵凌百不能，只今全是住庵僧。',32,'全唐诗/poet.song.92000.json','["疾病侵凌百不能，只今全是住庵僧。", "謝安肯爲蒼生起，早與吾君了中興。"]'),
('04bac1d9-6c01-46f6-97bd-53e1b5aba5f0','次韻王撫幹見惠','呂本中','宋','宋诗','song-poetry','','[]','新春忽忽到庭除，短褐經寒病却蘇。',64,'全唐诗/poet.song.92000.json','["新春忽忽到庭除，短褐經寒病却蘇。", "漫以詩書教兒子，嬾將薪水倩童奴。", "天涯每覺人情薄，眼界何知風景殊。", "萬里相逢君莫歎，好山無數簇城隅。"]'),
('5e7a14d4-6ef4-46a9-8a85-a21227f76998','次韻王漕見贈并寄曾吉父二首  其一','呂本中','宋','宋诗','song-poetry','','[]','前賢去則遠，今代不無人。',48,'全唐诗/poet.song.92000.json','["前賢去則遠，今代不無人。", "小出已無敵，深藏恐未仁。", "兩章知思苦，一語見情親。", "徑欲忘衰病，知公筆有神。"]'),
('be2a7719-a7f3-4fc1-a401-f9274ac143f4','次韻王漕見贈并寄曾吉父二首  其二','呂本中','宋','宋诗','song-poetry','','[]','曾子住南國，端居無所思。',48,'全唐诗/poet.song.92000.json','["曾子住南國，端居無所思。", "逃禪不用酒，投筆謾成詩。", "敏捷忘千慮，縱横又一奇。", "子中有住處，莫待折肱醫。"]'),
('d110de85-65c6-4e92-a2bd-16ddb87de845','次韻折仲古見贈','呂本中','宋','宋诗','song-poetry','','[]','未有絲毫補縣官，幾年流轉但求安。',64,'全唐诗/poet.song.92000.json','["未有絲毫補縣官，幾年流轉但求安。", "江湖自稱嵇康嬾，故舊空嗟范叔寒。", "顧我初無食肉相，喜公復著侍臣冠。", "新詩不忘東山志，敢作尋常禁近看。"]'),
('64da6606-354f-4546-843d-845b35edce22','再用前韻奉和','呂本中','宋','宋诗','song-poetry','','[]','自昔支離畏作官，只今猶望一枝安。',64,'全唐诗/poet.song.92000.json','["自昔支離畏作官，只今猶望一枝安。", "飽知時態病良已，心喜故人盟未寒。", "所至軍書銷日月，幾回戎馬污衣冠。", "公歸定有安邊策，不學愚夫靜處看。"]'),
('48c12bef-cee9-4e33-98cb-a2a1733198f5','夜坐有感','呂本中','宋','宋诗','song-poetry','','[]','五更月落雞未鳴，小爐殘火猶晶熒。',144,'全唐诗/poet.song.92000.json','["五更月落雞未鳴，小爐殘火猶晶熒。", "道人强起理衰疾，不聞松聲聞雨聲。", "跏趺坐稳百念去，豈有宿夢令神驚。", "平生于世萬事嬾，况復今兹飽憂患。", "中原北望四千里，三年不見南飛雁。", "著身天涯未爲遠，所至風沙莫深歎。", "時寒但趁僧房火，日暖可赴鄰家飯。", "嶺南無瘴便可老，江頭有酒猶堪喚。", "嗟哉甯子不自休，辛苦飯牛過夜半。"]'),
('0ff28817-c2c0-4c03-a7b4-6097ae375681','送密上人歸江西','呂本中','宋','宋诗','song-poetry','','["\u8861\u5c71"]','輕舟君先行，羸馬我已往。',120,'全唐诗/poet.song.92000.json','["輕舟君先行，羸馬我已往。", "湖山已在望，南嶽行可仰。", "不憂盜賊繁，漸喜草木長。", "密也負奇氣，少已離塵網。", "飽參諸方禪，所至被稱賞。", "獨留末後句，未肯休吾黨。", "經尋卓錐地，更足以自養。", "囊空脚頗健，體儉心甚廣。", "喜談江西勝，妙處猶指掌。", "未見頻寄書，悠然發遐想。"]'),
('4d7503c2-3f17-438a-b112-fa74df3f09e9','送常子正赴召二首  其一','呂本中','宋','宋诗','song-poetry','','[]','屬者聞居久，今來促召頻。',48,'全唐诗/poet.song.92000.json','["屬者聞居久，今來促召頻。", "但能消黨論，便足掃胡塵。", "衆水同歸海，殊塗必問津。", "如何彼黠虜，敢謂漢無人。"]'),
('96d12554-eb87-4bcc-a72c-303d53efe8cd','送常子正赴召二首  其二','呂本中','宋','宋诗','song-poetry','','[]','疾病老逾劇，交親窮轉疏。',48,'全唐诗/poet.song.92000.json','["疾病老逾劇，交親窮轉疏。", "惟公不改舊，怪我未安居。", "日月干戈裏，江山瘴癘餘。", "南行見李白，亦莫問何如。"]'),
('15a0725f-467f-42ab-9c63-37c100e8d449','頌送山上人游南華','呂本中','宋','宋诗','song-poetry','','[]','三浙三衢未說歸，且從嶺路訪曹溪。',32,'全唐诗/poet.song.92000.json','["三浙三衢未說歸，且從嶺路訪曹溪。", "盧公若問南來事，但道江湖盡鼓鼙。"]'),
('16ae3c8f-251f-4c29-919c-a017f5a58de4','山頌送譚師直歸湖南','呂本中','宋','宋诗','song-poetry','','[]','人事日翻覆，昔同今不然。',48,'全唐诗/poet.song.92000.json','["人事日翻覆，昔同今不然。", "于心苟有用，與世自無緣。", "剩結官田社，飽參雲蓋禪。", "已勝高鳥盡，徒泛五湖船。"]'),
('5ec21d1e-2fb3-43b8-87b6-bb48193dee08','送能化主還法輪','呂本中','宋','宋诗','song-poetry','','[]','嶺外三年避賊忙，法輪元不下禪床。',32,'全唐诗/poet.song.92000.json','["嶺外三年避賊忙，法輪元不下禪床。", "君歸却說嶺南事，瘴暑作時君自涼。"]'),
('d2fc3601-8c70-4550-9941-b047d6501e28','送夏少曾兄弟','呂本中','宋','宋诗','song-poetry','','[]','處處人家避賊忙，數因行李問舟航。',64,'全唐诗/poet.song.92000.json','["處處人家避賊忙，數因行李問舟航。", "江横晚照鳬鷗亂，春到空山草木香。", "我未有緣離嶺嶠，君今决策下湖湘。", "定知此去添貧病，不及相從氣味長。"]'),
('2422c451-2a0d-4ac0-ae13-6e505d025264','本中將爲江浙之行念當與夢貺遠别感歎傷懷因成長句奉呈','呂本中','宋','宋诗','song-poetry','','[]','客行已無聊，况此憂慮集。',156,'全唐诗/poet.song.92000.json','["客行已無聊，况此憂慮集。", "頹然念遠役，未見勇可習。", "虛庭覺氣潤，遠視螢火濕。", "故人不我厭，踏雨相勞揖。", "朝餐共饑飽，夜語同坐立。", "問我去此邦，何用如此急。", "干戈與瘴癘，未見可出入。", "何殊知二五，而不知有十。", "俛首謝勤意，此非愚所及。", "天涯重離别，所至方嶪岌。", "感懷平生舊，忍效兒女泣。", "風沙蔽中原，道路滿荆棘。", "世事古則然，臨分莫於邑。"]'),
('7f6bc856-c803-4cf3-8fbe-c538e3f89d8a','贈日者張直夫','呂本中','宋','宋诗','song-poetry','','[]','因循避世不求名，潦倒江湖過一生。',64,'全唐诗/poet.song.92000.json','["因循避世不求名，潦倒江湖過一生。", "賈誼定能尋季主，子雲先已識君平。", "獨行市肆口無語，嬾踏權門身自輕。", "看甑生塵只堅坐，世間寧有不平鳴。"]'),
('faed93bf-20ee-46fa-a23d-37683529d53f','永州西亭','呂本中','宋','宋诗','song-poetry','','[]','舊聞西亭勝，獨盛湘湖間。',204,'全唐诗/poet.song.92000.json','["舊聞西亭勝，獨盛湘湖間。", "山秀水亦好，千里在憑欄。", "今來乃不然，眼境故未寛。", "環城但濁水，滿目唯荒山。", "如何柳司馬，肯爲此解顔。", "始知憂慮久，方覺所遇安。", "我從避地來，山水亦飫觀。", "初不厭嶺嶠，况敢嫌荆蠻。", "徘徊念昔人，亦作故意看。", "所慚二三子，來不倦躋攀。", "開軒納微涼，共享一日閑。", "說詩到雅頌，論文參誥盤。", "快若箭破的，圓如坂下丸。", "此樂固可樂，此盟安得寒。", "天暑畏道路，時危安阻難。", "相逢得少款，莫問何時還。", "何須待杯酒，始盡平生歡。"]'),
('e63b3f45-b04d-4aa7-ac03-a681e9b325eb','浯溪','呂本中','宋','宋诗','song-poetry','','[]','五月行人汗如雨，意緒昏昏雜塵土。',192,'全唐诗/poet.song.92000.json','["五月行人汗如雨，意緒昏昏雜塵土。", "浯溪一見中興碑，便有清風濯煩暑。", "中興之業誠艱難，敢作漢武周宣看。", "紛然大歷上元間，文恬武嬉主則孱。", "但知追咎一祿山，袖手不作如旁觀。", "天亦未使庸夫干，故生李郭在人間。", "一時節士張許顔，其誰不知唐已安。", "道州落筆風雨寒，魯公大書鎮百蠻。", "訶叱水怪摧神姦，有臣若此亡所歎。", "而不能使君心還，我來轉嶺逾千盤。", "對此凜然清肺肝，想見羣小遭譏彈。", "爾曹何心猶誕謾，至今怒髪常衝冠。"]'),
('187c6c52-ff51-4d22-a1bb-4091a4065e8b','送元上人歸禾山','呂本中','宋','宋诗','song-poetry','','[]','長囂而寂，方作而息。',160,'全唐诗/poet.song.92000.json','["長囂而寂，方作而息。", "如射破的，初不以力。", "子居深山，又處絕頂。", "避囂不作，二事俱屏。", "往來臨川，道里且千。", "一見我喜，如舊交然。", "我欲屬子，重于發言。", "子請則堅，之子之賢。", "遍尋諸方，不主先入。", "唯是之從，何拘何執。", "惟昔善財，我曹之師。", "其心廣大，誰能間之。", "山高海深，德則不孤。", "不深不高，培塿潢汚。", "奚必深山，惟靜之守。", "求寂念息，以閲永久。"]'),
('189b9f07-c0c3-46d2-be3e-659fd28fbd36','贈一上人','呂本中','宋','宋诗','song-poetry','','[]','偶從嶺嶠轉江東，得向疏山見一公。',64,'全唐诗/poet.song.92000.json','["偶從嶺嶠轉江東，得向疏山見一公。", "所至共游常草草，爾來相遇更匆匆。", "晁郎埋骨虛無裏，璧老收聲蒼莽中。", "二十餘年往還事，半隨秋雁落寒空。"]'),
('fc512bb5-773d-46d1-ac55-1d60b8a3f8df','贈珪公杲公四首  其一','呂本中','宋','宋诗','song-poetry','','[]','北歸住江西，塵事日窘束。',48,'全唐诗/poet.song.92000.json','["北歸住江西，塵事日窘束。", "兩公時踵門，高誼已絕俗。", "空房擁殘火，更許相就宿。", "不嫌寒無氊，肯厭飯脫粟。"]'),
('fbe7b78a-b829-4156-8c16-1ff0f6e6729d','贈珪公杲公四首  其二','呂本中','宋','宋诗','song-poetry','','[]','杲公玉壺冰，所至自清淨。',48,'全唐诗/poet.song.92000.json','["杲公玉壺冰，所至自清淨。", "珪公出林鶴，肯與雞騖競。", "吾窮得兩公，頗覺意氣盛。", "未能出艱危，猶足起衰病。"]'),
('ed973499-6d84-4b96-b237-5997cca97ffe','贈珪公杲公四首  其三','呂本中','宋','宋诗','song-poetry','','[]','杲固昔所熟，珪亦舊聞名。',48,'全唐诗/poet.song.92000.json','["杲固昔所熟，珪亦舊聞名。", "江西一聚首，遂寛南去程。", "掃除文字習，追尋香火盟。", "期君向此道，隱若一長城。"]'),
('9a5ed7e5-85c8-423c-954c-427e9213cda8','贈珪公杲公四首  其四','呂本中','宋','宋诗','song-poetry','','[]','堂頭老居士，我識蓋自早。',48,'全唐诗/poet.song.92000.json','["堂頭老居士，我識蓋自早。", "聲名從少年，閉户今却掃。", "公能爲少留，尚可慰枯槁。", "欲知主人賢，但看此二老。"]'),
('2d45161e-0fa1-4b10-ac30-fa5ed24f2534','次韻錢遜叔清江圖後二首  其一','呂本中','宋','宋诗','song-poetry','','[]','公但一室堅坐，我方萬里生還。',28,'全唐诗/poet.song.92000.json','["公但一室堅坐，我方萬里生還。", "共作十年清夢，同尋五嶺名山。"]'),
('9b9f5856-f557-4f3e-92c8-093b468469fd','次韻錢遜叔清江圖後二首  其二','呂本中','宋','宋诗','song-poetry','','[]','作清江三兩曲，勝大厦千萬間。',28,'全唐诗/poet.song.92000.json','["作清江三兩曲，勝大厦千萬間。", "若保此中安坐，不必中原遽還。"]'),
('3d34e2c6-6301-4fa8-ba66-ed9ad81ed1c0','次韻錢遜叔獨鶴圖三首  其一','呂本中','宋','宋诗','song-poetry','','[]','長頸竦身嬾不前，此寧有望更騰鶱。',32,'全唐诗/poet.song.92000.json','["長頸竦身嬾不前，此寧有望更騰鶱。", "懿公愛爾非無意，要壓曹人三百軒。"]'),
('59622717-8ac4-4db3-9113-a0722ef4ea10','次韻錢遜叔獨鶴圖三首  其二','呂本中','宋','宋诗','song-poetry','','[]','粉墨半銷翎翅短，正如衰髮不勝簮。',32,'全唐诗/poet.song.92000.json','["粉墨半銷翎翅短，正如衰髮不勝簮。", "可憐少保功名悞，寫此凌雲意不堪。"]'),
('eafe0660-246c-4ba9-bb14-42aca5afb2f4','次韻錢遜叔獨鶴圖三首  其三','呂本中','宋','宋诗','song-poetry','','[]','眼明見此出籠鶴，似我北歸辭瘴嵐。',32,'全唐诗/poet.song.92000.json','["眼明見此出籠鶴，似我北歸辭瘴嵐。", "慎勿低頭待收養，人間欣戚盡朝三。"]'),
('9f375795-85e4-4106-918b-ee0bcb85d610','次韻錢遜叔畫圖','呂本中','宋','宋诗','song-poetry','','[]','西風著人塵滿襟，江山縱近難追尋。',144,'全唐诗/poet.song.92000.json','["西風著人塵滿襟，江山縱近難追尋。", "當年寫此數幅妙，坐使几案頻登臨。", "斷雲黤慘出古寺，遠岸杳靄連荒岑。", "漁舟蕩漾江路晚，烟雨濛籠山店陰。", "已知落筆氣象古，一任世間消息沈。", "最憐霜榦倚長石，不待歲久成枯林。", "知公此中興不淺，此畫故能留意深。", "只今燕坐一室裏，尚費從來長短吟。", "詩成掩卷坐秋晚，一唱三嘆求遺音。"]'),
('e3b08c78-6ce3-4098-bc28-4f519f18ff7d','送一上人','呂本中','宋','宋诗','song-poetry','','[]','我齒久已搖，君髮日向白。',168,'全唐诗/poet.song.92000.json','["我齒久已搖，君髮日向白。", "相逢不相笑，共被老境迫。", "周旋三十年，近歲多間隔。", "伊昔無事時，日夕望顔色。", "此道要琢磨，苦語費思索。", "不能如宿心，每負朋友責。", "别我寧陵縣，隨我昭德宅。", "所期無二三，可恨已千百。", "交游大半死，况值兵火厄。", "舉首望八荒，無乃天地窄。", "涼風吹秋深，江湖動行客。", "誰能于此時，出語見肝膈。", "胡塵蔽中原，盜賊暗阡陌。", "公其無遽行，待我有良策。"]'),
('de05e017-700b-44c1-a533-33fb9cc2b04f','錢遜叔諸公賦石鼓文請同作','呂本中','宋','宋诗','song-poetry','','[]','江頭羽書相續來，城中草木凍不開。',160,'全唐诗/poet.song.92000.json','["江頭羽書相續來，城中草木凍不開。", "腐儒坐視了無策，但守寒爐吹死灰。", "我公送我石鼓文，令我琢句要春回。", "簸蕩風雲走蛟蜃，百虫久蟄聞驚雷。", "錢公自是力扛鼎，持此浮游轉湖嶺。", "漢碑秦篆已么麽，况復鍾王敢馳騁。", "後來頗供兒女弄，神物有知當遠屏。", "石鼓之文公所知，正是周室中興時。", "庶幾我皇亦如此，一掃狂虜隨風飛。", "石鼓之文尚可讀，小臣願繼車攻詩。"]'),
('391141ba-ec05-4544-838e-97c0d3eb610e','和邢子堅韻','呂本中','宋','宋诗','song-poetry','','[]','萬里重歸舊禿翁，笑談聊復與君同。',64,'全唐诗/poet.song.92000.json','["萬里重歸舊禿翁，笑談聊復與君同。", "鷦鷯所願一枝足，鼯鼠從來五技窮。", "短髮自梳渾欲白，殘爐因客尚能紅。", "正須混迹師元亮，未忍低頭學敬通。"]'),
('7f738948-d877-42a3-8715-e0f25f2880ae','戲呈東林雲間二老','呂本中','宋','宋诗','song-poetry','','[]','幾年湖嶺費追尋，尚喜歸來聽足音。',64,'全唐诗/poet.song.92000.json','["幾年湖嶺費追尋，尚喜歸來聽足音。", "御虎已知吾有命，問禪方見子無心。", "風塵黤慘病如昨，歲月崢嶸窮至今。", "猶覺相逢有餘恨，老盆盛酒不同斟。"]'),
('1c4bf8c7-02ab-4e91-9ea6-9f86f8f0052e','佛日縱步相尋索歸甚苦戲成絕句','呂本中','宋','宋诗','song-poetry','','[]','相逢不用苦相催，只到更深月上回。',32,'全唐诗/poet.song.92000.json','["相逢不用苦相催，只到更深月上回。", "莫怪室空無侍者，夜窗相對有寒梅。"]'),
('bd26ed02-9791-41ca-9bd1-29b5e1baab9b','東林珪雲門杲將如雪峰因成長韻奉送','呂本中','宋','宋诗','song-poetry','','[]','東風被澤國，君有千里行。',180,'全唐诗/poet.song.92000.json','["東風被澤國，君有千里行。", "送君不能遠，宿昔春水生。", "胡馬污中原，旁淮多賊城。", "即今江南岸，盜賊猶縱横。", "頗聞閩粤靜，農民方及耕。", "雪峰佳主人，况欲屣履迎。", "兩公與談道，正欲平其衡。", "但見演若頭，自然心地明。", "云何未覽鏡，便欲其流清。", "君行可語此，勿憂兒女驚。", "鄙夫牙齒缺，苦遭塵事攖。", "七年憂奔走，一飽費經營。", "野鶴出籠飛，尚須完翅翎。", "今者與君别，故鄉他日情。", "新詩見萬一，庶用託同盟。"]'),
('de04de31-c8c9-40d9-9a2b-33a80423525e','贈童堯詢蔡楠謝敏行','呂本中','宋','宋诗','song-poetry','','[]','七年避胡塵，無復少年事。',192,'全唐诗/poet.song.92000.json','["七年避胡塵，無復少年事。", "適從嶺外歸，眼病不識字。", "尚幸戎馬間，得見此數士。", "蔡童南城傑，所養蓋有自。", "兩謝名家子，學已前作似。", "相逢眼暫明，已足慰遲暮。", "如何捨我去，使我起千慮。", "江深羽檄繁，况此日月騖。", "猶餘大謝留，與我相近住。", "風霜渺墟落，泥土暗道路。", "得無經此别，各復走他處。", "期君則甚遠，苦語不厭屢。", "微言恐遂絕，其誰與調護。", "要當發憤求，不欲僥倖遇。", "聖門極坦平，渠自有回互。", "河清倘有期，未死或可俟。"]'),
('1d2eb558-bb36-4aee-9685-2591e7c62c44','和范仲熊舜元游橘園見梅','呂本中','宋','宋诗','song-poetry','','[]','橘林經雨未全衰，歸路人家已見梅。',64,'全唐诗/poet.song.92000.json','["橘林經雨未全衰，歸路人家已見梅。", "風物粗知江左勝，瘴烟新離嶺南來。", "筆頭有眼方知妙，句裏忘言始絕埃。", "但得一寒無事過，與公還往勝銜杯。"]'),
('4b16dd54-4798-4bd9-aeb6-54a4dce930ca','答錢遜叔','呂本中','宋','宋诗','song-poetry','','[]','北風吹霜夜如雪，江城草木凍欲折。',96,'全唐诗/poet.song.92000.json','["北風吹霜夜如雪，江城草木凍欲折。", "病夫袖手無所爲，一坐臨川已三月。", "忽蒙妙句起衰憊，頓覺和氣生毛髮。", "公能忘機我亦倦，不待曼殊見摩詰。", "畫圖是非久未解，况保長年不磨滅。", "請公置畫莫多求，要與時人除愛渇。"]'),
('1fd0d37d-903d-4927-8e88-ab95da0df63e','與錢遜叔飲酒分韻得鳥字','呂本中','宋','宋诗','song-poetry','','[]','客游等浮萍，歲事如過鳥。',84,'全唐诗/poet.song.92000.json','["客游等浮萍，歲事如過鳥。", "逢公得一笑，不厭古寺悄。", "雨聲喧客耳，燭影吹半裊。", "宿酲未及解，更覺惡韻擾。", "時方足艱虞，身未識要妙。", "如何一杯酒，便出萬物表。", "别公願一言，使我意易了。"]'),
('b9d8b487-c5a3-4329-be26-79aa0fbe76db','贈别范一哥','呂本中','宋','宋诗','song-poetry','','[]','相送不嫌遠，詰朝當語離。',48,'全唐诗/poet.song.92000.json','["相送不嫌遠，詰朝當語離。", "文詞知子進，道路覺吾衰。", "力疾終無補，徐行敢厭遲。", "臨分更回首，苦語漫成詩。"]'),
('b4831d05-3a10-4ecf-b60e-51da9a31b6c6','送謙上人回建州三首  其一','呂本中','宋','宋诗','song-poetry','','[]','子來不憚千里遠，我病可無終歲憂。',32,'全唐诗/poet.song.92000.json','["子來不憚千里遠，我病可無終歲憂。", "相見匆匆又相别，主人無恨客無求。"]'),
('9175d207-ca3d-4a48-9625-71f284778098','送謙上人回建州三首  其二','呂本中','宋','宋诗','song-poetry','','[]','平生苦節胡元仲，老大多才劉致中。',32,'全唐诗/poet.song.92000.json','["平生苦節胡元仲，老大多才劉致中。", "爲我殷勤問消息，十年堅坐想高風。"]'),
('4569d0dc-4bcc-4a3c-87cd-8d29e4883543','送謙上人回建州三首  其三','呂本中','宋','宋诗','song-poetry','','[]','遙山渡口晚猶寒，道路奔波未許閑。',32,'全唐诗/poet.song.92000.json','["遙山渡口晚猶寒，道路奔波未許閑。", "頗恨獨來不同賞，竹輿穿雨上疏山。"]'),
('8f922149-99ac-48ec-94fa-4f1ff230c5eb','與范益謙炳文叔儀步月','呂本中','宋','宋诗','song-poetry','','[]','歲月忽已過，羈窮非獨今。',48,'全唐诗/poet.song.92000.json','["歲月忽已過，羈窮非獨今。", "稻塍分白水，月影上清陰。", "畎畝平生事，江湖他日心。", "相過無百步，猶覺費追尋。"]'),
('6dcc3f5a-bf71-4d1c-9c41-a6129e8cd012','陸庭元紹意齋','呂本中','宋','宋诗','song-poetry','','[]','聖人毋意物我同，大賢庶幾其屢空。',162,'全唐诗/poet.song.92000.json','["聖人毋意物我同，大賢庶幾其屢空。", "今君胡爲用此意，乃欲酬酢萬化參天工。", "客來無窮君不厭，所施不同皆有驗。", "風寒燥濕互相伐，一理驅馳無頓漸。", "衡門端坐一事無，衆皆刼刼君有餘。", "見賢不避忘其軀，肯與俗子急錙銖。", "知君此意久已絕，爲爾病生吾有說。", "偫儲百藥待百病，任爾紛紛强分别。", "君但守此心如銕，徧與衆生除衆熱。", "是則名爲無意訣，剩放南山著秋月。"]'),
('010b0774-ce91-4dbb-97bc-2ac483dfb9f3','病中口占示益謙四弟','呂本中','宋','宋诗','song-poetry','','[]','病來全少靜工夫，藥裏關心計已迂。',32,'全唐诗/poet.song.92000.json','["病來全少靜工夫，藥裏關心計已迂。", "縱使君來亦無語，更無餘法待文殊。"]'),
('e60d238a-7c7f-4954-b5ed-7f95ab830c2c','竹夫人','呂本中','宋','宋诗','song-poetry','','[]','與君宿昔尚同床，正坐西風一夜涼。',64,'全唐诗/poet.song.92000.json','["與君宿昔尚同床，正坐西風一夜涼。", "便學短檠墻角棄，不如團扇篋中藏。", "人情易變乃如此，世事多虞只自傷。", "却笑班姬與陳后，一生辛苦望專房。"]'),
('5b61e3f5-9abd-4af5-83a9-2381c7ccb631','郊居','呂本中','宋','宋诗','song-poetry','','[]','紛紛俗駕不容攀，尚喜郊居絕往還。',64,'全唐诗/poet.song.92000.json','["紛紛俗駕不容攀，尚喜郊居絕往還。", "野寺並冬終日雨，客房無事一秋閑。", "平生談說舌猶在，病起彫疏髩已斑。", "始悟莊周太多事，處夫才與不才間。"]'),
('4d4730ac-0524-4b9c-bee9-65130b68d5a0','送楊蒙秀才往樂平','呂本中','宋','宋诗','song-poetry','','[]','我有閩粤役，君成江浙行。',48,'全唐诗/poet.song.92000.json','["我有閩粤役，君成江浙行。", "窮途一回首，歲晚倍傷情。", "佳氣占行在，烟氛滿列營。", "如何抱奇策，不一請長纓。"]'),
('1c59fa79-ad07-49dc-ba3a-2abd00e2ae71','寄題暨尚卿雙蓮亭','呂本中','宋','宋诗','song-poetry','','[]','異畝同穎久未出，雙觡共抵復何物。',160,'全唐诗/poet.song.92000.json','["異畝同穎久未出，雙觡共抵復何物。", "今君何以得此花，和氣所致無他術。", "雙蓮共蔕中連理，相映同心出秋水。", "秋水池塘曉自涼，雙蓮中含風露香。", "飛燕姊妺不相妬，並騁逸艷來昭陽。", "自然容質見高韻，不必粉黛呈新粧。", "君家孝友聞近縣，故使奇祥眼中見。", "一洗東南戰鬬塵，小人知之亦革面。", "我來崎嶇山嶺間，忽聞雙蓮能解顔。", "請君更畫作圖看，毋使惡木譏彫殘。"]'),
('f8818e68-18a8-4e05-8742-6a526018091f','簡范信中鈐轄三首  其一','呂本中','宋','宋诗','song-poetry','','[]','交游契分如君少，湖嶺溪山似此稀。',32,'全唐诗/poet.song.92000.json','["交游契分如君少，湖嶺溪山似此稀。", "夾路梅花三十里，故人雖病莫先歸。"]'),
('6cc12e9a-c62e-48ac-9d6d-d367091224ae','簡范信中鈐轄三首  其二','呂本中','宋','宋诗','song-poetry','','[]','海角相逢又一奇，更憐朋舊得追隨。',32,'全唐诗/poet.song.92000.json','["海角相逢又一奇，更憐朋舊得追隨。", "滿堂舉酒話疇昔，疑是中原無事時。"]'),
('700cd4d9-3edb-4f78-bacc-2393fb623b44','簡范信中鈐轄三首  其三','呂本中','宋','宋诗','song-poetry','','[]','他日曹南十日雪，訪君尋酒不能回。',32,'全唐诗/poet.song.92000.json','["他日曹南十日雪，訪君尋酒不能回。", "梅花此日懷安路，更有清詩入座來。"]'),
('d70d8643-9380-4f80-af73-1f7b1e808342','次韻李仲輔僉判','呂本中','宋','宋诗','song-poetry','','[]','曉晴破雨却寒天，海上風光絕可憐。',32,'全唐诗/poet.song.92000.json','["曉晴破雨却寒天，海上風光絕可憐。", "更欲陪公了春事，不須乘醉始逃禪。"]'),
('504963ea-76e1-4191-bf45-8e7eedb8ae38','西施舌','呂本中','宋','宋诗','song-poetry','','[]','海上凡魚不識名，百千生命一杯羮。',32,'全唐诗/poet.song.92000.json','["海上凡魚不識名，百千生命一杯羮。", "無端更號西施舌，重與兒曹起妄情。"]'),
('7f6e0655-7264-45d3-8040-64498b5aa4dc','和秦楚材直閣韻','呂本中','宋','宋诗','song-poetry','','[]','胡馬南來議擊毬，忽聞羌虜斬楊酋。',64,'全唐诗/poet.song.92000.json','["胡馬南來議擊毬，忽聞羌虜斬楊酋。", "一年春事兵氛退，萬國歡聲佳氣浮。", "臺閣如君須强起，林泉容我且歸休。", "漢家基業無窮盡，早晚留侯與運籌。"]'),
('6c191a1f-724f-4f74-a6de-e322a4f70808','和展鉢詩','呂本中','宋','宋诗','song-poetry','','[]','紛紛未了向來因，同在浮漚寓此身。',64,'全唐诗/poet.song.92000.json','["紛紛未了向來因，同在浮漚寓此身。", "顧我久拚庵外事，知公曾是箇中人。", "齋盂已厭五鼎食，詩卷初無一點塵。", "今代王孫能樂此，中興祥瑞不緣麟。"]'),
('28b9f299-459c-4919-afcc-2d04beb7d978','鼓山','呂本中','宋','宋诗','song-poetry','','[]','危欄不知高，下瞰萬里路。',120,'全唐诗/poet.song.92000.json','["危欄不知高，下瞰萬里路。", "滄海近咫尺，大舶不敢度。", "風雲遞舒卷，川原更回互。", "如何此道場，乃倚絕壁住。", "得非化人居，無乃仙聖寓。", "斷崕石倒懸，絕壁水暗聚。", "我行天一涯，勝處時一遇。", "衰病九死餘，已乏濟勝具。", "登臨茲忘返，尚覺慰遲暮。", "山林與膏壤，未到已心悟。"]'),
('c8269afa-a49f-462a-818a-03a4dd1e2dcf','王傳巖起樂齋','呂本中','宋','宋诗','song-poetry','','[]','人生各有樂，所樂故不同。',144,'全唐诗/poet.song.92000.json','["人生各有樂，所樂故不同。", "吹竽與擊缶，同在可樂中。", "孰能識至樂，不計窮與通。", "顔子在陋巷，肯憂家屢空。", "朝從聖師游，暮歸無近功。", "忽然若有合，此樂固無窮。", "當時二三子，因之開蔽蒙。", "君生百世下，久已聞其風。", "端居有遐想，客至聊從容。", "四壁倚蓬蒿，萬卷蟠心胸。", "回視世所求，天道迷西東。", "此樂既不遠，欲往吾其從。"]'),
('249422cb-cd22-4274-8d55-f25b8104dc86','寄范四弟十弟','呂本中','宋','宋诗','song-poetry','','[]','俗事紛紛如亂麻，又扶衰病轉天涯。',64,'全唐诗/poet.song.92000.json','["俗事紛紛如亂麻，又扶衰病轉天涯。", "文章老矣思吾弟，頭角嶄然勝外家。", "異味幾回占食指，遠書終夕望燈花。", "何時更住城南寺，共聽春池兩部蛙。"]'),
('a6b875c1-a1da-408e-945d-68520f38b796','春日紀事寄內外諸弟三首  其一','呂本中','宋','宋诗','song-poetry','','[]','水生溪漲欲容舠，疾病因循厭作勞。',32,'全唐诗/poet.song.92000.json','["水生溪漲欲容舠，疾病因循厭作勞。", "莫道深居便無事，午窗疴癢費爬搔。"]'),
('f6181de3-fd8c-467a-ba73-b1ae59cfb02e','春日紀事寄內外諸弟三首  其二','呂本中','宋','宋诗','song-poetry','','[]','自聞賊報離揚州，凖擬春來泰出游。',32,'全唐诗/poet.song.92000.json','["自聞賊報離揚州，凖擬春來泰出游。", "所恨溪山最佳處，不容老子便歸休。"]'),
('177e89c8-0442-443a-a23d-6fdcec4ac959','春日紀事寄內外諸弟三首  其三','呂本中','宋','宋诗','song-poetry','','[]','長閑漸化讀書癖，遠道聊因避地行。',32,'全唐诗/poet.song.92000.json','["長閑漸化讀書癖，遠道聊因避地行。", "安得薄田了饘粥，便相依倚過平生。"]'),
('0aa825f7-27ac-4532-84b7-d6fd366093a6','寄諸弟','呂本中','宋','宋诗','song-poetry','','[]','九年任奔走，一飽費經營。',48,'全唐诗/poet.song.92000.json','["九年任奔走，一飽費經營。", "此日窮居意，他鄉獨往情。", "相憂只有病，所至但論兵。", "尚喜吾諸弟，形模遠勝兄。"]'),
('ae3e9c51-1e0c-4a6b-bd5b-d120c4548bad','游鳳池','呂本中','宋','宋诗','song-poetry','','[]','遠近諸山翠作堆，鳳池北望更崔嵬。',64,'全唐诗/poet.song.92000.json','["遠近諸山翠作堆，鳳池北望更崔嵬。", "青松夾路攙天去，白鳥翻雲旁海來。", "喜有故人同出郭，屬因衰病阻銜盃。", "猶憐不赴對牀約，獨上籃輿日暮回。"]'),
('7091a005-cb5d-46e0-bead-dc713aecbb50','題孫子紹所藏王摩詰渡水羅漢','呂本中','宋','宋诗','song-poetry','','[]','問渠褰裳欲何往，彷徨徙倚滄波上。',112,'全唐诗/poet.song.92000.json','["問渠褰裳欲何往，彷徨徙倚滄波上。", "至人入水固不濡，何以有此恐怖狀。", "我知摩詰意未真，欲以筆端調世人。", "此水此渡俱非實，摩詰亦未嘗下筆。", "孫郎寶藏今幾年，往來周旋兵火間。", "世人險阻更百難，彼渡水者安如山。", "請君但作如此觀，莫更思維尋筆端。"]'),
('4b03c559-43c2-4404-b91b-6294c86a1520','送筍與何晉之','呂本中','宋','宋诗','song-poetry','','[]','年來念念欲深藏，頗覺看書氣味長。',32,'全唐诗/poet.song.92000.json','["年來念念欲深藏，頗覺看書氣味長。", "莫怪囊空無一物，猶能分筍送何郎。"]'),
('23dc855f-29a4-4261-9d0c-dd6c2d750c9c','次韻李伯紀園亭  其一','呂本中','宋','宋诗','song-poetry','','[]','昔日翺翔雨露邊，已將勲業畫凌烟。',64,'全唐诗/poet.song.92000.json','["昔日翺翔雨露邊，已將勲業畫凌烟。", "便尋松菊同元亮，不訪丹砂學稚川。", "可但海山勝綠野，頗知風物似平泉。", "小園只在虛窗外，佳處常當几杖前。"]'),
('2dbc567f-444a-4eec-a384-9b48a513ac44','次韻李伯紀園亭  其二','呂本中','宋','宋诗','song-poetry','','[]','本無俗事可裝懷，藥圃花欄應手栽。',64,'全唐诗/poet.song.92000.json','["本無俗事可裝懷，藥圃花欄應手栽。", "乘興聊陪野僧坐，賞心時許故人來。", "頓令此地成三絕，不爲它鄉賦七哀。", "鐘鼎山林兩無礙，豫章須是棟梁材。"]'),
('9ae1ad10-c0eb-43dc-a4bf-091f167cb37c','送林之奇少穎秀才往行朝','呂本中','宋','宋诗','song-poetry','','[]','我爲福堂游，破屋占城市。',144,'全唐诗/poet.song.92000.json','["我爲福堂游，破屋占城市。", "城中幾萬戶，所識一林子。", "蓊然衆木中，見此真杞梓。", "未爲棟梁具，且映風日美。", "子之於爲學，其志蓋未已。", "上欲窮經書，下考百代史。", "發而爲文詞，一一當俊偉。", "夫豈效鄙夫，念彼不念此。", "今來赴行朝，學已優則仕。", "窮通决有命，所願求諸已。", "聖賢有明訓，不在於青紫。", "丈夫出事君，邪正從此始。"]'),
('28d96635-67cd-404f-ba28-975639179426','鄭昂用岑参太白胡僧歌韻作楞伽室老人歌寄杲老','呂本中','宋','宋诗','song-poetry','','[]','楞伽室中絕皂白，去天何止三百尺。',128,'全唐诗/poet.song.92000.json','["楞伽室中絕皂白，去天何止三百尺。", "只今更住最高峰，齋無木魚粥無鐘。", "已將虎兕等螻蟻，更許蛙蚓同蛟龍。", "聞道說禪通一線，爲爾不識楞伽面。", "一生强項我所知，氣壓霜皮四十圍。", "世人未辨此真僞，敢向楞伽論是非。", "諸公固是舊所適，鄭髯從之新有得。", "欲將此意向楞伽，但道鵠烏同一色。"]'),
('6ea66814-cfd4-4e11-8c35-20691a1446fb','贈王周士諸公','呂本中','宋','宋诗','song-poetry','','[]','空房夜氣清，落月傍簷明。',156,'全唐诗/poet.song.92000.json','["空房夜氣清，落月傍簷明。", "念我平生友，相望隔荒城。", "我老未厭書，破窗猶短檠。", "君亦不奈閑，黙坐數殘更。", "共結香火社，同尋文字盟。", "王子潮州來，一笑冠欹傾。", "午飯展僧鉢，村醪傾客瓶。", "相逢但談道，絕口不論兵。", "未免俗眼笑，屢遭時輩輕。", "人生各有趣，小大俱有程。", "譬彼澗底松，難伴池中萍。", "雲鵬與斥鷃，已矣兩忘情。", "一洗瘴海耳，此言君可聽。"]'),
('86cab05a-fe12-455b-b00f-f05b940cb4d6','贈范信中','呂本中','宋','宋诗','song-poetry','','[]','異時攜客醉公家，蠟燼堆盤酒過花。',64,'全唐诗/poet.song.92000.json','["異時攜客醉公家，蠟燼堆盤酒過花。", "萬里溪山隔春事，十年風景困胡沙。", "鄭莊好客渾如昨，何遜能詩老更佳。", "但得尊前添一笑，莫言漂泊在天涯。"]'),
('b1115892-207b-4985-8480-05d0bae251d9','會稽石道叟教授南劍兵火搶攘之餘興治郡學尺椽片瓦皆其所自經營也未朞月而學成遠近賴之又祠前輩賢者以風勵多士使游其間者望之而心化由是而入堯舜之道不難也古之教者蓋多術矣五帝憲三王有乞言憲賢于乞言也道叟知之矣呂本中爲作詩叙本末云','呂本中','宋','宋诗','song-poetry','','[]','聖遠道則微，世久學欲絕。',192,'全唐诗/poet.song.92000.json','["聖遠道則微，世久學欲絕。", "區區續微言，未易勝邪說。", "石侯東南秀，睹此心欲折。", "分教南劍州，意在補亡缺。", "欻令兵火後，復見俎豆設。", "廟貌甚尊嚴，上下有區别。", "先生黙無語，風化動閩粤。", "斯文自明白，如仰見日月。", "坐令穿鑿悞，不待湯沃雪。", "不知旁祠誰，今代古豪傑。", "孰能與之齊，共此歲寒節。", "入門日在望，未返意已竭。", "由來正心術，不在費頰舌。", "乃知薰陶功，自與聞見别。", "曾魯顔不愚，亦豈有優劣。", "此理倘可求，萬古同一轍。"]'),
('56fa4e22-582f-4f9f-86c3-b497af4766da','寄計議弟張彦實錢元成夏庭列','呂本中','宋','宋诗','song-poetry','','[]','遠書來稍稀，叔也經月病。',132,'全唐诗/poet.song.92000.json','["遠書來稍稀，叔也經月病。", "微官自拘束，歸興復未定。", "誰能相勞苦，頗亦奉朝請。", "安身子有道，可保在不競。", "寧聞鄭子真，肯待當世聘。", "張錢平生歡，未貴渠有命。", "舊交餘此人，豈减昔日盛。", "夏郎來幾時，問學當轉勝。", "高風隕寒梧，相助筆鋒勁。", "同歸定何日，不必有三徑。", "相從說平生，保此一室靜。"]'),
('e861daea-9bb8-4fcf-af62-7374213f3cad','寄內弟并示仲輔諸公','呂本中','宋','宋诗','song-poetry','','[]','江浙音書絕不聞，每逢時節嘆離羣。',64,'全唐诗/poet.song.92000.json','["江浙音書絕不聞，每逢時節嘆離羣。", "一秋多病常嫌客，短日無聊只閉門。", "淺學未容窺易象，舊書嬾復誦玄文。", "莫言耆舊彫零盡，海內交游尚數君。"]'),
('bd87e360-9d5b-44c0-b645-113cd5912c94','簡范信中','呂本中','宋','宋诗','song-poetry','','[]','詩人例窮君不然，畫堂繡户羅嬋娟。',112,'全唐诗/poet.song.92000.json','["詩人例窮君不然，畫堂繡户羅嬋娟。", "當時乘醉出三峽，至今妙句留西川。", "底事新來多退縮，梅花滿眼看未熟。", "便期載酒約來冬，似要惡詩相抵觸。", "曉來寒凜似中原，君忍閉門清晝眠。", "我病猶能相追逐，知君心期終不俗。", "但攜二妙喚諸公，一醉落花吾亦足。"]'),
('d444f457-6185-4378-bf41-767f04e33003','再簡范信中益謙呈張仲宗','呂本中','宋','宋诗','song-poetry','','[]','昨日之游樂不樂，主人愛客亦不惡。',124,'全唐诗/poet.song.92000.json','["昨日之游樂不樂，主人愛客亦不惡。", "梅花遠近遍川谷，雨練風揉未全落。", "明日之游復如何，城南城北梅更多。", "對酒我不飲，把琖君當歌。", "酒炙雖勤主人費，且幸吾黨頻相過。", "梅花縱落君莫歎，與君同住海南岸。", "花開花落都幾時，君醉我醒人得知。", "相逢一笑俱有詩，如何不飲令君嗤。"]'),
('9fca28b8-e467-4856-a12c-719f3a3dc96c','寄晁恭道鄭德成二漕','呂本中','宋','宋诗','song-poetry','','[]','二年住閩中，不識建溪茶。',120,'全唐诗/poet.song.92000.json','["二年住閩中，不識建溪茶。", "處處得殘杯，顧未愜齒牙。", "饑腸擁滯氣，病眼增昏花。", "故人持節來，憐我病有加。", "會當餉絕品，不但分新芽。", "蒼壁月墮曉，寶胯金披沙。", "一洗肝肺凈，兀坐如還家。", "陰雨又不解，天氣復未佳。", "持詩寄兩公，請爲交舊時。", "便續北苑譜，即日定等差。"]'),
('85416184-91b4-4a7b-86dd-a516c3811813','連得夏三十一翇兄弟范十五仲容趙十七穎達書相與甚勤作詩寄之','呂本中','宋','宋诗','song-poetry','','[]','閑居病亦侵，世務每絕念。',144,'全唐诗/poet.song.92000.json','["閑居病亦侵，世務每絕念。", "猶憐二三子，從我久未厭。", "書來不改昨，意苦辭亦贍。", "問我來何時，期我早會面。", "我行但謀食，欲去復未便。", "要當相就居，同止山水縣。", "讀我所傳書，亦足滿素願。", "開卷忽有得，如飲醇酒釅。", "吾聞古志士，學也蓋有漸。", "欲升夫子堂，不摘屈宋艶。", "倒籬望青天，豈必在窺覸。", "他時倘從容，此語子可驗。"]'),
('b0c236ca-1228-4239-a2f1-6841932d579c','送錢子虚撫幹往洪州赴新任二首  其一','呂本中','宋','宋诗','song-poetry','','[]','君不求時用，居然如病夫。',48,'全唐诗/poet.song.92000.json','["君不求時用，居然如病夫。", "經過閲歲月，相伴走江湖。", "白玉終無玷，寒松保不枯。", "同官多勝士，總爲致區區。"]'),
('ca0e5832-c7e5-41f7-b3c4-d3dfffd23b40','送錢子虚撫幹往洪州赴新任二首  其二','呂本中','宋','宋诗','song-poetry','','[]','老矣吾無用，歸歟子未宜。',48,'全唐诗/poet.song.92000.json','["老矣吾無用，歸歟子未宜。", "端能出奇策，略爲濟斯時。", "悶有書遮眼，閑須笏拄頤。", "西山有爽氣，當報故人知。"]'),
('07a61550-2b73-429e-abe1-1703da237ce6','題晁恭道善境界圖  其一','呂本中','宋','宋诗','song-poetry','','[]','疇昔相從三十年，如今休去不逃禪。',32,'全唐诗/poet.song.92000.json','["疇昔相從三十年，如今休去不逃禪。", "知君參見法輪老，始悟蒼蒼便是天。"]'),
('b0d0b821-4116-44fa-b94d-9584867b217f','題晁恭道善境界圖  其二','呂本中','宋','宋诗','song-poetry','','[]','境界本來無善惡，人間何處有新圖。',32,'全唐诗/poet.song.92000.json','["境界本來無善惡，人間何處有新圖。", "欲知箇裏真消息，臘月寒松永不枯。"]'),
('558567f4-4b0a-4992-a90c-5188fd43dafb','問乾元珪老','呂本中','宋','宋诗','song-poetry','','[]','問訊乾元老，江頭幾日回。',48,'全唐诗/poet.song.92000.json','["問訊乾元老，江頭幾日回。", "還應艤船待，不作御風來。", "漫有經旬别，頻思一笑開。", "庭前荔子熟，尚要著詩催。"]'),
('07f560c1-8055-40d6-aefb-2091a1fd27ce','贈楊紹祖','呂本中','宋','宋诗','song-poetry','','[]','城東往還者，相近得楊卿。',48,'全唐诗/poet.song.92000.json','["城東往還者，相近得楊卿。", "處世如無事，爲官不近名。", "匣藏防身劍，案有讀書檠。", "此外唯尊酒，時時喚客傾。"]'),
('306b28a8-c904-4194-937d-08b16a75e484','謝宇文漳州送茶','呂本中','宋','宋诗','song-poetry','','[]','暑氣侵人病逾劇，虚堂坐調出入息。',112,'全唐诗/poet.song.92000.json','["暑氣侵人病逾劇，虚堂坐調出入息。", "漳州太守送茶來，王圭小鳳俱無敵。", "太守憐我病無語，故遣此茶相勞苦。", "千金一餅君未許，百金一盞如潑乳。", "其它鬬芽未足數，下視紛紛等塵土。", "病夫未飲病先愈，坐覺爽氣生肺腑。", "城中車馬閙如雨，更有樂善如君否。"]'),
('721ead8a-01a8-4568-a6de-c4cc12788afd','夏日','呂本中','宋','宋诗','song-poetry','','[]','暑雨遂經月，客來困稍疏。',48,'全唐诗/poet.song.92000.json','["暑雨遂經月，客來困稍疏。", "閉門觀易象，反復看何如。", "妙處元非畫，微言不在書。", "故山初未遠，舉首是吾廬。"]'),
('365dbb55-f7c0-4cec-a73b-b11703a3666f','過劉忠顯公鄉縣作','呂本中','宋','宋诗','song-poetry','','[]','疾風知勁草，世亂識忠臣。',120,'全唐诗/poet.song.92000.json','["疾風知勁草，世亂識忠臣。", "自古有此語，今代豈無人。", "劉公生東南，節義邁等倫。", "時危出一死，以捍胡馬塵。", "遂令天下人，稍知吾道尊。", "至今生氣在，凜凜凌層雲。", "我行崇安野，瞻望彼高墳。", "流澤既未遠，有子賢而文。", "會當廣德業，早爲建殊勲。", "此意苟不泯，楚人生伍員。"]'),
('e19396a1-1164-4b7e-b3e2-4ac40bb9ef9e','夏日深居二首  其一','呂本中','宋','宋诗','song-poetry','','[]','匆匆車馬未言還，因病深居未得閑。',32,'全唐诗/poet.song.92000.json','["匆匆車馬未言還，因病深居未得閑。", "更爲故人留一夏，稍移行李過東山。"]'),
('1932da46-7759-48f9-a385-57ecb961d23b','夏日深居二首  其二','呂本中','宋','宋诗','song-poetry','','[]','故人多住城東寺，還許相過結净緣。',32,'全唐诗/poet.song.92000.json','["故人多住城東寺，還許相過結净緣。", "海寇求降荔子熟，是中風月可忘年。"]'),
('154b4532-f4d0-46e2-ae5a-1f47333a3612','乾元副寺欲還雲門','呂本中','宋','宋诗','song-poetry','','[]','子有四方志，雲門尋舊游。',48,'全唐诗/poet.song.92000.json','["子有四方志，雲門尋舊游。", "溪山往時夢，江海一番秋。", "物態隨高下，生涯任去留。", "閑将問庵主，如此是禪不。"]'),
('621aa4c2-9c15-42e3-baac-976e3435dbb1','慶堯侍者以詩相贈偶成絕句謝之','呂本中','宋','宋诗','song-poetry','','[]','滿城車馬雜塵埃，所至如雲撥不開。',32,'全唐诗/poet.song.92000.json','["滿城車馬雜塵埃，所至如雲撥不開。", "只有西禪堯侍者，肯衝劇暑送詩來。"]'),
('a2b36e50-a4af-4974-9a7b-f5f23728fc4a','渴雨簡張仲宗二首  其一','呂本中','宋','宋诗','song-poetry','','[]','强讀文書不補饑，只今一飽尚難期。',32,'全唐诗/poet.song.92000.json','["强讀文書不補饑，只今一飽尚難期。", "薄雲未肯蘇禾稼，細雨才堪濕荔枝。"]'),
('7519fbe4-a787-4c1b-92a1-536d1e00cdec','渴雨簡張仲宗二首  其二','呂本中','宋','宋诗','song-poetry','','[]','雨濕平林松桂香，斷雲冉冉拂疏篁。',32,'全唐诗/poet.song.92000.json','["雨濕平林松桂香，斷雲冉冉拂疏篁。", "江山故自可人意，從此歸休策最長。"]'),
('da4b0c5a-ca5d-4a61-b8ab-990b8827982a','謝楊紹祖惠玉友','呂本中','宋','宋诗','song-poetry','','[]','我來閩中居，中熱久斷酒。',108,'全唐诗/poet.song.92000.json','["我來閩中居，中熱久斷酒。", "端居苦無事，神氣思內守。", "故人憐我病，小缸送玉友。", "極知此不凡，嶺海見未有。", "感君意則重，納約况自牖。", "欣然洗盞嘗，不待捧素手。", "空杯貯玉色，一洗市沽醜。", "坐令百疾去，敢復望升斗。", "從令破酒戒，可以入道不。"]'),
('71f1dd39-36e3-4ca9-9415-51337c9a85af','與李似宗别後奉寄','呂本中','宋','宋诗','song-poetry','','[]','昔者相過今幾時，心期雖在事多疑。',64,'全唐诗/poet.song.92000.json','["昔者相過今幾時，心期雖在事多疑。", "滯留江海君先病，悵望雲山我欲歸。", "老境猶存作詩苦，故人多有食言肥。", "漢陰老父如無事，肯復逢人論是非。"]'),
('2761e22c-58a5-4b84-91c6-6d860813af9a','作雨不成旱暑愈甚未能就道','呂本中','宋','宋诗','song-poetry','','[]','三日陰風雨不成，坐嫌衝暑作宵征。',64,'全唐诗/poet.song.92000.json','["三日陰風雨不成，坐嫌衝暑作宵征。", "敢因貧故累公子，尚欲閑時尋友生。", "兵甲未休心已醉，詩書頗費眼猶明。", "便須凖擬庵居用，拄杖繩床折脚鐺。"]'),
('cf91551d-535e-4753-81f4-42bdf0080e2e','聞鵲','呂本中','宋','宋诗','song-poetry','','[]','一夏病如此，他鄉閑未回。',24,'全唐诗/poet.song.92000.json','["一夏病如此，他鄉閑未回。", "疏簷聞鵲喜，知有遠書來。"]'),
('24b9891d-a6ac-4a34-9afb-775f63092d39','荔子','呂本中','宋','宋诗','song-poetry','','[]','南征未厭苦關山，荔子今年已厭餐。',64,'全唐诗/poet.song.92000.json','["南征未厭苦關山，荔子今年已厭餐。", "時有野僧來獻供，每煩佳士約同槃。", "門前炎暑三伏旱，坐上冰霜六月寒。", "他日一尊須念此，中州傳買半棃乾。"]'),
('b8602d6f-e8c9-4445-aa42-ed4f94bd75e4','乾元真歇數約他日同庵居','呂本中','宋','宋诗','song-poetry','','[]','與君俱自走天涯，何處雲山不是家。',64,'全唐诗/poet.song.92000.json','["與君俱自走天涯，何處雲山不是家。", "城市少留真夢事，林泉高卧亦空花。", "久無佳句彫肝腎，漫有微言到齒牙。", "他日一庵如可必，願分齋罷半甌茶。"]'),
('7967197d-a9e0-4a0e-9999-4c6d63a3c0ee','将發福唐','呂本中','宋','宋诗','song-poetry','','[]','盡此一囊粟，我行當有期。',108,'全唐诗/poet.song.92000.json','["盡此一囊粟，我行當有期。", "涼風吹天涯，增我别後思。", "結束向行在，問子還何時。", "初無濟時策，處事多參差。", "環視中所有，無一施可宜。", "形骸久已病，敢徼當世知。", "不蒙朋友責，定遭兒輩嗤。", "矧此世外人，勸歸常恐遲。", "相尋有如日，請盟吾此詩。"]'),
('23bf7206-56f6-4fc5-96d4-8e829c2c8ddc','聽雨','呂本中','宋','宋诗','song-poetry','','[]','日數歸期似有期，故園無語說相思。',32,'全唐诗/poet.song.92000.json','["日數歸期似有期，故園無語說相思。", "芭蕉葉上三更雨，正是愁人睡覺時。"]'),
('c1f9a096-4c65-4143-be91-3078af6fe096','末利','呂本中','宋','宋诗','song-poetry','','[]','香如含笑全然勝，韵比酴醾更似高。',32,'全唐诗/poet.song.92000.json','["香如含笑全然勝，韵比酴醾更似高。", "所恨海濵出太遠，初無名字入風騷。"]'),
('1660e4f2-feb8-4d36-919f-9a32ce07e61e','聞二弟召對','呂本中','宋','宋诗','song-poetry','','[]','晚來忽雨已如秋，竹枕欹眠得自由。',64,'全唐诗/poet.song.92000.json','["晚來忽雨已如秋，竹枕欹眠得自由。", "忽報諸郎例升進，頗容老子便歸休。", "人傳胡虜三年旱，勢合山河一戰收。", "顧我迂疏最宜病，祗應隨處見莬裘。"]'),
('f933d346-8d70-4986-971e-99ce908904ae','夜涼早起尋李貽季陸慶長所惠詩有作','呂本中','宋','宋诗','song-poetry','','[]','夜長忘陰晴，忽聽簷雨滴。',108,'全唐诗/poet.song.92000.json','["夜長忘陰晴，忽聽簷雨滴。", "空房閉重門，涼氣通枕席。", "欣然欲攬被，如覓舊相識。", "那知庚伏內，得此睡通夕。", "起尋兩君詩，令我生氣力。", "成蹊長桃李，已自除荆棘。", "遠游得數士，舍此百無益。", "挑燈視皮膚，不顧蚊齩赤。", "因之不復寐，爲子增嘆息。"]'),
('8b9dd1e3-750f-4097-a68a-eafef9476ae5','聞大倫與三曾二范聚學并寄夏三十一四首  其一','呂本中','宋','宋诗','song-poetry','','[]','我思臨川居，欲往意未慊。',84,'全唐诗/poet.song.92000.json','["我思臨川居，欲往意未慊。", "每懷三二子，歲月多荏苒。", "後生慎所習，正是絲在染。", "未須極軒昂，且須就收斂。", "舉動思故人，此志豈不遠。", "才雖有高下，事亦要强勉。", "願爲江海深，莫作盆盎淺。"]'),
('a45df922-a876-47c2-adb2-4ae59c7ba48e','聞大倫與三曾二范聚學并寄夏三十一四首  其二','呂本中','宋','宋诗','song-poetry','','[]','世人爭錙銖，未語色已變。',60,'全唐诗/poet.song.92000.json','["世人爭錙銖，未語色已變。", "居然面頸赤，自處亦已賤。", "寧知烈士胸，渠自有志願。", "一介不妄取，萬鍾我亦倦。", "古人有伯夷，名冠太史傳。"]'),
('fbccb8c0-0d20-4bec-9ee5-bfddbde51fe2','聞大倫與三曾二范聚學并寄夏三十一四首  其三','呂本中','宋','宋诗','song-poetry','','[]','見人輒有求，所以百慮非。',48,'全唐诗/poet.song.92000.json','["見人輒有求，所以百慮非。", "但能守簞瓢，何事不可爲。", "愚夫飽欲死，志士固長饑。", "出門萬里塗，其亦慎所之。"]'),
('a76033a0-2305-4c9a-8568-98400d2bf85f','聞大倫與三曾二范聚學并寄夏三十一四首  其四','呂本中','宋','宋诗','song-poetry','','[]','莫惜一日勤，而忘終身憂。',48,'全唐诗/poet.song.92000.json','["莫惜一日勤，而忘終身憂。", "農夫力耕作，其必歲有秋。", "日前不鹵莽，久亦有倍收。", "少年不努力，老大復何求。"]'),
('77cd0541-cf2c-4947-b67e-66774969288d','别法一上人','呂本中','宋','宋诗','song-poetry','','[]','我有江浙役，子能乘興來。',48,'全唐诗/poet.song.92000.json','["我有江浙役，子能乘興來。", "便同湯院浴，却爲故人回。", "此道恐遂絕，後生良可哀。", "試尋鑰匙子，一一與重開。"]'),
('b0e47189-b819-4845-936f-5daf4e5b8bd8','别後寄珪粹中','呂本中','宋','宋诗','song-poetry','','[]','海上相逢兩過秋，飄然乘興亦悠悠。',32,'全唐诗/poet.song.92000.json','["海上相逢兩過秋，飄然乘興亦悠悠。", "送行百里還歸去，同是江湖不繫舟。"]'),
('c6865882-821e-48aa-ac4c-fd3312c48841','哭王元邁','呂本中','宋','宋诗','song-poetry','','[]','紛紛舉手爭毫末，砥柱當河獨不流。',32,'全唐诗/poet.song.92000.json','["紛紛舉手爭毫末，砥柱當河獨不流。", "一夕便隨波浪没，天涯黄葉更悲秋。"]'),
('ff50a9d9-ed12-4003-9cc1-736a0bb4c4e2','别林氏兄弟','呂本中','宋','宋诗','song-poetry','','[]','二年住閩嶺，所閲足青紫。',96,'全唐诗/poet.song.92000.json','["二年住閩嶺，所閲足青紫。", "那知萬衆中，得此數君子。", "相從不我厭，但覺歲月駛。", "高論脱時俗，如風濯煩暑。", "出處雖未同，氣味固相似。", "人生有離合，所畏爲物使。", "要當啜英華，不必計渣滓。", "他年肯相尋，在彼不在此。"]'),
('2d23d792-c3ff-49b4-b6a4-bceb881ea3c2','本中欲謀他日復來福唐之東山林少穎請作詩以記因成兩絕  其一','呂本中','宋','宋诗','song-poetry','','[]','老大馳驅百不宜，敢將筋力蹈危機。',32,'全唐诗/poet.song.92000.json','["老大馳驅百不宜，敢將筋力蹈危機。", "他年更欲眠雲住，同過東山嘗荔枝。"]'),
('0fc74c53-72d4-48b2-895b-e15bcfef1021','本中欲謀他日復來福唐之東山林少穎請作詩以記因成兩絕  其二','呂本中','宋','宋诗','song-poetry','','[]','更作東山住，尋盟尚有詩。',24,'全唐诗/poet.song.92000.json','["更作東山住，尋盟尚有詩。", "看君騰踏去，及我未歸時。"]'),
('8f12fa76-c5ff-4358-b0d4-41233a11e9bb','謝人惠陳家紫','呂本中','宋','宋诗','song-poetry','','[]','煩君惠我陳家紫，萬里漂流合得嘗。',32,'全唐诗/poet.song.92000.json','["煩君惠我陳家紫，萬里漂流合得嘗。", "莫道聞名不相識，舊隨籩實到吾鄉。"]'),
('734c6c55-a0f5-452c-87d8-3621ea4b85b4','閑居感舊偶成十絕乘興有作不復詮次  其一','呂本中','宋','宋诗','song-poetry','','[]','四海交遊一信民，後來情分更誰親。',32,'全唐诗/poet.song.92000.json','["四海交遊一信民，後來情分更誰親。", "可憐相伴谿堂老，一去塵寰三十春。"]'),
('fd864b37-104d-4c00-9483-0a928c0d7df0','閑居感舊偶成十絕乘興有作不復詮次  其二','呂本中','宋','宋诗','song-poetry','','[]','一世聲名高與關，亦知不合住人間。',32,'全唐诗/poet.song.92000.json','["一世聲名高與關，亦知不合住人間。", "不令整頓乾坤了，虚逐松聲半夜還。"]'),
('6cecb052-247a-486c-9906-e660a864f657','閑居感舊偶成十絕乘興有作不復詮次  其三','呂本中','宋','宋诗','song-poetry','','[]','璧老投冠去學禪，堂堂一鼓陣無前。',32,'全唐诗/poet.song.92000.json','["璧老投冠去學禪，堂堂一鼓陣無前。", "平生老伴唯均父，馬病塗窮不著鞭。"]'),
('8c442fa1-a8be-40cc-ac81-74b96f134ca3','閑居感舊偶成十絕乘興有作不復詮次  其四','呂本中','宋','宋诗','song-poetry','','[]','屏醫郤藥病良已，絕學捐書我又休。',32,'全唐诗/poet.song.92000.json','["屏醫郤藥病良已，絕學捐書我又休。", "却到舊時行履處，五湖烟水上漁舟。"]'),
('7fa9cb8e-7919-4098-8064-38c8ff3937ee','閑居感舊偶成十絕乘興有作不復詮次  其五','呂本中','宋','宋诗','song-poetry','','[]','萬里飄然不繫舟，老來專憶舊交游。',32,'全唐诗/poet.song.92000.json','["萬里飄然不繫舟，老來專憶舊交游。", "西風日落中原路，虚度江湖數十秋。"]'),
('e1b0a8fe-a0e9-4ec8-a4d0-951dba5a562e','閑居感舊偶成十絕乘興有作不復詮次  其六','呂本中','宋','宋诗','song-poetry','','[]','唐子直心絕可憐，夏侯苦節更誰傳。',32,'全唐诗/poet.song.92000.json','["唐子直心絕可憐，夏侯苦節更誰傳。", "諸晁事業風流在，各有殘詩十數篇。"]'),
('53a63ad6-c355-45c2-8b78-3db42c297445','閑居感舊偶成十絕乘興有作不復詮次  其七','呂本中','宋','宋诗','song-poetry','','[]','平生親愛獨諸晁，叔也相親共寂寥。',32,'全唐诗/poet.song.92000.json','["平生親愛獨諸晁，叔也相親共寂寥。", "半日不來須折簡，暫時相遠定相招。"]'),
('c25f6e1e-c2a4-428e-93e6-4a6739c646f5','閑居感舊偶成十絕乘興有作不復詮次  其八','呂本中','宋','宋诗','song-poetry','','[]','病夫長病合長饑，豈復輕隨世上兒。',32,'全唐诗/poet.song.92000.json','["病夫長病合長饑，豈復輕隨世上兒。", "雲雨覆翻渠有分，江湖潦倒我無知。"]'),
('efcd3346-c2d7-4c6f-ae2d-572e2018b470','閑居感舊偶成十絕乘興有作不復詮次  其九','呂本中','宋','宋诗','song-poetry','','[]','曾郎學行冠姻親，趙子才能又絕倫。',32,'全唐诗/poet.song.92000.json','["曾郎學行冠姻親，趙子才能又絕倫。", "仲弟故應同二妙，一時先後委埃塵。"]'),
('59ad9e4e-9639-4c56-9332-bd0379e111b6','閑居感舊偶成十絕乘興有作不復詮次  其一○','呂本中','宋','宋诗','song-poetry','','[]','便欲長休老未能，爾來頻愧住庵僧。',32,'全唐诗/poet.song.92000.json','["便欲長休老未能，爾來頻愧住庵僧。", "直須棄盡人間事，始見從來一點燈。"]'),
('46164aaf-82b9-4eec-8fc6-ffc1535426ae','温泉','呂本中','宋','宋诗','song-poetry','','[]','海上秋來早晚涼，客愁蘇醒似還鄉。',32,'全唐诗/poet.song.92000.json','["海上秋來早晚涼，客愁蘇醒似還鄉。", "歸途尚欲療瘡疥，剩乞温泉一勺湯。"]'),
('58f4d8f9-c392-4886-bbf7-31f3c92f4428','将去福州','呂本中','宋','宋诗','song-poetry','','[]','委曲隨人久未甘，翛然午枕睡方酣。',64,'全唐诗/poet.song.92000.json','["委曲隨人久未甘，翛然午枕睡方酣。", "功名到此終無分，身世從來百不堪。", "爲己工夫今粗曉，住山活計久相諳。", "他時不用求三徑，投老才須住一庵。"]'),
('39320bd9-6eb8-48d1-b545-a65f25e5ea36','初秋','呂本中','宋','宋诗','song-poetry','','[]','涼風驚木葉，意欲作深秋。',48,'全唐诗/poet.song.92000.json','["涼風驚木葉，意欲作深秋。", "客病渾如昨，囊空却自由。", "因閑得飲酒，端坐勝封侯。", "寄語平生友，當能爲我謀。"]'),
('748ae73c-f1b1-451e-b36c-79d978cdf5f0','奉呈鼓山雲門二老','呂本中','宋','宋诗','song-poetry','','[]','汝水相逢今幾年，只今同住海南偏。',64,'全唐诗/poet.song.92000.json','["汝水相逢今幾年，只今同住海南偏。", "月明本自無虧缺，山色何嘗有變遷。", "他日會逢晜弟語，一時驚散老狐禪。", "倘因居士閑開口，却作冲和二月天。"]'),
('844b0a08-3792-47bd-92f9-ffb8ed212f2b','從叔巽叔覓茶','呂本中','宋','宋诗','song-poetry','','[]','疾病侵凌轉不堪，時思一室奉清談。',32,'全唐诗/poet.song.92000.json','["疾病侵凌轉不堪，時思一室奉清談。", "嗣宗已餉兵廚酒，當有新茶惠阿咸。"]'),
('bf74a61f-c0d5-4e2d-aa93-8d4b9e19b7b3','福建界首寄福州親舊','呂本中','宋','宋诗','song-poetry','','[]','海上秋風吹客衣，屢煩親舊送将歸。',32,'全唐诗/poet.song.92000.json','["海上秋風吹客衣，屢煩親舊送将歸。", "今朝更入江東路，便恐書來即漸稀。"]'),
('3b18408b-9abb-4908-a274-3e61e3a98298','嚴州九日坐上贈胡明仲常子正','呂本中','宋','宋诗','song-poetry','','[]','今年得交舊，九日會嚴州。',72,'全唐诗/poet.song.92000.json','["今年得交舊，九日會嚴州。", "城角風雲暮，天涯景色秋。", "功名有長鋏，行李付扁舟。", "苦恨三年别，聊因一笑留。", "病添文字嬾，老恥稻粱謀。", "活國須公等，吾生便可休。"]'),
('66332c96-7880-4584-9334-ecc3cf9fa3ee','方允迪挽詞二首  其一','呂本中','宋','宋诗','song-poetry','','[]','已矣儒林老，今爲地下郎。',48,'全唐诗/poet.song.92000.json','["已矣儒林老，今爲地下郎。", "空山留几杖，遺稿漫文章。", "徑狹風霜遠，溪深草木長。", "傷心釣臺路，千載閟幽光。"]'),
('af1ef163-878a-4e5b-a6fe-0a9c870788b8','方允迪挽詞二首  其二','呂本中','宋','宋诗','song-poetry','','[]','惟君好兄弟，少小共聲名。',48,'全唐诗/poet.song.92000.json','["惟君好兄弟，少小共聲名。", "豈止千人傑，俱爲一代英。", "云何卧丘壑，不使至公卿。", "慟哭松風遠，悲雲咽莫聲。"]'),
('41212c2f-185e-4aa6-8967-85f85f0fb96f','程伯禹母夫人挽詩二首  其一','呂本中','宋','宋诗','song-poetry','','[]','久矣閨門秀，端如玉在淵。',48,'全唐诗/poet.song.92000.json','["久矣閨門秀，端如玉在淵。", "相夫成令德，教子作名賢。", "遽逐秋風盡，空令莫景遷。", "傷心江左地，松柏閉新阡。"]'),
('c3abca9e-870c-46f7-9e1e-b36d1f01b7f1','程伯禹母夫人挽詩二首  其二','呂本中','宋','宋诗','song-poetry','','[]','舊隨賢子後，每得熟嚴規。',48,'全唐诗/poet.song.92000.json','["舊隨賢子後，每得熟嚴規。", "未獲升堂拜，空成相挽詩。", "爵頻賜湯沐，壽不到期頤。", "他日家聲在，流傳世未知。"]'),
('2db52902-230a-42b9-b62d-b2ac48cf3d85','送范師厚宣諭四川','呂本中','宋','宋诗','song-poetry','','[]','老境侵尋久廢詩，送君寧復似當時。',64,'全唐诗/poet.song.92000.json','["老境侵尋久廢詩，送君寧復似當時。", "虺隤病馬猶長路，偃蹇寒松只舊枝。", "想得山川瞻使節，便令父老識家規。", "聖朝本意惟寛大，網漏吞舟始合宜。"]'),
('7f999f99-cbab-4573-a61c-eedc4c76d0ff','贈了老','呂本中','宋','宋诗','song-poetry','','[]','前年見公滄海上，法會堂堂萬騎将。',112,'全唐诗/poet.song.92000.json','["前年見公滄海上，法會堂堂萬騎将。", "今年見公浙河東，猶是當時舊老翁。", "送行更有天童老，騏驥齊驅獵霜草。", "野狐射干膽欲破，不但獨噴羣馬倒。", "我衰且病百念絕，便得從公不爲早。", "忘情遁跡亦未是，言與不言俱一掃。", "世人擾擾不歸家，公行問渠有何好。"]'),
('f5652860-a9ea-4397-947e-2fab488b699c','送楊晨當時赴夔漕','呂本中','宋','宋诗','song-poetry','','[]','楊侯從舊名籍籍，吳中一見如舊識。',128,'全唐诗/poet.song.92000.json','["楊侯從舊名籍籍，吳中一見如舊識。", "憐我衰頽病已侵，怪我辛勤百無益。", "今君遽作巴蜀行，江頭宿昔春水生。", "路經三峽不艱阻，遍與疲民問疾苦。", "隨身長劍莫輕舞，試伐蛟鼉斬豺虎。", "此來人士衆如雨，得君此行慰羈旅。", "君但垂情一笑許，勝使區區入州府。", "百城因之遂安堵，亦勝無事閑坐否。"]'),
('c9835fe7-443a-4865-a616-c1b921e87367','送徐林稚山赴江西漕','呂本中','宋','宋诗','song-poetry','','[]','總角相從四十年，如今衰病已華顛。',64,'全唐诗/poet.song.92000.json','["總角相從四十年，如今衰病已華顛。", "久無耆老可訪事，尚喜交游不乏賢。", "未使從容持從橐，却令辛苦上江船。", "百城編户皆疲瘵，日望公來與息肩。"]'),
('80ecef91-8938-4285-aa46-600cbc683344','將發金陵奉懷張彦實','呂本中','宋','宋诗','song-poetry','','[]','老矣君何往，翩然我欲歸。',48,'全唐诗/poet.song.92000.json','["老矣君何往，翩然我欲歸。", "文章晚未用，歲月事多違。", "江接鄱陽路，風吹游子衣。", "不應蘧伯玉，獨悟昔年非。"]'),
('5455e51b-5e9a-43b9-9731-bd33d5192e7d','初離建康  其一','呂本中','宋','宋诗','song-poetry','','[]','嘗憶他年出舊京，汴堤榆柳與船平。',32,'全唐诗/poet.song.92000.json','["嘗憶他年出舊京，汴堤榆柳與船平。", "寧知此日鍾山路，亦是東行第一程。"]'),
('7d339f9d-991b-4bb5-b2be-4b5d9eddb169','初離建康  其二','呂本中','宋','宋诗','song-poetry','','[]','紛紛車馬未言還，我獨支離便得閑。',32,'全唐诗/poet.song.92000.json','["紛紛車馬未言還，我獨支離便得閑。", "尚有同門二三子，肯同今夜宿鍾山。"]'),
('3a37066e-3a47-4554-bb40-3c2632ded7e9','寓會稽禹迹寺','呂本中','宋','宋诗','song-poetry','','[]','陰雨靜不出，端居還自由。',48,'全唐诗/poet.song.92000.json','["陰雨靜不出，端居還自由。", "客來從短褐，天氣已深秋。", "所在兵猶鬬，中原亂不休。", "廟堂如有意，便與萬人謀。"]'),
('05e2f61f-2f60-4b67-a5b0-57a6e5057f34','會稽初秋四首  其一','呂本中','宋','宋诗','song-poetry','','[]','今來留滯浙河東，想見閩山荔子紅。',32,'全唐诗/poet.song.92000.json','["今來留滯浙河東，想見閩山荔子紅。", "雖有故人家在彼，可無方便託西風。"]'),
('f63a886a-aa02-4d09-b653-7bd4d810aff8','會稽初秋四首  其二','呂本中','宋','宋诗','song-poetry','','[]','張侯問舍復何時，我亦留連去未期。',32,'全唐诗/poet.song.92000.json','["張侯問舍復何時，我亦留連去未期。", "便欲爲君草堂客，幾時先寄落成詩。"]'),
('6677dd57-3abf-4c46-a0c5-8c0bc5d72af6','會稽初秋四首  其三','呂本中','宋','宋诗','song-poetry','','[]','故園回首但斜陽，所至奔波避賊忙。',32,'全唐诗/poet.song.92000.json','["故園回首但斜陽，所至奔波避賊忙。", "天下何曾有定處，越南燕北是中央。"]'),
('562d2c75-5f53-4082-9743-c7565ab19d6a','會稽初秋四首  其四','呂本中','宋','宋诗','song-poetry','','[]','病來每有居山興，老去初無住世心。',32,'全唐诗/poet.song.92000.json','["病來每有居山興，老去初無住世心。", "三尺枯桐無舊譜，始知三歎有遺音。"]'),
('0fd26de5-0b67-4327-bed1-e0c47fc718f1','錢遜叔侍郎奉京師舊墳改葬天柱謹成挽詩一首','呂本中','宋','宋诗','song-poetry','','[]','錢氏霸吳越，功德在斯民。',180,'全唐诗/poet.song.92000.json','["錢氏霸吳越，功德在斯民。", "遜王早退居，身退道益尊。", "至今二百年，盛事傳後昆。", "文采震本朝，豈惟光一門。", "後來翰林公，又以直聲聞。", "累葉其外家，家世悉殊勲。", "善惡久乃效，其報于此分。", "裔孫傑立者，迎喪自中原。", "遂令擾攘後，得安久旅魂。", "依依天柱山，不必京洛塵。", "死者如有知，當言吾有孫。", "小人託末契，所恨老不文。", "睹此一時盛，忍終無一言。", "越水流不竭，越山旱不昏。", "孝子亦不匱，錫類到礽雲。"]'),
('bb8c1f2b-299b-4687-a546-fde3618f39b6','重陽日西興寄臨安親舊','呂本中','宋','宋诗','song-poetry','','[]','我來西興口，君在龍山旁。',48,'全唐诗/poet.song.92000.json','["我來西興口，君在龍山旁。", "如何阻一水，不共作重陽。", "别浦潮猶白，深秋菊未黄。", "遥知對杯酌，不記是他鄉。"]'),
('ef2b38ce-51a1-43b8-a3fb-e551d4c513d0','范伯言藥隱','呂本中','宋','宋诗','song-poetry','','[]','烈士故徇名，中民但榮官。',180,'全唐诗/poet.song.92000.json','["烈士故徇名，中民但榮官。", "寧知陋巷士，堅坐有餘歡。", "出從聖師游，歸坐守一簞。", "出門視天壤，密邇心自寛。", "范侯嬾仕宦，决意歸西山。", "西山有藥隱，此地可盤桓。", "誓將從古人，上追孔與顔。", "有田可以耕，有屋可以安。", "寧能伴兒曹，日夜不得閑。", "我亦倦游者，世味更百難。", "夢寐想君家，父子兄弟間。", "便當卜隣居，一生長往還。", "相依得情話，出語清肺肝。", "後生有郢質，更爲斵其漫。", "君行問安否，此盟當未寒。"]'),
('cf46edd8-2927-48a1-beb0-cf524858a54c','題趙祖文盤谷圖','呂本中','宋','宋诗','song-poetry','','[]','趙郎落筆寫盤谷，正是太平無事時。',32,'全唐诗/poet.song.92000.json','["趙郎落筆寫盤谷，正是太平無事時。", "今日太行那有此，滿山樵採盡癡兒。"]'),
('40356311-e937-4011-8ab2-a54a84af2154','送胡明仲知永州','呂本中','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','君行西游浮沅湘，洞庭岳麓天一方。',160,'全唐诗/poet.song.92000.json','["君行西游浮沅湘，洞庭岳麓天一方。", "岳前老人望君久，歲晚不嫌歸路長。", "晴天萬里去鴻鵠，韞玉未售猶深藏。", "遠行固是君素願，多蓄奇謀羞自獻。", "後生紛紛了目前，大策定非凡所見。", "簿書汩沒渠自忙，道里嵠嶇我不倦。", "百州東下例無澗，要君嶷然如斷山。", "我老無用逢多艱，敢復著腳塵埃間。", "胸次偪塞良未寛，日夜矯首須君還。", "運斤成風君不難，不使世人漫鼻端。"]'),
('c450f75e-aa9b-41ba-95ce-9a63fc83dec5','孫首之短堂','呂本中','宋','宋诗','song-poetry','','[]','孫郎囊空意且滿，因謂身長才則短。',64,'全唐诗/poet.song.92000.json','["孫郎囊空意且滿，因謂身長才則短。", "以短名堂堂未成，長短是非俱不管。", "嚴州一見鬢倉浪，贈我新詩如夜光。", "何時到君短堂上，更話如今歸興長。"]'),
('f8411bd1-9e7b-4ea6-95cc-29dffca9b9f2','贈孫首之','呂本中','宋','宋诗','song-poetry','','[]','子窮非一時，所歷固長久。',144,'全唐诗/poet.song.92000.json','["子窮非一時，所歷固長久。", "自從太平時，以至戎馬後。", "今兹益窮甚，所至但縮手。", "遂令甑生塵，不止衿見肘。", "未能脱身去，且作避地走。", "金盤貯火齊，熟視不一取。", "溪船下濤江，亦未還南斗。", "固知松柏生，必不在培塿。", "見我嚴州城，世事嬾到口。", "念子抱奇才，有節空自守。", "簞瓢在陋巷，世亦如此不。", "乘離勿重言，寒甚且飲酒。"]'),
('57560ac9-098a-48ae-903a-95619dbcc073','朱成伯秀野堂','呂本中','宋','宋诗','song-poetry','','[]','客愁固多岐，我懷亦蕭散。',144,'全唐诗/poet.song.92000.json','["客愁固多岐，我懷亦蕭散。", "連年尋故人，見子二水岸。", "官居少閑暇，歲月忽已換。", "有堂名秀野，未入俗眼看。", "得名自君子，可當清淨觀。", "未能藝桃李，且自飽藜莧。", "荒涼城一隅，初不越門限。", "脱身少年場，念此已熟爛。", "嗟予老病侵，閲世蓋多難。", "相逢黙無語，自足洗憂患。", "窮冬足雨雪，近市乏薪炭。", "時來正堂堂，尚得一笑粲。"]'),
('57b05077-e6a2-4187-8f20-43bd9796e702','次秀亭韻二首  其一','呂本中','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','忽見新亭起廢基，暮雲疏雨兩霏霏。',64,'全唐诗/poet.song.92000.json','["忽見新亭起廢基，暮雲疏雨兩霏霏。", "憑欄一望長江遠，鑿石新開小徑微。", "治世從今可招隱，至人何苦更藏輝。", "使君不厭賓朋集，正爲飄流到眼稀。"]'),
('56b28b20-4740-406c-9481-3d4e17b80372','次秀亭韻二首  其二','呂本中','宋','宋诗','song-poetry','','[]','舟車來往閙回環，今日陪公得暫閑。',64,'全唐诗/poet.song.92000.json','["舟車來往閙回環，今日陪公得暫閑。", "漸喜著身人迹外，勝如隨衆馬蹄間。", "縈紆細數溪頭路，蒼翠遥看雨後山。", "正恐朝廷須舊物，不容常此面孱顔。"]'),
('de75968a-6a63-440b-9fee-d856e85930c2','甘棠樓','呂本中','宋','宋诗','song-poetry','','[]','高樓面面好，舉目是溪山。',96,'全唐诗/poet.song.92000.json','["高樓面面好，舉目是溪山。", "急水瀉湍瀨，諸峰呈髻鬟。", "聊爲半日出，得伴使君閑。", "作者風流在，承平氣象還。", "身雖住世網，心已離塵寰。", "未厭陪游數，唯愁覓句慳。", "高風雖在望，逸韻恐難攀。", "咫尺蓬萊路，惟公指顧間。"]'),
('f57a2e46-cb27-4cdb-a7f4-c9fa67390f11','師奴病化  其一','呂本中','宋','宋诗','song-poetry','','[]','伴我閑中氣味長，竹輿游歷徧諸方。',64,'全唐诗/poet.song.92000.json','["伴我閑中氣味長，竹輿游歷徧諸方。", "火邊每與人爭席，睡起偏嫌犬吠床。", "能與兒童較幾許，賢于臧獲便相忘。", "他生尚欲隨吾在，要奉香爐漉水囊。"]'),
('e74076cd-cd84-46c0-9d35-b680889439b7','師奴病化  其二','呂本中','宋','宋诗','song-poetry','','[]','受戒不捕鼠，聽經如欲譍。',24,'全唐诗/poet.song.92000.json','["受戒不捕鼠，聽經如欲譍。", "誰知兩溪畔，今日送亡僧。"]'),
('d4a851bd-cbd2-49f8-848c-d248c32b7bf3','舟行至桐廬','呂本中','宋','宋诗','song-poetry','','[]','乘舟待潮發，一日到桐廬。',48,'全唐诗/poet.song.92000.json','["乘舟待潮發，一日到桐廬。", "物色寒初甚，溪山畫不如。", "往來真是夢，親舊不須書。", "猶勝鴟夷在，時容託後車。"]'),
('e329be7d-3228-45ca-bc97-d87eae113c2e','示兒','呂本中','宋','宋诗','song-poetry','','[]','忍窮吾有味，雕句汝無功。',48,'全唐诗/poet.song.92000.json','["忍窮吾有味，雕句汝無功。", "客舍囂塵裏，春隨浩蕩中。", "初無買山費，真與住庵同。", "更想顔氏宅，簞瓢亦屢空。"]'),
('7486004d-7198-46a4-ac28-1aa339ebb814','陳朝奉坐化','呂本中','宋','宋诗','song-poetry','','[]','東風吹雨欲翻盆，杏樹前頭柳暗村。',32,'全唐诗/poet.song.92000.json','["東風吹雨欲翻盆，杏樹前頭柳暗村。", "試問老人何處去，夜來新月又黄昏。"]'),
('c88fdf3a-fc41-44c3-9db4-a7d79076e191','嚴州春曉  其一','呂本中','宋','宋诗','song-poetry','','[]','居閑病常攖，出郭春已老。',48,'全唐诗/poet.song.92000.json','["居閑病常攖，出郭春已老。", "微雨淨新綠，轉覺原野好。", "故人各漂散，頗恨來不早。", "尚有壁間詩，猶堪寫懷抱。"]'),
('7bf837e5-cf46-434f-a8cb-015f769814bf','嚴州春曉  其二','呂本中','宋','宋诗','song-poetry','','[]','是月足陰晦，暮春常苦寒。',48,'全唐诗/poet.song.92000.json','["是月足陰晦，暮春常苦寒。", "閉門猶疾病，春物豈相干。", "堅坐客已少，長貧心自安。", "幽蘭有花在，尚肯結餘歡。"]'),
('1154305c-0b5b-4583-9b07-3f4229c5b31f','子将爲三衢之行下塔僧惠道求詩留題因成絕句遺之','呂本中','宋','宋诗','song-poetry','','[]','欲過城東病不能，飛簷高棟想層層。',32,'全唐诗/poet.song.92000.json','["欲過城東病不能，飛簷高棟想層層。", "半年夢作嚴州住，一首詩留塔下僧。"]'),
('61fa40ce-a44a-4f7b-8f27-5830acfa9269','将適三衢而七弟欲往臨安臨行作詩奉送','呂本中','宋','宋诗','song-poetry','','[]','弟要題詩别，人還勸我留。',48,'全唐诗/poet.song.92000.json','["弟要題詩别，人還勸我留。", "如何南去路，更送北行舟。", "處事須遠略，擇交當廣求。", "秋風理歸棹，爲我上衢州。"]'),
('b4444bf4-09a0-4c35-b57e-17ebe3dae731','椿閣  其一','呂本中','宋','宋诗','song-poetry','','[]','往時椿閣老，盛德傳鄉閭。',24,'全唐诗/poet.song.92000.json','["往時椿閣老，盛德傳鄉閭。", "至今風流在，遺芳殊未疏。"]'),
('ec6cc1d6-d030-4682-b19e-985134a381b3','椿閣  其二','呂本中','宋','宋诗','song-poetry','','[]','有孫仁者靜，遠近伏共賢。',24,'全唐诗/poet.song.92000.json','["有孫仁者靜，遠近伏共賢。", "定知建德民，祝令如翁年。"]'),
('913938fe-143e-41c7-b3de-dd7a716a14fe','弋陽魏令賞音亭','呂本中','宋','宋诗','song-poetry','','[]','高亭已寂寞，山水自清音。',48,'全唐诗/poet.song.92000.json','["高亭已寂寞，山水自清音。", "主人去已久，此意誰復尋。", "夢回還舊觀，川上有微吟。", "于焉繼前作，因見平生心。"]'),
('af4eed37-cb4f-474d-9857-f312a496fc04','建安熊述之爲令建德不言而民治将適三衢留詩美之二首  其一','呂本中','宋','宋诗','song-poetry','','[]','熊卿治建德，隱几心若水。',48,'全唐诗/poet.song.92000.json','["熊卿治建德，隱几心若水。", "民肥吏乾枯，亦不用笞箠。", "問子何能然，此豈力可使。", "建安今多賢，于子可見爾。"]'),
('db513673-b229-4383-9814-9ee4d0d533a4','建安熊述之爲令建德不言而民治将適三衢留詩美之二首  其二','呂本中','宋','宋诗','song-poetry','','[]','建安固多賢，故人劉與胡。',48,'全唐诗/poet.song.92000.json','["建安固多賢，故人劉與胡。", "山川古秀潤，珠生崖不枯。", "我病日已懶，觸事見迂疏。", "行當脱身去，一廛從子居。"]'),
('c8d75c76-2a19-459d-a957-f4b29d56cb28','擬古樂府','呂本中','宋','宋诗','song-poetry','','[]','高堂陳八音，同聽不同樂。',60,'全唐诗/poet.song.92000.json','["高堂陳八音，同聽不同樂。", "狂飈送鴻鵠，萬里翔寥廓。", "一去三十年，事事非前約。", "當時綠綺琴，塵埃無處著。", "時節非不久，此意但如昨。"]'),
('a158df3c-5db7-4f0c-8602-2c9e461837df','己未重陽','呂本中','宋','宋诗','song-poetry','','[]','病無佳思只深藏，漫遶東籬菊未黄。',32,'全唐诗/poet.song.92000.json','["病無佳思只深藏，漫遶東籬菊未黄。", "最是一年秋好處，可能無酒過重陽。"]'),
('32ebf046-89e0-43bd-8d9d-25220044e13f','李珹拙軒','呂本中','宋','宋诗','song-poetry','','[]','念彼巧者勞，知此拙者安。',120,'全唐诗/poet.song.92000.json','["念彼巧者勞，知此拙者安。", "拙者固無營，一生長得閑。", "子豈真拙者，託此以自安。", "何嘗曵長裾，顧肯卑小官。", "世人極變態，翻手覆手間。", "子獨如不聞，黙坐安如山。", "九衢走紅塵，百事不相干。", "我老始見子，古井久不瀾。", "贈子拙軒詩，留子靜處看。", "當蒙一笑許，敢言愁肺肝。"]'),
('3ce1d041-0463-4875-99dc-d42cfdc37d1c','清慎軒','呂本中','宋','宋诗','song-poetry','','[]','清慎軒中一事無，午窗高枕似吾廬。',32,'全唐诗/poet.song.92000.json','["清慎軒中一事無，午窗高枕似吾廬。", "世人稱意何須道，乃祖風流正不疏。"]'),
('95eb6b1b-e4de-4d92-9841-8596d2fb7d72','将往城南觀音寺阻雨未果','呂本中','宋','宋诗','song-poetry','','[]','野寺他年别，溪山浪作秋。',48,'全唐诗/poet.song.92000.json','["野寺他年别，溪山浪作秋。", "初涼頗宜出，小雨故妨游。", "僧老渾無念，田荒近不收。", "猶思五更懴，清切勝蠻謳。"]'),
('cfa58d75-a279-4734-b1c5-b30b350059d9','余迪漫浪齋','呂本中','宋','宋诗','song-poetry','','[]','顔子在陋巷，無一當其心。',96,'全唐诗/poet.song.92000.json','["顔子在陋巷，無一當其心。", "日惟聖之學，正自惜分陰。", "子生千載後，此意尚能尋。", "齋雖名漫浪，跡豈計浮沉。", "文字浩今古，不受俗務侵。", "端如貯美酒，妙處當自斟。", "臨卷忽有得，如來君義臨。", "即此是聖域，子行無滯淫。"]'),
('ed75d881-0f0e-4abc-bd13-2503eb1e0c07','無題四首  其一','呂本中','宋','宋诗','song-poetry','','[]','我病無能到處窮，子才安得尚漂蓬。',32,'全唐诗/poet.song.92000.json','["我病無能到處窮，子才安得尚漂蓬。", "如何共飲重陽酒，相對無言似乃翁。"]'),
('0536cddd-47f2-405e-a75b-19d6ff0a06f7','無題四首  其二','呂本中','宋','宋诗','song-poetry','','[]','重陽共採東籬菊，却似乃翁年少時。',32,'全唐诗/poet.song.92000.json','["重陽共採東籬菊，却似乃翁年少時。", "顧我無能甘老病，相尋唯有向來詩。"]'),
('2a637e27-fa3d-4095-9dd1-c79a434e5471','無題四首  其三','呂本中','宋','宋诗','song-poetry','','[]','聞鐘即起待天明，客舍無聊坐五更。',32,'全唐诗/poet.song.92000.json','["聞鐘即起待天明，客舍無聊坐五更。", "何日長風破巨浪，看渠萬里出門行。"]'),
('5e5d6d37-f53b-47b0-9d39-24f9d2883776','無題四首  其四','呂本中','宋','宋诗','song-poetry','','[]','平生飽我飯脱粟，靜夜不眠尋細書。',32,'全唐诗/poet.song.92000.json','["平生飽我飯脱粟，靜夜不眠尋細書。", "可見烏衣諸子弟，從來志業不如渠。"]'),
('a3334fd3-3804-4b90-b42f-b23b2913560b','邊愁  其一','呂本中','宋','宋诗','song-poetry','','[]','胡人吹短笛，一半是離聲。',24,'全唐诗/poet.song.92000.json','["胡人吹短笛，一半是離聲。", "想得南飛鳥，雲間亦厭聽。"]'),
('76c0b6de-782b-4aff-8058-06632d6f0f7c','邊愁  其二','呂本中','宋','宋诗','song-poetry','','[]','秋聲晚來急，邊塞乍寒時。',24,'全唐诗/poet.song.92000.json','["秋聲晚來急，邊塞乍寒時。", "不似江南日，愁多只自知。"]'),
('758f4b32-16cd-4a6b-b689-81e7b9f49a92','招范四弟','呂本中','宋','宋诗','song-poetry','','[]','涼風忽滿箑，江漢有歸心。',48,'全唐诗/poet.song.92000.json','["涼風忽滿箑，江漢有歸心。", "顧我病如昨，憐君窮至今。", "苦嫌歸夢短，不厭酒杯深。", "試問玉川老，何時許降臨。"]'),
('222074ba-72e6-4093-b471-cad0e409fad2','衢州路中','呂本中','宋','宋诗','song-poetry','','[]','今日衢州路，師奴不共行。',24,'全唐诗/poet.song.92000.json','["今日衢州路，師奴不共行。", "阿童渾似汝，只是太粗生。"]'),
('3e4287ca-5acd-4322-93dc-df01139f577c','憶福州舊居菊花','呂本中','宋','宋诗','song-poetry','','[]','問訊階前菊，如今屬阿誰。',24,'全唐诗/poet.song.92000.json','["問訊階前菊，如今屬阿誰。", "祗應風露底，猶記摘殘枝。"]'),
('f645c64c-f627-412d-ad62-f3bf6e930d9a','求趙表之墨','呂本中','宋','宋诗','song-poetry','','[]','超然堂中墨如戟，支撐宗門渠有力。',64,'全唐诗/poet.song.92000.json','["超然堂中墨如戟，支撐宗門渠有力。", "參得諸方一味禪，以此示人人不識。", "病夫見之喜折屐，便欲投詩恐無益。", "主人不吝是家風，會見琅琅送珪璧。"]'),
('0aba2fcd-c09a-4170-84e6-5b500179851d','陋巷','呂本中','宋','宋诗','song-poetry','','[]','陋巷客自稀，短日寒未到。',72,'全唐诗/poet.song.92000.json','["陋巷客自稀，短日寒未到。", "感君時一來，得以慰懷抱。", "論文有根柢，落筆清且奧。", "如歌五弦琴，促軫有餘操。", "黄花開正繁，薄酒可相勞。", "請君尋此盟，妙處同一造。"]'),
('7afbf70c-1e47-4cca-aada-55919f6e542e','示聞生','呂本中','宋','宋诗','song-poetry','','[]','形容落魄猶須酒，疾病因尋久廢詩。',32,'全唐诗/poet.song.92000.json','["形容落魄猶須酒，疾病因尋久廢詩。", "忽見聞郎七字句，却如王謝少年時。"]'),
('b5f7e87b-7a3a-4dd0-9249-6e6d0dc1c86a','簡何居厚','呂本中','宋','宋诗','song-poetry','','[]','我乏濟勝具，子懷經世才。',48,'全唐诗/poet.song.92000.json','["我乏濟勝具，子懷經世才。", "寒窗得一笑，陋巷絕纖埃。", "白酒難充醉，黄花只强開。", "更憐無事日，時有好詩來。"]'),
('e1cf291b-1dc6-4b9b-8918-5ce11e88f33a','謝人送酒','呂本中','宋','宋诗','song-poetry','','[]','他鄉逢故人，已覺意氣盛。',96,'全唐诗/poet.song.92000.json','["他鄉逢故人，已覺意氣盛。", "得君雙榼酒，起我終日病。", "清如兩龔潔，氣出徐邈聖。", "乃知無功鄉，欲往有捷徑。", "一盃我已足，不必待歷聘。", "扁舟下東陽，此計或未定。", "尚欲尋舊盟，短拙恐未稱。", "先生肯降臨，時掃一室淨。"]'),
('00431c05-f356-4317-a89b-e50dbd3edd57','聞蔡九弟十四弟到行在','呂本中','宋','宋诗','song-poetry','','[]','苦懷吾表弟，别久費相思。',48,'全唐诗/poet.song.92000.json','["苦懷吾表弟，别久費相思。", "愛客能忘酒，長貧不廢詩。", "每蒙高士喜，終少貴人知。", "試問游吳興，何如在蜀時。"]'),
('1d1d029f-490f-4332-a183-0d194d9425d9','贈蔡九弟十四弟','呂本中','宋','宋诗','song-poetry','','[]','年來疾病日衰頽，忽報山中兩弟來。',32,'全唐诗/poet.song.92000.json','["年來疾病日衰頽，忽報山中兩弟來。", "徑欲相從營一醉，未須辛苦便輕回。"]'),
('d1ebddbc-0e84-418c-a162-61a7433bfa5f','病中','呂本中','宋','宋诗','song-poetry','','[]','貸米供晨炊，尚欠數束薪。',48,'全唐诗/poet.song.92000.json','["貸米供晨炊，尚欠數束薪。", "平生甘此味，此去未爲貧。", "新霜已嚴厲，况我病經旬。", "但守此心足，無爲思古人。"]'),
('6e6750af-79ea-400a-9ed8-d09e7ababa45','病中曾端伯見訪','呂本中','宋','宋诗','song-poetry','','[]','不見倉曹十五年，江城相遇各華顛。',64,'全唐诗/poet.song.92000.json','["不見倉曹十五年，江城相遇各華顛。", "何時更踐隣居約，判斷諸方五味禪。", "浮生擾擾亂初定，久病昏昏閑始便。", "欲問小童尋大隗，勝于猛將畫凌烟。"]'),
('6cd9f1f6-80b4-4d49-8f50-df9ae042a108','無題','呂本中','宋','宋诗','song-poetry','','[]','一任衡門可雀羅，時容欹枕聽懸河。',32,'全唐诗/poet.song.92000.json','["一任衡門可雀羅，時容欹枕聽懸河。", "因君小試屠龍手，要與午窗降睡魔。"]'),
('0eb40e1e-3d65-44d5-a83b-4858137823ab','送曾吉父','呂本中','宋','宋诗','song-poetry','','[]','吾道從來到處窮，八珍常與一簞同。',64,'全唐诗/poet.song.92000.json','["吾道從來到處窮，八珍常與一簞同。", "子房故是青雲士，圮上乃逢黄石翁。", "聖學有傳爲可喜，宦游少味自無功。", "亦知湖嶺如江淛，盡在先生指顧中。"]'),
('c9755531-0403-4a1e-889a-c2dcba0811e3','次曾吉父蘭溪三絕  其一','呂本中','宋','宋诗','song-poetry','','[]','夜窗相對不成眠，苦爲離愁定不然。',32,'全唐诗/poet.song.92000.json','["夜窗相對不成眠，苦爲離愁定不然。", "政以蒼生未蘇息，思君日夕望回船。"]'),
('00f948df-fc45-4858-85b7-a911387950c4','次曾吉父蘭溪三絕  其二','呂本中','宋','宋诗','song-poetry','','[]','春信先尋嶺上梅，兩年零落待君開。',32,'全唐诗/poet.song.92000.json','["春信先尋嶺上梅，兩年零落待君開。", "非關使節須重到，自是溪山未遣回。"]'),
('704c1f12-245d-4300-8c5d-f652ec924b0e','次曾吉父蘭溪三絕  其三','呂本中','宋','宋诗','song-poetry','','[]','久覺藏身不厭深，舊游風物要追尋。',32,'全唐诗/poet.song.92000.json','["久覺藏身不厭深，舊游風物要追尋。", "書來肯附銅魚使，記我今年病不禁。"]'),
('2e9c5ae3-ad61-45b3-b4ad-3e21baeaaed5','窮臘有懷','呂本中','宋','宋诗','song-poetry','','[]','冰霜抵窮臘，伏枕久亦倦。',84,'全唐诗/poet.song.92000.json','["冰霜抵窮臘，伏枕久亦倦。", "思公如和風，咫尺未得見。", "人生無賢愚，各自有志願。", "但得所趣同，公固不我賤。", "何須肱九折，始見金百鍊。", "平安望中原，棲息各異縣。", "尚欲從公游，衰年保窮健。"]'),
('8890b8d6-0b4c-42ec-b0a2-9b07958bdfb7','病中聞諸范日赴飲會','呂本中','宋','宋诗','song-poetry','','[]','諸公相隨日酣飲，我病昏昏困衾枕。',64,'全唐诗/poet.song.92000.json','["諸公相隨日酣飲，我病昏昏困衾枕。", "人生苦樂故不同，世味再尋如拾瀋。", "良醫更在肱九折，曾子從來日三省。", "不離方丈走諸方，萬事只如驢覷井。"]'),
('6d451515-daa3-4dcf-9eab-108bea4e7dbc','深居','呂本中','宋','宋诗','song-poetry','','[]','深居如山林，初不識城市。',60,'全唐诗/poet.song.92000.json','["深居如山林，初不識城市。", "塵凝喜事少，犬吠知客至。", "生涯付衰疾，日力破昏睡。", "欣然一笑足，自省甘若薺。", "收身當在早，過此恐少味。"]'),
('9624633c-a747-4dfd-ba62-6fa4286eeaf1','慶大悲閣成','呂本中','宋','宋诗','song-poetry','','[]','自離閩嶺罷參禪，疾病深藏不計年。',32,'全唐诗/poet.song.92000.json','["自離閩嶺罷參禪，疾病深藏不計年。", "尚得閑人相印可，隔門惟有白衣仙。"]'),
('57bc2703-3719-4061-8973-4392c25cde52','贈人','呂本中','宋','宋诗','song-poetry','','[]','堅卧因循欲過冬，故人無復馬牛風。',64,'全唐诗/poet.song.92000.json','["堅卧因循欲過冬，故人無復馬牛風。", "得君好句能忘病，笑我長饑不諱窮。", "清夢肯嫌齋舍冷，破囊常伴酒杯空。", "新正所願長窮健，剩作歌詩準備公。"]'),
('8fec2fdf-3d0c-49cd-8b56-ddf78b68d114','送廣東漕范子儀','呂本中','宋','宋诗','song-poetry','','[]','我爲三衢居，君作番禺行。',96,'全唐诗/poet.song.92000.json','["我爲三衢居，君作番禺行。", "君行我方病，歲序仍崢嶸。", "嶺海未寂寞，斯民則憔悴。", "得君鎮臨之，固可以卒歲。", "嗟君盛德後，窮獨與我同。", "比年數見之，長在寒苦中。", "番禺盛賓僚，莫如元帥賢。", "君行問安否，道我如昔然。"]'),
('60e7e45b-93c3-4978-8aba-91da79f9ea15','夜聞諸生讀書因成寄趙十七姪','呂本中','宋','宋诗','song-poetry','','[]','紛紛藥裹了新正，北望蘭溪不數程。',32,'全唐诗/poet.song.92000.json','["紛紛藥裹了新正，北望蘭溪不數程。", "且喜諸生會勤苦，夜窗如子讀書聲。"]'),
('09365297-480e-4413-974c-2d8b6c5e7206','夜坐','呂本中','宋','宋诗','song-poetry','','[]','所至留連不計程，兩年堅卧厭南征。',64,'全唐诗/poet.song.92000.json','["所至留連不計程，兩年堅卧厭南征。", "荒城日短溪山靜，野寺人稀鸛鶴鳴。", "藥裹向人閑自好，文書到眼病猶明。", "較量定力差精進，夜夜蒲團坐五更。"]'),
('faad19ee-e54f-416e-9d15-5b2ec294eadc','簡李巽伯','呂本中','宋','宋诗','song-poetry','','[]','愛酒舊無敵，能詩新有聲。',48,'全唐诗/poet.song.92000.json','["愛酒舊無敵，能詩新有聲。", "荒城時過我，長句屢尋盟。", "厭病時招客，因行不計程。", "祗應有餘暇，未肯賦閑情。"]'),
('3880b32f-9ab1-414f-8935-fc080166de12','追記昔年正月十日宣城出城至廣教','呂本中','宋','宋诗','song-poetry','','[]','嘗憶他年在宛陵，好山松竹面層層。',64,'全唐诗/poet.song.92000.json','["嘗憶他年在宛陵，好山松竹面層層。", "江城氣候猶含雪，草市人家已掛燈。", "每怪愁腸難貯酒，時隨拄杖出尋僧。", "如今轉覺衰頹甚，病坐南窗冷欲冰。"]'),
('136ce808-688f-4a51-b566-6b30f811d239','病中上元','呂本中','宋','宋诗','song-poetry','','[]','病久仍多事，深居未識春。',24,'全唐诗/poet.song.92000.json','["病久仍多事，深居未識春。", "殷勤今夜雨，且爲阻游人。"]'),
('3c62384a-d41b-40fa-8dfe-1facd1811155','三衢上元','呂本中','宋','宋诗','song-poetry','','[]','俗事紛紛避作煩，夢中時厭雨聲喧。',64,'全唐诗/poet.song.92000.json','["俗事紛紛避作煩，夢中時厭雨聲喧。", "但看閑客時來去，勝說羣兒手覆翻。", "事業不同俱可笑，形骸如此尚何言。", "他年更有相逢話，同是三衢過上元。"]'),
('fb01b141-9752-4b4b-bcb6-ff11674588bd','贈人','呂本中','宋','宋诗','song-poetry','','[]','剩作閑官不計年，得公相近轉翛然。',64,'全唐诗/poet.song.92000.json','["剩作閑官不計年，得公相近轉翛然。", "飽諳文字能生病，始信虚空不住禪。", "水澁船回休進棹，路長馬倦莫加鞭。", "漫成拙句爲公壽，要作新正第一篇。"]'),
('2dabd279-00cb-4c05-9899-e6f0e5e480bf','官閑贈人','呂本中','宋','宋诗','song-poetry','','[]','自喜閑官不計員，月叨微祿勝歸田。',64,'全唐诗/poet.song.92000.json','["自喜閑官不計員，月叨微祿勝歸田。", "藥囊往往充詩藁，米劵時時當酒錢。", "忍病作勞吾不厭，對人無語子差賢。", "不須更見盧溪老，會得安心即是禪。"]'),
('9164958b-97ce-430f-8803-d3a6fb23f072','正月十七日','呂本中','宋','宋诗','song-poetry','','[]','令節今安在，晨鐘奉夙興。',48,'全唐诗/poet.song.92000.json','["令節今安在，晨鐘奉夙興。", "空庭留素月，廣殿有殘燈。", "笑語已難記，經游如未曾。", "吾衰得堅卧，差勝住房僧。"]'),
('b8dc39ac-44c1-447c-bbe0-1fc13e71a570','病中得舍弟信','呂本中','宋','宋诗','song-poetry','','[]','頻通婺女訊，兼得會稽書。',48,'全唐诗/poet.song.92000.json','["頻通婺女訊，兼得會稽書。", "歲月呻吟裏，文章困睡餘。", "百年判憔悴，萬里付迂疏。", "尚欲身强健，相從得定居。"]'),
('b914d698-49f3-4bc7-b11e-d73144e1b88f','疥','呂本中','宋','宋诗','song-poetry','','[]','瘙癢撓膚無春冬，爲害略與惡疾同。',32,'全唐诗/poet.song.92000.json','["瘙癢撓膚無春冬，爲害略與惡疾同。", "只有瘡痂不相負，夜闌長滿寝衣中。"]'),
('6af48468-add1-49cb-b32e-f4e8a2a39d27','正月十九日暴熱','呂本中','宋','宋诗','song-poetry','','[]','一夜飛蚊遶鬢鳴，却忘時節是新正。',32,'全唐诗/poet.song.92000.json','["一夜飛蚊遶鬢鳴，却忘時節是新正。", "祗應朝暮須風雨，便作疏簷瀉竹聲。"]'),
('da062003-08da-4e06-8af9-6b8ddabf9048','即事','呂本中','宋','宋诗','song-poetry','','[]','十年不調張廷尉，一字拔人山巨源。',64,'全唐诗/poet.song.92000.json','["十年不調張廷尉，一字拔人山巨源。", "萬事重尋已陳跡，此公相對可忘言。", "故人久已音書絕，古寺終嫌市井喧。", "更欲移家近深僻，漫留書冊教兒孫。"]'),
('15004009-7d5b-42eb-a242-29721736ebba','送向仲告往江西','呂本中','宋','宋诗','song-poetry','','[]','紛紛車馬閙如雲，膏火煎熬祗自焚。',64,'全唐诗/poet.song.92000.json','["紛紛車馬閙如雲，膏火煎熬祗自焚。", "亦有故人來問疾，苦無佳思與論文。", "江湖老矣頻搔首，毛髮翛然政似君。", "他日卜鄰猶有約，靜中風景要平分。"]'),
('bbcdcc42-afb3-4048-949e-60992e6379b0','寄臨川親舊十首意到輒書不復次序  其一','呂本中','宋','宋诗','song-poetry','','[]','偶從行李轉江湖，所至翛然一物無。',32,'全唐诗/poet.song.92000.json','["偶從行李轉江湖，所至翛然一物無。", "午枕久拚閑事業，夜窗新有靜工夫。"]'),
('6f8217ef-bd06-47c0-b92d-dcf2a42aa0bb','寄臨川親舊十首意到輒書不復次序  其二','呂本中','宋','宋诗','song-poetry','','[]','少小交游不乏賢，二三豪傑聚臨川。',32,'全唐诗/poet.song.92000.json','["少小交游不乏賢，二三豪傑聚臨川。", "自從老大飄零盡，獨有殘詩數百篇。"]'),
('2be3ff35-628d-44cf-8724-6a092d763b2d','寄臨川親舊十首意到輒書不復次序  其三','呂本中','宋','宋诗','song-poetry','','[]','屢試吳中千里蓴，閩中荔子亦嘗新。',32,'全唐诗/poet.song.92000.json','["屢試吳中千里蓴，閩中荔子亦嘗新。", "獨游每恨無佳思，正好溪山少故人。"]'),
('bbb435b3-df37-4526-954b-7e939f367840','寄臨川親舊十首意到輒書不復次序  其四','呂本中','宋','宋诗','song-poetry','','[]','故人自失嵇中散，疾病衰頹轉不堪。',32,'全唐诗/poet.song.92000.json','["故人自失嵇中散，疾病衰頹轉不堪。", "猶喜閑居有賢弟，且隨長鋏住江南。"]'),
('f0ed6d44-826f-4d46-9b9b-6d8ff55ec642','寄臨川親舊十首意到輒書不復次序  其五','呂本中','宋','宋诗','song-poetry','','[]','張卿别後且郊居，無復黄公舊酒壚。',32,'全唐诗/poet.song.92000.json','["張卿别後且郊居，無復黄公舊酒壚。", "試問今年有閑暇，亦隨書劍入城無。"]'),
('a38d86dc-6377-4bdc-a75e-550a0e4fb877','寄臨川親舊十首意到輒書不復次序  其六','呂本中','宋','宋诗','song-poetry','','[]','交游疇昔住臨川，博士高風世不傳。',32,'全唐诗/poet.song.92000.json','["交游疇昔住臨川，博士高風世不傳。", "饒謝得名三十載，當時已道小汪賢。"]'),
('77c5fd53-847f-4b28-9973-dc8425016284','寄臨川親舊十首意到輒書不復次序  其七','呂本中','宋','宋诗','song-poetry','','[]','故人子弟惟汪謝，每一思之忘寝興。',32,'全唐诗/poet.song.92000.json','["故人子弟惟汪謝，每一思之忘寝興。", "莫道臨川便寂寞，後來相繼有諸曾。"]'),
('d18096fc-ffdd-409b-bb19-30d8e76ae8fb','寄臨川親舊十首意到輒書不復次序  其八','呂本中','宋','宋诗','song-poetry','','[]','吏部聲名動一時，中原人物未全衰。',32,'全唐诗/poet.song.92000.json','["吏部聲名動一時，中原人物未全衰。", "低摧不用還歸去，坐守遺經可療饑。"]'),
('c439bdb7-e833-4595-996e-9a6d63a6d286','寄臨川親舊十首意到輒書不復次序  其九','呂本中','宋','宋诗','song-poetry','','[]','金谿比歲復何如，二董風流却未疏。',32,'全唐诗/poet.song.92000.json','["金谿比歲復何如，二董風流却未疏。", "聞道移家遠城市，欲攜書籍更深居。"]'),
('6dc6fad0-c1ca-44fd-9732-8cc1c8d7adf0','寄臨川親舊十首意到輒書不復次序  其一○','呂本中','宋','宋诗','song-poetry','','[]','愛賢如渇吳夫子，不染世間兒女塵。',32,'全唐诗/poet.song.92000.json','["愛賢如渇吳夫子，不染世間兒女塵。", "老病不逢終不悔，後生誰復記斯人。"]'),
('c0130587-c021-42a0-b7de-428b51302ad7','奉懷季平范丈戲成兩絕句錄呈  其一','呂本中','宋','宋诗','song-poetry','','[]','形骸已病尤宜懶，歲月長貧屢有詩。',32,'全唐诗/poet.song.92000.json','["形骸已病尤宜懶，歲月長貧屢有詩。", "猶得深居少塵事，只如同在嶺南時。"]'),
('beebe314-f61e-41de-b59b-78bda1aec55b','奉懷季平范丈戲成兩絕句錄呈  其二','呂本中','宋','宋诗','song-poetry','','[]','新年爲况復何如，尚有心情打酒無。',32,'全唐诗/poet.song.92000.json','["新年爲况復何如，尚有心情打酒無。", "只恐後生行樂處，轉嫌吾輩白髭鬚。"]'),
('2e2e5796-f745-4d05-a713-01639f07a027','病中寄胡原仲劉致中','呂本中','宋','宋诗','song-poetry','','[]','累月不寄書，我病亦在床。',72,'全唐诗/poet.song.92000.json','["累月不寄書，我病亦在床。", "仰見出林鶴，如覩二子翔。", "冰壺貯秋月，所至有輝光。", "僻郡足風雨，深春猶雪霜。", "閩水遠而清，閩山深且長。", "何時一尊酒，更復議行藏。"]'),
('f8c48d40-fb3b-45c0-b555-c5430729f156','才元相過三衢偶成近體詩一首奉呈','呂本中','宋','宋诗','song-poetry','','[]','紛紛俗事起如毛，病起南窗厭作勞。',64,'全唐诗/poet.song.92000.json','["紛紛俗事起如毛，病起南窗厭作勞。", "正欲往來求飯飽，敢將辛苦治名高。", "長閑似稱三冬卧，舊學虚蒙一字褒。", "他日相逢有餘地，尚容衰晚鬬堅牢。"]'),
('6977c94b-367a-4413-9b67-769d3def1af5','無題','呂本中','宋','宋诗','song-poetry','','[]','衾稠尚冷知春早，意緒無聊覺病深。',32,'全唐诗/poet.song.92000.json','["衾稠尚冷知春早，意緒無聊覺病深。", "夜半故詩緣底事，向來餘習正關心。"]'),
('a9051dd4-8b83-4bf8-85eb-dce37b530cd2','寄人三首  其一','呂本中','宋','宋诗','song-poetry','','[]','世久無高識，斯人我獨知。',24,'全唐诗/poet.song.92000.json','["世久無高識，斯人我獨知。", "子行吾羨子，雖病敢忘詩。"]'),
('cc761fde-17bc-4c6d-8d59-640b49e98991','寄人三首  其二','呂本中','宋','宋诗','song-poetry','','[]','念昔無事日，同升夫子堂。',24,'全唐诗/poet.song.92000.json','["念昔無事日，同升夫子堂。", "江湖晚相見，猶喜共行藏。"]'),
('366460e7-3589-443f-a9b1-43c90a56c964','寄人三首  其三','呂本中','宋','宋诗','song-poetry','','[]','世久趨浮末，于時爾獨賢。',24,'全唐诗/poet.song.92000.json','["世久趨浮末，于時爾獨賢。", "閑游衆目外，却立萬夫前。"]'),
('82cca7fd-4bf8-484e-8b97-2385db87c215','寄人三首  其四','呂本中','宋','宋诗','song-poetry','','[]','老驥空伏櫪，長琴有斷弦。',24,'全唐诗/poet.song.92000.json','["老驥空伏櫪，長琴有斷弦。", "傷心共隱地，回首更茫然。"]'),
('32007741-0628-45cb-a042-9a8053e76f9d','寄祁居士','呂本中','宋','宋诗','song-poetry','','[]','聞道祁居士，抄書手未停。',48,'全唐诗/poet.song.92000.json','["聞道祁居士，抄書手未停。", "艱難走異縣，辛苦抱遺經。", "野寺猶堪隱，人言懶復聽。", "十年事夫子，今日得儀型。"]'),
('8f9e4234-0b57-47c0-aa2b-49f670131c77','贈人四首  其一','呂本中','宋','宋诗','song-poetry','','[]','病欲相尋久未能，虎丘山下在家僧。',32,'全唐诗/poet.song.92000.json','["病欲相尋久未能，虎丘山下在家僧。", "諸方本末須君記，拈出叢林舊葛藤。"]'),
('c4f1ac61-d4ab-4c6f-95a4-5f4a40952a72','贈人四首  其二','呂本中','宋','宋诗','song-poetry','','[]','昔年曾侍老姑傍，誨我全身只退藏。',32,'全唐诗/poet.song.92000.json','["昔年曾侍老姑傍，誨我全身只退藏。", "長恐風流便疏遠，子猶他日及升堂。"]'),
('2b1835b6-a3a3-4967-aab4-35b9fd633619','贈人四首  其三','呂本中','宋','宋诗','song-poetry','','[]','跬步無功已厭遲，後生誰復肯從師。',32,'全唐诗/poet.song.92000.json','["跬步無功已厭遲，後生誰復肯從師。", "無人識子閑居意，手冷深藏只自知。"]'),
('d7b58e63-e92b-46c0-aac8-3aaa03867975','贈人四首  其四','呂本中','宋','宋诗','song-poetry','','[]','三江古路更深居，白首窮經一丈夫。',32,'全唐诗/poet.song.92000.json','["三江古路更深居，白首窮經一丈夫。", "借問新年入城市，亦曾頻到虎丘無。"]'),
('08e379de-f5e4-4dc1-a5a3-a718d899681f','寄朱希真','呂本中','宋','宋诗','song-poetry','','[]','幕下諸侯老，微言衆不聽。',48,'全唐诗/poet.song.92000.json','["幕下諸侯老，微言衆不聽。", "祗應有餘論，時復注前經。", "郡古疏還往，官閑任醉醒。", "主人鵝可換，更爲寫黄庭。"]'),
('6a47ecb0-7a62-4b75-ac18-83c32ed11147','寄向縣丞','呂本中','宋','宋诗','song-poetry','','[]','念子他時兩頰紅，十年奔走變衰翁。',32,'全唐诗/poet.song.92000.json','["念子他時兩頰紅，十年奔走變衰翁。", "耐官丞相風流在，坐守簞瓢不訴窮。"]'),
('d0aa7ad6-e7e9-4726-bdc9-25a901141891','病中','呂本中','宋','宋诗','song-poetry','','[]','藥裹關心老不宜，只今筋力已全衰。',32,'全唐诗/poet.song.92000.json','["藥裹關心老不宜，只今筋力已全衰。", "何由更得身無事，却似他時把酒時。"]'),
('4461d14d-2779-4313-aaad-96e13ba52d4a','山城','呂本中','宋','宋诗','song-poetry','','[]','山城雨雪繁，春氣來不早。',120,'全唐诗/poet.song.92000.json','["山城雨雪繁，春氣來不早。", "思君如和風，未見意已好。", "時蒙枉車騎，笑語得傾倒。", "我能知子賢，子亦憐我老。", "舊交半鬼錄，在者跡已掃。", "慨然念平生，令人惡懷抱。", "相從飽喫飯，此計或未保。", "東游有前約，預恐别草草。", "豈無一言贈，妙句寫黙藁。", "出户仰高山，猶堪慰枯槁。"]'),
('80c4f2a3-9ad0-4544-a3e2-7f63a229e292','病夫','呂本中','宋','宋诗','song-poetry','','[]','病夫坐穏懶出門，底事逢春作癯瘦。',128,'全唐诗/poet.song.92000.json','["病夫坐穏懶出門，底事逢春作癯瘦。", "故人相尋不憚遠，欲以一盃爲我壽。", "鋪張古昔引大義，勸使忍窮如忍詬。", "感君意氣但如昨，顧我情懷已非舊。", "平生甘作蟻旋磨，萬事只如船放溜。", "十年參差故鄉夢，一心守待靈芝秀。", "辱身竊比柳下惠，疾惡幸逢朱伯厚。", "他時城市望雲山，歲晚何由數相就。"]'),
('26635501-2a5a-40fb-aed8-8cbedf78cecb','無題','呂本中','宋','宋诗','song-poetry','','[]','心廣體故胖，意肅氣自屏。',84,'全唐诗/poet.song.92000.json','["心廣體故胖，意肅氣自屏。", "頹然萬物表，樂此一室靜。", "念君久安坐，轉覺此味勝。", "疏籬過野馬，破牖行日景。", "但令此意真，不必費譏評。", "想當溪山横，更有松竹映。", "隱几得晝眠，此固可補病。"]'),
('6992e984-df67-4609-bce8-25812d435e7d','偶成兩絕句奉寄文若庭列  其一','呂本中','宋','宋诗','song-poetry','','[]','强欲馳驅老不宜，故人雖在費相思。',32,'全唐诗/poet.song.92000.json','["强欲馳驅老不宜，故人雖在費相思。", "祗應大府多還往，職事雖忙不廢詩。"]'),
('e722c97e-47b4-4920-9dbe-2daf90a61dab','偶成兩絕句奉寄文若庭列  其二','呂本中','宋','宋诗','song-poetry','','[]','夏子經時不寄書，十年奔走尚窮途。',32,'全唐诗/poet.song.92000.json','["夏子經時不寄書，十年奔走尚窮途。", "不知自到高安縣，亦有心情記我無。"]'),
('46570ea5-888c-4fef-b148-2c4f6e270ba9','寄閩中親舊','呂本中','宋','宋诗','song-poetry','','[]','濃陰蔽烈日，小院有餘涼。',48,'全唐诗/poet.song.92000.json','["濃陰蔽烈日，小院有餘涼。", "頓覺枕簟好，時聞荷芰香。", "秋成今可必，衰疾未相妨。", "徑欲閩中去，尋僧不裹糧。"]'),
('42c2f277-9ffe-4d1e-83ab-3ed7c5c736ad','廖用中世綵堂','呂本中','宋','宋诗','song-poetry','','[]','廖氏居七閩，土俗變齊魯。',132,'全唐诗/poet.song.92000.json','["廖氏居七閩，土俗變齊魯。", "子孫仁且壽，每繼先父祖。", "作堂名世綵，此意天所予。", "近者得矜式，遠者快先覩。", "今公懷直道，邪正有區處。", "還家上此堂，父祖當笑許。", "小人慕清風，想像濯煩暑。", "孰知少年場，有此毛髪古。", "何時望世綵，得聽公笑語。", "老松卧歲寒，亦以蔽風雨。", "人或不予知，亦莫予敢侮。"]'),
('946446a6-3dde-4ac5-9578-c69a189a2a80','劇暑','呂本中','宋','宋诗','song-poetry','','[]','劇暑先庚伏，經旬在炮燔。',96,'全唐诗/poet.song.92000.json','["劇暑先庚伏，經旬在炮燔。", "今夕驟雨過，我病亦少安。", "涼風醒病骨，好月上更闌。", "尚恐賊報急，凌風無羽翰。", "閩中故人書，日夜望我還。", "無車載家具，欲往故不難。", "所恨去已晚，不及荔子丹。", "家家有白酒，自足解愁顔。"]'),
('da7ba89c-a299-436c-8480-3603c2a15ffa','即事','呂本中','宋','宋诗','song-poetry','','[]','經旬困炮煮，今夕有微風。',48,'全唐诗/poet.song.92000.json','["經旬困炮煮，今夕有微風。", "市井囂塵外，溪山嘯傲中。", "秋涼亦不遠，吾道恐終窮。", "準擬閩中士，今年一笑同。"]'),
('c71dade6-d7ee-42de-b3e3-e6edac284d8c','秋日','呂本中','宋','宋诗','song-poetry','','[]','斟酒莫辭酒琖寛，酒琖少寛令心安。',72,'全唐诗/poet.song.92000.json','["斟酒莫辭酒琖寛，酒琖少寛令心安。", "客游無聊思舊歡，舊歡新愁千萬端。", "如何不飲空長歎，歲云秋矣風落山。", "白露應節衣裳單，南游並海當不難，雨雪欲下何時還。"]'),
('4f1af95a-65d5-43f0-8665-115a638c95ba','懷秋','呂本中','宋','宋诗','song-poetry','','[]','秋風日夜至，念我少年時。',120,'全唐诗/poet.song.92000.json','["秋風日夜至，念我少年時。", "新涼喜欲舞，至今心未衰。", "心雖未遽衰，老病則已甚。", "頹然坐前階，乃若兩鳥噤。", "子病少則爾，衰羸非獨今。", "徘徊以徬徨，何以異夙心。", "死者合已死，空費子百慮。", "在者亦已老，契闊少相遇。", "洗心西方觀，子復未肯然。", "胡然競日力，今年如去年。"]'),
('9ef84383-4a4b-4ba0-8c32-9c6899ae6aba','贈范十八','呂本中','宋','宋诗','song-poetry','','[]','君去留不得，我窮前未聞。',48,'全唐诗/poet.song.92000.json','["君去留不得，我窮前未聞。", "如何出籠鶴，更送離山雲。", "歲晚逢同志，人稀莫離羣。", "肯思臨别語，只用十年勤。"]'),
('6dc53a2a-af6a-4bfb-af30-43fd6dd1dbf3','秋日','呂本中','宋','宋诗','song-poetry','','[]','少年固長貧，長歲復多疾。',96,'全唐诗/poet.song.92000.json','["少年固長貧，長歲復多疾。", "閉門取堅坐，到此多事日。", "不嫌冷如漿，所要甘似蜜。", "舊書堆几案，老眼厭塗乙。", "不如壁角坐，萬事付以實。", "况今雨澤足，已覺憂患失。", "秋成日在望，所至有棃栗。", "賊報雖未衰，一飽良可必。"]'),
('5a3ab060-243e-4547-86d7-d3d55f6fff3c','讀書','呂本中','宋','宋诗','song-poetry','','[]','老去有餘業，讀書空作勞。',48,'全唐诗/poet.song.92000.json','["老去有餘業，讀書空作勞。", "時聞夜蟲響，每伴午雞號。", "久靜能忘病，因行得出遨。", "胡爲良自苦，膏火自煎熬。"]'),
('2ce944ef-b042-410d-9d6b-3db6f5e9f881','宿昔','呂本中','宋','宋诗','song-poetry','','[]','宿昔尚煩暑，平生悲遠游。',48,'全唐诗/poet.song.92000.json','["宿昔尚煩暑，平生悲遠游。", "長貧不貰酒，雖健懶登樓。", "晚節勞千慮，經年走數州。", "新涼事事好，只是迫防秋。"]'),
('cf649315-f95c-42e4-8be9-82f454e1a332','謝人送詩','呂本中','宋','宋诗','song-poetry','','[]','堅坐少愉樂，欲行還滯淫。',48,'全唐诗/poet.song.92000.json','["堅坐少愉樂，欲行還滯淫。", "時蒙七字句，可慰十年心。", "歲晚日晷短，天寒霜雪侵。", "主人不厭客，敢辭酒杯深。"]'),
('1ce976e5-ab53-4465-8988-314791a071c1','水仙  其一','呂本中','宋','宋诗','song-poetry','','[]','澹綠衣裳白玉膚，近人香欲透衣襦。',32,'全唐诗/poet.song.92000.json','["澹綠衣裳白玉膚，近人香欲透衣襦。", "不嫌破屋颼飀甚，肯與寒梅作伴無。"]'),
('05af0241-90b3-4fef-a9d3-cc949a536b09','水仙  其二','呂本中','宋','宋诗','song-poetry','','[]','破臘迎春開未遲，十分香是苦寒時。',32,'全唐诗/poet.song.92000.json','["破臘迎春開未遲，十分香是苦寒時。", "小瓶尚恐無佳對，更乞江梅三四枝。"]'),
('c10c8c1f-1296-4aaf-aa6f-7ecd57fb0335','處暑','呂本中','宋','宋诗','song-poetry','','[]','平時遇處暑，庭戶有餘涼。',48,'全唐诗/poet.song.92000.json','["平時遇處暑，庭戶有餘涼。", "乙紀走南國，炎天非故鄉。", "寥寥秋尚遠，杳杳夜光長。", "尚可留連否，年豐秔稻香。"]'),
('5e5a25c8-9fc4-458a-abb6-bb965112c678','教授鄭國材挽詞','呂本中','宋','宋诗','song-poetry','','[]','松桂在荆棘，所趨故不同。',96,'全唐诗/poet.song.92000.json','["松桂在荆棘，所趨故不同。", "雖云被剪伐，所至仰清風。", "念子行古道，簞瓢生屢空。", "我來則已病，不復能從容。", "平生務躬行，聖處久收功。", "堅坐想顔子，欲往吾其從。", "丹旐忽已遠，暮靄千萬重。", "論文一尊酒，堅坐更誰逢。"]'),
('dbb9adbe-ab3f-4df3-a09d-b1ce999637f1','無題二首  其一','呂本中','宋','宋诗','song-poetry','','[]','柴門羅雀懶頻開，喜有新詩到眼來。',32,'全唐诗/poet.song.92000.json','["柴門羅雀懶頻開，喜有新詩到眼來。", "聞道繫舟城脚底，莫乘溪漲便輕回。"]'),
('e1942113-f8b9-416c-900d-562cb20cb4e3','無題二首  其二','呂本中','宋','宋诗','song-poetry','','[]','入秋多病渾無酒，學道無成却讀書。',32,'全唐诗/poet.song.92000.json','["入秋多病渾無酒，學道無成却讀書。", "莫謂窮居便寂寞，天涼猶枉故人車。"]'),
('cdab18ed-af1e-44ff-ba8c-6ac8a4c48348','潘義榮惠木犀二首  其一','呂本中','宋','宋诗','song-poetry','','[]','年年無酒對新秋，辜負涼天懶出游。',32,'全唐诗/poet.song.92000.json','["年年無酒對新秋，辜負涼天懶出游。", "想得故人憐我病，故分巖桂洗窮愁。"]'),
('ef29bbc1-0342-43bb-92d9-780ab63dd909','潘義榮惠木犀二首  其二','呂本中','宋','宋诗','song-poetry','','[]','掃除炎暑脱氛埃，色似菊花香似梅。',32,'全唐诗/poet.song.92000.json','["掃除炎暑脱氛埃，色似菊花香似梅。", "知是西風要清賞，少留陰雨候晴開。"]'),
('0da822e4-4ca3-4fe2-bf84-35057d25f56d','次潘都尉富季申冬日探梅韻二首  其一','呂本中','宋','宋诗','song-poetry','','[]','暑退園林物物新，過溪風好月初晨。',64,'全唐诗/poet.song.92000.json','["暑退園林物物新，過溪風好月初晨。", "酒壺茶具偏宜坐，細草殘花别是春。", "但得主人令客醉，不辭秋冷和詩頻。", "從來禮節生疏放，見我狂歌意自親。"]'),
('f006c8f5-d013-4f8b-83c3-e3d0777b532b','次潘都尉富季申冬日探梅韻二首  其二','呂本中','宋','宋诗','song-poetry','','[]','開府新從日下歸，却尋山水對烟霏。',64,'全唐诗/poet.song.92000.json','["開府新從日下歸，却尋山水對烟霏。", "剩披詩律留花住，不使親知到眼稀。", "但見鯤鵬常遠舉，應憐蜩鷃只卑飛。", "此游尚恨還家早，未許溪頭送落暉。"]'),
('03f4afc2-a7a0-4c2d-8093-c1a770c7151e','次韻木犀二首  其一','呂本中','宋','宋诗','song-poetry','','[]','折送幽花與做秋，溪頭風物未重游。',32,'全唐诗/poet.song.92000.json','["折送幽花與做秋，溪頭風物未重游。", "已憐多病逢三益，更喜詩成擬四愁。"]'),
('e359b77c-38b4-4303-86a0-a01cbcdca266','次韻木犀二首  其二','呂本中','宋','宋诗','song-poetry','','[]','洛陽車馬走塵埃，一歲顛狂自探梅。',32,'全唐诗/poet.song.92000.json','["洛陽車馬走塵埃，一歲顛狂自探梅。", "還識此花風味否，年年秋後兩番開。"]'),
('2602f0e8-8a26-427f-8f5c-ea03b28fbd0d','謝潘義榮送菊二首  其一','呂本中','宋','宋诗','song-poetry','','[]','經旬霖雨足莓苔，忽喜雙盆送菊來。',32,'全唐诗/poet.song.92000.json','["經旬霖雨足莓苔，忽喜雙盆送菊來。", "已似風霜憔悴損，主人云是待晴開。"]'),
('57757472-061b-41e5-9505-82ff87b1f173','謝潘義榮送菊二首  其二','呂本中','宋','宋诗','song-poetry','','[]','漸開粉白間微黄，肯與新橙一例香。',32,'全唐诗/poet.song.92000.json','["漸開粉白間微黄，肯與新橙一例香。", "送與衰翁元未稱，且留青蕋作重陽。"]'),
('d687e3fd-6abc-483a-9506-f53cc516ff85','畜犬','呂本中','宋','宋诗','song-poetry','','[]','王人長年閑，柴戶終日閉。',72,'全唐诗/poet.song.92000.json','["王人長年閑，柴戶終日閉。", "雖云伴我懶，常有跋扈志。", "端如在籠鶴，又若伏櫪驥。", "舉首望道路，久欲從此逝。", "恨無陸探微，寫此師子戲。", "如何尚搖尾，更作求食計。"]'),
('bebffeb6-4787-4805-9249-01bfc44d2d96','疥','呂本中','宋','宋诗','song-poetry','','[]','刺刺齪齪疥欲作，今年去年只如昨。',64,'全唐诗/poet.song.92000.json','["刺刺齪齪疥欲作，今年去年只如昨。", "人生縱病莫病此，此病雖輕更作惡。", "寒窗夜長燈燼落，敗人禪觀妨人樂。", "安得壮士挽天河，盡洗此瘡閑處著。"]'),
('e2a4eb1b-7f41-4a1a-9e03-41f4a0558f43','潦倒','呂本中','宋','宋诗','song-poetry','','[]','潦倒心猶在，衰遲分獨深。',48,'全唐诗/poet.song.92000.json','["潦倒心猶在，衰遲分獨深。", "如何一朝淚，空費百年心。", "好月思同步，清尊懶獨斟。", "惜哉王子敬，誰復嘆人琴。"]'),
('fec1a913-c442-4297-ae15-6c460a22d55f','贈人','呂本中','宋','宋诗','song-poetry','','[]','他年好兄弟，見我嶠南時。',48,'全唐诗/poet.song.92000.json','["他年好兄弟，見我嶠南時。", "相對能忘病，清言可療饑。", "後生寧復有，末俗漫相疑。", "尚想閑居處，疏燈守破帷。"]'),
('b40db090-d923-4779-a1cf-8a4460feb857','無題','呂本中','宋','宋诗','song-poetry','','[]','疾病侵凌我亦衰，後生誰復更相知。',32,'全唐诗/poet.song.92000.json','["疾病侵凌我亦衰，後生誰復更相知。", "可憐日落長安路，不見驊騮整轡時。"]'),
('db44686d-e052-4526-9141-334320df4c83','寄京口使君','呂本中','宋','宋诗','song-poetry','','[]','使君鎮京口，隱若一長城。',48,'全唐诗/poet.song.92000.json','["使君鎮京口，隱若一長城。", "詩律有同社，溪山聊主盟。", "囂塵不挂念，鷗鳥自忘情。", "曾記貧交否，衰頹判此生。"]'),
('e5bab3ad-0901-460e-9747-54aea6f42007','再贈','呂本中','宋','宋诗','song-poetry','','[]','婺女勝京口，公來歲已秋。',48,'全唐诗/poet.song.92000.json','["婺女勝京口，公來歲已秋。", "閑雲出山寺，好月掛星樓。", "往事付情話，故人多倦游。", "十年浪奔走，今日爲公留。"]'),
('0ac0ab4e-c610-4033-be8d-9c425059d50f','贈友','呂本中','宋','宋诗','song-poetry','','[]','子來已冬深，僅得數夕款。',48,'全唐诗/poet.song.92000.json','["子來已冬深，僅得數夕款。", "寒窗聽談道，未厭白日短。", "從來不飲酒，萬事付茗盌。", "别去今幾日，荒階月猶滿。"]'),
('fa5539d4-8107-4ba0-9fb6-93d95d36244c','歲暮','呂本中','宋','宋诗','song-poetry','','[]','歲暮少懽愉，况復嬰病苦。',72,'全唐诗/poet.song.92000.json','["歲暮少懽愉，况復嬰病苦。", "閉門每厭客，幸此連日雨。", "寒爐火復焰，乃若相媚嫵。", "披衣坐壁角，妙處時一暏。", "風聲耿初夜，有句或未吐。", "還書問故人，可復一笑許。"]'),
('537d5e7b-fd12-48ae-9047-a777cdef7fe1','戲成二絕句  其一','呂本中','宋','宋诗','song-poetry','','[]','老讀文書懶不前，亦無餘地可逃禪。',32,'全唐诗/poet.song.92000.json','["老讀文書懶不前，亦無餘地可逃禪。", "閉門省事羣囂遠，惟有貍奴附日眠。"]'),
('a64397a0-f834-449d-8d99-5d90f573d520','戲成二絕句  其二','呂本中','宋','宋诗','song-poetry','','[]','病犬虺隤惟附日，懶猫藏縮可逃寒。',32,'全唐诗/poet.song.92000.json','["病犬虺隤惟附日，懶猫藏縮可逃寒。", "寧知兩馬霜風下，更有長途不道難。"]'),
('2b2c9ba3-3f0a-41c5-9146-9ef32a7a0f94','久病二首  其一','呂本中','宋','宋诗','song-poetry','','[]','久病畏人事，長閑增道心。',48,'全唐诗/poet.song.92000.json','["久病畏人事，長閑增道心。", "寧貪風日好，不避雪霜侵。", "跼蹐身猶在，高低手自斟。", "酒盃休厭滿，茗盌向來深。"]'),
('4c0f54d6-ebaf-4f8a-9077-413a037668c5','久病二首  其二','呂本中','宋','宋诗','song-poetry','','[]','未愈俱生疾，空懷宿昔憂。',48,'全唐诗/poet.song.92000.json','["未愈俱生疾，空懷宿昔憂。", "時因發孤興，尚足慰窮愁。", "月落初無念，花開不自由。", "如何雁南鄉，不共水東流。"]'),
('a933bac9-2be3-4914-b2cb-fec681270591','偶作二絕  其一','呂本中','宋','宋诗','song-poetry','','[]','不嫌羸病守繩床，世念紛紛久已降。',32,'全唐诗/poet.song.92000.json','["不嫌羸病守繩床，世念紛紛久已降。", "一夜月明如白日，驟聞急雨打天窗。"]'),
('29da471f-54b8-4a86-b172-5c028cc3d510','偶作二絕  其二','呂本中','宋','宋诗','song-poetry','','[]','膏火從來只自焚，何曾野鶴駐雞羣。',32,'全唐诗/poet.song.92000.json','["膏火從來只自焚，何曾野鶴駐雞羣。", "如何死亦無公論，地下猶存衛府勲。"]'),
('4c85d8af-505f-493b-aa4c-77821eac374e','謝滕尉送梅','呂本中','宋','宋诗','song-poetry','','[]','破帷冷落不禁風，疾病深藏稱懶慵。',64,'全唐诗/poet.song.92000.json','["破帷冷落不禁風，疾病深藏稱懶慵。", "忽有梅花來陋巷，喜聞春信出初冬。", "未須趁雪爭先睹，尚恐衝寒不滿容。", "會約君家好兄弟，他年尊酒便相從。"]'),
('7f66e947-bb73-43e0-945e-2ce4c75ba313','游山','呂本中','宋','宋诗','song-poetry','','[]','世味日可厭，兹游那得忘。',48,'全唐诗/poet.song.92000.json','["世味日可厭，兹游那得忘。", "稻田疏宿雨，木葉犯新霜。", "潦倒交游在，追隨氣味長。", "僧窗有靜供，茗盌侑爐香。"]'),
('e698b7d7-ad3b-4afb-bf50-e56f52e635f1','李丞相挽詩三首  其一','呂本中','宋','宋诗','song-poetry','','[]','舊學邈難繼，相期從少年。',48,'全唐诗/poet.song.92000.json','["舊學邈難繼，相期從少年。", "初看驥伏櫪，遽作鶴冲天。", "烈所平生志，高名萬代傳。", "如何事未濟，此老下黄泉。"]'),
('75237b5e-006c-41c9-b481-018f29c3642f','李丞相挽詩三首  其二','呂本中','宋','宋诗','song-poetry','','[]','兄弟俱英妙，聲名萃一門。',48,'全唐诗/poet.song.92000.json','["兄弟俱英妙，聲名萃一門。", "論才無不可，於道獨爲尊。", "未定千年策，終嫌萬丈渾。", "天乎乃如此，不使拯乾坤。"]'),
('9ba9d9d3-9c8d-45a5-9d99-0ee2b9a38e12','李丞相挽詩三首  其三','呂本中','宋','宋诗','song-poetry','','[]','事業懷蕭相，胸襟識謝安。',48,'全唐诗/poet.song.92000.json','["事業懷蕭相，胸襟識謝安。", "流風有餘烈，志士只長歎。", "淮海他年竭，冰霜此夜寒。", "向來交友淚，南望不曾乾。"]'),
('f1561f79-38d6-493b-b0f6-a6c8da3aaaa8','以一縑寄范四弟','呂本中','宋','宋诗','song-poetry','','[]','中原厭胡馬，所至是賊窟。',72,'全唐诗/poet.song.92000.json','["中原厭胡馬，所至是賊窟。", "念君空懸罄，何以備倉卒。", "窮冬霜雪繁，欲救乃無術。", "兒號君莫厭，婢怨君莫恤。", "平生師顔子，于此見仿佛。", "此縑君所知，自我機杼出。"]'),
('6e2a2665-29ba-409c-9516-42135132eeee','江梅','呂本中','宋','宋诗','song-poetry','','[]','江梅消息未真傳，微露芳心几杖前。',64,'全唐诗/poet.song.92000.json','["江梅消息未真傳，微露芳心几杖前。", "不信冰霜能作惡，要令桃李便爭先。", "斜枝似带千峰雪，冷艶偷回二月天。", "準擬從君出城去，竹輿仍勝百花韀。"]'),
('6aa8daa8-5317-4cea-bd1b-95ac32521c85','鼓山頌法眼語在裏即求出云大家合眼跳黄河戲成四韵奉答','呂本中','宋','宋诗','song-poetry','','[]','合眼跳黄河，未有過得者。',48,'全唐诗/poet.song.92000.json','["合眼跳黄河，未有過得者。", "豈惟不得過，身亦須判捨。", "告君過河妙，止要具船筏。", "乘時等風去，過此無别法。"]'),
('1748c951-066c-4080-a1ce-e5f807be79b7','夜深歸家聞隣家小兒讀書可喜有作','呂本中','宋','宋诗','song-poetry','','[]','還家更寒三鼓餘，隣家小兒猶讀書。',64,'全唐诗/poet.song.92000.json','["還家更寒三鼓餘，隣家小兒猶讀書。", "王侯將相乃無種，紈袴綺襦寧似渠。", "北風颼颼霜被草，聽汝讀書聲轉好。", "莫言翁媪惜膏油，有兒如此可無憂。"]'),
('65387dad-e606-4e71-8923-30cc46a8de39','梅花','呂本中','宋','宋诗','song-poetry','','[]','野水依城竹映沙，江梅開處又人家。',32,'全唐诗/poet.song.92000.json','["野水依城竹映沙，江梅開處又人家。", "天晴徑欲花前醉，只恐衰顔不稱花。"]'),
('0194b8ca-a575-4861-848d-a5cc35a06e8d','無題二首  其一','呂本中','宋','宋诗','song-poetry','','[]','德盛不狎侮，玄談多作俳。',48,'全唐诗/poet.song.92000.json','["德盛不狎侮，玄談多作俳。", "居然少荘語，無乃近齊諧。", "恨此達者趣，猶乖壮士懷。", "故當先復禮，方得盡梯階。"]'),
('b2482b11-a61f-43c5-ad0c-030f03cf6dde','無題二首  其二','呂本中','宋','宋诗','song-poetry','','[]','聖學邈難繼，斯文當望誰。',48,'全唐诗/poet.song.92000.json','["聖學邈難繼，斯文當望誰。", "還能養志氣，且務攝威儀。", "曾子但三省，子長徒愛奇。", "從來要功處，本不在多知。"]'),
('9f7fb012-dba3-4cd3-968d-52ceadf7fe50','贈李元亮之子李子','呂本中','宋','宋诗','song-poetry','','[]','往時諸李在江都，文采風流一代無。',64,'全唐诗/poet.song.92000.json','["往時諸李在江都，文采風流一代無。", "每得清詩如小謝，已聞前輩許封胡。", "好松久已埋深澗，老馬今猶憶舊途。", "令子相逢初未識，尚容衰晚見規模。"]'),
('ca283415-79da-479d-9d24-3f70cd84cd40','二月七日與羣從游陳氏園  其一','呂本中','宋','宋诗','song-poetry','','[]','平居羸病每相妨，今日尋春有底忙。',32,'全唐诗/poet.song.92000.json','["平居羸病每相妨，今日尋春有底忙。", "何以至人常不出，看人衝雨度浮航。"]'),
('dd70c181-4b98-439d-ae7c-b09312f6ba25','二月七日與羣從游陳氏園  其二','呂本中','宋','宋诗','song-poetry','','[]','橋北橋南花亂開，小園和雨掃莓苔。',32,'全唐诗/poet.song.92000.json','["橋北橋南花亂開，小園和雨掃莓苔。", "不嫌拄杖衝泥入，更許乘閑著屐來。"]'),
('419c046f-e5ff-4cd9-b9d1-11606e5f66d1','懷許子禮','呂本中','宋','宋诗','song-poetry','','[]','寒松厭庭院，老馬倦維縶。',84,'全唐诗/poet.song.92000.json','["寒松厭庭院，老馬倦維縶。", "翛然出塵去，粗免朝夕急。", "我友隔湖嶺，尚作一日葺。", "平生學道心，擇善有固執。", "豈不在行路，自遠霜露濕。", "百川灌河來，砥柱乃中立。", "何時一尊酒，更與交舊集。"]'),
('5d557b78-5356-4e63-89a7-20146a8b1df8','雪  其一','呂本中','宋','宋诗','song-poetry','','[]','窮巷無人對雪，小詩自可逃禪。',28,'全唐诗/poet.song.92000.json','["窮巷無人對雪，小詩自可逃禪。", "看取一年三白，喜歡共入新年。"]'),
('1aa1241c-e078-4736-b82b-83ccbacfb0f6','雪  其二','呂本中','宋','宋诗','song-poetry','','[]','堅坐正宜養病，開門便當幽尋。',28,'全唐诗/poet.song.92000.json','["堅坐正宜養病，開門便當幽尋。", "一夜雪深一尺，與誰取酒同斟。"]'),
('68bdd339-fdee-44cc-be94-40bb210af644','報暉庵','呂本中','宋','宋诗','song-poetry','','[]','寸草仰生活，春暉常照臨。',120,'全唐诗/poet.song.92000.json','["寸草仰生活，春暉常照臨。", "不知欲報德，何以見此心。", "江漢有時竭，此心無淺深。", "魏氏有令德，傳家非獨今。", "結庵在山阿，日瞻松柏林。", "仁風被遠迹，猛獸不敢侵。", "令子守直道，意往無崎嶔。", "遂令此鄉人，得聞金玉音。", "我行時序晚，回望西山岑。", "延領長太息，聊爲純孝吟。"]'),
('ee89edc8-41fb-469a-a878-ef86389b8f43','贈荘季路','呂本中','宋','宋诗','song-poetry','','[]','老矣荘夫子，居閑肯厭貧。',48,'全唐诗/poet.song.92000.json','["老矣荘夫子，居閑肯厭貧。", "盛時更讀易，憂道不無人。", "記往詩猶在，相逢意倍親。", "尚期香火社，文字約遺民。"]'),
('00c618c7-d3f4-4dda-81b5-99626662f89f','李尚書挽詞','呂本中','宋','宋诗','song-poetry','','[]','李氏三吳秀，尚書一代英。',72,'全唐诗/poet.song.92000.json','["李氏三吳秀，尚書一代英。", "立朝惟直道，守已但純誠。", "報國心雖在，憂時病已成。", "人推四兄弟，氣壓百公卿。", "未就養生術，獨取强諫名。", "傷心舊游地，城郭漫溪聲。"]'),
('4edbe5cf-be33-4801-9c73-ac827c5a39cf','李器之履齋','呂本中','宋','宋诗','song-poetry','','[]','人履履險巇，君履履平地。',96,'全唐诗/poet.song.92000.json','["人履履險巇，君履履平地。", "平地信可履，行穩居亦易。", "責己不責人，爲道不爲利。", "熟視履險者，豈不心有愧。", "君家天台守，固學有餘味。", "微言化子姪，自足警一世。", "初無舉足勞，寧有半塗滯。", "君能識其然，我亦從子逝。"]'),
('997d8150-6b57-4912-a5a8-9b25999d25b5','野寺','呂本中','宋','宋诗','song-poetry','','[]','曉窗日未融，野寺雨欲作。',72,'全唐诗/poet.song.92000.json','["曉窗日未融，野寺雨欲作。", "經旬少客到，靜坐差可樂。", "平生遭病擾，今更不如昨。", "囊空畏高醫，何以致良藥。", "所幸秋已至，所在身可著。", "洗耳聽涼風，不待一葉落。"]'),
('6b625303-fa3c-479c-83ab-af55e7b3ccb9','辛酉立春','呂本中','宋','宋诗','song-poetry','','[]','中原擾擾尚胡塵，堅坐江南懶問津。',64,'全唐诗/poet.song.92000.json','["中原擾擾尚胡塵，堅坐江南懶問津。", "漫讀舊詩如昨夢，却疑往事是前身。", "子桑自了經時病，原憲長甘一味貧。", "刺忍雪寒君莫病，土牛花勝已迎春。"]'),
('70efcceb-0aa0-4865-bce0-3d01be53711b','雪夜','呂本中','宋','宋诗','song-poetry','','[]','破屋除燈雪自明，案頭無用讀書檠。',64,'全唐诗/poet.song.92000.json','["破屋除燈雪自明，案頭無用讀書檠。", "老慵已慣跏趺坐，昏夢尤便松竹吟。", "知有故人來問道，久無佳興與尋盟。", "明年更有閩山興，但辦行纒莫計程。"]'),
('7abba5aa-07f1-41bc-bbbf-cbe95a982240','謝方倅惠炭','呂本中','宋','宋诗','song-poetry','','[]','寒壓新春雪不融，布衾如銕坐衰翁。',32,'全唐诗/poet.song.92000.json','["寒壓新春雪不融，布衾如銕坐衰翁。", "煩君又送南山炭，更放殘爐一夜紅。"]'),
('d98bd275-6cd8-4c8f-9f83-e363431d2a72','即事四絕  其一','呂本中','宋','宋诗','song-poetry','','[]','老來于世轉無求，事業聲名種種休。',32,'全唐诗/poet.song.92000.json','["老來于世轉無求，事業聲名種種休。", "伴得鄰僧忍饑慣，閉門無飯讀春秋。"]'),
('a801fc27-7455-47f7-b1a3-f4d2c49b1724','即事四絕  其二','呂本中','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','匆匆和夢别星樓，擾擾隨緣住信州。',32,'全唐诗/poet.song.92000.json','["匆匆和夢别星樓，擾擾隨緣住信州。", "尚笑長江少方便，只教溪水暫西流。"]'),
('24bf5f92-3656-486e-836a-7ad383e0e23f','即事四絕  其三','呂本中','宋','宋诗','song-poetry','','[]','問柳尋花懶不知，登山臨水病難爲。',32,'全唐诗/poet.song.92000.json','["問柳尋花懶不知，登山臨水病難爲。", "日長客去松陰靜，强課兒曹學和詩。"]'),
('e0f4afe9-01c9-428e-bb80-70ae301213a8','即事四絕  其四','呂本中','宋','宋诗','song-poetry','','[]','經旬却怕酒盃深，野寺雖閑病至今。',32,'全唐诗/poet.song.92000.json','["經旬却怕酒盃深，野寺雖閑病至今。", "莫謂閑居厭醫藥，未妨隨證檢千金。"]'),
('c9c8daf4-9ef0-45b3-8176-d1acc0e8e629','贈人','呂本中','宋','宋诗','song-poetry','','[]','中表多離隔，情親子獨賢。',48,'全唐诗/poet.song.92000.json','["中表多離隔，情親子獨賢。", "心游衆目外，氣出萬夫前。", "米賤猶堪飽，官閑不記年。", "春風上嚴瀨，爲我略回船。"]'),
('9dfc4b52-90fc-45cd-aee1-0a9fd270fd26','辛酉之冬周提宫埅惠行隔','呂本中','宋','宋诗','song-poetry','','[]','深冬坐窮閻，未厭風日惡。',108,'全唐诗/poet.song.92000.json','["深冬坐窮閻，未厭風日惡。", "今晨起濃陰，正恐雨雪作。", "故人憐我寒，垂意到丘壑。", "虚堂排竹牖，已覺暖勝昨。", "初無窮窒勞，漸有閑適樂。", "我生甚易足，所至况旅泊。", "不爲御冬計，敢復備隕籜。", "偶蒙仁者念，僻處未蕭索。", "從今作新年，對酒且斟酌。"]'),
('9e8ff3a6-706a-4d86-9e72-0cb3436aee3a','寄張仲宗','呂本中','宋','宋诗','song-poetry','','[]','聞道張夫子，今年已定居。',48,'全唐诗/poet.song.92000.json','["聞道張夫子，今年已定居。", "偶緣荔子債，遂絕故人書。", "歲月足可惜，溪山莫負渠。", "他年得相近，不必問庖廚。"]'),
('d216d002-1c5e-4ce0-9c6d-a0ad6f48597a','周仲固尚論齋','呂本中','宋','宋诗','song-poetry','','[]','周侯不出何所爲，閉門讀書心自知。',160,'全唐诗/poet.song.92000.json','["周侯不出何所爲，閉門讀書心自知。", "簞瓢陋巷君不厭，讀書萬卷能忘饑。", "上參羲皇下秦漢，采取英華幾脱腕。", "是非榮辱姑置之，忽若乘船到彼岸。", "古人之學有傳授，君生寂寞千載後。", "問君何以識古人，袖手無言坐清晝。", "以此讀書爲尚友，是事渺茫人信否。", "人信不信君不問，松柏固難生培塿。", "朝來落葉亂荒城，青山照人溪水横。", "往來車馬作塵土，想君深夜讀書聲。"]'),
('a7ac8106-4735-412f-b065-e2a9485fb25d','吉州段秀才粟庵','呂本中','宋','宋诗','song-poetry','','[]','大千非有餘，一粟豈不足。',48,'全唐诗/poet.song.92000.json','["大千非有餘，一粟豈不足。", "須彌納芥子，豈復論盈縮。", "今君住世網，何以得此獨。", "始知陋巷居，已悟不遠復。"]'),
('2fbe5669-f537-4b5c-91a8-548697b7ce71','自如齋','呂本中','宋','宋诗','song-poetry','','[]','朝爲事所奪，莫爲饑所驅。',48,'全唐诗/poet.song.92000.json','["朝爲事所奪，莫爲饑所驅。", "不知六合間，何人能自如。", "永新段夫子，屋小心有餘。", "教之有家法，逃禪猶作書。"]'),
('cfa3ef52-283d-430d-84b2-4d10242bff78','醉經堂','呂本中','宋','宋诗','song-poetry','','[]','紛紛入醉夢，一語令渠醒。',48,'全唐诗/poet.song.92000.json','["紛紛入醉夢，一語令渠醒。", "段子閉門居，云何猶醉經。", "其醉蓋非醉，初無能解酲。", "問經何所說，明善故能誠。"]'),
('e734326e-857f-4226-8478-3883f924c853','題焦寺丞詩冊三絕  其一','呂本中','宋','宋诗','song-poetry','','[]','一世奔波在别離，君家孝友獨天知。',32,'全唐诗/poet.song.92000.json','["一世奔波在别離，君家孝友獨天知。", "已令好夢傳消息，更有賓鴻效羽儀。"]'),
('4fea5d5a-b4a0-4298-9864-c0ddd8af5c76','題焦寺丞詩冊三絕  其二','呂本中','宋','宋诗','song-poetry','','[]','路旁來報定何人，物理潛通自有神。',32,'全唐诗/poet.song.92000.json','["路旁來報定何人，物理潛通自有神。", "想得三衢相見地，至今草木亦長春。"]'),
('3289f537-c9d3-4e31-99d9-54b20829dcba','題焦寺丞詩冊三絕  其三','呂本中','宋','宋诗','song-poetry','','[]','河朔家人墮渺茫，江南風日正舒長。',32,'全唐诗/poet.song.92000.json','["河朔家人墮渺茫，江南風日正舒長。", "已知原上鶺鴒處，更入雲間鴻雁行。"]'),
('2133519d-1c12-4a27-8fff-3ad66609e37c','暴物','呂本中','宋','宋诗','song-poetry','','[]','暴物看日景，頃刻未嘗停。',84,'全唐诗/poet.song.92000.json','["暴物看日景，頃刻未嘗停。", "隨景移暴物，日示令心驚。", "寓此不停景，乃復望長生。", "匆匆駒過隙，悠悠池汛萍。", "况兹兵火中，而每疾病攖。", "野寺過毒暑，旱氣浮高城。", "出門君莫厭，宿昔已秋聲。"]'),
('68b64b2f-0008-4783-b82c-8f4e9b9e6bc0','次葉守喜雨','呂本中','宋','宋诗','song-poetry','','[]','羣囂寂寞已收聲，預怯秋房獨夜情。',64,'全唐诗/poet.song.92000.json','["羣囂寂寞已收聲，預怯秋房獨夜情。", "忽聽僧簷鳴宿雨，定知田舍舞安甿。", "盡消積暑經時早，不厭新涼數日晴。", "更喜此邦賢太守，樂爲詩頌教諸生。"]'),
('dfa51030-8b22-45e3-ab1b-fcdf1c3d5340','無題','呂本中','宋','宋诗','song-poetry','','[]','學詩漸老轉銷聲，末路蒙山此日情。',64,'全唐诗/poet.song.92000.json','["學詩漸老轉銷聲，末路蒙山此日情。", "尚有文章能起疾，豈惟田里解蚩甿。", "近郊秔稻成秋熟，繞郭溪山入晚晴。", "剩繞長廊和新句，不知庭下薄寒生。"]'),
('088ce3d4-8ee1-44b2-958c-42597e000688','次韻曾宏甫木犀','呂本中','宋','宋诗','song-poetry','','[]','風吹旱暑未成秋，辜負江村事事幽。',64,'全唐诗/poet.song.92000.json','["風吹旱暑未成秋，辜負江村事事幽。", "巖桂敢煩先折送，好詩仍不待邀求。", "自憐疾病常高枕，坐想風流換此州。", "他日出門尋舊約，未嫌疏懶作人不。"]'),
('4eaece3e-92f7-40eb-a1d3-0be9e7863894','贈鄭侍郎二首  其一','呂本中','宋','宋诗','song-poetry','','[]','便欲深居過一寒，破窗重覓舊蒲團。',32,'全唐诗/poet.song.92000.json','["便欲深居過一寒，破窗重覓舊蒲團。", "莫年生活如何做，子細煩公指示看。"]'),
('a347a1b5-2e1c-4b3f-85b3-0f0fc0688e77','贈鄭侍郎二首  其二','呂本中','宋','宋诗','song-poetry','','[]','幾時不過西禪寺，直自初秋到晚秋。',32,'全唐诗/poet.song.92000.json','["幾時不過西禪寺，直自初秋到晚秋。", "聞道主人憐我病，天寒酒未送新篘。"]'),
('30bfb170-1901-4659-93d4-00a3944a40b5','次曾宏甫九日韻','呂本中','宋','宋诗','song-poetry','','[]','僧園曉色散棲鵶，强起新詩整復斜。',64,'全唐诗/poet.song.92000.json','["僧園曉色散棲鵶，强起新詩整復斜。", "正想故人披宿霧，忽蒙佳句洗昏花。", "舊游往往違心事，老病昏昏漫歲華。", "辜負重陽一尊酒，且來占雨又朝霞。"]'),
('efc5d41e-f0ca-4d6d-a1f3-cda1d0a8e918','九日贈曾宏甫二絕  其一','呂本中','宋','宋诗','song-poetry','','[]','茶花過雨十分香，山後山前已带霜。',32,'全唐诗/poet.song.92000.json','["茶花過雨十分香，山後山前已带霜。", "何事東籬數株菊，已將青蕋趁重陽。"]'),
('9cdd43c4-162d-4cc9-bca2-116a9f476366','九日贈曾宏甫二絕  其二','呂本中','宋','宋诗','song-poetry','','[]','漸退中原胡馬塵，溪山未厭往來頻。',32,'全唐诗/poet.song.92000.json','["漸退中原胡馬塵，溪山未厭往來頻。", "雖無名酒酬佳節，尚有新詩答故人。"]'),
('79939403-3be5-4dd8-9560-462483cba8e1','送徐止秀才歸小葉','呂本中','宋','宋诗','song-poetry','','[]','後生少規模，子學有根源。',84,'全唐诗/poet.song.92000.json','["後生少規模，子學有根源。", "紛然衆室中，獨識孔氏尊。", "古人雖不作，此理固常存。", "滄海無津涯，寧有衆水分。", "鑑明不受垢，垢盡亦無痕。", "子還訪師友，當自得其門。", "躬行見日用，餘事不論文。"]'),
('fc99adc7-aa2f-49f6-8615-5d4248e8d8d7','次葉守韻','呂本中','宋','宋诗','song-poetry','','[]','新正無所爲，出戶亦乘興。',96,'全唐诗/poet.song.92000.json','["新正無所爲，出戶亦乘興。", "欲尋林泉幽，不避風雪迸。", "搜腸乞佳話，分外若贅癭。", "故知藜藿盤，不受珍果飣。", "清詩洗病目，鄙陋知不稱。", "披雪見新月，乃悟本來性。", "溪山况瀟灑，復有松竹映。", "何須待醇酒，然後有酩酊。"]'),
('cfa39322-0220-44f5-9144-d2260be5f28b','送曾宏甫知黄州四絕  其一','呂本中','宋','宋诗','song-poetry','','[]','雨餘天氣欲嘗橙，栗可煨炮芋可羮。',32,'全唐诗/poet.song.92000.json','["雨餘天氣欲嘗橙，栗可煨炮芋可羮。", "正是一年秋好處，忍令無酒送君行。"]'),
('5d7d5f86-c79f-4a9e-a691-0f4de273d0e5','送曾宏甫知黄州四絕  其二','呂本中','宋','宋诗','song-poetry','','[]','口脣白醭未嘗開，正始餘音挽復回。',32,'全唐诗/poet.song.92000.json','["口脣白醭未嘗開，正始餘音挽復回。", "他日爐香爲誰起，公曾親見了翁來。"]'),
('4f75d50e-9d67-4714-9773-245cbc41b1c9','送曾宏甫知黄州四絕  其三','呂本中','宋','宋诗','song-poetry','','[]','君到江頭不問津，雪堂草木幾番新。',32,'全唐诗/poet.song.92000.json','["君到江頭不問津，雪堂草木幾番新。", "一生未得文章力，要掃中原胡馬塵。"]'),
('bbb21f5d-73c2-4f98-8cb8-1e8cabcfd408','送曾宏甫知黄州四絕  其四','呂本中','宋','宋诗','song-poetry','','[]','騏驥徐行不離羣，却行江北訪斯文。',32,'全唐诗/poet.song.92000.json','["騏驥徐行不離羣，却行江北訪斯文。", "潘何子弟能傳業，當奉遺書與使君。"]'),
('207886d8-480e-4998-98d7-5b2debc0f86e','題范才元畫軸後','呂本中','宋','宋诗','song-poetry','','[]','昔年曾過嶺南州，爭看湘江萬里流。',32,'全唐诗/poet.song.92000.json','["昔年曾過嶺南州，爭看湘江萬里流。", "妙手可傳詩外意，亂雲寒木更孤舟。"]'),
('815db34d-a107-42b2-b397-13369cb1c662','送尹少稷賢良還懷玉山','呂本中','宋','宋诗','song-poetry','','[]','青松在庭檻，乃受衆目憐。',180,'全唐诗/poet.song.92000.json','["青松在庭檻，乃受衆目憐。", "念彼歲寒枝，肯爭桃李妍。", "不如卧澗壑，歲久霜雪前。", "尹侯東州英，炯若珠在淵。", "避地走南荒，因循留瘴烟。", "歸來懷玉山，草草屋數椽。", "深居絕萬慮，讀書欲忘年。", "偶出到城市，頗厭塵囂煎。", "搜腸出妙語，贈我以長篇。", "行潦被注挹，朽木煩彫鐫。", "紛紛車馬間，孰能知子賢。", "别歸值短晷，肯復更留連。", "我老百事廢，鈍馬難加鞭。", "清霜粲屋瓦，白雲常在天。", "悵望子所居，欲去無夤緣。"]'),
('1add545d-7831-4f14-a0f7-18dd102d6851','寄題曾黄州重修睡足齋','呂本中','宋','宋诗','song-poetry','','[]','雲濤際天江北路，郡古人稀春欲暮。',160,'全唐诗/poet.song.92000.json','["雲濤際天江北路，郡古人稀春欲暮。", "平生想像睡足庵，頗見王杜安身處。", "十年兵火庵已壞，草莽連崗穴狐兔。", "使君初來席未暖，重就新齋立窗戶。", "疏疏脩竹带泉石，歷歷幽光點烟霧。", "竹樓月波不寂寞，雪堂東坡復共住。", "昔者同遭盜賊擾，今者定蒙神物護。", "使君忘言坐搔首，抖擻衣襟脱巾履。", "下簾高枕百吏散，一任江頭風斷渡。", "會思王杜與新詩，夢裏相逢得奇句。"]'),
('43e70454-ba5e-4a07-82fb-1c50ee5b3af6','重陽前一日作','呂本中','宋','宋诗','song-poetry','','[]','涼風策策旁江城，道路猶寛遠去程。',64,'全唐诗/poet.song.92000.json','["涼風策策旁江城，道路猶寛遠去程。", "秋晚情懷常索莫，夜長更漏轉分明。", "未償臍腹三年艾，不負膏油二尺檠。", "明日黄花一尊酒，苦思親舊與同傾。"]'),
('b8dd8093-99d4-46d3-9f08-c9d144d40470','春晚','呂本中','宋','宋诗','song-poetry','','[]','春色忽已晚，悠悠留此心。',48,'全唐诗/poet.song.92000.json','["春色忽已晚，悠悠留此心。", "深居有閑暇，令節廢追尋。", "更老愁何在，長貧病亦侵。", "一盃聊自勸，不爲落花斟。"]'),
('a6cfabb2-68a2-4ff2-a19c-e282fc878206','寒食二絕  其一','呂本中','宋','宋诗','song-poetry','','[]','梨花雪白柳深青，也似中原舊驛亭。',32,'全唐诗/poet.song.92000.json','["梨花雪白柳深青，也似中原舊驛亭。", "猶記往來寒食下，客房無酒卧空瓶。"]'),
('4f4c8ceb-e073-4361-bade-80c2be391aba','寒食二絕  其二','呂本中','宋','宋诗','song-poetry','','[]','今年春物更匆匆，野杏山桃取次紅。',32,'全唐诗/poet.song.92000.json','["今年春物更匆匆，野杏山桃取次紅。", "底事無錢作寒食，可無新語記車公。"]'),
('9000f675-1f50-4177-86bf-79ff30344107','閑居即事','呂本中','宋','宋诗','song-poetry','','[]','新舊音書寂不來，略無一事可縈懷。',64,'全唐诗/poet.song.92000.json','["新舊音書寂不來，略無一事可縈懷。", "春風寂寞花侵路，野寺荒涼草上階。", "剩欲出門留客坐，不妨扶杖看僧齋。", "無人會得龐公意，只道淵明是正儕。"]'),
('742b4f04-5a75-44b1-a0f4-0464e43d7bc7','偶出謝客','呂本中','宋','宋诗','song-poetry','','[]','才過清明日更長，竹輿頻出度浮梁。',64,'全唐诗/poet.song.92000.json','["才過清明日更長，竹輿頻出度浮梁。", "雨侵田水連溪白，春入山花带蜜香。", "數有故人相勞苦，不嫌俗事且窮忙。", "今年尚有湖湘興，不待秋風便促装。"]'),
('55d9d106-2ebb-4fa1-ae8a-4918ef861107','蔬食三首  其一','呂本中','宋','宋诗','song-poetry','','[]','殺物以活己，肉食固多慚。',48,'全唐诗/poet.song.92000.json','["殺物以活己，肉食固多慚。", "况無一事勤，敢于滋味貪。", "今晨病少間，調羮有酸鹹。", "居然飽笋蕨，自足慰清饞。"]'),
('67c35156-3067-4dfd-b267-f22442a075e0','蔬食三首  其二','呂本中','宋','宋诗','song-poetry','','[]','磨刀向猪羊，渠有千種苦。',48,'全唐诗/poet.song.92000.json','["磨刀向猪羊，渠有千種苦。", "廚人盡心力，博汝一笑許。", "此道在忠恕，觀彼更觀汝。", "聖人雖未言，寧可自莽鹵。"]'),
('e109334c-104c-4681-afbd-1b89502ab08d','蔬食三首  其三','呂本中','宋','宋诗','song-poetry','','[]','夫子釣不綱，于理已不隱。',48,'全唐诗/poet.song.92000.json','["夫子釣不綱，于理已不隱。", "浮屠斷食肉，此語說始盡。", "人生慣便習，奉法乃不謹。", "要當守淡薄，萬事可堅忍。"]'),
('35206069-b76b-4086-b5e7-4e565a83bdd9','戒殺八首  其一','呂本中','宋','宋诗','song-poetry','','[]','勸君勿殺犬，犬有爲主心。',48,'全唐诗/poet.song.92000.json','["勸君勿殺犬，犬有爲主心。", "爲主反見殺，君何無淺深。", "君貧犬不去，君富犬分憂。", "執以付鼎鑊，于君心穏不。"]'),
('d3d06999-ac94-4a30-b9d5-4cd6fc8e267a','戒殺八首  其二','呂本中','宋','宋诗','song-poetry','','[]','畜犬被縛時，猶爲主人吠。',48,'全唐诗/poet.song.92000.json','["畜犬被縛時，猶爲主人吠。", "吠聲不絕口，湯沸主已退。", "主人調醯鹽，欲以佐滋味。", "持此望身安，世間寧有是。"]'),
('7d13b29f-a1d2-4645-8df1-f65ab13d35af','戒殺八首  其三','呂本中','宋','宋诗','song-poetry','','[]','犬雖有小過，未至不得活。',48,'全唐诗/poet.song.92000.json','["犬雖有小過，未至不得活。", "賣錢與屠宰，使得恣臠割。", "君兒小不安，君夜不得眠。", "何獨于此犬，如此安忍然。"]'),
('3a459f44-3863-4372-abf9-e73b58b9e2bc','戒殺八首  其四','呂本中','宋','宋诗','song-poetry','','[]','勸君勿殺鷄，鷄能伺昏曉。',48,'全唐诗/poet.song.92000.json','["勸君勿殺鷄，鷄能伺昏曉。", "聞鷄君即起，一一家事了。", "一朝被烹煮，不念前日功。", "主人取暫飽，鷄苦固無窮。"]'),
('515fe42d-0303-4324-af61-919d115bf457','戒殺八首  其五','呂本中','宋','宋诗','song-poetry','','[]','縱犬使殺鼠，鼠窘生百畏。',48,'全唐诗/poet.song.92000.json','["縱犬使殺鼠，鼠窘生百畏。", "其饑使之出，此亦有何罪。", "犬鼠俱可殺，莫計有無功。", "苟以無功死，還與殺犬同。"]'),
('c3b7c854-56bd-4f59-9f0b-ad560252082a','戒殺八首  其六','呂本中','宋','宋诗','song-poetry','','[]','願君普斷殺，能益君壽數。',48,'全唐诗/poet.song.92000.json','["願君普斷殺，能益君壽數。", "子孫亦長年，皆以不殺故。", "君子遠庖廚，非有意于善。", "但能觀自身，此理即可見。"]'),
('7c806d03-fe16-49cc-8311-989eb20c4abf','戒殺八首  其七','呂本中','宋','宋诗','song-poetry','','[]','商臣殺其父，身亦烹楚國。',48,'全唐诗/poet.song.92000.json','["商臣殺其父，身亦烹楚國。", "世民殺其兄，亦未妨大福。", "以此知報應，未必在此時。", "此時雖無他，終久君試思。"]'),
('49945a69-5903-4a17-84b7-1269a2590ca2','戒殺八首  其八','呂本中','宋','宋诗','song-poetry','','[]','虎狼非不仁，天機使之然。',48,'全唐诗/poet.song.92000.json','["虎狼非不仁，天機使之然。", "蛇虺肆百毒，此亦受之天。", "願君勿憎怒，憫此心謬用。", "仁氣苟薰蒸，終皆變麟鳳。"]'),
('cf95829c-8af0-4871-b824-e50a438ae270','寄祁居之','呂本中','宋','宋诗','song-poetry','','[]','苦憶均陽祁處士，只今全似住庵僧。',32,'全唐诗/poet.song.92000.json','["苦憶均陽祁處士，只今全似住庵僧。", "何時更得相從去，細話叢林舊葛藤。"]'),
('4e189cac-748f-4408-a4c0-1830f97eba17','送韓念八迪功','呂本中','宋','宋诗','song-poetry','','[]','君去留不得，我行還未忙。',48,'全唐诗/poet.song.92000.json','["君去留不得，我行還未忙。", "漂零更遠别，衰疾且深藏。", "野水千山綠，荷花一路香。", "猶思往還地，相望隔浮航。"]'),
('e7341ce7-8c66-491f-8269-c17bc0cb557c','謙上人清湍亭','呂本中','宋','宋诗','song-poetry','','[]','道人結庵殊未就，先起小亭山左右。',144,'全唐诗/poet.song.92000.json','["道人結庵殊未就，先起小亭山左右。", "不將溪水濯塵埃，且以清湍爲客壽。", "雲烟映靄作春濃，草木堅枯辨秋瘦。", "客來相對兩無語，豈有浮辭問時候。", "一生行脚如夢覺，天意似于君獨厚。", "我今留滯未得往，想像此亭如故舊。", "再三伸紙誦清詩，已勝開尊飲醇酎。", "簞瓢可樂不淡薄，蘭菊重生足滋茂。", "他時有暇更分題，此游未落諸公後。"]'),
('9d2d0263-44f5-4644-a854-fdca300c0444','送韓臨亨提舉','呂本中','宋','宋诗','song-poetry','','[]','君有千里行，我獨留此居。',144,'全唐诗/poet.song.92000.json','["君有千里行，我獨留此居。", "君行赴何許，沅江隔重湖。", "我留此山中，欲去尚躊躇。", "沅江道里僻，罷民待君蘇。", "君亦憐其民，溼沫勤喣濡。", "涼風促君斾，小雨膏君車。", "漸去囂塵遠，及此夏景初。", "野色望行路，東門初首涂。", "風土日已好，誰能懷舊廬。", "舉手謝拘束，有若縱壑魚。", "路逢舊交游，相見問何如。", "道我且貧病，因風時寄書。"]'),
('9453211b-82ea-4342-b3a6-36b370e08183','和伯少穎迂仲將歸福唐偶成數詩欲奉寄無便未果也辰叔常季南還因以奉送  其一','呂本中','宋','宋诗','song-poetry','','[]','紛紛走道途，擾擾雜泥滓。',48,'全唐诗/poet.song.92000.json','["紛紛走道途，擾擾雜泥滓。", "既爲風俗移，又以血氣使。", "百川灌河來，夫豈有涯涘。", "故人林與李，始可與語此。"]'),
('5d7689ec-c04b-45ef-b90c-d9257a4f0f5b','和伯少穎迂仲將歸福唐偶成數詩欲奉寄無便未果也辰叔常季南還因以奉送  其二','呂本中','宋','宋诗','song-poetry','','[]','方子獨立士，歲暮亦深居。',48,'全唐诗/poet.song.92000.json','["方子獨立士，歲暮亦深居。", "林李從之游，欲出更躊躇。", "紛華晚不顧，浮湛同里閭。", "時從陸丈人，共此一篇書。"]'),
('ca00ffc9-c328-45ba-b4b6-587dec45c1a4','和伯少穎迂仲將歸福唐偶成數詩欲奉寄無便未果也辰叔常季南還因以奉送  其三','呂本中','宋','宋诗','song-poetry','','[]','閩山固多奇，閩士亦多傑。',48,'全唐诗/poet.song.92000.json','["閩山固多奇，閩士亦多傑。", "弱水不勝舟，有此積立鐵。", "胡劉守節意，亦豈待言說。", "堂堂混衆流，此固不得折。"]'),
('05045541-4593-4f7d-9033-c83d53e2440b','和伯少穎迂仲將歸福唐偶成數詩欲奉寄無便未果也辰叔常季南還因以奉送  其四','呂本中','宋','宋诗','song-poetry','','[]','經時望子來，慰我終歲病。',48,'全唐诗/poet.song.92000.json','["經時望子來，慰我終歲病。", "西行道路迂，復見復未定。", "秋毫論得失，此豈不有命。", "嘗聞安身要，其本在無競。"]'),
('239f0df4-e659-4680-a993-27706a1ce7d7','和伯少穎迂仲將歸福唐偶成數詩欲奉寄無便未果也辰叔常季南還因以奉送  其五','呂本中','宋','宋诗','song-poetry','','[]','才叔策名時，已自能不動。',48,'全唐诗/poet.song.92000.json','["才叔策名時，已自能不動。", "中年謫南荒，與世作梁棟。", "生平所踐履，自待九鼎重。", "失固不足言，得亦何所用。"]'),
('92c2d192-d1d1-41ab-97e3-a309b3c04800','送范才元','呂本中','宋','宋诗','song-poetry','','[]','胡塵犯中原，冠蓋走東南。',132,'全唐诗/poet.song.92000.json','["胡塵犯中原，冠蓋走東南。", "同時辟地人，十不存二三。", "相逢各衰病，豈復能清談。", "君今尚行役，未暇脱征衫。", "聲名自宿昔，文字性所眈。", "誰能隨少年，下筆令人慙。", "並海雖名郡，嗜愛殊酸鹹。", "君但撫罷民，未須嚴轡銜。", "開堂宴賓客，清詩消半酣。", "時寄荔子來，尚能憐我饞。", "自餘君不問，只向鼻端參。"]'),
('def0efc0-9360-4fe8-ba32-cdf57a4ac076','贈魏邦達張彦素','呂本中','宋','宋诗','song-poetry','','[]','公更深居我更衰，山林膏壤偶同時。',64,'全唐诗/poet.song.92000.json','["公更深居我更衰，山林膏壤偶同時。", "兩年疾病略相似，二老風流應自知。", "苦學養生猶有累，不知閑過是無爲。", "初冬寄遠無他物，半夜才成一首詩。"]'),
('dfc927ce-8bc6-4de8-a83c-106c75b180ac','送南上人','呂本中','宋','宋诗','song-poetry','','[]','閑居病益侵，俗事初一掃。',84,'全唐诗/poet.song.92000.json','["閑居病益侵，俗事初一掃。", "南公犯寒來，爲我略傾倒。", "論詩已得妙，不必在窮討。", "我懶百慮廢，識子恨不早。", "歸途見徐董，更問此二老。", "所恨聊復翁，向者骨已槁。", "拭目看遺文，令人惡懷抱。"]'),
('80a2e256-1aca-4e34-9a14-6e89cd321bcd','贈曾吉甫','呂本中','宋','宋诗','song-poetry','','[]','荒城少往還，居處喜相近。',96,'全唐诗/poet.song.92000.json','["荒城少往還，居處喜相近。", "欣然得一笑，渠敢有不盡。", "詞源久欲竭，此道或少進。", "作氣在一鼓，軍士况未憗。", "涼風動高梧，塵土朝作陣。", "臨溪惜暫别，溪淺雨復吝。", "豈無一言贈，以當百鎰贐。", "沉綿我未瘳，李君更須慎。"]'),
('cc6a6247-ab3e-4337-9dde-881bde03390a','贈魏邦達張彦素','呂本中','宋','宋诗','song-poetry','','[]','橘綠冬未黄，菊老霜變紫。',60,'全唐诗/poet.song.92000.json','["橘綠冬未黄，菊老霜變紫。", "不知風土佳，但覺日月駛。", "閑居得養疾，調氣實在此。", "從今便休去，敢復爲物使。", "誰能明吾心，旁邑有君子。"]'),
('76e86e79-3b89-4b61-a5b4-24bab1a05aa3','次韻汪教授木犀','呂本中','宋','宋诗','song-poetry','','[]','治藥呼醫懶出門，每聞樂事漫消魂。',64,'全唐诗/poet.song.92000.json','["治藥呼醫懶出門，每聞樂事漫消魂。", "秋花带雨寒猶在，老病尋詩日更昏。", "但見晚霞翻雨脚，不知山石是雲根。", "主人有意留巖桂，要使貧交奉一尊。"]'),
('a7085e3d-0978-470f-aa2a-914efbf26c9d','送詹慥秀才','呂本中','宋','宋诗','song-poetry','','[]','子今來幾時，歲月忽已晚。',108,'全唐诗/poet.song.92000.json','["子今來幾時，歲月忽已晚。", "今當别我去，道里初不遠。", "家山霜正濃，馬草寒更短。", "何以奉親懽，一笑和氣滿。", "邇來游學士，已見如子罕。", "讀書要躬行，俗事不厭簡。", "故鄉多老儒，歸日正可款。", "時能寄餘論，尚足起我懶。", "兩州多便人，自可數往反。"]'),
('d71fcc92-02da-42b3-83b5-ed4af54916df','靜軒','呂本中','宋','宋诗','song-poetry','','[]','紛紛逐人行，擾擾與事競。',108,'全唐诗/poet.song.92000.json','["紛紛逐人行，擾擾與事競。", "不知一世間，能得幾人靜。", "公今黙無語，種種以靜勝。", "人來漫相接，事至聊復應。", "開軒道院旁，足以補我病。", "日高公事散，轉與靜相稱。", "千載師蓋公，此理久已證。", "爐烟裊晴窗，松聲韻鐘磬。", "簿書勿勤來，公方在禪定。"]'),
('167fd0ec-b5b7-466d-9e69-03663f6a4e6f','贈吳周保','呂本中','宋','宋诗','song-poetry','','[]','舊琴無譜亦無絃，子獨深求不許年。',64,'全唐诗/poet.song.92000.json','["舊琴無譜亦無絃，子獨深求不許年。", "正以安閑有餘地，不因言語悟先天。", "論詩再到新刪後，讀易仍窺未畫前。", "老病相逢聊一笑，非關無地可逃禪。"]'),
('cf8864f6-8691-4222-a303-0960fd7eaf7a','尹穡少稷方齋','呂本中','宋','宋诗','song-poetry','','[]','人圓君方君但方，鑿圓枘方君不忙。',104,'全唐诗/poet.song.92000.json','["人圓君方君但方，鑿圓枘方君不忙。", "富貴可取君則忘，閉門讀書聲琅琅。", "舊書重疊堆在床，點勘同異分偏傍。", "運精竭思心力强，十年足不離僧房。", "荒山野路秋水長，客雖欲來嫌路妨。", "幽蘭無人爲君芳，采菊落英充餱糧，客雖不來有餘香。"]'),
('6dadefe9-4f2f-497e-a83c-1d1afdbc1f3c','送義先上人歸古田','呂本中','宋','宋诗','song-poetry','','[]','斷雲無水去無蹤，回望關山指顧中。',32,'全唐诗/poet.song.92000.json','["斷雲無水去無蹤，回望關山指顧中。", "何處尋君問消息，古田南路已春風。"]'),
('66093c16-4871-42c4-b36a-4519b5096f63','送范十八','呂本中','宋','宋诗','song-poetry','','[]','范子閑行定不窮，袖中詩卷敵清風。',64,'全唐诗/poet.song.92000.json','["范子閑行定不窮，袖中詩卷敵清風。", "野僧道士有餘意，同學故人多近功。", "已辦辛勤十年讀，時須談笑一尊同。", "相看又作韶州客，却望臨川是夢中。"]'),
('ef186746-8cad-4a73-aaba-794556c3ea21','徐師川挽詩三首  其一','呂本中','宋','宋诗','song-poetry','','[]','江西人物勝，初未減前賢。',48,'全唐诗/poet.song.92000.json','["江西人物勝，初未減前賢。", "公獨爲舉首，人誰敢比肩。", "時雖在廊廟，終亦返林泉。", "今日西川路，臨風更弦然。"]'),
('473da127-4829-4944-a7b5-482f8f236d98','徐師川挽詩三首  其二','呂本中','宋','宋诗','song-poetry','','[]','異日逢明主，端居不復藏。',48,'全唐诗/poet.song.92000.json','["異日逢明主，端居不復藏。", "一心扶正道，極力拯頽綱。", "已病猶軒豁，臨衰更激昂。", "始知操韞處，餘事及文章。"]'),
('24646643-9b5c-4fb5-8425-1c9cd2b34efd','徐師川挽詩三首  其三','呂本中','宋','宋诗','song-poetry','','[]','念昔從耆舊，公知我獨深。',48,'全唐诗/poet.song.92000.json','["念昔從耆舊，公知我獨深。", "意猶如昨日，愛不減南金。", "撫事思前作，干時愧夙心。", "素琴理舊曲，無復有知音。"]'),
('07bc3aef-fd24-4c67-a407-dcaeff3ad4d4','即事六言七首  其一','呂本中','宋','宋诗','song-poetry','','[]','老來與世相忘，尚喜攤書滿床。',28,'全唐诗/poet.song.92000.json','["老來與世相忘，尚喜攤書滿床。", "憶得少年無事，苦心更學文章。"]'),
('d22d7a12-947c-4cce-88cf-246eeca4eec7','即事六言七首  其二','呂本中','宋','宋诗','song-poetry','','[]','少年與世無求，老覺心情自由。',28,'全唐诗/poet.song.92000.json','["少年與世無求，老覺心情自由。", "顛倒文章事業，追隨倦鳥虚舟。"]'),
('a1989319-7dcc-4bc0-80d3-b996a9493774','即事六言七首  其三','呂本中','宋','宋诗','song-poetry','','[]','不入樂天歡會，不隨淵明酒徒。',28,'全唐诗/poet.song.92000.json','["不入樂天歡會，不隨淵明酒徒。", "看取簞瓢陋巷，十分晝夜工夫。"]'),
('e841b80c-183b-41fa-96db-48f4f7186b2b','即事六言七首  其四','呂本中','宋','宋诗','song-poetry','','[]','百壯艾能已疾，一盃酒便生春。',28,'全唐诗/poet.song.92000.json','["百壯艾能已疾，一盃酒便生春。", "熟睡覺時意思，罷勞歇後精神。"]'),
('71660e30-e137-499d-93ce-cec3c74f82e8','即事六言七首  其五','呂本中','宋','宋诗','song-poetry','','[]','游夏一辭不措，非關未究源流。',28,'全唐诗/poet.song.92000.json','["游夏一辭不措，非關未究源流。", "直至孟軻没後，無人會讀春秋。"]'),
('e767a01e-cf1a-4dcd-a8f1-2d724cf1e79b','即事六言七首  其六','呂本中','宋','宋诗','song-poetry','','[]','養生不能延年，忘言未是安禪。',28,'全唐诗/poet.song.92000.json','["養生不能延年，忘言未是安禪。", "聖學工夫安在，重尋曲禮三千。"]'),
('82c8288a-cadc-460f-961c-0323d6e4d192','即事六言七首  其七','呂本中','宋','宋诗','song-poetry','','[]','畢竟學書不成，誰道能詩有聲。',28,'全唐诗/poet.song.92000.json','["畢竟學書不成，誰道能詩有聲。", "點檢平生交舊，幾人曾是同盟。"]'),
('6f943367-621b-4f8c-b413-c3f62b919880','楊雄','呂本中','宋','宋诗','song-poetry','','[]','讀易先知未畫前，聖人何事絕韋編。',32,'全唐诗/poet.song.92000.json','["讀易先知未畫前，聖人何事絕韋編。", "始知楊子多閑暇，更有功夫草太玄。"]'),
('51cd1552-3e4f-407b-86d1-1cc565b9fa3f','嚴君平','呂本中','宋','宋诗','song-poetry','','[]','千秋蜀道一君平，氣象從來不近名。',32,'全唐诗/poet.song.92000.json','["千秋蜀道一君平，氣象從來不近名。", "可惜下簾無一事，才將老子授諸生。"]'),
('84bada91-afc8-4221-8744-a745d29c7ccc','賈誼','呂本中','宋','宋诗','song-poetry','','[]','孔丘墨翟並稱賢，始信先生學未堅。',32,'全唐诗/poet.song.92000.json','["孔丘墨翟並稱賢，始信先生學未堅。", "何事退之傳此謬，亦將餘論點遺編。"]'),
('30e33201-85bc-43fa-ad5c-915c0a4bb626','晉二絕  其一','呂本中','宋','宋诗','song-poetry','','[]','紛紛禮樂付浮埃，一取玄虚禍始開。',32,'全唐诗/poet.song.92000.json','["紛紛禮樂付浮埃，一取玄虚禍始開。", "但見出言齊老易，始知戎馬不虚來。"]'),
('e13cbf3b-d1c6-48c1-8a0c-8d7962139251','晉二絕  其二','呂本中','宋','宋诗','song-poetry','','[]','晉朝朝士安知禮，盡出紛紛簒賊餘。',32,'全唐诗/poet.song.92000.json','["晉朝朝士安知禮，盡出紛紛簒賊餘。", "漫使當時辟世士，放言高論祖浮虛。"]'),
('1dd900a0-a925-446f-bef5-e14218484a7a','畜犬雪童黠甚勝人壬戌夏暴死作詩傷之  其一','呂本中','宋','宋诗','song-poetry','','[]','他生與我有微因，來見防家最後身。',64,'全唐诗/poet.song.92000.json','["他生與我有微因，來見防家最後身。", "共住世間均是夢，未因心境不如人。", "浮雲屢見本無迹，乂路多岐莫問津。", "此夜窮愁走南北，更誰隨馬踏埃塵。"]'),
('371a07e8-16cb-4d2f-887a-5dffd13d5b0f','畜犬雪童黠甚勝人壬戌夏暴死作詩傷之  其二','呂本中','宋','宋诗','song-poetry','','[]','伴我走道途，直前無葛藤。',24,'全唐诗/poet.song.92000.json','["伴我走道途，直前無葛藤。", "三年貧病裏，幾度送亡僧。"]'),
('99333d5a-169a-46aa-a760-788e27bf8271','又作二絕  其一','呂本中','宋','宋诗','song-poetry','','[]','荒山古寺欲黄昏，梁上諸君欲到門。',32,'全唐诗/poet.song.92000.json','["荒山古寺欲黄昏，梁上諸君欲到門。", "雨濕雪童埋處土，向來精爽更誰論。"]'),
('12d8fd08-2df9-441a-ad00-88b660c19f9f','又作二絕  其二','呂本中','宋','宋诗','song-poetry','','[]','客至書來總不知，却緣邇日吠聲稀。',32,'全唐诗/poet.song.92000.json','["客至書來總不知，却緣邇日吠聲稀。", "蛛絲網遍常行處，猶道奔逃未肯歸。"]'),
('1d50e011-672a-4590-a8ba-ee08b33536cd','秋日','呂本中','宋','宋诗','song-poetry','','[]','御盜犬新死，放生羊尚存。',48,'全唐诗/poet.song.92000.json','["御盜犬新死，放生羊尚存。", "有書消永日，無客到衡門。", "山色熱猶好，溪流雨不渾。", "還須止雜念，數息度黄昏。"]'),
('6f0e7cf3-2a28-4648-97d8-94cd81decb8d','懷雪童','呂本中','宋','宋诗','song-poetry','','[]','老來于世漫多悲，夢幻推移且自知。',64,'全唐诗/poet.song.92000.json','["老來于世漫多悲，夢幻推移且自知。", "想得開山藏骨處，却如搖尾乞憐時。", "送行識我貧無蓋，閑坐思渠悶有詩。", "從此窮居添寂寞，夜長誰復遶簾帷。"]'),
('32b37ff4-4744-4d03-a67e-349a624798af','即事','呂本中','宋','宋诗','song-poetry','','[]','畏事成閑厭出遨，故人不見如曹逃。',64,'全唐诗/poet.song.92000.json','["畏事成閑厭出遨，故人不見如曹逃。", "一寒一暑便衰老，如夢如幻無堅牢。", "客游滚滚漫南北，往事悠悠增鬱陶。", "此去還能安坐否，割雞元不用牛刀。"]'),
('be80db0b-6d20-4523-841a-9fe35c678164','念舊','呂本中','宋','宋诗','song-poetry','','[]','俯首思疇昔，常期不負渠。',48,'全唐诗/poet.song.92000.json','["俯首思疇昔，常期不負渠。", "事隨心境轉，人與舊情疏。", "少日猶相憶，多年遂絕書。", "况于生死隔，寧復似年居。"]'),
('baa6c48e-e58b-41b4-b187-abd844c16e8e','和汪教授','呂本中','宋','宋诗','song-poetry','','[]','羡君鬚作緣坡竹，飽飯我詩聲徹屋。',128,'全唐诗/poet.song.92000.json','["羡君鬚作緣坡竹，飽飯我詩聲徹屋。", "閉門不出動經旬，坐看禪房花柳簇。", "却記冰霜動地時，半夜小園風折木。", "一尊相對任濁清，三徑閑行漫松菊。", "長篇短句動盈軸，想像清香有餘馥。", "問君何以得此妙，未潤只緣山有玉。", "我窮猶敢和君詩，不留和氣滿臍腹。", "搜尋險韻少工夫，敢與諸公鬬遲速。"]'),
('eba3df34-b935-4d73-8d99-20dc12202d67','癸亥歲正月二首  其一','呂本中','宋','宋诗','song-poetry','','[]','閑居足因循，所至漫冬夏。',84,'全唐诗/poet.song.92000.json','["閑居足因循，所至漫冬夏。", "今年忽六十，稍覺日有暇。", "孔子固大聖，未害六十化。", "同時蘧伯玉，亦豈出此下。", "荘周與惠施，初未識此話。", "何因爲此語，百世呈縫罅。", "不如姑置之，以俟一朝霸。"]'),
('76a01008-d3c4-4d41-8429-16cd54f271c4','癸亥歲正月二首  其二','呂本中','宋','宋诗','song-poetry','','[]','孔子六十時，入耳心則通。',84,'全唐诗/poet.song.92000.json','["孔子六十時，入耳心則通。", "所造不可知，誰能强形容。", "當世設梯級，聊發百世蒙。", "如何陋巷顔，年少兩頰紅。", "出門請從之，便欲齊此翁。", "心知路不遠，試用一日功。", "還家對簞瓢，此士正不窮。"]'),
('9cb11774-c340-4ac8-bb22-11ae6e67f9e6','寄蔡伯世李良宇','呂本中','宋','宋诗','song-poetry','','[]','兩君羈旅宦西蜀，我亦江南住僧屋。',128,'全唐诗/poet.song.92000.json','["兩君羈旅宦西蜀，我亦江南住僧屋。", "想像平生肺腑親，晴天何處飛黄鵠。", "庾郎故是豐年玉，道兒更是見不足。", "藜羮脱粟有餘味，富貴薰天果非福。", "死生契闊今誰在，往事悠悠陵谷改。", "他年乘興下瞿塘，見我衰顔莫驚怪。", "别尋好語和君詩，償盡平生難韻債。", "掃除壁土更焚香，下酒如今有鮭菜。"]'),
('68288f0d-485d-4947-9605-99e8934750f1','贈魏承事二絕  其一','呂本中','宋','宋诗','song-poetry','','[]','雨漲溪渾欲斷橋，水鄉風物轉蕭條。',32,'全唐诗/poet.song.92000.json','["雨漲溪渾欲斷橋，水鄉風物轉蕭條。", "煩君下筆留春住，令我寒窗不寂寥。"]'),
('1f5687b6-16a3-4fb9-8bb9-e27f43e08c29','贈魏承事二絕  其二','呂本中','宋','宋诗','song-poetry','','[]','四十餘年别歷陽，舊游如夢費思量。',32,'全唐诗/poet.song.92000.json','["四十餘年别歷陽，舊游如夢費思量。", "眼明見此老居士，聽話舊游如到鄉。"]'),
('306a6815-cec0-4926-9759-676437efdb1a','送魏縣丞之官餘杭','呂本中','宋','宋诗','song-poetry','','[]','君去我逾靜，我病君得知。',120,'全唐诗/poet.song.92000.json','["君去我逾靜，我病君得知。", "如何便相遠，未有再見期。", "溪橋已春晚，紅紫久離披。", "初無一尊酒，慰君别後思。", "君才則甚長，所用無不宜。", "但當歛光芒，匣劍深藏之。", "初非擊刺用，肯顧庸人嗤。", "平生富事業，餘事尤長詩。", "當官倘見念，琢句敢嫌遲。", "上以寄難兄，下以愈我饑。"]'),
('d680f5b0-2b34-47d7-9a00-c67e20b58c4a','葉尚書普光明庵','呂本中','宋','宋诗','song-poetry','','[]','日月豈不明，明乃有昏晝。',132,'全唐诗/poet.song.92000.json','["日月豈不明，明乃有昏晝。", "四時所出火，更自表新舊。", "寧知普光明，亘古不傳授。", "獨照萬物表，不見所成就。", "遠乃包須彌，近不間圭竇。", "茫茫濁水源，我此明亦透。", "尚書所居庵，草木甚癯瘦。", "收藏萬丈光，歛退著懷袖。", "至寶久不耀，却立萬夫後。", "我願從公游，昏病方待救。", "先持此微言，遠寄爲公壽。"]'),
('f23193fd-1326-4d9e-8069-b61ef83a56cb','焦復州惟正寄鼎復兩州喜雨詩來以近體詩一首寄之','呂本中','宋','宋诗','song-poetry','','[]','聞道復州賢太守，只如前在武陵時。',64,'全唐诗/poet.song.92000.json','["聞道復州賢太守，只如前在武陵時。", "相逢未說爲州樂，所至先傳喜雨詩。", "行比曾參仍不魯，政同龔遂更何疑。", "懸知此去長閑暇，定是愚民不敢欺。"]'),
('dee9c63d-5b0a-42fe-88a1-6849659601af','送范十八還江西效白樂天體','呂本中','宋','宋诗','song-poetry','','[]','與君此别重依然，再得相逢又幾年。',64,'全唐诗/poet.song.92000.json','["與君此别重依然，再得相逢又幾年。", "無使人言長似舊，况教人道不如前。", "窮通軒輊皆由命，貴賤高低總是天。", "只有脩身全屬我，少遲留處更加鞭。"]'),
('f74fcf24-b012-4672-8196-c4cb5b3d44f6','晁公詩九經堂','呂本中','宋','宋诗','song-poetry','','[]','人家有屋但堆錢，君家有屋定不然。',80,'全唐诗/poet.song.92000.json','["人家有屋但堆錢，君家有屋定不然。", "一堂無物四壁立，六藝三傳相周旋。", "人言君貧君不顧，以此辛勤立門户。", "聖人遺意要沉思，暫脱楚騷辭漢賦。", "他年相見問何如，且說九經得力處。"]'),
('946dce94-b42b-4489-8904-e8b5e02cf5dc','送瑞印上人歸福州','呂本中','宋','宋诗','song-poetry','','[]','不須布襪與行纒，參得諸方五味禪。',32,'全唐诗/poet.song.92000.json','["不須布襪與行纒，參得諸方五味禪。", "散盡白雲見明月，虚空只是水中天。"]'),
('d10589a9-aaa5-4572-9d30-d47ffeefd6ce','尤美軒在玉山縣小葉村喻子才作尉時名之取歐陽文忠公醉翁亭記所謂林壑尤美望之蔚然者後數年舊軒既毁復作寺僧移軒山下汪聖錫要詩叙本末因成數句寄之','呂本中','宋','宋诗','song-poetry','','[]','兹軒在何許，遠在洞巖側。',120,'全唐诗/poet.song.92000.json','["兹軒在何許，遠在洞巖側。", "洞巖山水勝，自與塵土隔。", "天以奉幽人，寧肯媚過客。", "尉曹昔吏隱，到此若有獲。", "名軒曰尤美，盡去眼界窄。", "坐令歐陽公，餘意轉明白。", "車馬走道路，我久度此厄。", "茫茫六合間，於此有安宅。", "軒雖有成壞，山本無異色。", "舉頭見林壑，不必更遠索。"]'),
('ff3e3b0c-c8f8-4c7b-bd08-dfed531c1954','金谿董需彦先凌岑庵','呂本中','宋','宋诗','song-poetry','','[]','我爲江南游，衰病轉不堪。',132,'全唐诗/poet.song.92000.json','["我爲江南游，衰病轉不堪。", "往來信撫間，未上凌岑庵。", "凌岑賢主人，清峻如山巖。", "避事若荼苦，守貧如薺甘。", "平生好交游，十不存二三。", "令弟又繼往，世不聞清談。", "高風故絕俗，想像令人慙。", "浮生有欣戚，此味久已諳。", "請君但高枕，客來睡方酣。", "茫茫岐路間，與渠爲指南。", "乘風本餘事，不向鼻端參。"]'),
('0af9c835-af2f-49c1-903e-eb344405841a','盛華彦光丘壑軒','呂本中','宋','宋诗','song-poetry','','[]','盛侯少時偉儀觀，下筆不休人共歡。',144,'全唐诗/poet.song.92000.json','["盛侯少時偉儀觀，下筆不休人共歡。", "胸中别自有丘壑，萬里溪山藏几案。", "往來車馬閙泥土，盛侯何嘗著眼看。", "較量今古放同異，抖擻胸襟别真贋。", "今朝示我故人詩，老病窮愁得消散。", "故人相繼在鬼錄，君雖獨在飽憂患。", "且住溪南數間屋，坐穩不憂時節換。", "人言丘壑殊不惡，君守一丘只如昨。", "文章老健氣如虹，不向山巖何處著。"]'),
('acd27c4e-89e4-48c3-8cdf-0db64f17f11c','送晁公慶西歸','呂本中','宋','宋诗','song-poetry','','[]','頃從君家諸父游，談經語道久未休。',112,'全唐诗/poet.song.92000.json','["頃從君家諸父游，談經語道久未休。", "死生契闊風塵起，往事追尋三十秋。", "疾病衰頹且深坐，喜見後生勤勝我。", "臨行索我送行詩，短句長篇無不可。", "少年學問要躬行，世人營營勿與爭。", "閉户忍窮心自樂，簞食瓢飲殊不惡。", "紛紛得失誰厚薄，得此失彼莫籌度。"]'),
('9b92d877-ad13-40c0-bbcb-9699bf8f4ff1','曾吉父横碧軒','呂本中','宋','宋诗','song-poetry','','[]','囂塵等山林，此理久未盡。',108,'全唐诗/poet.song.92000.json','["囂塵等山林，此理久未盡。", "君今住世網，于此已自信。", "僧居隔長溪，屋古柱礎潤。", "不知市聲遠，但覺山色近。", "開軒有餘地，草木當夏盛。", "一身船轉頭，萬事燈落燼。", "譬如癢在體，搔抑吾已認。", "青山故在眼，已絕對閉吝。", "悠然有遐想，此語君所印。"]'),
('51ee19ee-d9e5-4e5b-ae07-64fd1df83020','送邢道州趙邵州歸湖南','呂本中','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','相逢不得款，奈此别離何。',132,'全唐诗/poet.song.92000.json','["相逢不得款，奈此别離何。", "長塗已新秋，從此風雨多。", "欣然出殘暑，如鳥離網羅。", "我獨此淹留，衰病日婆娑。", "跂足望二子，洞庭秋始波。", "道州通家舊，口辯如懸河。", "邵州我表弟，玉也保不磨。", "無由得相就，相近日經過。", "黄塵翻馬足，未暇眄庭柯。", "何時寄書來，與我消睡魔。", "天涼不飲酒，爲子一高歌。"]'),
('1d0f5a45-e17d-4c93-ba60-bc68fb5fa423','送方豐之秀才歸福唐','呂本中','宋','宋诗','song-poetry','','[]','我居江東，惟信之州。',220,'全唐诗/poet.song.92000.json','["我居江東，惟信之州。", "子來自南，而與我游。", "問其所友，一時之秀。", "其兄韞德，亦既有就。", "子學既立，子志甚遠。", "何以終之，止在不倦。", "貧賤勿厭，自然無悶。", "富貴勿羡，害德之本。", "彼古之人，能聖與仁。", "我胡不能，歎其絕塵。", "今子歸矣，歲亦有秋。", "何以告子，惟聖之求。", "水流有源，木生有根。", "惟源與根，入德之門。", "求聖根源，惟正之守。", "正之不守，棄師背友。", "絲毫之僞，勿萌于心。", "無有內外，亦無淺深。", "由此則聖，舍此則病。", "是以君子，所守先正。", "于以贈别，亦以自警。", "爲别後思，且以三省。"]'),
('faf79ee5-9b47-459b-b22e-c315765f5b49','向敦武挽詞','呂本中','宋','宋诗','song-poetry','','[]','耐官丞相後，世固不無人。',48,'全唐诗/poet.song.92000.json','["耐官丞相後，世固不無人。", "位下能安命，身閑不厭貧。", "還能死異域，便足繼前塵。", "此日何山路，空悲草木新。"]'),
('08aa0ad6-a465-4ae2-9710-127d8441095f','向僉判母挽詞','呂本中','宋','宋诗','song-poetry','','[]','懶作塵寰住，虚隨雲雨山。',48,'全唐诗/poet.song.92000.json','["懶作塵寰住，虚隨雲雨山。", "人皆欽懿範，天不予長年。", "室靜如歸隱，心安勝學禪。", "傳家有令子，尚得慰重泉。"]'),
('ec435cb5-d581-49c6-93eb-090f24f26797','贈眼醫張子驥郎中','呂本中','宋','宋诗','song-poetry','','[]','人生所有疾，萬種皆眼病。',204,'全唐诗/poet.song.92000.json','["人生所有疾，萬種皆眼病。", "由眼不得明，故視有不正。", "指白以爲黒，遠邇皆未定。", "如何少醫膜，遂失本來性。", "今君有妙手，與世脱機穽。", "病雖有多端，但以一理勝。", "不須望奇功，藥病自相應。", "吾觀世間物，唯眼爲至淨。", "不容著纖毫，况復計少剩。", "自古大醫王，其治有捷徑。", "不能添汝明，但要除此症。", "鏡有塵則昏，塵本不在鏡。", "塵去鏡自明，豈必與物競。", "皎潔玉壺冰，澄澈秋月瑩。", "坦然望長途，欲往不待倩。", "其說甚易知，在汝聽不聽。", "請君明其然，說法我已竟。"]'),
('861c7fab-b6be-44c0-b19f-fe4fc478d380','送晁侍郎知撫州','呂本中','宋','宋诗','song-poetry','','[]','與君相從四十載，老病昏昏君不怪。',144,'全唐诗/poet.song.92000.json','["與君相從四十載，老病昏昏君不怪。", "交游大半在鬼錄，一時輩行惟君在。", "前年簮筆侍明光，論議風流傳梗概。", "邇來同住此荒城，笑語瀾翻絕機械。", "薄酒重尋他日盟，新詩未了平生債。", "今君奉詔作鄰郡，共喜朝廷有除拜。", "定知惠政及斯民，一洗從來州郡隘。", "甕頭春色早晚熟，遠寄還須例霑丐。", "爲君試草德政碑，蕭何自昔文無害。"]'),
('536d8e93-27f5-4b22-b50a-26579139f913','晁留臺劉夫人挽詩三首  其一','呂本中','宋','宋诗','song-poetry','','[]','自昔聞諸父，文章漢兩京。',48,'全唐诗/poet.song.92000.json','["自昔聞諸父，文章漢兩京。", "風流傳壼範，烜赫振家聲。", "睦族今無匹，能書舊得名。", "如何江左郡，今日望銘旌。"]'),
('f888a907-e5e1-490b-9d0a-32414bcd8114','晁留臺劉夫人挽詩三首  其二','呂本中','宋','宋诗','song-poetry','','[]','故家劉與魏，我亦忝姻親。',48,'全唐诗/poet.song.92000.json','["故家劉與魏，我亦忝姻親。", "久矣思前作，居然愧後塵。", "遺芳接惇史，舊德見夫人。", "悵望鵝湖路，新年草木春。"]'),
('cc1177fa-c631-42cb-9376-f40d0f8f32b5','晁留臺劉夫人挽詩三首  其三','呂本中','宋','宋诗','song-poetry','','[]','留臺無恙日，樂善出誠心。',48,'全唐诗/poet.song.92000.json','["留臺無恙日，樂善出誠心。", "文采不復見，聲名空至今。", "半生資內助，三歎有遺音。", "撫事思前輩，于誰覓斷金。"]'),
('3b856bdd-d453-4f5e-b647-9b710795a5ab','贈鄭侍郎','呂本中','宋','宋诗','song-poetry','','[]','鄭公一勺酒，時與故人傾。',168,'全唐诗/poet.song.92000.json','["鄭公一勺酒，時與故人傾。", "况兹冲和天，草木日向榮。", "山茶逞獨艶，著意呈軒楹。", "坐中四五客，還來尋此盟。", "主人久未厭，頻得倒屣迎。", "燒燭夜照花，知公有餘情。", "清歌洗俗耳，軟語令心醒。", "豈伊鶴頂丹，獨自能傾城。", "要令同二妙，相伴作三英。", "紛紛桃李花，開謝略不停。", "誰知此深院，别有高世名。", "我老百事廢，對此眼暫明。", "還家不能寐，起坐數殘更。", "明朝有新句，更欲煩公聽。"]'),
('d6226afe-df14-4db1-8211-c7e177bcbc36','送宗紀上人歸福州','呂本中','宋','宋诗','song-poetry','','[]','道人海上來，訪我江外寺。',84,'全唐诗/poet.song.92000.json','["道人海上來，訪我江外寺。", "春風吹行李，飄搖不得住。", "手中主人書，足下千里路。", "臨行請一語，懇款遇外慕。", "人生未入道，所至皆旅寓。", "急參庭前柏，會取末後句。", "相逢與相别，惟此是先務。"]'),
('650b6598-59d9-44ab-9e93-028daf9074ed','郡會分韻得蠻字','呂本中','宋','宋诗','song-poetry','','[]','柳外高樓四面山，使君攜客共躋攀。',64,'全唐诗/poet.song.92000.json','["柳外高樓四面山，使君攜客共躋攀。", "塵埃不動日方永，桃李無言春自閑。", "未厭簿書時到眼，每逢詩酒亦怡顔。", "夜闌一倍園林勝，尚覺清歌欠小蠻。"]'),
('7e290e88-6df2-4b59-b7e9-ca5c719123e7','郡會賞牡丹分韻得裳字','呂本中','宋','宋诗','song-poetry','','[]','敢辭深坐懶衣裳，便欲追陪恐病妨。',64,'全唐诗/poet.song.92000.json','["敢辭深坐懶衣裳，便欲追陪恐病妨。", "小户長憂勸酒滿，短才仍怯和詩忙。", "牡丹花在逢寒食，羣玉山如望洛陽。", "不是使君尋舊賞，更無人會憶姚黄。"]'),
('8e1d7dc0-b746-4772-8a3d-4fe7d024ae9d','次蔡楠韻','呂本中','宋','宋诗','song-poetry','','[]','交舊悠悠西復東，建昌南望水連空。',32,'全唐诗/poet.song.92000.json','["交舊悠悠西復東，建昌南望水連空。", "蔡侯念我有新句，猶似灞橋風雪中。"]'),
('d19f0156-2bf0-47ef-9371-182be6ae38d3','送王提舉赴淮東七首  其一','呂本中','宋','宋诗','song-poetry','','[]','君爲千里行，我此一室住。',24,'全唐诗/poet.song.92000.json','["君爲千里行，我此一室住。", "清風隨畫舸，已過江北路。"]'),
('a22cd575-f3e2-43c3-b4a9-ec73b0121bca','送王提舉赴淮東七首  其二','呂本中','宋','宋诗','song-poetry','','[]','君如暑伏冰，所至自清靜。',24,'全唐诗/poet.song.92000.json','["君如暑伏冰，所至自清靜。", "翛然接新秋，已復天地性。"]'),
('b7aa5f73-8867-47fb-beec-32a9c4a7d6ba','送王提舉赴淮東七首  其三','呂本中','宋','宋诗','song-poetry','','[]','隨行萬卷書，既足以自娯。',24,'全唐诗/poet.song.92000.json','["隨行萬卷書，既足以自娯。", "因知君所樂，不在使者車。"]'),
('f367717c-eb4e-491a-81d0-7078fc37a838','送王提舉赴淮東七首  其四','呂本中','宋','宋诗','song-poetry','','[]','入門雖多塗，其究有安宅。',24,'全唐诗/poet.song.92000.json','["入門雖多塗，其究有安宅。", "君能識其然，一語在物格。"]'),
('f6640b49-5542-4ac3-b8ba-4613c1e92000','送王提舉赴淮東七首  其五','呂本中','宋','宋诗','song-poetry','','[]','學道貴積習，天地故相似。',24,'全唐诗/poet.song.92000.json','["學道貴積習，天地故相似。", "不容有秋心，毫髮在胸次。"]'),
('439440f3-1507-485e-9f3a-4c088d014e45','送王提舉赴淮東七首  其六','呂本中','宋','宋诗','song-poetry','','[]','海陵我舊游，歲月亦已久。',24,'全唐诗/poet.song.92000.json','["海陵我舊游，歲月亦已久。", "不知兵火後，尚有昔人否。"]'),
('a93d08a8-9aa9-4b65-ad3e-98a38ddc8e1b','送王提舉赴淮東七首  其七','呂本中','宋','宋诗','song-poetry','','[]','官閑有新作，寄我莫憚遠。',24,'全唐诗/poet.song.92000.json','["官閑有新作，寄我莫憚遠。", "兼書海陵事，令我開病眼。"]'),
('b77aae3b-741f-4d14-b6df-f7d31dc1f8ca','送財用歸開化二首  其一','呂本中','宋','宋诗','song-poetry','','[]','年來相聚欲無言，懶說諸方五味禪。',32,'全唐诗/poet.song.92000.json','["年來相聚欲無言，懶說諸方五味禪。", "所恨歸程太匆遽，不收吾骨瘴江邊。"]'),
('bae1e79f-a3f3-472f-ad57-8d48081f2cee','送財用歸開化二首  其二','呂本中','宋','宋诗','song-poetry','','[]','疾病支離欲著床，爾來殊不負秋陽。',32,'全唐诗/poet.song.92000.json','["疾病支離欲著床，爾來殊不負秋陽。", "頭童齒豁西風裏，尚費縈簾一炷香。"]'),
('301474d1-c003-447f-a7c1-94d2c8571bbd','謝范子儀見寄因次其韻','呂本中','宋','宋诗','song-poetry','','[]','疾病深藏一事無，眼從昏澁廢看書。',64,'全唐诗/poet.song.92000.json','["疾病深藏一事無，眼從昏澁廢看書。", "清詩忽覩驚人句，遠道如瞻使者車。", "頗放溪山時入座，不妨賓客醉騎驢。", "傳家事業風流在，早晚還朝得盡攄。"]'),
('1070ee1f-da81-4aba-b339-2cf3ac80e118','謝周侍郎送木瓜','呂本中','宋','宋诗','song-poetry','','[]','染以猩猩血，緣以刺繡文。',132,'全唐诗/poet.song.92000.json','["染以猩猩血，緣以刺繡文。", "天生此碩果，似是百果君。", "杯槃快先覩，便足張吾軍。", "雅宜椽燭照，正合侑金尊。", "環橙與大柑，其從蓋如雲。", "我病日已衰，故人時見存。", "晨興有奇事，此果蒙光分。", "開緘見珍異，坐使童僕奔。", "把玩不去手，舉室生清芬。", "所恨茅屋底，著此大不倫。", "瓊琚永不報，拙句聊相聞。"]'),
('aac92afd-c561-43ef-8c27-12c690cd3b2d','謝幽巖長老送荔枝二首  其一','呂本中','宋','宋诗','song-poetry','','[]','年來疾病日衰頹，咫尺閩山懶便回。',32,'全唐诗/poet.song.92000.json','["年來疾病日衰頹，咫尺閩山懶便回。", "不是幽巖老尊宿，更無人寄荔枝來。"]'),
('331c65d2-bbcc-4e14-8c5f-e273b265281b','謝幽巖長老送荔枝二首  其二','呂本中','宋','宋诗','song-poetry','','[]','荔子焦乾久未嘗，今年霜下始聞香。',32,'全唐诗/poet.song.92000.json','["荔子焦乾久未嘗，今年霜下始聞香。", "幽巖闊略庵前事，容得先生爲口忙。"]'),
('592e74d3-00fb-48fa-acae-4ece0594acfb','撫州俞隱居挽詩','呂本中','宋','宋诗','song-poetry','','[]','臨川俞處士，獨擅隱居名。',48,'全唐诗/poet.song.92000.json','["臨川俞處士，獨擅隱居名。", "懶倦不復出，風流聞後生。", "自甘長寂寞，肯作太鮮明。", "松柏新阡路，傷心秋後聲。"]'),
('01fc5acc-ea61-4ae3-af8f-f6694411dbc4','贈汪信民之子如愚','呂本中','宋','宋诗','song-poetry','','[]','四海同門一信民，近淮來往七經春。',64,'全唐诗/poet.song.92000.json','["四海同門一信民，近淮來往七經春。", "生平坎壈不如意，死去聲名多悞人。", "漫以文章付兒子，略無毫髮仰交親。", "請君但自傳家學，陋巷簞瓢莫道貧。"]'),
('2b8329c7-2f2d-47f8-9b10-40f0cbeafcec','謝曾台州送梅  其一','呂本中','宋','宋诗','song-poetry','','[]','不辭深坐轉衰頹，養病仍無酒一杯。',32,'全唐诗/poet.song.92000.json','["不辭深坐轉衰頹，養病仍無酒一杯。", "尚喜故人相勞苦，臘前先送一枝梅。"]'),
('37dfa15b-5c59-41ca-8d23-b03cf03b949f','謝曾台州送梅  其二','呂本中','宋','宋诗','song-poetry','','[]','甕間吏部久不見，江東步兵那得知。',32,'全唐诗/poet.song.92000.json','["甕間吏部久不見，江東步兵那得知。", "故人憐我太寂寞，一枝梅送兩篇詩。"]');
